window.QUIZ_DATA = {"topics": [{"id": "all", "label": "G検定 全範囲", "count": 455, "desc": "基本+応用 全章から混合出題。本番形式に近い演習。", "problems": [{"q": "『強いAI』と『弱いAI』という分類を1980年に提唱した哲学者は誰か。", "choices": ["アラン・チューリング", "ジョン・サール", "マービン・ミンスキー", "ジョン・マッカーシー"], "answer": 1, "explanation": ""}, {"q": "1956年に『Artificial Intelligence』という用語が初めて公式に使われた会議は。", "choices": ["ダートマス会議", "ジュネーブ会議", "スタンフォード会議", "MIT AI Lab 設立会議"], "answer": 0, "explanation": ""}, {"q": "チューリングテストの説明として最も適切なものは。", "choices": ["AIに将棋で人間に勝てるかを試す", "人間とAIが対話し、判定者がどちらか見分けられないかを試す", "AIが画像を正しく分類できるかを試す", "AIが論理パズルを解けるかを試す"], "answer": 1, "explanation": ""}, {"q": "『シンギュラリティ』を2045年頃と予測したことで知られる人物は。", "choices": ["イーロン・マスク", "ジェフリー・ヒントン", "レイ・カーツワイル", "ヤン・ルカン"], "answer": 2, "explanation": ""}, {"q": "特化型AI（ANI）と汎用AI（AGI）について正しい記述は。", "choices": ["AGIはANIの寄せ集めである", "現在実用化されているAIはほとんどANIで、AGIは未実現", "深層学習で容易にAGIが実現する", "ANIとAGIは同義語"], "answer": 1, "explanation": ""}, {"q": "フレーム問題とは何か。", "choices": ["画像のフレーム検出問題", "AIが状況の中で何を考慮すべきかを限定できない問題", "ハードウェアの制約問題", "学習データのフレームレート問題"], "answer": 1, "explanation": ""}, {"q": "シンボルグラウンディング問題が指す内容は。", "choices": ["記号が現実世界の意味に結びつかない", "シンボリックAIが性能で劣る", "プログラム記号の文字化け", "記号処理が遅い"], "answer": 0, "explanation": ""}, {"q": "『中国語の部屋』思考実験の主張として最も適切なものは。", "choices": ["中国語は習得が難しい", "記号操作だけでは意味理解は生じない", "コンピュータは中国語が苦手", "部屋の構造は計算に重要"], "answer": 1, "explanation": ""}, {"q": "『AI効果』とは何か。", "choices": ["AIが他のAIに影響を与える現象", "AIがタスクを達成すると『それはAIではない』と再評価される現象", "AIが学習で性能向上する効果", "AI導入による経済効果"], "answer": 1, "explanation": ""}, {"q": "AI / 機械学習 / 深層学習の関係として正しいものは。", "choices": ["AI ⊂ 機械学習 ⊂ 深層学習", "AI ⊃ 機械学習 ⊃ 深層学習", "AI = 機械学習 = 深層学習", "これらは互いに独立"], "answer": 1, "explanation": ""}, {"q": "Russell & Norvigによる4象限の知能観で『チューリングテスト』が位置するのは。", "choices": ["人間のように考える", "合理的に考える", "人間のように行動する", "合理的に行動する"], "answer": 2, "explanation": ""}, {"q": "『中国語の部屋』への代表的な反論として、『部屋全体としてなら理解している』とする立場は。", "choices": ["システム説", "ロボット説", "脳シミュレーション説", "その他の存在説"], "answer": 0, "explanation": ""}, {"q": "AIの定義について研究者の意見が完全に一致しない最大の理由は。", "choices": ["技術進歩が速いから", "『知能』そのものに普遍的な合意がないから", "国により法律が違うから", "翻訳が困難だから"], "answer": 1, "explanation": ""}, {"q": "ELIZA（1966年、ワイゼンバウム）の中核技術は。", "choices": ["深層学習", "強化学習", "パターンマッチングと書き換えルール", "知識グラフ"], "answer": 2, "explanation": ""}, {"q": "ASI（人工超知能）の説明として最も適切なものは。", "choices": ["特定タスクで人間を超えるAI", "人間と同程度の柔軟性を持つAI", "あらゆる領域で人間の知能を超えるAI", "ハードウェア性能の高いAI"], "answer": 2, "explanation": ""}, {"q": "フレーム問題に対する現代AIの現実的な対応として最も近いものは。", "choices": ["完全に解決済み", "大規模学習データから『暗黙の常識』を獲得し回避（根本解決ではない）", "フレーム問題は存在しない", "量子計算で解く"], "answer": 1, "explanation": ""}, {"q": "『弱いAI』の典型例として誤っているものは。", "choices": ["Google Translate", "AlphaGo", "顔認証システム", "意識を持つ人工知能"], "answer": 3, "explanation": ""}, {"q": "『シンタックスはセマンティクスを生まない』というテーゼで知られるのは。", "choices": ["チューリング", "サール", "ハルナッド", "マッカーシー"], "answer": 1, "explanation": ""}, {"q": "2022年にGoogleエンジニアBlake Lemoineが『感覚を持つ』と主張して論争になったAIは。", "choices": ["GPT-3", "Claude", "LaMDA", "AlphaFold"], "answer": 2, "explanation": ""}, {"q": "現代の生成AI（GPT-4等）がチューリングテストを実質的に通過したと多くの研究者が認めるが、それでも『AGI到達』とは多くが認めない。その主要な理由は。", "choices": ["速度が遅すぎる", "表面的振る舞いの合格と本質的知能は別問題（中国語の部屋の問題）", "多言語対応が不十分", "コストが高すぎる"], "answer": 1, "explanation": ""}, {"q": "2018年チューリング賞を共同受賞した3名（深層学習の父たち）は誰か。", "choices": ["Hinton, LeCun, Bengio　(1) Goodfellow, Hochreiter, LeCun　(2) Sutskever, Karpathy, Hinton　(3) Norvig, Russell, Mitchell"], "answer": 0, "explanation": "Geoffrey Hinton、Yann LeCun、Yoshua Bengio。2018年チューリング賞を『conceptual and engineering breakthroughs that have made deep neural networks a critical component of computing』として共同受賞。→ §1.6, §1.7"}, {"q": "機械学習で扱う『テンソル』の最も適切な説明は次のうちどれか。", "choices": ["物理学の座標変換則を満たす対象<br>", "スカラーまたはベクトルのみ<br>", "軸が3つ以上のものに限る<br>", "スカラー(0軸)・ベクトル(1軸)・行列(2軸)・3軸以上 を含む多次元配列の総称"], "answer": 3, "explanation": "機械学習における『テンソル』は単に多次元配列の意味で使われ、軸数を問わない。TensorFlow の Tensor も同様。物理学の意味は別。"}, {"q": "RGB カラー画像 (高さ 224, 幅 224, チャネル 3) は何階テンソルか。", "choices": ["1階", "2階", "3階", "4階"], "answer": 2, "explanation": "軸が3つ（H, W, C）あるため3階テンソル。これにバッチ次元を加えると (B, H, W, C) または (B, C, H, W) の4階テンソルとなり、CNN の入力形式となる。"}, {"q": "ベクトル u=(2, 3, 1) と v=(1, -1, 2) の内積 u·v は。", "choices": ["0", "1", "3", "7"], "answer": 1, "explanation": "2·1 + 3·(-1) + 1·2 = 2 - 3 + 2 = 1。"}, {"q": "2つのベクトルが直交するとき、内積の値は。", "choices": ["必ず正", "必ず負", "0", "1"], "answer": 2, "explanation": "u·v = ||u||||v||cosθ で、直交（θ=90°）なら cos90°=0 のため 0。これが Word Embedding の独立性、Attention の出力の独立次元、直交初期化の根拠。"}, {"q": "L1 ノルムが Lasso 正則化で『スパース解』を生む理由として正しいのは。", "choices": ["L1単位球が円形で滑らかなため<br>", "L1単位球が菱形で『角』があり、最適解が軸上に来やすいため<br>", "L1ノルムが微分可能なため<br>", "L1ノルムが指数関数を含むため"], "answer": 1, "explanation": "L1単位球（||w||₁=1）は菱形で、その『角』は軸上にある。制約付き最適化の解は等高線と単位球が接する点であり、角に当たることが多く、その軸の重みが正確に 0 になる（スパース化）。L2 の円には角がなく、すべての重みが小さく縮むだけ。"}, {"q": "ベクトル v₁=(1, 2)、v₂=(2, 4) が形作る関係として正しいのは。", "choices": ["線形独立で平面を張る<br>", "直交している<br>", "線形従属（v₂ = 2 v₁）で直線のみを張る<br>", "ノルムが等しい"], "answer": 2, "explanation": "v₂ = 2 v₁ なので一方が他方の定数倍。すなわち線形従属で、両者は同じ直線上にあり、平面を張れない。"}, {"q": "正方行列 A の逆行列が存在する必要十分条件は。", "choices": ["det(A) = 0", "det(A) ≠ 0 かつ A はフルランク", "A が対称", "A の全要素が正"], "answer": 1, "explanation": "det(A) ≠ 0 と『フルランク（rank=n）』は同値。これらが逆行列存在の条件。実用では条件数 κ(A) で『近似的特異性』も警戒する。"}, {"q": "固有値分解 A = QΛQ⁻¹ が常に可能となる行列の特徴は。", "choices": ["全ての正方行列<br>", "対称（実対称）行列 — このとき Q は直交行列、Λ は実対角<br>", "特異行列のみ<br>", "上三角行列のみ"], "answer": 1, "explanation": "一般の正方行列は固有値分解が常に可能とは限らない（Jordan 標準形が必要なケースあり）。しかし対称行列は実スペクトル定理により、必ず実固有値で直交対角化可能。PCA・カーネル法・ヘッセ行列の解析がうまく行く根拠。"}, {"q": "PCA の理論的根拠として最も適切な記述は。", "choices": ["共分散行列の固有値分解で分散最大方向（主成分）を見つける<br>", "クラスラベルの分散を最大化<br>", "データを log 変換する<br>", "重みを正則化する"], "answer": 0, "explanation": "PCA は中心化したデータの共分散行列 Σ = (1/n)XTX を固有値分解し、固有値が大きい順の固有ベクトル（主成分）にデータを射影する。教師ラベルは使わない（教師なし）。クラス分離は LDA。"}, {"q": "対称行列 A の固有値がすべて正のとき、A は何と呼ばれるか。", "choices": ["半正定値", "正定値（positive definite）", "不定値", "対角行列"], "answer": 1, "explanation": "対称行列で全固有値 &gt; 0 のとき正定値（PD）。等号許可なら半正定値（PSD、全固有値 ≥ 0）。共分散行列は必ず PSD、最適化のヘッセ行列が PD ならその点は極小。"}, {"q": "行列式 det(A) の幾何学的意味として正しいのは。", "choices": ["A の各要素の平均<br>", "A が表す線形写像による体積の倍率<br>", "A の固有値の数<br>", "A の行数"], "answer": 1, "explanation": "|det(A)| は A による線形写像が単位立方体に作用したときの体積倍率。負なら向きが反転（鏡映）。det = 0 は『写像が次元を潰す』ことを意味し、逆写像が不可能。"}, {"q": "機械学習で『多重共線性』が問題となる理由として最も適切なのは。", "choices": ["計算速度が遅くなる<br>", "特徴量行列のランクが落ち、(X<sup>T</sup>X)⁻¹ が不安定になり係数推定が安定しない<br>", "損失関数が複雑になる<br>", "データが増えすぎる"], "answer": 1, "explanation": "線形回帰の正規方程式 w = (XTX)⁻¹XTy は XTX の可逆性に依存。特徴量間に強い線形関係があると XTX はほぼ特異になり、係数推定の標準誤差が爆発、解釈不能に。対処は VIF 検出、変数削減、PCA、Ridge 回帰など。"}, {"q": "Eckart-Young 定理が示すことは。", "choices": ["任意の行列は LU 分解できる<br>", "行列の最良の rank-k 近似は、上位 k 個の特異値を残した SVD で得られる<br>", "すべての行列は対称<br>", "固有値は必ず実数"], "answer": 1, "explanation": "Eckart-Young 定理（1936）：任意の行列 A に対し、Frobenius ノルム（または2-ノルム）で最良の rank-k 近似は、SVD の上位 k 特異値を残し残りを 0 にしたもの。これが画像圧縮、レコメンドシステム、LoRA の理論的根拠。"}, {"q": "『高次元での距離の呪い』の本質的な問題は。", "choices": ["計算速度が遅い<br>", "高次元では点同士の距離が均一化し、最近傍探索などの距離ベース手法が機能しなくなる<br>", "メモリが不足する<br>", "ファイルが大きい"], "answer": 1, "explanation": "高次元では距離の最大/最小の比が 1 に近づき、すべての点がほぼ等距離になる。これにより k-NN、K-means などが意味を持たなくなる。対処は次元削減（PCA, t-SNE, UMAP, Autoencoder）、特徴選択、距離計量学習（Metric Learning）。"}, {"q": "f(x) = x³ - 2x + 1 の x=2 における微分値は。", "choices": ["4", "8", "10", "12"], "answer": 2, "explanation": "f'(x) = 3x² - 2、f'(2) = 12 - 2 = 10。"}, {"q": "勾配ベクトル ∇f(x) が指す方向は。", "choices": ["最も急に減少する方向", "最も急に増加する方向", "関数の零点", "接平面の法線"], "answer": 1, "explanation": "勾配は『最急上昇方向』を指す。最小化問題では負の勾配方向 -∇f に進む（最急降下法・SGD・Adam）。等高線に垂直になる幾何学的事実も重要。"}, {"q": "合成関数 y = f(g(x)) の微分（連鎖律）として正しいのは。", "choices": ["dy/dx = f'(g(x)) · g'(x)", "dy/dx = f'(x) · g'(x)", "dy/dx = f'(x) + g'(x)", "dy/dx = f(g'(x))"], "answer": 0, "explanation": "連鎖律：外側の関数の微分（g(x) で評価）と内側の微分の積。NNの逆伝播は連鎖律を計算グラフ上で機械的に適用したもの。"}, {"q": "ヘッセ行列 H の固有値がすべて正のとき、その臨界点は。", "choices": ["極大", "極小", "鞍点", "縮退"], "answer": 1, "explanation": "H 正定値 → 周囲が下に凸 → 極小。負定値なら極大、固有値に正負混在なら鞍点。"}, {"q": "テイラー展開を機械学習で用いる典型例は。", "choices": ["決定木の分岐", "Newton 法、XGBoost の更新方向決定", "データ拡張", "ハッシュ化"], "answer": 1, "explanation": "テイラー展開は局所近似で、1次近似→勾配降下、2次近似→Newton 法・XGBoost。誤差解析にも頻出。"}, {"q": "凸関数の重要な性質として正しいのは。", "choices": ["局所最小と大域最小が一致する", "必ず微分不可能", "学習が遅い", "制約付き最適化に使えない"], "answer": 0, "explanation": "凸関数では局所最小＝大域最小。これが線形回帰、ロジスティック回帰、SVM などが理論的に扱いやすい根拠。NN は非凸なので局所最小が複数存在しうる。"}, {"q": "勾配降下法の更新式 θ ← θ − η ∇L における η が大きすぎるとき起きうる現象は。", "choices": ["過学習", "振動・発散", "計算量増", "パラメータ削減"], "answer": 1, "explanation": "η が大きすぎると更新が最小を行き過ぎ、振動・発散。一般に Lipschitz 連続な勾配なら η ≤ 1/L が収束保証境界。"}, {"q": "SGD（確率的勾配降下）の利点として正しくないものは。", "choices": ["反復が高速", "ノイズが鞍点脱出に貢献", "メモリ効率", "必ず大域最適に収束"], "answer": 3, "explanation": "SGDは局所最適や鞍点に陥る可能性があり、大域最適への収束保証はない（凸関数では確率収束）。それでも実用上は非常に有効、特に NN ではノイズが正則化として機能。"}, {"q": "Momentum オプティマイザが解決する問題は。", "choices": ["学習率自動調整", "勾配ノイズによる振動と遅い収束", "正則化", "データ拡張"], "answer": 1, "explanation": "Momentum は勾配の指数移動平均を慣性として保持し、振動を抑制しつつ収束を加速する。物理的には『谷を転がるボール』のアナロジー。"}, {"q": "Adam オプティマイザの特徴として正しいのは。", "choices": ["Momentum と RMSProp（適応学習率）の組み合わせ＋バイアス補正", "2次オプティマイザ", "学習率不要", "NN以外でしか動かない"], "answer": 0, "explanation": "Adam は1次モーメント（Momentum）と2次モーメント（RMSProp）を併用し、初期段階のバイアス補正を加えた1次オプティマイザ。深層学習のデファクト。"}, {"q": "AdamW が通常の Adam と異なる点は。", "choices": ["重み減衰を勾配計算から分離した", "Momentum を削除した", "学習率を固定した", "全く同じ"], "answer": 0, "explanation": "Adam で L2 正則化を素朴に加えると2次モーメントとの相互作用で正則化が弱まる。AdamW は重み減衰 λθ を更新式の最後で直接引くことで、SGD と同じ正則化効果を実現。LLM 学習の事実上の標準。"}, {"q": "ラグランジュ未定乗数法が解く問題のタイプは。", "choices": ["無制約最適化", "等式制約付き最適化", "線形回帰", "クラスタリング"], "answer": 1, "explanation": "ラグランジュ関数 L(x, λ) = f(x) - λg(x) で等式制約 g(x)=0 のもとでの f(x) の最適化を扱う。不等式制約まで拡張すると KKT 条件。SVM、エントロピー最大化で核心。"}, {"q": "バックプロパゲーション（逆伝播）の理論的根拠は。", "choices": ["連鎖律", "中心極限定理", "大数の法則", "ベイズの定理"], "answer": 0, "explanation": "逆伝播は連鎖律を計算グラフ上で機械的に適用するアルゴリズム。1986年に Rumelhart, Hinton, Williams が普及させた。これがなければ深層学習は実用化できなかった。"}, {"q": "Newton 法と勾配降下法の主な違いは。", "choices": ["Newton 法は1次情報のみ使用", "Newton 法はヘッセ行列の逆を使う2次最適化、局所的に高速", "全く同じ", "勾配降下法は教師あり"], "answer": 1, "explanation": "Newton 法 θ ← θ − H⁻¹∇L は2次情報を使い、凸問題で局所的に2次収束。深層学習では H が巨大で実装困難なため、Adam 等の対角近似が実用的妥協。"}, {"q": "学習率 Warmup が必要な典型的状況は。", "choices": ["線形回帰", "大バッチ学習や Transformer 学習の初期段階", "決定木", "K-means"], "answer": 1, "explanation": "大バッチや Transformer では、初期の勾配が大きく不安定なため、η を 0 から徐々に上げる Warmup（数千ステップ）が学習安定化に必須。Cosine Annealing と組み合わせるのが現代標準。"}, {"q": "高次元損失曲面で最も多く存在するのは。", "choices": ["局所最小", "鞍点", "極大", "平坦領域のみ"], "answer": 1, "explanation": "Dauphin et al. 2014 が示したように、高次元ではヘッセ行列のすべての固有値が同符号になる確率が指数的に小さく、鞍点が圧倒的に多い。SGDのノイズが脱出に貢献。"}, {"q": "活性化関数 sigmoid σ(x) = 1/(1+e^{-x}) の微分は。", "choices": ["1", "σ(x)", "σ(x)(1 - σ(x))", "e^{-x}"], "answer": 2, "explanation": "σ'(x) = σ(x)(1 - σ(x))。出力値で書ける（再利用効率高い）。最大値は σ(0)=0.5 の点で 0.25 と小さく、深層NNで勾配消失の原因に。これがReLU普及の理由の一つ。"}, {"q": "バッチサイズを大きくした際の典型的なトレードオフは。", "choices": ["並列効率↑、汎化性能やや低下（シャープミニマへ）", "全てが向上", "全てが悪化", "メモリは変わらない"], "answer": 0, "explanation": "大バッチは並列効率・メモリ効率↑だが、勾配ノイズ↓で『シャープなミニマ』に収束しやすく汎化が劣化する傾向。Linear Scaling Rule＋Warmup で部分的補正。"}, {"q": "Gradient Checkpointing が解決する問題は。", "choices": ["計算速度の遅さ", "学習中の活性化保存に必要なメモリの大きさ", "ハイパーパラメータ選択", "データの不均衡"], "answer": 1, "explanation": "通常の逆伝播は順伝播の全活性化を保存（O(L) メモリ）。Checkpointing は一部だけ保存し、必要時に再計算でメモリを O(√L) に。計算は 1.3〜2 倍に増えるが、巨大モデル学習で必須。"}, {"q": "KKT 条件が登場する典型問題は。", "choices": ["不等式制約付き最適化、SVM など", "クラスタリング", "単純線形回帰", "K-NN"], "answer": 0, "explanation": "KKT（Karush-Kuhn-Tucker）条件は不等式制約付き最適化で必要十分（凸の場合）の最適性条件。停留性・主実行可能性・双対実行可能性・相補性の4つ。SVMの双対形式、エントロピー最大化など。"}, {"q": "サイコロを2回振って和が 7 になる確率は。", "choices": ["1/36", "1/12", "1/6", "1/4"], "answer": 2, "explanation": "和が7になる組合せは (1,6)(2,5)(3,4)(4,3)(5,2)(6,1) の6通り、全 36 通り → 6/36 = 1/6。"}, {"q": "事象 A と B が独立であることの定義として正しいのは。", "choices": ["P(A∪B) = P(A) + P(B)", "P(A∩B) = P(A)P(B)", "A=B", "P(A|B) = 0"], "answer": 1, "explanation": "独立性の定義は P(A∩B) = P(A)P(B)。これは P(A|B) = P(A) と同値。①は『排反』ではなく『独立』との混同に注意。"}, {"q": "ベイズの定理 P(A|B) = ? を正しく表すのは。", "choices": ["P(B|A) P(A) / P(B)", "P(A) P(B) / P(A∩B)", "P(A∩B) / P(A)", "P(A) + P(B)"], "answer": 0, "explanation": "ベイズの定理。これにより事前 × 尤度 / エビデンスで事後分布が得られる。"}, {"q": "連続確率変数の確率密度関数 f(x) が満たすべき性質は。", "choices": ["0 ≤ f(x) ≤ 1", "f(x) ≥ 0 かつ ∫f(x)dx = 1", "f(x) = 1", "離散値のみ"], "answer": 1, "explanation": "PDFは非負＋全積分1。値自体は1を超えうる（密度であり確率ではない）ことに注意。"}, {"q": "確率変数 X, Y が独立のとき Var(X+Y) は。", "choices": ["Var(X) + Var(Y)", "Var(X) - Var(Y)", "Var(X)Var(Y)", "Var(XY)"], "answer": 0, "explanation": "一般に Var(X+Y) = Var(X) + Var(Y) + 2Cov(X,Y)。独立なら Cov = 0 で右辺第3項が消える。"}, {"q": "ベルヌーイ分布 Be(p) の平均と分散は。", "choices": ["p, p²", "p, p(1-p)", "1-p, p", "0, p"], "answer": 1, "explanation": "E[X]=p, Var[X]=p(1-p)。分散は p=0.5 で最大 0.25。"}, {"q": "標準正規分布 N(0, 1) の確率密度関数の値が最大となる x は。", "choices": ["-1", "0", "1", "∞"], "answer": 1, "explanation": "正規分布のピークは平均 μ=0 の位置。最大密度は 1/√(2π) ≈ 0.399（1を超えない例）。"}, {"q": "中心極限定理の主張として正しいのは。", "choices": ["母集団は必ず正規", "標本平均は母集団分布によらず正規分布に近づく", "期待値=分散", "どんな分布も同じ平均"], "answer": 1, "explanation": "CLT は母集団分布が何であれ（有限分散なら）、標本平均が正規分布に収束することを示す。実用上、n≥30 で近似が良い。"}, {"q": "最尤推定（MLE）の基本的な考え方は。", "choices": ["観測データを最も尤もらしくするパラメータを選ぶ", "事前分布の中央値", "事後分布の期待値", "ランダム選択"], "answer": 0, "explanation": "MLEは観測データの尤度 P(D|θ) を最大化する θ を選ぶ。実装では対数尤度を最大化（数値安定）。"}, {"q": "MAP 推定と MLE の関係は。", "choices": ["完全に同じ", "事前分布が一様なら一致", "MAP は事前を使わない", "MLEはベイズ"], "answer": 1, "explanation": "MAP = argmax P(D|θ)P(θ)、事前が一様なら P(θ) が定数となり MAP=MLE。L2 正則化はガウス事前のMAPに相当。"}, {"q": "機械学習で『L2 正則化』に対応する事前分布は。", "choices": ["一様", "ガウシアン", "ラプラス", "ベータ"], "answer": 1, "explanation": "L2 ≡ -log P(θ) で P(θ) ∝ exp(-λ||θ||²) なのでガウシアン。L1 はラプラス分布の MAP に対応。"}, {"q": "ナイーブベイズが『naive（素朴）』と呼ばれる理由は。", "choices": ["パラメータが少ない", "特徴量が条件付き独立と仮定する", "線形", "学習が速い"], "answer": 1, "explanation": "強い独立性仮定が『素朴』の由来。実際にはほとんど成立しないが、結果は意外と頑健で実用的。"}, {"q": "EM アルゴリズムの典型用途は。", "choices": ["線形回帰の解析解", "潜在変数を含むモデルの MLE（GMM など）", "勾配計算", "正則化選択"], "answer": 1, "explanation": "EM は潜在変数（クラスタ割当、隠れ状態）を含むモデルの反復 MLE。GMM, HMM, LDA, VAE の基礎。"}, {"q": "変分推論（VI）が最大化する量は。", "choices": ["尤度のみ", "ELBO（Evidence Lower BOund）", "クロスエントロピー", "距離"], "answer": 1, "explanation": "VIは事後分布 P(θ|D) を近似分布 q(θ;φ) で近似し、ELBO を最大化する。これは KL(q||P) 最小化と等価。VAE の損失の根拠。"}, {"q": "95% 信頼区間の正しい解釈は。", "choices": ["真値が 95% の確率でこの区間にある", "同じ手順を多数回繰り返すと 95% の区間が真値を含む", "必ず真値を含む", "効果量"], "answer": 1, "explanation": "頻度論の解釈は『同じ手順を繰り返すと』。①はベイズの『信用区間』の解釈で、頻度論では誤り。"}, {"q": "p値の正しい意味は。", "choices": ["H0 が真の確率", "H0 が真と仮定したとき、観測以上に極端な結果が得られる確率", "H1 が真の確率", "効果量"], "answer": 1, "explanation": "p値は条件付き確率 P(データ|H0)。『H0 が真の確率』ではない（よくある誤解）。p &lt; α で H0 棄却。"}, {"q": "多変量正規分布 N(μ, Σ) において Σ が満たすべき条件は。", "choices": ["対角行列", "対称かつ半正定値", "単位行列", "上三角"], "answer": 1, "explanation": "共分散行列は常に対称、必ず半正定値。これは共分散の定義から数学的に従う。"}, {"q": "分類器の確率出力（softmax）が真の確率と一致するように調整する手法を何と呼ぶか。", "choices": ["キャリブレーション（Platt Scaling、Isotonic、Temperature Scaling など）", "正則化", "標準化", "量子化"], "answer": 0, "explanation": "現代のNNは過信気味で、出力確率と真の頻度が一致しないことが多い。Calibration がそれを補正。Reliability Diagram, ECE で評価。"}, {"q": "ベイズ的 A/B テストの利点は。", "choices": ["p値だけが分かる", "『B が A より良い確率』など直観的な確率解釈ができ、逐次更新が自然", "サンプル不要", "必ず A が勝つ"], "answer": 1, "explanation": "事後分布から『P(B&gt;A)』が直接出る。逐次的なデータ追加で事前を更新でき、peeking 問題が起きにくい。"}, {"q": "多重検定の補正で最も保守的な手法は。", "choices": ["Bonferroni（α/m）", "FDR (Benjamini-Hochberg)", "Holm", "無補正"], "answer": 0, "explanation": "Bonferroni は α/m と最も厳しい。検出力は犠牲だが、FWER（少なくとも1つの偽発見の確率）を α 以下に保証。現代の標準は FDR（Benjamini-Hochberg）。"}, {"q": "確率 p で起こる事象の自己情報量は。", "choices": ["p", "-p", "-log p", "1-p"], "answer": 2, "explanation": "h(x) = -log P(x)。確率が小さいほど情報量が大きい。"}, {"q": "エントロピー H(X) が最大となるのは。", "choices": ["確定的", "一様分布", "最も歪んだ分布", "連続のみ"], "answer": 1, "explanation": "離散K値の場合、一様分布で H = log K が最大。確定的は H=0 で最小。"}, {"q": "公平なコインのエントロピーは。", "choices": ["0 bit", "0.5 bit", "1 bit", "2 bit"], "answer": 2, "explanation": "H = -(0.5 log₂0.5 + 0.5 log₂0.5) = 1 bit。公平コイン1回分の情報量＝1bit。"}, {"q": "相互情報量 I(X;Y) と H の関係で誤りはどれか。", "choices": ["I(X;Y) = H(X) + H(Y) - H(X,Y)", "I(X;Y) = H(X) - H(X|Y)", "I(X;Y) ≥ 0", "I(X;Y) は負の値も取りうる"], "answer": 3, "explanation": "相互情報量は常に非負（I≥0）。X,Y独立なら 0、強く依存するなら大きい値。"}, {"q": "KLダイバージェンス KL(p||q) について誤りはどれか。", "choices": ["常に非負", "p=q なら 0", "対称：KL(p||q) = KL(q||p)", "距離関数ではない"], "answer": 2, "explanation": "KL は非対称。これが距離関数でない理由。対称化したのが JS ダイバージェンス。"}, {"q": "クロスエントロピー H(p, q) と KL の関係は。", "choices": ["H(p,q) = H(p) - KL(p||q)", "H(p,q) = H(p) + KL(p||q)", "関係なし", "H(p,q) = KL(q||p)"], "answer": 1, "explanation": "CE = H(p) + KL(p||q)。H(p) は学習データ固定なので、CE最小化 = KL最小化 = q を p に近づける。"}, {"q": "NN の分類で『Softmax + CE 損失』が標準的に使われる理由として最も適切なのは。", "choices": ["計算が遅い", "多項分布のMLEと等価、勾配が ŷ-y で簡潔", "パラメータ数を減らす", "正則化のため"], "answer": 1, "explanation": "多項分布の負の対数尤度であり、ロジットへの勾配が ŷ-y となる美しい性質を持つ。これが NN 分類学習の効率を支える。"}, {"q": "決定木の分岐基準『情報利得（IG）』の定義は。", "choices": ["H(D) - H(D|A) （分割前後のエントロピー差）", "H(D) のみ", "Var(D)", "平均値"], "answer": 0, "explanation": "IG は属性Aで分割したときのエントロピー減少量。これが大きい属性を選ぶことで予測能力の高い分岐を作る。ID3/C4.5の基準。"}, {"q": "VAE の損失関数 -ELBO の構成として正しいのは。", "choices": ["再構成損失 + KL(q(z|x) || p(z))", "CE のみ", "MSE のみ", "正則化なし"], "answer": 0, "explanation": "-ELBO = 再構成損失 + KL正則化。エンコーダ出力が事前分布N(0,I)に近づくよう KL で正則化。"}, {"q": "t-SNE が最小化する量は。", "choices": ["ユークリッド距離", "高次元と低次元の分布の KL ダイバージェンス", "MSE", "Hinge損失"], "answer": 1, "explanation": "高次元での近傍類似度分布 P と低次元での Q の KL(P||Q) を最小化。クラスタを可視化する標準手法。"}, {"q": "『最大エントロピー原理』が示すのは。", "choices": ["与えられた制約条件下で最も不確実な分布を選ぶ", "最頻分布を選ぶ", "最頻値", "中央値"], "answer": 0, "explanation": "既知の制約以外について余計な仮定をしない原則。例：平均と分散だけ既知 → 正規分布が最大エントロピー解。"}, {"q": "微分エントロピーが離散エントロピーと異なる点で正しいのは。", "choices": ["負の値も取りうる", "必ず非負", "必ず整数", "必ず log K 以下"], "answer": 0, "explanation": "連続分布の微分エントロピーは負になりうる（例：分散が極小な正規分布）。スケール変換にも不変でない。"}, {"q": "Shannon の情報源符号化定理が示す下限は。", "choices": ["1記号あたり 1 bit", "1記号あたり log K bit", "1記号あたりエントロピー H(X) bit", "上限なし"], "answer": 2, "explanation": "平均符号長 ≥ H(X)。これがロスレス圧縮の理論的下限。Huffman 符号は H+1 までで実現。"}, {"q": "GAN（原論文）の損失関数が最小化する分布間距離は。", "choices": ["KL（forward）", "JSダイバージェンス", "MSE", "ユークリッド"], "answer": 1, "explanation": "Goodfellow の元のGANは JS ダイバージェンスを最小化することが示されている。Wasserstein GAN は別の距離（Wasserstein距離）を使う。"}, {"q": "相互情報量を使った特徴選択の利点は。", "choices": ["計算速度のみ", "線形・非線形両方の依存関係を捉える", "ピアソン相関の代替で線形のみ", "ラベル不要"], "answer": 1, "explanation": "Pearson相関は線形のみだが、MIは任意の関数関係（U字、二次、複雑な依存）を捉える。教師あり特徴選択で強力。"}, {"q": "エントロピーが大きい状況の例として最も適切なのは。", "choices": ["確定的シーン", "完全にランダムなビット列", "単一値の連続", "既知の数列"], "answer": 1, "explanation": "完全にランダム＝予測不能＝エントロピー最大。圧縮も不可能（log K bit/記号）。"}, {"q": "InfoNCE（対照学習で使う）の役割は。", "choices": ["CE損失と同じ", "正サンプルと負サンプルの間で相互情報量の下限を推定して最大化", "MSE", "正則化のみ"], "answer": 1, "explanation": "InfoNCE は対照学習（SimCLR, MoCo）の損失。表現空間で正ペア類似度を負ペアより高くする、MI下限の最大化として解釈可能。"}, {"q": "2分類タスクで真ラベル y=1、予測確率 p=0.8 のとき、二値CE損失は。", "choices": ["-log(0.8)", "-log(0.2)", "0.5", "1.0"], "answer": 0, "explanation": "CE = -[y log p + (1-y) log(1-p)]、y=1 なら CE = -log p = -log(0.8) ≈ 0.223。"}, {"q": "『Label Smoothing』は何を変更するか。", "choices": ["one-hotラベル y を [1-ε, ε/(K-1), ...] に置き換え、過信を防ぐ", "損失関数を別物に変更", "学習率", "バッチサイズ"], "answer": 0, "explanation": "真ラベルの確信度を 1.0 から 1-ε（典型 0.9）に下げる正則化。NNの過信を防ぎ、汎化を改善。情報論的にはエントロピーの底上げ。"}, {"q": "KL(p||q) と KL(q||p) が大きく違う典型的状況は。", "choices": ["単峰分布同士の中心ずれ", "多峰分布 vs 単峰分布", "全く同じ分布", "KLは常に対称"], "answer": 1, "explanation": "多峰の p を単峰の q で近似する場合、KL(p||q) は mode covering（q を広く）を要求し、KL(q||p) は mode seeking（q を一つに集中）を要求。VAEは reverse KL を使い結果として1つのモードに集中しやすい。"}, {"q": "教師あり学習の定義として正しいのは。", "choices": ["ラベルなしから学ぶ", "(入力, 正解) ペアからマッピングを学ぶ", "報酬から学ぶ", "学習しない"], "answer": 1, "explanation": "教師あり学習は (x, y) ペアから関数 y=f(x) を学習。分類と回帰が代表。"}, {"q": "K-means や PCA はどの学習パラダイムか。", "choices": ["教師あり", "教師なし", "強化学習", "自己教師あり"], "answer": 1, "explanation": "ラベルを使わずデータ構造（クラスタ、主成分）を見出す教師なし学習の代表。"}, {"q": "BERT の MLM や GPT の Next Token Prediction はどのパラダイムか。", "choices": ["教師あり", "教師なし", "自己教師あり（データから教師信号を作る）", "強化学習"], "answer": 2, "explanation": "大量のラベルなしテキストから、自分自身でマスク埋めや次トークン予測という『教師信号』を作って学習。現代基盤モデルの核。"}, {"q": "強化学習の中核要素は。", "choices": ["ラベル", "状態・行動・報酬・方策", "クラスタ", "ベクトル化"], "answer": 1, "explanation": "エージェントが状態s_tで行動a_tを取り、報酬r_tを得て次状態s_{t+1}へ。累積報酬を最大化する方策 π(a|s) を学習。AlphaGo, RLHF の根幹。"}, {"q": "訓練・検証・テストデータの主な役割として正しい組合せは。", "choices": ["訓練=学習、検証=ハイパラ選択、テスト=最終評価", "すべて同じ", "テストで学習", "検証はランダム"], "answer": 0, "explanation": "テストデータは『最終評価1回のみ』。検証で繰り返しチューニングしたあとに、初めて見るデータで本番性能を推定。"}, {"q": "『データリーク』が起きる典型例は。", "choices": ["時系列データを単純シャッフルで分割、全データで正規化、目的変数情報の混入", "大きすぎるバッチ", "学習率小さい", "パラメータ少ない"], "answer": 0, "explanation": "いずれもテスト情報の漏洩。本番性能を大幅に過大評価する致命的バグ。時系列は時間順分割、正規化は訓練データで計算してテストに適用。"}, {"q": "過学習（overfitting）の典型的サインは。", "choices": ["訓練・検証とも誤差大", "訓練誤差小、検証誤差大", "両方小", "ランダム"], "answer": 1, "explanation": "過学習は『訓練データを暗記して、未見データで失敗』。対処はEarly Stopping、Dropout、L2、データ拡張、Augmentation。"}, {"q": "バイアス-バリアンス分解で『バイアス大』を表す状況は。", "choices": ["モデルが複雑すぎ", "モデルが単純すぎて関数を表現できない（未学習）", "データ多すぎ", "正則化なし"], "answer": 1, "explanation": "Bias は『系統的な誤差』、モデルの表現力不足が原因。対処はモデル複雑化、特徴量追加、正則化緩和。"}, {"q": "5-fold Cross-Validation の目的は。", "choices": ["データ量を増やす", "モデル評価の分散を減らし安定化、ハイパラ選択の信頼性", "計算を減らす", "正則化"], "answer": 1, "explanation": "データを5分割し各回1つを検証に。5回の評価の平均で評価分散を抑える。小データで特に重要。"}, {"q": "高次元ハイパラ探索で Grid Search より Random Search が推奨される理由は。", "choices": ["Bergstra 2012：少数の重要パラメータを効率的に探索できる", "計算量が同じ", "ランダムは常に最適", "コードが短い"], "answer": 0, "explanation": "多くの場合、性能を支配するハイパラは少数。Grid は全格子点を試すが、無関係次元の試行が無駄。Random は重要次元を多くサンプリングできる。"}, {"q": "Bayesian Optimization の特徴は。", "choices": ["過去の試行結果からガウス過程で次の候補を予測、試行数を最小化", "ランダム", "厳密な数学なし", "Optuna は使えない"], "answer": 0, "explanation": "GP やTPE で予測平均と分散を考慮し『有望かつ未探索な点』を選ぶ。NN の学習など1試行が高コストな場合に強力。Optuna は TPE ベースで実装。"}, {"q": "転移学習（Transfer Learning）の典型的フローは。", "choices": ["事前学習（大規模データで自己教師あり）→ ファインチューニング（少量タスクデータ）", "ゼロから訓練のみ", "ハイパラ調整のみ", "ランダム"], "answer": 0, "explanation": "BERT/GPT/ViT すべてこの流れ。LLM ではIn-Context Learning, LoRA, RLHFなど発展形が多数。"}, {"q": "No Free Lunch（NFL）定理が示唆することは。", "choices": ["あるアルゴリズムが万能", "すべての可能な問題分布で平均すると、どのアルゴリズムも同性能 → 問題ごとに適した手法を選ぶ必要", "学習不要", "深層学習が最強"], "answer": 1, "explanation": "Wolpert 1996。実用問題が特定構造（画像・言語の局所性、自然法則）を持つから NN が機能するが、すべての問題に最強なアルゴリズムは数学的に存在しない。"}, {"q": "層化抽出（Stratified Sampling）が必要な典型ケースは。", "choices": ["クラス不均衡データの分類", "完全に均一なデータ", "連続値のみ", "時系列のみ"], "answer": 0, "explanation": "クラス比が偏った（陽性 1% など）データで単純ランダム分割すると検証セットに陽性が含まれない可能性も。層化で各分割のクラス比を均一に保つ。"}, {"q": "『Early Stopping』が機能する原理は。", "choices": ["訓練を最後まで続ける", "検証損失が悪化し始める前に学習を止めて過学習を防ぐ", "パラメータ削減", "データ拡張"], "answer": 1, "explanation": "訓練損失は単調減少するが検証損失は U字。最低点で止めると過学習せず汎化性能最大化。Patience（数エポック改善なしで停止）で実装。"}, {"q": "Few-shot Learning の典型は。", "choices": ["大量データで学習", "数〜数十サンプルで新タスクに適応（MAML, In-Context Learning）", "ゼロデータ", "パラメータ調整なし"], "answer": 1, "explanation": "限られたサンプルで新タスクに適応する手法。GPT-4 のIn-Context Learning はプロンプトの例から推論する強力な Few-shot 手法。"}, {"q": "マルチタスク学習の利点として誤りはどれか。", "choices": ["タスク間で知識共有", "各タスクで Bias を下げる効果", "正則化効果でVariance↓", "全てのタスクが互いに干渉して性能が必ず下がる"], "answer": 3, "explanation": "実際にはタスク間の知識共有でしばしば性能↑。ただし関連性のないタスク同時学習は『負の転移』を起こすことがある。"}, {"q": "『Double Descent』現象（深層学習で観察）の主張は。", "choices": ["モデル複雑度を上げ続けると、過学習を超えて再び汎化が改善する", "U字カーブのみ", "学習しない", "必ず単調減少"], "answer": 0, "explanation": "古典的 U字 の後に二度目の下降。過パラメータ化された NN が経験的に汎化することの一つの説明。Belkin 2019。"}, {"q": "半教師あり学習が威力を発揮する状況は。", "choices": ["ラベル付け不可", "ラベル付きデータが少ないがラベルなしデータは大量にある（医療画像など）", "全データラベル付き", "データなし"], "answer": 1, "explanation": "ラベル収集コストが高い領域で、ラベルなしデータを活用して学習を強化。Pseudo-Labeling, FixMatch, MixMatch などの手法。"}, {"q": "『時系列データ』を扱う際の正しい分割方法は。", "choices": ["ランダム k-fold", "時系列順に分割：過去で訓練、未来で検証・テスト（Time Series Split）", "シャッフル", "階層化"], "answer": 1, "explanation": "時系列の単純シャッフルは『未来を見て過去を予測』するデータリークの典型。常に時間順で分割。Expanding window / Rolling window などの手法がある。"}, {"q": "線形回帰のOLS解析解は。", "choices": ["(XᵀX)⁻¹Xᵀy", "Xy", "X⁻¹y", "XᵀX"], "answer": 0, "explanation": "正規方程式 XᵀXβ = Xᵀy の解。XᵀX が可逆（フルランク）であることが条件。多重共線性で不安定化。"}, {"q": "ロジスティック回帰の出力は。", "choices": ["連続値", "確率 P(y=1|x)", "クラスタID", "ハードラベル"], "answer": 1, "explanation": "シグモイドで [0,1] に押込めた確率。0.5閾値でハードラベル化。"}, {"q": "SVM の最大化対象は。", "choices": ["学習データ数", "マージン（境界とサポートベクター間の距離）", "学習率", "パラメータ数"], "answer": 1, "explanation": "マージン = 2/||w|| の最大化。これは ||w|| 最小化に帰着、凸最適化問題。"}, {"q": "SVM のカーネルトリックが解決する問題は。", "choices": ["計算速度", "線形分離不可能なデータ（非線形特徴空間への暗黙写像）", "ノイズ除去", "データ拡張"], "answer": 1, "explanation": "K(x,x')=φ(x)·φ(x') で高次元への明示的写像なしに非線形分離。RBF, 多項式, シグモイドなどのカーネルが使われる。"}, {"q": "決定木の分岐基準（分類）として一般的なのは。", "choices": ["情報利得（エントロピー減少）、ジニ係数", "MSE のみ", "ランダム", "多数決"], "answer": 0, "explanation": "分類木では情報利得（ID3, C4.5）かジニ係数（CART）。回帰木では分散減少 or MSE。"}, {"q": "Bagging と Boosting の根本的違いは。", "choices": ["Bagging=並列・Variance削減、Boosting=逐次・Bias削減", "全く同じ", "Bagging が常に強い", "Boosting は弱学習器を使えない"], "answer": 0, "explanation": "Bagging は独立な弱学習器の平均で分散削減。Boosting は前の誤差を補正する逐次学習でバイアス削減。両者は相補的。"}, {"q": "ランダムフォレストが決定木より頑健な理由は。", "choices": ["1本の深い木を使う", "Bootstrap + 特徴量ランダム選択で木同士の相関を下げ、Variance削減", "学習が速い", "パラメータが少ない"], "answer": 1, "explanation": "2重のランダム性（データのBootstrap、各分岐での特徴量選択）で木の多様性を確保。100本の木の平均で過学習を抑える。"}, {"q": "表形式データでGBDT（XGBoost等）がNNより強い傾向にある主な理由は。", "choices": ["計算が遅い", "スケーリング不要、カテゴリ・欠損対応、不均衡データに頑健", "パラメータが多い", "メモリ消費が大きい"], "answer": 1, "explanation": "GBDTは表形式の特性に最適化。NNは特徴量の前処理に敏感で、表形式では性能発揮しにくい（一部例外：FT-Transformer、TabTransformer）。"}, {"q": "XGBoost、LightGBM、CatBoost の特徴対応として正しいのは。", "choices": ["XGBoostはGPUなし", "LightGBMは葉単位成長で高速", "CatBoostはカテゴリ非対応", "全て同じ"], "answer": 1, "explanation": "LightGBM はヒストグラム法＋Leaf-wise成長で超高速。XGBoost は精度志向、CatBoost はカテゴリ特徴を内蔵処理。"}, {"q": "k-NN の特徴として正しくないのは。", "choices": ["学習フェーズが軽量", "推論で全データを保持・距離計算が必要", "高次元で『距離の呪い』に弱い", "大規模データで超高速"], "answer": 3, "explanation": "k-NN は遅延学習で学習は速いが、推論で毎回全データとの距離計算が必要、大規模では遅い。Approximate NN（FAISS, HNSW）で実用化。"}, {"q": "K-means が苦手なケースは。", "choices": ["球状クラスタ", "異なるサイズ・密度・形状のクラスタ（非球状）", "数値データ", "教師あり"], "answer": 1, "explanation": "K-meansは球状クラスタを仮定（ユークリッド距離・等分散）。非球状や密度差・サイズ差があるとDBSCAN, GMM, HDBSCANが良い。"}, {"q": "K-means の初期化問題への対処は。", "choices": ["ランダム初期化のみ", "K-means++、複数回試行＋最良採用", "全データを初期点に", "1点のみ"], "answer": 1, "explanation": "K-means++ は初期点を順次最も遠い点から選ぶ。これにより局所最適確率を大幅に削減。sklearn の n_init で複数試行も標準。"}, {"q": "PCA の主成分の取得方法は。", "choices": ["ランダム", "共分散行列の固有値分解 or データのSVD", "k-NN距離", "勾配降下"], "answer": 1, "explanation": "共分散行列 Σ の固有値分解で主成分（固有ベクトル）。実装上は SVD で直接行うのが数値的に安定。"}, {"q": "DBSCAN の利点は。", "choices": ["クラスタ数 k を事前指定不要、任意形状、ノイズラベル付与", "球状のみ", "K指定必要", "学習なし"], "answer": 0, "explanation": "密度ベースでk不要、任意形状クラスタ検出、ノイズ点を明示的に分離。eps と min_samples のチューニングが鍵。"}, {"q": "Ridge と Lasso の違いとして正しいのは。", "choices": ["Ridge=L2でスパース、Lasso=L1で全保持", "Ridge=L2で全て縮小、Lasso=L1でスパース化", "同じ", "どちらも線形不可"], "answer": 1, "explanation": "Ridge は L2 ペナルティで全係数を縮小、Lasso は L1 ペナルティで多くを正確に 0 に（自動的特徴選択）。Elastic Net は両者のブレンド。"}, {"q": "SHAP（SHapley Additive exPlanations）の役割は。", "choices": ["学習アルゴリズム", "モデル解釈（各特徴量が予測にどう寄与したか）", "ハイパラ調整", "正則化"], "answer": 1, "explanation": "ゲーム理論のShapley値ベース。各特徴量の貢献を一貫した方法で説明。XAI（説明可能AI）の標準ツール。"}, {"q": "AdaBoost の仕組みは。", "choices": ["並列学習", "誤分類サンプルの重みを大きくして弱学習器を逐次学習", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Boosting の元祖。各回で誤分類点の重みを増やし、次の弱学習器が苦手部分に集中。XGBoostは Gradient Boosting の発展形。"}, {"q": "Stacking の典型構造は。", "choices": ["1つのモデルのみ", "複数モデルの予測を入力としてメタ学習器が最終予測", "多数決のみ", "ランダム"], "answer": 1, "explanation": "ベース学習器（GBDT、RF、ロジ回帰）の予測をメタ学習器（多くは線形）で統合。Kaggle上位の常套手段。CVの設計に注意。"}, {"q": "RFE（Recursive Feature Elimination）の役割は。", "choices": ["学習アルゴリズム", "特徴量を重要度の低い順から削除する反復的特徴量選択", "正則化", "クラスタ"], "answer": 1, "explanation": "モデルを学習→重要度を取得→最低の特徴量を削除→繰り返し。所望の特徴量数まで縮約。"}, {"q": "『Elbow法』が判定するものは。", "choices": ["学習率", "K-means のクラスタ数 k（クラスタ内分散の減少が緩むk）", "正則化強度", "過学習"], "answer": 1, "explanation": "k を 1, 2, 3... と増やし、SSE（クラスタ内分散和）をプロット。減少率が急変する『ひじ』を最適 k とする経験則。Silhouette score などより厳密な手法も。"}, {"q": "混同行列の TP は何を意味するか。", "choices": ["真陽性（陽性を陽性と予測）", "偽陽性", "偽陰性", "真陰性"], "answer": 0, "explanation": "TP = True Positive。"}, {"q": "Precision の定義は。", "choices": ["TP/(TP+FN)", "TP/(TP+FP)", "TN/(TN+FP)", "(TP+TN)/全体"], "answer": 1, "explanation": "陽性予測のうち実際に陽性の割合。FPが増えると下がる。"}, {"q": "Recall（感度）の定義は。", "choices": ["TP/(TP+FN)", "TP/(TP+FP)", "TN/(TN+FP)", "(TP+TN)/全体"], "answer": 0, "explanation": "実際の陽性のうち検出できた割合。FN（見逃し）が増えると下がる。医療診断で重視。"}, {"q": "F1スコアの定義は。", "choices": ["算術平均", "P×R", "PとRの調和平均", "P/R"], "answer": 2, "explanation": "F1=2PR/(P+R)。両方が高くないと高くならない。"}, {"q": "スパム検知で『全て非スパム』予測で Accuracy 99% のモデルは。", "choices": ["良い", "完全に無価値（Recall=0、F1=0）", "完全分類器", "ベスト"], "answer": 1, "explanation": "不均衡データでの Accuracy の典型的な罠。F1・PR-AUC は0。"}, {"q": "ROC-AUC の意味として正しいのは。", "choices": ["訓練時間", "陽性-陰性ペアで陽性のスコアが高い確率", "Precisionの平均", "パラメータ数"], "answer": 1, "explanation": "AUCの確率的解釈。0.5=ランダム、1.0=完全。"}, {"q": "極端な不均衡（陽性率 0.1%）で適切な指標は。", "choices": ["Accuracy", "PR-AUC", "MSE", "R²"], "answer": 1, "explanation": "ROC-AUCは不均衡に頑健すぎて高く出るがPR-AUCは真の困難度を反映。"}, {"q": "医療診断で重視すべき指標は。", "choices": ["Precision", "Recall", "Specificity", "MSE"], "answer": 1, "explanation": "Recall でFN（見逃し）を最小化。"}, {"q": "スパムフィルタで重視すべきは。", "choices": ["Precision", "Recall", "両方", "Accuracy"], "answer": 0, "explanation": "Precision でFP（重要メール誤検出）を最小化。"}, {"q": "回帰指標で外れ値に頑健なのは。", "choices": ["MSE", "RMSE", "MAE", "MAPE"], "answer": 2, "explanation": "MAE は絶対値、外れ値の影響が線形。MSE は二乗で敏感。中間に Huber Loss。"}, {"q": "R²（決定係数）の意味は。", "choices": ["必ず0〜1", "1-SSE/SST、モデルが説明する分散の割合", "パラメータ数", "Accuracy"], "answer": 1, "explanation": "テストで負になることもある。"}, {"q": "NNの予測確率を真の頻度に合わせる手法は。", "choices": ["正則化", "Calibration（Platt、Isotonic、Temperature）", "標準化", "Augmentation"], "answer": 1, "explanation": "現代NNは過信気味。Calibrationで補正、ECEで評価。"}, {"q": "多クラス F1 で macro と weighted の違いは。", "choices": ["同じ", "macro は各クラス等値、weighted はクラス頻度で重み付け", "macroはスパース", "weightedは教師あり"], "answer": 1, "explanation": "不均衡では macro が公平、頻度反映なら weighted。"}, {"q": "推薦システムでの MAP@k の意味は。", "choices": ["全体精度", "上位k個のAverage Precisionの平均、ランキング品質指標", "MSE", "R²"], "answer": 1, "explanation": "NDCG とともに推薦・検索で標準。"}, {"q": "Log Loss と Accuracy の違いは。", "choices": ["同じ", "Log Lossは予測確率の質を評価（自信度を考慮）、Accuracyはハードラベルのみ", "Log Lossは離散", "Accuracyは確率"], "answer": 1, "explanation": "自信を持って間違えるほどLog Lossが高くなる。"}, {"q": "McNemar検定の用途は。", "choices": ["t検定の代替", "同一データに対する2モデル予測比較で差が有意か判定", "クラスタリング評価", "回帰分析"], "answer": 1, "explanation": "同データ・異モデルの予測一致／不一致を表で集計し検定。"}, {"q": "SMOTE が行うことは。", "choices": ["少数クラスを単純複製", "少数クラスのk近傍間に合成サンプルを補間生成", "多数クラスを削除のみ", "ランダム"], "answer": 1, "explanation": "単純複製と違い、合成データで多様性を保つ。imbalanced-learnで実装。"}, {"q": "Cross-Validation の主目的は。", "choices": ["データ拡張", "評価分散を減らしハイパラ選択の信頼性向上", "計算高速化", "ラベル予測"], "answer": 1, "explanation": "1回分割では運次第。k-foldで多数評価の平均で安定化。"}, {"q": "Focal Loss が解決する問題は。", "choices": ["過学習", "クラス不均衡＋簡単例の過剰寄与（物体検出由来）", "学習率", "正則化"], "answer": 1, "explanation": "-(1-p)^γ log p で容易例の損失を下げ、難しい例（少数クラス）に集中。RetinaNet で導入。"}, {"q": "分類閾値の標準値 0.5 を変える理由として正しいのは。", "choices": ["必ず0.5", "業務要件、不均衡、コスト非対称性に応じて最適化", "変えてはいけない", "モデル変更必要"], "answer": 1, "explanation": "0.5は単なる慣例値。F1最大化、期待コスト最小化などで決定。"}, {"q": "パーセプトロンが解けない代表的問題は。", "choices": ["AND", "OR", "XOR", "NOT"], "answer": 2, "explanation": "XORは線形分離不可能。Minsky 1969でこの限界が指摘され第一次AI冬の時代の一因に。MLPで解決。"}, {"q": "普遍近似定理（UAP）の主張は。", "choices": ["1層では何もできない", "1層の隠れ層でユニット数十分なら任意の連続関数を任意精度で近似可能", "必ず2層必要", "ReLUのみ"], "answer": 1, "explanation": "Hornik 1989, Cybenko 1989。ただし実用では深層化の方が指数的に効率良い。"}, {"q": "ReLU の利点で正しいのは。", "choices": ["計算が遅い", "勾配消失を緩和、計算高速、スパース化", "出力が(0,1)", "必ず連続微分可能"], "answer": 1, "explanation": "max(0,x)。x&gt;0で勾配1、入力側まで勾配が伝わる。深層化を可能にした立役者。"}, {"q": "Sigmoid 活性化関数の勾配消失の原因は。", "choices": ["微分の最大値が0.25と小さく、深層では勾配が指数的に減衰", "計算が複雑", "線形", "出力が-1から1"], "answer": 0, "explanation": "σ'(x) = σ(x)(1-σ(x))の最大が0.25。10層で 0.25¹⁰ ≈ 10⁻⁶。勾配が入力側でほぼ0に。"}, {"q": "BERT/GPT で標準的に使われる活性化関数は。", "choices": ["Sigmoid", "Tanh", "GELU（Gaussian Error Linear Unit）", "Hardmax"], "answer": 2, "explanation": "GELU(x) = x·Φ(x)。ReLUより滑らか、Transformer系で標準。Swish/SiLU も類似形状。"}, {"q": "Softmax 関数の役割は。", "choices": ["二値分類", "多クラスの確率分布出力（合計1、非負）", "ノイズ追加", "正則化"], "answer": 1, "explanation": "多クラス分類の出力層標準。CE損失と組み合わせると勾配が ŷ-y で簡潔。"}, {"q": "He初期化が想定する活性化関数は。", "choices": ["Sigmoid", "Tanh", "ReLU 系", "Softmax"], "answer": 2, "explanation": "He（Kaiming）初期化：W ~ N(0, 2/fan_in)。ReLU で半分が0になることを補正。Xavier/Glorot は Tanh/Sigmoid 用。"}, {"q": "NN の重みを全て 0 で初期化すると。", "choices": ["学習加速", "対称性により全ニューロンが同じ更新を受け、多様性が生まれず学習しない", "過学習", "高速"], "answer": 1, "explanation": "対称性破壊が必要で、ランダム初期化が必須。バイアスは0でもOK。"}, {"q": "残差接続（Skip Connection、ResNet）の主な役割は。", "choices": ["パラメータ削減", "勾配伝播の改善、超深層化を可能に", "メモリ節約", "計算高速化"], "answer": 1, "explanation": "y = F(x) + x で勾配がスキップ経路から直接伝わる。100層以上を可能にした。Transformerにも採用。"}, {"q": "ミニバッチ学習の利点として誤りはどれか。", "choices": ["計算効率", "GPU並列化", "ノイズが汎化に有利", "必ず大域最適に収束"], "answer": 3, "explanation": "SGD は確率的なので大域最適保証なし。実用では十分機能、むしろノイズが鞍点脱出に役立つ。"}, {"q": "Embedding 層の役割は。", "choices": ["数値の正規化", "離散カテゴリ（単語ID、ユーザID）を学習可能な連続ベクトルに変換", "損失計算", "出力層"], "answer": 1, "explanation": "単語ID → 128〜4096次元ベクトル。Word2Vec, BERT, GPT, 推薦システムで標準。"}, {"q": "多クラス分類で使う損失関数は。", "choices": ["MSE", "Hinge", "Cross Entropy（Softmax + CE）", "MAE"], "answer": 2, "explanation": "Softmax + CE が標準。多項分布の負の対数尤度と等価。"}, {"q": "Layer Normalization が Batch Normalization より好まれる場面は。", "choices": ["CNN", "バッチサイズが小さい、可変、または RNN/Transformer", "線形回帰", "K-means"], "answer": 1, "explanation": "BN はバッチ依存、小バッチで不安定。LN は1サンプル内で正規化、Transformer ・LLM で標準。"}, {"q": "『深層化』が UAP の単層拡大より有利な理由は。", "choices": ["単に流行", "同精度を達成するパラメータ数が指数的に少なくて済む（階層的特徴学習）", "計算高速", "ランダム性"], "answer": 1, "explanation": "Telgarsky 2016 等の理論。階層的に低レベル→高レベル特徴を学習でき、効率と汎化が良い。"}, {"q": "Dying ReLU 問題への対処は。", "choices": ["Sigmoid に戻す", "Leaky ReLU, ELU, GELU 等、x&lt;0でも小さな勾配を持つ関数", "学習停止", "入力反転"], "answer": 1, "explanation": "ReLU は x≤0 で勾配0、ニューロンが死んで復活しない。Leaky ReLU（α=0.01）, GELU で緩和。"}, {"q": "バッチサイズを大きくすると一般に。", "choices": ["必ず汎化が向上", "並列効率↑だが、ノイズが減って汎化やや悪化（シャープミニマへ）", "メモリ減", "学習率不要"], "answer": 1, "explanation": "大バッチは並列効率良いが、勾配ノイズ減でシャープなミニマに収束しやすく汎化が劣化する傾向。Linear Scaling Rule + Warmupで補正。"}, {"q": "Softmax+CE の logit に対する勾配は。", "choices": ["ŷ + y", "ŷ - y", "-y", "1"], "answer": 1, "explanation": "ŷ-y というシンプルな形。これがNN分類学習の計算効率の根拠。"}, {"q": "NN の汎化が良い理由として有力な仮説は。", "choices": ["神秘的", "SGDの暗黙的正則化、フラットなミニマの選好、データの多様体仮説", "ランダム", "パラメータ多いから良い"], "answer": 1, "explanation": "過パラメータ化されているのに汎化する『深層学習の謎』。SGDの確率性が良いミニマへ導く説明が有力。"}, {"q": "『計算グラフ』の概念は何のために使われるか。", "choices": ["可視化のみ", "自動微分の実装：演算をノードとして記録し、逆伝播で勾配を機械的に計算", "メモリ節約", "学習率"], "answer": 1, "explanation": "PyTorch, TensorFlow の自動微分の根幹。連鎖律を計算グラフ上で機械的に適用。"}, {"q": "バイアス項 b の役割は。", "choices": ["不要", "線形変換に平行移動を加え、原点を通らない決定境界を可能に", "正則化", "学習率"], "answer": 1, "explanation": "y = Wx + b の b。原点を通らない超平面を表現可能に。BNを使う層では省略することもある。"}, {"q": "逆伝播の数学的核心は。", "choices": ["線形回帰", "連鎖律（chain rule）を計算グラフ上で系統的に適用", "ランダム", "クラスタリング"], "answer": 1, "explanation": "dy/dx = (dy/du)(du/dx) を多層に適用、計算グラフのbackwardで自動化。"}, {"q": "逆伝播を実用化した1986年の論文の著者は。", "choices": ["Turing", "Rumelhart, Hinton, Williams", "Bengio", "LeCun"], "answer": 1, "explanation": "Nature論文『Learning representations by back-propagating errors』。多層NNの実用化を可能にした歴史的論文。"}, {"q": "100万パラメータNNで全勾配を計算するのに必要な順伝播・逆伝播の回数は。", "choices": ["100万回", "順伝播1回 + 逆伝播1回（合計でも O(N) パラメータ数）", "1000回", "ゼロ"], "answer": 1, "explanation": "これが逆伝播の真価。素朴な有限差分なら100万倍のコスト。reverse-mode auto-diff の効率性。"}, {"q": "Sigmoid 関数の微分は。", "choices": ["σ(x)", "σ(x)·(1-σ(x))", "1-σ(x)", "x"], "answer": 1, "explanation": "美しい形。最大値は σ(0)·(1-σ(0)) = 0.25。これが勾配消失の主因。"}, {"q": "ReLU の微分は。", "choices": ["常に1", "x&gt;0で1、x≤0で0", "x", "ランダム"], "answer": 1, "explanation": "x=0で厳密には微分不可能だが、実装で0または1を採用。シンプルさが計算効率に貢献。"}, {"q": "Softmax + CE の合成勾配が美しい形は。", "choices": ["p+y", "p-y", "p²", "y²"], "answer": 1, "explanation": "logit z への ∂L/∂z = (p - y_onehot) / N。シンプル＆数値安定。NN分類の計算効率の根拠。"}, {"q": "全結合層 z = Wx + b で、上流勾配 δ = ∂L/∂z から得られる ∂L/∂W は。", "choices": ["δ・x", "δ・xᵀ（外積）", "Wδ", "δ"], "answer": 1, "explanation": "形状 dₒᵤₜ × dᵢₙ。バッチでは Σ δᵢ·xᵢᵀ。∂L/∂b = δ, ∂L/∂x = Wᵀδ。"}, {"q": "NN学習で reverse-mode 自動微分が使われる理由は。", "choices": ["パラメータ数 ≫ 出力数（損失1つ）なので、forward-modeより遥かに効率的", "唯一の方法", "ランダム", "メモリ少ない"], "answer": 0, "explanation": "Forward は入力数に、Reverse は出力数に計算量が比例。NN は損失1つなので Reverse 一択。"}, {"q": "勾配消失の主因は。", "choices": ["学習率", "活性化関数の微分の積が層数で指数的に減衰（Sigmoid/Tanh）", "パラメータ数", "データ量"], "answer": 1, "explanation": "Sigmoid 微分最大 0.25、L層で 0.25^L。10層で 1e-6。ReLU、BN、ResNet で解決。"}, {"q": "勾配爆発の対処は。", "choices": ["学習率を上げる", "Gradient Clipping（勾配ノルムを上限でカット）", "何もしない", "パラメータ増加"], "answer": 1, "explanation": "RNN/Transformer で標準。||g|| &gt; threshold なら g ← g · threshold/||g||。閾値 1.0 が典型。"}, {"q": "SGD の更新式は。", "choices": ["θ ← θ + η・∂L/∂θ", "θ ← θ - η・∂L/∂θ", "θ ← ∂L/∂θ", "θ ← η・θ"], "answer": 1, "explanation": "勾配方向の逆（descent）に η（学習率）だけ動く。シンプルだが汎化が良いことがある。"}, {"q": "逆伝播でメモリを最も消費するのは。", "choices": ["パラメータ", "オプティマイザ状態", "順伝播の中間活性化（逆伝播で必要）", "損失値"], "answer": 2, "explanation": "各層の出力（B × D）を逆伝播のために保存。L 層では O(L·B·D)。これが大規模NN のメモリ消費の主因。"}, {"q": "Gradient Checkpointing の効果は。", "choices": ["計算高速化", "中間活性化を一部だけ保存し逆伝播で再計算、メモリ O(L)→O(√L)", "精度向上", "パラメータ削減"], "answer": 1, "explanation": "メモリと計算のトレードオフ（計算1.5倍）。LLM 学習で必須。PyTorch torch.utils.checkpoint で実装。"}, {"q": "Mixed Precision Training（FP16/BF16）の主な利点は。", "choices": ["精度向上", "GPU メモリ半減＆計算2〜3倍速、Tensor Coreを活用", "パラメータ削減", "ランダム性"], "answer": 1, "explanation": "FP16計算 + FP32重みコピー + Loss Scaling。BF16はダイナミックレンジが広く Loss Scaling 不要。LLM学習で標準。"}, {"q": "Data Parallel の動作は。", "choices": ["1GPUだけ使う", "各GPUに同じモデルコピー、ミニバッチを分割、勾配をAllReduceで集約", "モデルを分割", "ランダム"], "answer": 1, "explanation": "最も基本的な並列化。PyTorch DDP, Horovod。モデルがGPUに載るサイズなら最初の選択肢。"}, {"q": "勾配チェック（Gradient Check）の用途は。", "choices": ["学習加速", "解析的に計算した勾配と数値微分を比較し、実装バグを検出", "パラメータ削減", "必須学習"], "answer": 1, "explanation": "カスタム backward を書いたとき必須。差が 1e-7〜1e-5 オーダーなら正しい。学習中は遅いので無効化。"}, {"q": "PyTorch で勾配計算を有効化するには。", "choices": ["自動で有効", "requires_grad=True で作成、または .requires_grad_() で設定", "不可能", "ランダム"], "answer": 1, "explanation": "requires_grad=True の Tensor は計算グラフに含まれ、.backward() で勾配が記録される。.grad 属性で取得。"}, {"q": "ZeRO（DeepSpeed）が分散するのは。", "choices": ["モデルのみ", "オプティマイザ状態、勾配、パラメータを分散保持しメモリ削減", "データのみ", "ランダム"], "answer": 1, "explanation": "ZeRO-1：オプティマイザ状態、ZeRO-2：+勾配、ZeRO-3：+パラメータも分散。LLM学習で必須。"}, {"q": "Operator Fusion（Fused operations）の効果は。", "choices": ["精度向上", "連続した演算を1カーネルに融合、メモリ転送削減でGPU効率↑", "パラメータ削減", "ランダム"], "answer": 1, "explanation": "FlashAttention の核心。HBM ↔ SRAM 転送を減らす。Triton, CUDA Graph で実装。"}, {"q": "『Stop Gradient』の用途は。", "choices": ["学習停止", "計算グラフの一部で勾配を遮断（GAN、対照学習、強化学習の Target Network 等で必須）", "パラメータ削除", "ランダム"], "answer": 1, "explanation": ".detach() で実装。Target を更新せず参照だけしたいときに使う。BYOL、DQN、PPO で必須テクニック。"}, {"q": "L2 正則化（Weight Decay）が抑制するのは。", "choices": ["学習速度", "大きな重みの値、過学習", "計算量", "メモリ"], "answer": 1, "explanation": "L_total = L + λ||θ||² で大きな重みを罰し、汎化を改善。MAP推定でガウス事前に対応。"}, {"q": "Dropout の典型的なドロップ率は。", "choices": ["0.01", "0.1〜0.5", "0.9", "1.0"], "answer": 1, "explanation": "一般に 0.1〜0.5。隠れ層で 0.5、入力層で 0.2 が古典的。BN と併用するときは小さめにする傾向。"}, {"q": "Dropout の動作として正しいのは。", "choices": ["訓練時のみニューロンを確率的に無効化、推論時はすべて使用", "常に無効化", "推論でのみ動作", "パラメータ削減"], "answer": 0, "explanation": "訓練時のみドロップ、推論時は通常通り（スケール補正あり）。アンサンブル近似と解釈できる。"}, {"q": "Batch Normalization の正規化対象は。", "choices": ["単一サンプル内", "ミニバッチ内の各チャネルごと", "パラメータ自体", "学習率"], "answer": 1, "explanation": "ミニバッチ内で各特徴/チャネルごとに平均・分散を計算し正規化。バッチサイズ依存、Tiny バッチでは不安定。"}, {"q": "Transformer で標準的な正規化は。", "choices": ["BatchNorm", "LayerNorm（バッチサイズ非依存、系列長変化OK）", "なし", "Dropout"], "answer": 1, "explanation": "LayerNorm は単一サンプル内の特徴次元で正規化。可変長の系列、小バッチでも安定。最近は RMSNorm も（LLaMA 等）。"}, {"q": "He 初期化が適している活性化関数は。", "choices": ["Sigmoid", "tanh", "ReLU 系（Leaky ReLU、GELU を含む）", "Step"], "answer": 2, "explanation": "He（2015）は分散 2/n_in で、ReLU の片側 0 の性質を考慮。Xavier は Sigmoid/tanh 向け。LeCun は SELU 向け。"}, {"q": "Early Stopping の動作は。", "choices": ["訓練を必ず最終エポックまで", "検証損失が改善しなくなったら停止（過学習開始前）", "ランダム停止", "学習しない"], "answer": 1, "explanation": "Patience（数エポック改善なし）で停止。最も簡単で効果的な正則化。最良時のモデルを保存して使う。"}, {"q": "画像認識でよく使われる強力な自動データ拡張は。", "choices": ["反転のみ", "RandAugment、AutoAugment、TrivialAugment", "ノイズのみ", "なし"], "answer": 1, "explanation": "RandAugment は2つの操作を強度 9 でランダム適用。AutoAugment は RL で最適化された方策。深層学習の SOTA で標準。"}, {"q": "Label Smoothing が変更する対象は。", "choices": ["学習率", "one-hot ラベルを [ε/(K-1), 1-ε,...] に置換、過信抑制", "パラメータ数", "バッチサイズ"], "answer": 1, "explanation": "真ラベルの確信度を 1.0 から 1-ε（典型 0.9）に下げる。汎化改善＋過信抑制。ImageNet, NMT などで標準。"}, {"q": "Mixup の動作は。", "choices": ["単一サンプル", "2サンプルを λ:1-λ で線形混合、ラベルも同様に混合", "ノイズ加算", "パラメータ平均"], "answer": 1, "explanation": "Zhang 2018。画像とラベルを線形補間。決定境界を滑らかにし、汎化と頑健性を改善。CutMix は領域置換版。"}, {"q": "Gradient Clipping の目的は。", "choices": ["過学習防止", "勾配爆発防止（特に RNN/Transformer 学習）", "計算高速化", "メモリ削減"], "answer": 1, "explanation": "||g|| が閾値超過時にスケーリング。RNN の長系列・Transformer の大規模学習で標準（threshold=1.0 が典型）。"}, {"q": "Knowledge Distillation（蒸留）の目的は。", "choices": ["パラメータ増加", "大きな教師モデルの知識を小さな生徒モデルに転送", "ランダム学習", "クラスタリング"], "answer": 1, "explanation": "Hinton 2015。教師の softmax 出力（soft target）で生徒を学習。DistilBERT、TinyLLaMA、MobileBERT 等で軽量化に必須。"}, {"q": "Mixed Precision Training で主に使う型は。", "choices": ["FP32 のみ", "FP16 や BF16 と FP32 重みコピーの組合せ", "INT8 のみ", "INT4 のみ"], "answer": 1, "explanation": "計算は FP16/BF16、重みは FP32 で保持、損失スケーリングで underflow 防止。GPU メモリ半減、計算2-3倍速。BF16 はダイナミックレンジが広く実用的。"}, {"q": "Gradient Checkpointing（Activation Checkpointing）の効果は。", "choices": ["計算高速化", "順伝播の活性化を一部のみ保存し、逆伝播で再計算。メモリO(L) → O(√L)に", "精度向上", "学習率自動調整"], "answer": 1, "explanation": "メモリと計算のトレードオフ。LLM 学習では巨大モデルを限られた GPU で訓練するために必須。"}, {"q": "『Warmup』（学習率ウォームアップ）が必要な代表的状況は。", "choices": ["全ての状況", "Transformer 学習、大バッチ学習", "線形回帰", "K-means"], "answer": 1, "explanation": "初期の勾配が大きく不安定なため、η を 0 から徐々に上げる（数千ステップ）。Transformer、ViT、LLM 学習で必須。Cosine Annealing と組合せが標準。"}, {"q": "深層 CNN で勾配消失を抑制する主要技術として誤りはどれか。", "choices": ["ReLU", "残差接続", "Batch Normalization", "Sigmoid 活性化"], "answer": 3, "explanation": "Sigmoid は勾配消失の主要原因の一つ。ReLU、残差接続、BN、適切な初期化が勾配消失緩和の四天王。"}, {"q": "Stochastic Depth の動作は。", "choices": ["パラメータをランダムドロップ", "残差ブロックを確率的にスキップ（恒等写像に）", "学習率変化", "ノイズ加算"], "answer": 1, "explanation": "Huang 2016。残差NNの深さをランダム化することで正則化。100+ 層 ResNet で標準的に使われる。"}, {"q": "推論時に Dropout を有効にして複数回サンプリングする手法は何の推定に使うか。", "choices": ["高速化", "不確実性推定（Monte Carlo Dropout, Gal 2016）", "学習継続", "正則化"], "answer": 1, "explanation": "Yarin Gal が示した。推論時 Dropout で N 回サンプリング、出力の分散が予測不確実性の近似となる。ベイズ NN の安価な近似。"}, {"q": "『Cosine Annealing』学習率スケジューラの形状は。", "choices": ["直線的減少", "余弦関数で滑らかに減衰（T_max でゼロ近くに）", "階段状", "一定"], "answer": 1, "explanation": "lr = lr_max · (1+cos(π·t/T))/2 で滑らかに減衰。Warmup と組み合わせが現代学習の標準。SGDR で再起動版もある。"}, {"q": "AdamW が Adam と異なる主要な点は。", "choices": ["Momentumなし", "重み減衰を更新式の最後で適用（Adam の正則化と分離）、L2 正則化と等価に動作", "学習率を増やす", "Bias 補正削除"], "answer": 1, "explanation": "元の Adam で L2 を勾配に足すと2次モーメントとの相互作用で減衰効果が薄れる。AdamW は θ ← θ - η(m̂/√v̂ + ε) - η λ θ と最後で減衰、L2 と一致。LLM学習の事実上の標準。"}, {"q": "CNN が MLP より画像処理に適している理由は。", "choices": ["計算が遅い", "空間的局所性と平行移動不変性の帰納バイアス、パラメータ共有でパラメータ削減", "学習が不安定", "メモリを大量に必要とする"], "answer": 1, "explanation": "CNN は同じフィルタを全位置で適用（パラメータ共有）し、近い画素関係を仮定。MLPの全結合に比べパラメータが2〜3桁少なく、性能も高い。"}, {"q": "2012年の AlexNet が ImageNet コンペで起こした革命の核心は。", "choices": ["浅い NN を使った", "深層CNN + ReLU + Dropout + GPU + データ拡張で従来手法を圧倒", "教師なし学習", "強化学習"], "answer": 1, "explanation": "Krizhevsky 2012。誤り率 15.3% vs 2位 26.2%。深層学習革命の起点となった。"}, {"q": "入力 32x32、3x3 Conv、stride=1、padding=1 のとき出力サイズは。", "choices": ["30x30", "32x32（same パディング）", "16x16", "34x34"], "answer": 1, "explanation": "(32 + 2·1 - 3) / 1 + 1 = 32。padding='same' で入力と同じサイズを維持。VGG以降で標準。"}, {"q": "Max Pooling の役割として正しいのは。", "choices": ["学習可能パラメータ追加", "領域内最大値を取り、空間ダウンサンプリング・平行移動不変性強化", "正則化のみ", "出力層"], "answer": 1, "explanation": "パラメータなし、空間次元削減、強い活性化を保持。Average Pooling より一般的。"}, {"q": "ResNet（2015）が解決した深層化の壁は。", "choices": ["計算量", "勾配消失と退化問題：残差接続 y=F(x)+x で 152層を学習可能に", "メモリのみ", "ラベル不足"], "answer": 1, "explanation": "He 2015。スキップ接続で勾配が直接伝播。ImageNet 誤り率 3.57%、人間（5.1%）超え。現代CNN/Transformerの標準構造。"}, {"q": "VGG の特徴的な設計は。", "choices": ["1x1 Conv のみ", "3x3 Conv のみを多層積み重ね（16〜19層）", "ランダム", "全結合のみ"], "answer": 1, "explanation": "Simonyan 2014。シンプルで強力。3x3 を 2層で 5x5 相当の受容野をパラメータ少なく実現する発見。"}, {"q": "『受容野（Receptive Field）』とは。", "choices": ["出力ピクセルが影響を受ける入力上の領域", "パラメータ数", "バッチサイズ", "学習率"], "answer": 0, "explanation": "深い層ほど受容野が広い。3x3 conv を 2層重ねると 5x5 受容野。Dilated Conv で更に拡大可能。"}, {"q": "EfficientNet (2019) の貢献は。", "choices": ["ランダム探索", "深さ・幅・解像度を複合スケーリングで最適化、同精度で大幅パラメータ削減", "教師なし", "ViT 提案"], "answer": 1, "explanation": "Tan & Le 2019。compound scaling で計算予算に対する精度効率を最大化。モバイル向けにも適用。"}, {"q": "Vision Transformer (ViT) の入力処理は。", "choices": ["画素単位", "画像を 16x16 などのパッチに分けてトークン化し Transformer に入力", "Conv のみ", "MLP のみ"], "answer": 1, "explanation": "Dosovitskiy 2020。CNN の帰納バイアスなしで、大量データ（JFT-300M）で CNN を超えた。CLIP、Stable Diffusion で標準。"}, {"q": "YOLO シリーズの特徴は。", "choices": ["2-stage", "1-stage：画像をグリッド分割し各セルで物体予測、リアルタイム", "教師なし", "セグメンテーション特化"], "answer": 1, "explanation": "Redmon 2016 で導入、YOLOv8/v10 まで進化。FPS が高く、産業応用で広く使われる。"}, {"q": "U-Net (2015) が広く使われる分野は。", "choices": ["物体検出", "医療画像セグメンテーション、エンコーダ-デコーダ＋スキップ接続", "言語モデル", "強化学習"], "answer": 1, "explanation": "Ronneberger 2015。U字型構造で詳細を保持。Diffusion モデル（DDPM、Stable Diffusion）の denoiser にも採用。"}, {"q": "転移学習（ImageNet → 別タスク）が機能する理由は。", "choices": ["偶然", "浅層が汎用的特徴（エッジ、テクスチャ）を学習、それは多くのタスクで再利用可能", "ランダム", "パラメータ多いから"], "answer": 1, "explanation": "階層的特徴学習。少量データのタスクで事前学習モデルをファインチューニングすると、ゼロから学習より大幅に高精度。"}, {"q": "Global Average Pooling (GAP) の役割は。", "choices": ["学習する", "各チャネルの空間平均でベクトル化、最終FC層代替、パラメータ削減", "ノイズ追加", "正則化のみ"], "answer": 1, "explanation": "NIN/ResNet以降で標準。Flatten + 巨大 FC をGAPで置換、過学習防止＋パラメータ削減。Class Activation Map の基礎にも。"}, {"q": "Grad-CAM の目的は。", "choices": ["学習加速", "予測根拠の可視化（どの画像領域がクラス予測に貢献したか）", "圧縮", "ノイズ除去"], "answer": 1, "explanation": "Selvaraju 2017。最終 Conv 層の勾配を使ってヒートマップを生成。XAI（説明可能AI）の標準ツール、医療画像で重要。"}, {"q": "1x1 Convolution（pointwise）の役割は。", "choices": ["役立たず", "チャネル間の線形結合、次元削減・拡張、Inception/ResNet で頻用", "プーリング代替", "正則化"], "answer": 1, "explanation": "空間方向は1x1で変えず、チャネル方向のみ変換。Bottleneck構造で計算量削減。MobileNet（Depthwise Separable Conv）でも核心。"}, {"q": "Segment Anything Model (SAM, 2023) の特徴は。", "choices": ["単一タスク", "プロンプト型セグメンテーション、未知物体も可、Foundation Modelとして広く転用可", "教師なしのみ", "軽量モデル"], "answer": 1, "explanation": "Meta AI 2023。点・ボックス・テキストプロンプトで任意の物体をセグメント。10億+のマスクで事前学習。"}, {"q": "DenseNet (2017) の特徴は。", "choices": ["全層をスキップ接続でなく完全に連結（dense connection）、特徴再利用と勾配伝播改善", "パラメータ激増", "浅い NN", "物体検出専用"], "answer": 0, "explanation": "Huang 2017。各層が前のすべての層の出力を入力に。パラメータ効率と精度が高い。"}, {"q": "物体検出の評価指標として標準的なのは。", "choices": ["Accuracy", "mAP（mean Average Precision）@IoU 0.5、0.5:0.95", "MSE", "R²"], "answer": 1, "explanation": "COCO標準。クラスごとの AP の平均、IoU 閾値で性能評価。YOLO, Faster R-CNN等の比較で使用。"}, {"q": "ConvNeXt (2022) の主張は。", "choices": ["ViTが万能", "CNNにViTの工夫（GELU、LN、大きなカーネル等）を取り入れれば、CNNがViTと同等以上の精度に", "Conv 不要", "教師なし"], "answer": 1, "explanation": "Liu 2022。ViT の優位性はアーキテクチャ自体ではなく、学習レシピと工夫にあると示唆。"}, {"q": "Dilated（Atrous）Convolution の効果は。", "choices": ["パラメータ増加", "カーネル内のサンプル間隔を空けて受容野を拡大、パラメータ・計算量は同じ", "ノイズ追加", "教師なし"], "answer": 1, "explanation": "DeepLab系で活用。セグメンテーションで詳細を保ちつつ広い文脈を捉える。"}, {"q": "RNNが MLP より系列データに適する理由は。", "choices": ["計算高速", "隠れ状態 h で過去の文脈を保持、可変長系列を扱える", "パラメータ多い", "教師なし"], "answer": 1, "explanation": "h_t = f(h_{t-1}, x_t) で過去情報を伝播、同じパラメータを全時刻で共有。"}, {"q": "BPTT（Backprop Through Time）の問題は。", "choices": ["不要", "長系列で計算・メモリ増、勾配消失/爆発", "教師なし限定", "学習しない"], "answer": 1, "explanation": "系列長Tに比例して計算が増え、勾配が指数的に減衰または爆発。Truncated BPTT、Gradient Clipping、LSTM/GRU で対処。"}, {"q": "勾配消失問題で『記憶できる時間』の典型は。", "choices": ["1ステップ", "Vanilla RNNでは 10〜20ステップが限界", "無限", "100万ステップ"], "answer": 1, "explanation": "tanh の勾配積が指数減衰。LSTM/GRU でこれを数百ステップまで拡大。"}, {"q": "LSTM のセル状態 c_t の特徴は。", "choices": ["隠れ状態と同じ", "加算更新で勾配が保存され、長期依存を学べる", "出力のみ", "ノイズ"], "answer": 1, "explanation": "c_t = f_t ⊙ c_{t-1} + i_t ⊙ c̃_t の加算ベース更新が勾配消失を緩和。これが LSTM の核心。"}, {"q": "LSTMの3つのゲートとして正しいのは。", "choices": ["入力、Conv、Pool", "忘却（forget）、入力（input）、出力（output）", "順、逆、双方向", "学習、推論、評価"], "answer": 1, "explanation": "Hochreiter & Schmidhuber 1997。Sigmoidゲートで情報の流れを制御。"}, {"q": "GRU がLSTMより優れる点は。", "choices": ["必ず高精度", "パラメータが少なく、計算高速、性能はほぼ同等", "ゲートなし", "双方向のみ"], "answer": 1, "explanation": "Cho 2014。リセットゲートと更新ゲートだけで2ゲート構造。実装簡素、性能はLSTMと拮抗。"}, {"q": "双方向RNN（Bi-LSTM）が使えない典型タスクは。", "choices": ["文分類", "NER", "言語モデル（次トークン予測、未来情報禁止）", "感情分析"], "answer": 2, "explanation": "生成・予測タスクは未来情報を使えない（カンニングになる）。分類・タグ付けには Bi-LSTM が長く標準。"}, {"q": "Seq2Seq モデルの構造は。", "choices": ["1個のRNN", "エンコーダ（入力→ベクトル）+ デコーダ（ベクトル→出力）", "CNN のみ", "MLP のみ"], "answer": 1, "explanation": "Sutskever 2014。機械翻訳、要約、対話の基本枠組み。固定長ベクトルがボトルネック、Attentionで解消。"}, {"q": "Attention（Bahdanau 2015）が解決した Seq2Seq の課題は。", "choices": ["学習速度", "固定長ベクトルのボトルネック、長文で性能劣化", "メモリ消費", "過学習"], "answer": 1, "explanation": "エンコーダ全時刻の隠れ状態にデコーダが重み付き参照。長文翻訳の品質が劇的改善。Transformer の母。"}, {"q": "Beam Search の役割は。", "choices": ["学習加速", "系列生成で上位 k 候補を保持して探索、Greedy より高品質", "正則化", "クラスタリング"], "answer": 1, "explanation": "翻訳・要約で標準。beam size 4〜8 で BLEU 2〜3 ポイント改善。LLM 生成では nucleus sampling 等の方が人気。"}, {"q": "Truncated BPTT の目的は。", "choices": ["精度向上", "長系列で計算・メモリを節約、一定ステップで切って勾配計算", "学習なし", "過学習防止"], "answer": 1, "explanation": "全系列のBPTTは不可能なので、典型 35〜200 ステップで切る。長期依存は LSTM/GRU の力で。"}, {"q": "勾配爆発の対処として有効なのは。", "choices": ["学習率を上げる", "Gradient Clipping（勾配ノルムを閾値で制限）", "パラメータ削除", "Sigmoid を使う"], "answer": 1, "explanation": "torch.nn.utils.clip_grad_norm_ で実装。閾値1.0〜5.0が典型。Transformer 学習でも常用。"}, {"q": "音声認識で 2020〜2026 の標準は。", "choices": ["古典GMM-HMM", "Whisper、Conformer など Transformer 系", "Bi-LSTM のみ", "K-means"], "answer": 1, "explanation": "Whisper（OpenAI 2022）が多言語SOTA。Conformer（Google）はTransformer+Convの組合せでオンライン認識に強い。"}, {"q": "時系列予測で Transformer 系の代表例は。", "choices": ["ResNet", "Informer、PatchTST、Temporal Fusion Transformer", "K-NN", "ARIMA"], "answer": 1, "explanation": "長系列・多変量を効率良く扱える。最近の研究では『単純MLPでもTransformerと同等』との指摘も（DLinear等）。"}, {"q": "2023 年以降、『RNN の系譜』を継ぐ新世代モデルは。", "choices": ["CNN", "Mamba（SSM）、RWKV、Linear Attention", "MLP のみ", "K-NN"], "answer": 1, "explanation": "Selective SSM (Mamba 2023) が Transformer に対抗、線形メモリ・長文脈で優位。RWKV は RNN ライクな並列学習。"}, {"q": "『Teacher Forcing』の意味は。", "choices": ["強制学習", "Seq2Seq学習時に、デコーダへの入力に過去のモデル出力ではなく『正解』を与える手法", "教師なし", "クラスタ"], "answer": 1, "explanation": "訓練効率を上げるが、推論時の自己回帰生成と乖離する『Exposure Bias』問題も。Scheduled Sampling が緩和策。"}, {"q": "BiLSTM-CRF が長く標準だったタスクは。", "choices": ["画像分類", "NER（固有表現抽出）、品詞タグ付けなどの系列ラベリング", "強化学習", "K-means"], "answer": 1, "explanation": "BiLSTM が文脈、CRF がラベル間依存関係を学習。BERT 登場（2018）まで最強。今もリソース制約環境で実用。"}, {"q": "機械翻訳の評価指標として標準的なのは。", "choices": ["Accuracy", "BLEU、METEOR、chrF、最近は COMET、BERTScore", "MSE", "R²"], "answer": 1, "explanation": "BLEU が古典標準、ただし表面文字列マッチで限界あり。LLM 時代は BERTScore、COMET 等の埋め込みベース指標が好まれる。"}, {"q": "2014〜2017 の機械翻訳の主流は。", "choices": ["ルールベース", "RNN+Attentionのニューラル機械翻訳（NMT）、Google翻訳が全面採用（2016）", "Transformer", "LLM"], "answer": 1, "explanation": "2017 年に Transformer 登場し急速に置換。現在は LLM が機械翻訳でも事実上の SOTA。"}, {"q": "CTC（Connectionist Temporal Classification）の用途は。", "choices": ["画像分類", "音声認識・手書き認識など、入力と出力の長さが異なる・整列がないタスクの損失関数", "強化学習", "クラスタ"], "answer": 1, "explanation": "Graves 2006。アラインメントを暗黙にマージしながら学習。RNN+CTC（DeepSpeech）が音声認識の標準だった。"}, {"q": "『Attention is All You Need』論文（2017）の革命性は。", "choices": ["CNN を提案", "RNN/Convolutionなしで Self-Attention のみで Seq2Seq を実現、並列化可能", "K-means 改良", "強化学習"], "answer": 1, "explanation": "Vaswani 2017、Google Brain。WMT 英→独 で SOTA、しかも RNN より高速。現代AIの基盤。"}, {"q": "Self-Attention の計算式は。", "choices": ["QV+K", "softmax(QKᵀ/√dₖ) V", "Q·K", "Σ Q·V"], "answer": 1, "explanation": "Scaled Dot-Product Attention。√dₖで割るのは数値安定性のため。"}, {"q": "Multi-Head Attention の利点は。", "choices": ["計算量削減", "異なる『観点』で並列に注目、表現力増加", "パラメータ削減", "教師なし"], "answer": 1, "explanation": "典型 8〜16 ヘッド。各ヘッドが構文、共参照、意味類似など異なる側面を学習。"}, {"q": "Transformer が Position Encoding を必要とする理由は。", "choices": ["高速化", "Self-Attentionは置換不変、位置情報を別途与える必要", "正則化", "教師信号"], "answer": 1, "explanation": "sin/cos の固定位置埋め込み（オリジナル）、学習可能埋め込み（BERT）、RoPE（LLaMA、相対位置）など。"}, {"q": "RoPE（Rotary Position Embedding）が現代LLMで採用される理由は。", "choices": ["学習不要", "相対位置を回転で表現、外挿性能と長文脈で優位", "計算最遅", "メモリ大"], "answer": 1, "explanation": "Su 2021。LLaMA, GPT-NeoX, PaLM 等で採用。長文脈学習・補間で優れる。"}, {"q": "Self-Attention の計算量は。", "choices": ["O(N)", "O(N · d)", "O(N² · d)", "O(N³)"], "answer": 2, "explanation": "N = 系列長、d = 次元。長文で爆発するため Flash Attention、Sparse Attention、Mamba 等で対処。"}, {"q": "FlashAttention の貢献は。", "choices": ["精度向上", "メモリO(N²) → O(N) の実装、GPU メモリ階層を活用", "教師なし", "ランダム"], "answer": 1, "explanation": "Dao 2022。SRAM/HBM のデータ移動を最小化。計算結果は数値的に同一、高速・低メモリ。長文脈 LLM 必須。"}, {"q": "Decoder の Causal Mask の役割は。", "choices": ["高速化", "生成時に未来のトークンを見せない（カンニング防止）", "正則化", "教師なし"], "answer": 1, "explanation": "Attention 行列の上三角を -∞ で埋める。GPT 系の自己回帰生成で必須。"}, {"q": "Encoder-only Transformer の代表例は。", "choices": ["GPT", "BERT、RoBERTa、DeBERTa", "T5", "ResNet"], "answer": 1, "explanation": "理解タスク（分類、NER、QA）に強い。MLM で事前学習。"}, {"q": "Decoder-only Transformer の代表例は。", "choices": ["BERT", "GPT、LLaMA、Claude、Mistral", "T5", "ViT"], "answer": 1, "explanation": "Next Token Prediction で事前学習。生成タスクの王者。現代 LLM のデファクト。"}, {"q": "Encoder-Decoder Transformer の代表例は。", "choices": ["GPT", "T5、BART、mT5、オリジナル Transformer", "BERT", "K-means"], "answer": 1, "explanation": "テキスト→テキスト変換に強い。要約、翻訳、QAを統一フレームで扱える（T5）。"}, {"q": "Layer Normalization が Transformer で標準採用される理由は。", "choices": ["高速", "バッチサイズ非依存、系列長変化OK、学習安定化", "パラメータ削減", "教師なし"], "answer": 1, "explanation": "Batch Norm はバッチ依存、可変長系列・小バッチで不安定。LayerNorm が Transformer の標準。最近は RMSNorm も（LLaMA）。"}, {"q": "Vision Transformer (ViT, 2020) の入力処理は。", "choices": ["画素単位", "画像を 16x16 などのパッチに分けてトークン化", "Conv のみ", "MLP のみ"], "answer": 1, "explanation": "Dosovitskiy 2020。CNN の帰納バイアスなしで、大量データなら CNN 超え。CLIP、Stable Diffusion 等で採用。"}, {"q": "Cross-Attention の用途は。", "choices": ["Encoder内", "Decoderが Encoder出力を参照、機械翻訳・要約で使用", "教師なし", "計算不要"], "answer": 1, "explanation": "Q を Decoder から、K/V を Encoder から。Encoder-Decoder アーキの架け橋。"}, {"q": "Pre-Norm と Post-Norm の違いは。", "choices": ["同じ", "Pre: y=x+Sub(LN(x)), Post: y=LN(x+Sub(x))、Pre が学習安定で現代LLM標準", "パラメータ違う", "学習なし"], "answer": 1, "explanation": "オリジナル Transformer は Post-Norm だが Warmup が必要。Pre-Norm（GPT-2 以降）は学習がより安定。"}, {"q": "KV Cache の役割は。", "choices": ["訓練加速", "自己回帰生成で過去トークンの K, V を保存して再計算回避、推論を大幅高速化", "正則化", "ノイズ"], "answer": 1, "explanation": "各トークン生成時、過去全トークンの K, V は変わらないため再利用。LLM 推論の効率化に必須。メモリは N に線形に増加。"}, {"q": "SwiGLU 活性化が LLaMA 等の現代 LLM で採用される理由は。", "choices": ["古典的", "Gated Linear Unit + Swish、ReLU/GELU より高性能", "計算最速", "教師なし"], "answer": 1, "explanation": "Shazeer 2020。SwiGLU(x) = (xW)⊙Swish(xV) で2つの線形変換のゲート積。LLaMA, PaLM 等で標準。"}, {"q": "『Sparse Attention』の戦略は。", "choices": ["全位置に注目", "一部位置だけに注目し計算量を O(N√N) や O(N log N) に削減", "教師なし", "Conv 化"], "answer": 1, "explanation": "Sparse Transformer、Longformer、BigBird、Reformer 等。長文脈モデルで重要、ただし Flash Attention + 通常 Attention で多くの場合十分。"}, {"q": "Mixture of Experts (MoE) の Transformer での利用は。", "choices": ["不要", "FFN を複数の Expert に分け、Router が選択。総パラメータ大、アクティブパラメータ小", "Attention のみ", "教師なし"], "answer": 1, "explanation": "GShard、Switch Transformer、Mixtral 8x7B、GPT-4 等で採用。スケーリングと計算効率の両立。"}, {"q": "Transformer が CNN/RNN に勝った根本的理由は。", "choices": ["帰納バイアスが弱く、大量データで純粋に学習できる（スケーリング有利）+ 並列計算可能", "計算量が少ない", "パラメータ少ない", "教師なし"], "answer": 0, "explanation": "CNN は局所性、RNN は逐次性の帰納バイアス。Transformer はそれらが弱い分、データから自由に学習可能でスケーリング則に最適。並列学習で計算リソース活用も容易。"}, {"q": "BERT の事前学習タスクで主要なものは。", "choices": ["次トークン予測", "Masked Language Model（MLM）と Next Sentence Prediction", "クラスタリング", "強化学習"], "answer": 1, "explanation": "入力の15%を [MASK] に置換し復元するMLMが核。NSPは後の改良（RoBERTa）で削除。"}, {"q": "GPT の事前学習タスクは。", "choices": ["MLM", "Next Token Prediction（因果的言語モデル）", "分類", "強化学習"], "answer": 1, "explanation": "左から右に次のトークンを予測する自己回帰モデル。生成タスクに自然に適合。"}, {"q": "BERT と GPT のアーキテクチャの違いは。", "choices": ["BERTはエンコーダ（双方向Attention）、GPTはデコーダ（因果Attention）", "全く同じ", "BERTはRNN", "GPTはCNN"], "answer": 0, "explanation": "どちらもTransformerベースだが、Attentionの方向と用途が異なる。理解はBERT、生成はGPTが得意。"}, {"q": "『事前学習＋微調整』パラダイムの利点は。", "choices": ["タスクごとに学習し直す必要なし、汎用言語知識を活用、少量データで高精度", "計算量が増える", "精度が下がる", "言語別必要"], "answer": 0, "explanation": "大規模事前学習1回 → 多タスクに転移。NLPを変革したパラダイム。"}, {"q": "BERT で使われる Tokenization は。", "choices": ["単語分割のみ", "WordPiece（サブワード分割）", "文字単位", "ランダム"], "answer": 1, "explanation": "WordPiece は未知語に強く、語彙サイズを抑える。'unhappiness' → 'un', '##happiness' のような分割。"}, {"q": "『RoPE（Rotary Position Embedding）』を採用しているLLMは。", "choices": ["BERT", "GPT-2", "LLaMA, GPT-NeoX 等の現代LLM", "T5"], "answer": 2, "explanation": "Su 2021。相対位置を回転で表現、長さ外挿に有利。LLaMA 系の標準。"}, {"q": "T5 が提唱した paradigm は。", "choices": ["RNN復活", "すべてのタスクを Text-to-Text として統一", "線形化", "ハードコーディング"], "answer": 1, "explanation": "分類も生成も翻訳もすべて『テキスト入力→テキスト出力』。プレフィックスでタスク指定。"}, {"q": "RoBERTa が BERT を改良した主要点は。", "choices": ["NSP削除、データ量と学習時間を大幅増、動的マスキング", "アーキテクチャ変更", "パラメータ削減", "Sigmoid化"], "answer": 0, "explanation": "Liu et al. 2019。アーキテクチャは同じだが学習レシピで GLUE 大幅改善。『正しく訓練』の重要性を示した。"}, {"q": "ELECTRA の事前学習タスクは。", "choices": ["MLM", "NTP", "Replaced Token Detection（置換されたトークンを識別）", "Clustering"], "answer": 2, "explanation": "生成器が置換したトークンを判別器が識別。MLMより学習効率良く、同パラメータで高性能。"}, {"q": "GPT-3 で注目された『In-Context Learning』とは。", "choices": ["パラメータ更新", "プロンプト内の数件の例から、新タスクを推論時に学習", "微調整", "クラスタリング"], "answer": 1, "explanation": "Few-shot Learning の革命。重みは変更せず、コンテキスト内の例だけでタスク適応。Brown 2020。"}, {"q": "『微調整』と『プロンプティング』の違いは。", "choices": ["同じ", "微調整=モデル重み更新、プロンプティング=入力テキストで指示（重み不変）", "どちらも教師なし", "必ず両方必要"], "answer": 1, "explanation": "微調整はGPU・データ必要、プロンプティングはAPI呼び出しのみ。実用ではプロンプトエンジニアリングが先、必要に応じて微調整。"}, {"q": "LoRA（Low-Rank Adaptation）の役割は。", "choices": ["学習率調整", "元モデルを凍結し、低ランク差分行列だけ学習し効率的微調整", "量子化", "クラスタ"], "answer": 1, "explanation": "Hu 2021。学習可能パラメータを1/10000に削減しつつ性能維持。LLM実用微調整の標準。QLoRAで4-bit量子化と組合せ。"}, {"q": "BERT の文埋め込み取得で[CLS]以外に良いとされる方法は。", "choices": ["ランダム", "全トークンのmean pooling", "1番目のトークンのみ", "不可能"], "answer": 1, "explanation": "[CLS] よりも全トークンの平均が下流タスクで強いことが多い。Sentence-BERT で標準化。"}, {"q": "GPT の生成サンプリングで『創造性と一貫性のバランス』を制御する典型パラメータは。", "choices": ["学習率", "Temperature、Top-p（Nucleus）、Top-k", "バッチサイズ", "Dropout"], "answer": 1, "explanation": "Temperature 低→決定的、高→多様。Top-p=0.9 で上位累積90%から選択、Hallucination抑制と多様性のバランス。"}, {"q": "GPT-3 の InstructGPT/ChatGPT で導入された手法は。", "choices": ["CNN", "RLHF（Reinforcement Learning from Human Feedback）で指示追従性を学習", "K-means", "Random Forest"], "answer": 1, "explanation": "人間のフィードバックで報酬モデルを学習し、PPO で方策を最適化。指示追従性と無害化の核心技術。"}, {"q": "BERT が最も得意なタスクは。", "choices": ["長文生成", "文章理解（分類、QA、NER）", "音楽生成", "画像認識"], "answer": 1, "explanation": "双方向 Attention で文脈理解が強い。SQuAD で人間超え、GLUEベンチマークを大幅刷新（2018）。"}, {"q": "『スケーリング則』（Kaplan 2020）の主張は。", "choices": ["パラメータ数だけが効く", "パラメータ・データ・計算の3軸でモデル性能が予測可能に改善", "ランダム", "関係なし"], "answer": 1, "explanation": "損失がパワーロー則で改善。これがGPT-3, GPT-4のスケール拡大を駆動。Chinchilla（DeepMind 2022）が最適配分を改良。"}, {"q": "SentencePiece が WordPiece より優れる点は。", "choices": ["必ず速い", "言語非依存、生のテキストから直接学習、空白を特殊文字として扱う", "英語専用", "なし"], "answer": 1, "explanation": "日本語・中国語のような空白区切りでない言語に強い。T5, mBART, ALBERTで採用。"}, {"q": "『MLM（Masked LM）』が双方向文脈学習を可能にする仕組みは。", "choices": ["ランダム", "マスクされたトークンを予測するため、両側の文脈を見る必要がある（因果制約なし）", "線形", "距離計算"], "answer": 1, "explanation": "『私は[MASK]を見た』の[MASK]を予測するには前後両方が必要。これがGPTの因果Attentionとの本質的違い。"}, {"q": "日本語特化の事前学習モデルとして代表的なものは。", "choices": ["全く存在しない", "東北大BERT、cl-tohoku/bert-base-japanese、rinna/japanese-gpt等", "GPT-1のみ", "ELMo"], "answer": 1, "explanation": "多言語BERTより日本語特化モデルが精度高いことが多い。最近はLLM（Swallow、Stockmark、ELYZA等）も日本語特化版が登場。"}, {"q": "『スケーリング則（Scaling Laws）』の主張は。", "choices": ["パラメータ数だけが効く", "パラメータ・データ・計算の3軸で損失がパワーロー則で改善", "関係なし", "ランダム"], "answer": 1, "explanation": "Kaplan et al. 2020。これがGPT-3, GPT-4 のスケール拡大を駆動。Chinchilla で最適配分が改良。"}, {"q": "『Chinchilla 最適化』（DeepMind 2022）が示した知見は。", "choices": ["必ずパラメータを増やせ", "計算予算が決まればパラメータとデータをほぼ同じスケールで増やすのが最適", "データ不要", "パラメータ削減"], "answer": 1, "explanation": "Hoffmann et al. それまでのLLMはパラメータ過大・データ不足。70Bモデル+1.4Tトークンが280Bを凌駕。LLaMA系がこの教訓を踏襲。"}, {"q": "『In-Context Learning（ICL）』とは。", "choices": ["微調整", "プロンプト内の例だけで推論時にタスク適応（パラメータ更新なし）", "クラスタリング", "強化学習"], "answer": 1, "explanation": "GPT-3 で発見された創発能力。Few-shot Learning の革命。"}, {"q": "『Chain-of-Thought』プロンプトが効果的なタスクは。", "choices": ["単純な事実検索", "多段推論（数学、論理パズル、複雑な計算）", "翻訳", "分類"], "answer": 1, "explanation": "『step by step』『let's think』で思考過程を出力させ、最終答えの質を向上。GSM8K等の数学で劇的改善。"}, {"q": "RLHF の3つのステップは。", "choices": ["SFT → 報酬モデル学習 → PPO で方策最適化", "学習なし", "強化学習のみ", "単純な教師あり"], "answer": 0, "explanation": "SFT で初期化、人間のランキングから報酬モデル、PPO（KL正則化付き）で最適化。InstructGPT/ChatGPT の核心。"}, {"q": "DPO（Direct Preference Optimization）の利点は。", "choices": ["RLHFと同じ", "報酬モデルもPPOも不要、CE風損失だけで好み学習が可能", "学習しない", "パラメータ削減"], "answer": 1, "explanation": "Rafailov 2023。RLHF より実装が大幅に簡単で性能同等以上、現代の標準。"}, {"q": "LLM の Hallucination（幻覚）対策として有効でないのは。", "choices": ["RAG（外部知識検索）", "Tool Use", "Citation", "学習率を上げる"], "answer": 3, "explanation": "学習率変更は事前学習段階の話。Hallucination は RAG, Tool Use, Self-Consistency, Citation, Calibration で対処。"}, {"q": "『MoE（Mixture of Experts）』の動作は。", "choices": ["すべてのパラメータ常時使用", "トークンごとに専門家サブネットを選択的アクティブ化（疎活性化）", "クラスタリング", "アンサンブル"], "answer": 1, "explanation": "総パラメータは巨大、計算は一部のみ。Mixtral、GPT-4（推定）、Gemini 1.5 で採用。スケール効率の鍵。"}, {"q": "LLM の評価ベンチマークで『多分野QA』に該当するのは。", "choices": ["HumanEval", "MMLU（57科目）", "GSM8K", "SWE-bench"], "answer": 1, "explanation": "MMLU は数学、歴史、医学等57分野の選択肢QA。HumanEval=コード、GSM8K=数学、SWE-bench=実コーディング。"}, {"q": "『Constitutional AI』（Anthropic）の特徴は。", "choices": ["学習なし", "原則のセットでモデル自身に出力を批判・修正させ、人間ラベルを最小化", "検索のみ", "パラメータ削減"], "answer": 1, "explanation": "Claude の核技術。AI Feedback（RLAIF）への発展。スケーラブルな安全性技術。"}, {"q": "Instruction Tuning（指示チューニング）の入力形式は。", "choices": ["(画像, ラベル)", "(指示, 入力, 出力) のペア", "クラスタ", "ラベルなし"], "answer": 1, "explanation": "FLAN、T0、Alpacaなど。多様なタスクの指示理解を学習。RLHFの前段。"}, {"q": "『創発的能力』とは何か。", "choices": ["全モデルが持つ", "パラメータ／計算が閾値を超えると突然現れる能力（多段推論、コーディング等）", "ランダム", "線形改善のみ"], "answer": 1, "explanation": "Wei et al. 2022。小モデルでは ≈0%、大モデルで急激に向上するタスクが存在。スケーリングの最も興味深い性質。"}, {"q": "長文文脈処理の効率化技術として該当するのは。", "choices": ["Dropout", "Flash Attention、KV Cache、Sparse Attention、PagedAttention", "Sigmoid", "K-means"], "answer": 1, "explanation": "Attention の O(n²) を抑えてメモリ・計算効率化。100万トークン超の文脈（Gemini 1.5, Claude 3.7）を可能にした。"}, {"q": "o1/o3 など『推論モデル』の特徴は。", "choices": ["高速応答のみ", "テスト時に長い思考過程を生成して推論精度を向上、数学・コーディングで SOTA", "学習しない", "ラベル不要"], "answer": 1, "explanation": "CoT を内部化、テスト時の計算量増で性能向上。新しいスケーリング軸（テスト時計算）の発見。"}, {"q": "LLM の温度（temperature）パラメータの意味は。", "choices": ["モデルサイズ", "Softmaxを T で割って分布の鋭さを調整。低い=決定的、高い=多様", "パラメータ数", "学習率"], "answer": 1, "explanation": "創造性と一貫性のバランス。T=0で貪欲、T=1で標準、T=2で創造的だがHallucination増。"}, {"q": "『Top-p Nucleus Sampling』の動作は。", "choices": ["全ての候補から", "累積確率が p になるまで上位トークンを選び、その中からサンプリング", "必ず1位", "ランダム"], "answer": 1, "explanation": "Top-k よりも適応的。低確率の長い裾を切り落としつつ多様性確保。p=0.9 が典型。"}, {"q": "LLM 微調整の効率技術『LoRA』が更新するパラメータは。", "choices": ["全パラメータ", "元の行列に低ランク差分（A·B、ランクr）を加え、その差分のみ学習", "凍結のみ", "ランダム"], "answer": 1, "explanation": "学習可能パラメータを 0.1〜1% に削減。QLoRA で 4-bit 量子化と組合せ、コンシューマGPUで70Bモデル微調整可能に。"}, {"q": "LLM の『指示追従性』を実現する手法は。", "choices": ["単なる事前学習", "Instruction Tuning + RLHF（または DPO）", "線形化", "クラスタ"], "answer": 1, "explanation": "事前学習だけでは『次のトークン予測機』にすぎない。指示理解と安全性は Instruction Tuning + RLHF で獲得。"}, {"q": "『Self-Consistency』の手法は。", "choices": ["1回サンプリング", "同じ問題を複数回CoTでサンプリングし、最頻の答えを選ぶ", "線形回帰", "クラスタリング"], "answer": 1, "explanation": "Wang 2022。数学推論で CoT+Self-Consistency が CoT 単独より大幅に強い。複数の思考経路の多数決。"}, {"q": "『Knowledge Cutoff』とは。", "choices": ["計算リソース上限", "LLM が事前学習した時点までしか知識を持たないという制約", "パラメータ数", "学習率"], "answer": 1, "explanation": "GPT-4o は2024年初頭まで、Claude 3.7 は2025年初頭までなど。新しい情報は RAG, Web 検索、Tool Use で補完。"}, {"q": "GAN の基本構造は。", "choices": ["エンコーダのみ", "Generator と Discriminator の敵対的学習", "デコーダのみ", "クラスタリング"], "answer": 1, "explanation": "Goodfellow 2014。Generator が偽画像、Discriminator が真偽判定、min-max ゲーム。"}, {"q": "GAN の典型的な問題で『多様性が失われる』現象を何と呼ぶか。", "choices": ["過学習", "モード崩壊（Mode Collapse）", "勾配消失", "不確実性"], "answer": 1, "explanation": "Generator が騙しやすい一部モードに局所最適。WGAN-GP、Spectral Normalization、Mini-batch Discrimination で対策。"}, {"q": "VAE の損失関数 ELBO は何と何の組合せか。", "choices": ["再構成損失 + KL ダイバージェンス（事前との距離）", "MSE のみ", "Hinge", "敵対的損失"], "answer": 0, "explanation": "ELBO = 再構成 - KL(q(z|x)||p(z))。再構成精度と潜在分布の事前 N(0,I) への近さのバランス。"}, {"q": "Diffusion Model の学習は何を予測するか。", "choices": ["ラベル", "画像に加えられたノイズ（または score = ∇log p(x)）", "クラスタ", "Bounding Box"], "answer": 1, "explanation": "各タイムステップで NN がノイズを予測し、それを差し引いて x_{t-1} を得る。これを T 回繰り返してノイズから画像復元。"}, {"q": "Stable Diffusion の核心技術は。", "choices": ["ピクセル空間のDiffusion", "Latent Diffusion（VAEで圧縮した潜在空間で Diffusion）", "GAN", "Flow"], "answer": 1, "explanation": "Rombach 2022。512×512 を 64×64 潜在に圧縮し、計算量1/64に。コンシューマGPUで動作可能に。"}, {"q": "ControlNet の役割は。", "choices": ["高速化", "Stable Diffusion に追加制約（姿勢、深度、エッジ）を与えて生成を制御", "パラメータ削減", "学習率自動"], "answer": 1, "explanation": "Zhang 2023。骨格→人物、線画→塗り絵、深度→立体感のある画像など。生成の制御性を劇的向上。"}, {"q": "『Classifier-Free Guidance（CFG）』の役割は。", "choices": ["分類器学習", "条件付き/無条件のスコア差を増幅、テキスト指示への忠実度を高める", "クラスタ", "学習率"], "answer": 1, "explanation": "Ho 2022。guidance_scale パラメータで強さを調整。7-10 が典型、高すぎると過剰でアーティファクト発生。"}, {"q": "DALL-E 2 の主な構成要素は。", "choices": ["CNN のみ", "CLIP（テキスト・画像埋め込み）＋ Diffusion （prior + decoder）", "RNN のみ", "K-means"], "answer": 1, "explanation": "CLIP埋め込みを介してテキストと画像を結ぶ、unCLIP アーキテクチャ。"}, {"q": "画像生成評価の代表的指標『FID』は何を測るか。", "choices": ["学習速度", "Inception 特徴量で実画像分布と生成画像分布の距離", "クラス数", "パラメータ数"], "answer": 1, "explanation": "Fréchet Inception Distance。画像品質と多様性を一値に集約。低いほど良い。"}, {"q": "『CLIP Score』が評価するのは。", "choices": ["画像品質のみ", "テキストプロンプトと生成画像の意味的整合性", "計算速度", "ファイルサイズ"], "answer": 1, "explanation": "CLIP モデルの埋め込み類似度。プロンプト忠実度の標準指標。"}, {"q": "Sora や Veo は何のためのモデルか。", "choices": ["音楽生成", "動画生成（テキスト→1分以上の高品質動画）", "顔認識", "文章生成"], "answer": 1, "explanation": "OpenAI Sora（2024）、Google Veo。Diffusion Transformer ベース、物理理解・長時間生成が特徴。"}, {"q": "Whisper（OpenAI）の用途は。", "choices": ["画像生成", "多言語音声認識（STT）", "TTS", "翻訳のみ"], "answer": 1, "explanation": "Speech-to-Text の多言語モデル。99言語対応、ノイズに頑健。オープンウェイト。"}, {"q": "VQ-VAE の特徴は。", "choices": ["連続潜在", "離散コードブックで潜在表現、画像・音声生成や Tokenizer で活用", "線形変換", "ノイズなし"], "answer": 1, "explanation": "連続潜在を離散コードに量子化。Audio LM、画像 Tokenizer などで使用。"}, {"q": "Normalizing Flow の利点は。", "choices": ["厳密な尤度計算が可能（可逆変換）", "高速生成", "パラメータ少", "学習不要"], "answer": 0, "explanation": "可逆な変換 f: z → x を学習し、変数変換公式で厳密尤度。GANやVAEと違い密度評価可能。画像品質は Diffusion に劣る。"}, {"q": "Diffusion Models の高速化『Distillation』が達成するのは。", "choices": ["学習速度のみ", "50ステップを 1-4 ステップに圧縮、リアルタイム生成可能に", "パラメータ削減", "不可能"], "answer": 1, "explanation": "教師モデルから生徒モデルへの蒸留。SDXL Turbo、LCM などでリアルタイム画像生成（30fps）が可能に。"}, {"q": "LoRA を Diffusion に適用する利点は。", "choices": ["全パラメータ学習", "10-100枚の画像で特定キャラ/スタイル学習、数MBで配布可能", "高速学習不可", "精度低下"], "answer": 1, "explanation": "Civitai 等で大量のLoRA公開、コミュニティが活発。Stable Diffusion カスタマイズの主流。"}, {"q": "StyleGAN の特徴は。", "choices": ["全結合のみ", "スタイル（属性）と画像内容を分離、高解像度顔生成、潜在空間編集", "線形", "RNN"], "answer": 1, "explanation": "NVIDIA、Karras 2019。ThisPersonDoesNotExist のあの顔。潜在空間の意味的編集（笑顔強度、年齢など）。"}, {"q": "音楽生成モデル MusicGen は何で学習されているか。", "choices": ["画像のみ", "大量の楽曲とテキスト説明のペア、自己回帰モデル", "ランダム", "MIDI のみ"], "answer": 1, "explanation": "Meta、2023。テキスト→音楽の Transformer ベース。Suno、Udio などのサービスも類似アプローチ。"}, {"q": "生成 AI の社会的課題として該当しないのは。", "choices": ["ディープフェイク", "著作権", "バイアス", "必ず物理法則を守る"], "answer": 3, "explanation": "生成モデルは物理法則を必ずしも守らない（手指の数間違い、不自然な液体運動など）。Sora は改善したが完璧でない。"}, {"q": "Diffusion Model が現在 GAN を凌駕している主な理由は。", "choices": ["学習が速い", "学習安定、高品質、多様性確保、テキスト条件付け容易、スケール可能", "パラメータ少", "メモリ少"], "answer": 1, "explanation": "GANの不安定学習・モード崩壊の問題なし、Diffusion Transformer でスケール可能（Sora）。現代生成AIの主流。"}, {"q": "MDP の5要素（S, A, P, R, γ）の γ は何か。", "choices": ["学習率", "割引率（将来報酬の現在価値）", "探索率", "ノイズ"], "answer": 1, "explanation": "γ ∈ [0,1)。0.99 が典型。1なら無限地平の累積発散、0なら短期報酬のみ重視。"}, {"q": "Q-Learning がオフポリシーである理由は。", "choices": ["学習しない", "行動方策と異なる方策（最適）を学習可能、更新で max を使う", "オンライン", "モデルベース"], "answer": 1, "explanation": "Q(s,a) ← Q + α[r + γ max Q(s', a') - Q]。max を使うので実際の次行動と独立。SARSAはオンポリシー。"}, {"q": "DQN（DeepMind 2015）の核心的貢献は。", "choices": ["教師あり", "Experience Replay + Target Network で深層NN+RL を安定化、Atari 49ゲーム人間超え", "教師なし", "クラスタリング"], "answer": 1, "explanation": "Mnih et al. 2015 Nature。これが Deep RL 革命の始まり。"}, {"q": "AlphaGo の構成要素として正しいのは。", "choices": ["教師あり学習のみ", "Policy Net + Value Net + MCTS + 自己対戦RL", "Q-tableのみ", "ランダム"], "answer": 1, "explanation": "人間棋譜での教師あり初期化＋自己対戦RL強化＋モンテカルロ木探索による推論時計画。2016年世界トップ棋士を破る。"}, {"q": "AlphaZero が AlphaGo と異なる点は。", "choices": ["教師データ不要、純粋自己対戦のみ", "より小さなNN", "MCTS不使用", "教師あり強化"], "answer": 0, "explanation": "ルールだけからゼロベース自己対戦、人間データ完全不要。囲碁・将棋・チェスすべて同一アーキテクチャでトップ性能。"}, {"q": "PPO（Proximal Policy Optimization）の特徴は。", "choices": ["クリップ損失で方策更新を安定化、実装簡単で汎用性高い", "オンポリシーのみ", "Q-tableのみ", "ランダム"], "answer": 0, "explanation": "OpenAI 2017。L^CLIP = E[min(rA, clip(r, 1-ε, 1+ε)A)]。RLHFの主力アルゴリズム、現代RL標準。"}, {"q": "RLHF（ChatGPT/Claudeで使用）の3ステップは。", "choices": ["SFT → 報酬モデル → PPO", "教師あり → 教師なし → 強化", "事前 → 中間 → 微調整", "Pretrain → Fine-tune → Distill"], "answer": 0, "explanation": "Supervised Fine-Tuning → Reward Model（人間ランクで学習）→ PPO で報酬最大化。InstructGPT (2022) で確立。"}, {"q": "DPO（Direct Preference Optimization、2023）の利点は。", "choices": ["計算重い", "報酬モデル不要で嗜好データから直接最適化、PPOより安定で簡単", "教師あり不要", "必ず劣る"], "answer": 1, "explanation": "Rafailov 2023。報酬モデル+PPOの2段階を1段階に。Llama-2-Chat、Mistral、Zephyr などで採用。最近のRLHF主流。"}, {"q": "価値関数 V(s) と Q(s,a) の違いは。", "choices": ["同じ", "V は状態の価値、Q は(状態,行動)の価値", "V は数値、Q は関数", "V は離散"], "answer": 1, "explanation": "V(s) = E[累積報酬|s]、Q(s,a) = E[累積報酬|s,a]。関係：Vπ(s) = Σ π(a|s) Qπ(s,a)。"}, {"q": "Bellman 最適方程式 V*(s) = max_a Σ P(s'|s,a)[R + γV*(s')] が示すのは。", "choices": ["最適価値の再帰関係", "ランダム", "教師ラベル", "必ず線形"], "answer": 0, "explanation": "最適価値は『最善の次行動の期待値』として再帰的に定義。Value Iteration、DQN学習の基礎。"}, {"q": "ε-greedy の役割は。", "choices": ["学習率", "探索と活用のバランス（εでランダム、1-εで最良Q行動）", "正則化", "クラスタ"], "answer": 1, "explanation": "探索（未知行動を試す）と活用（既知の良い行動を取る）のトレードオフ。実用では学習進行で ε を減衰。"}, {"q": "Actor-Critic アーキテクチャは何の組合せか。", "choices": ["教師あり+教師なし", "方策（Actor）+ 価値関数（Critic）", "クラスタ+回帰", "DQN+SARSA"], "answer": 1, "explanation": "Actor が行動、Critic が状態を評価。分散低減で安定学習。A2C/A3C/PPO/SAC の基礎。"}, {"q": "『マルコフ性』とは。", "choices": ["過去履歴を全て参照", "次状態は現在状態と行動のみに依存（過去履歴不要）", "必ず連続", "線形"], "answer": 1, "explanation": "P(s_{t+1}|s_t, a_t) = P(s_{t+1}|s_t, a_t, history)。POMDP（部分観測）では緩和される。"}, {"q": "スパース報酬問題への対処として正しいのは。", "choices": ["学習率を上げる", "Reward Shaping、Curiosity-driven exploration（RND, ICM）、HER", "教師あり化", "クラスタ"], "answer": 1, "explanation": "報酬がほとんど0のタスク（Montezuma's Revenge等）で重要。内発的動機付け（好奇心）、後付け目標（HER）で対処。"}, {"q": "モデルベース RL とモデルフリー RL の違いは。", "choices": ["同じ", "モデルベースは環境モデル(P, R)を学習・利用、モデルフリーはサンプルから直接学習", "教師あり vs 教師なし", "速度"], "answer": 1, "explanation": "モデルベース（MuZero、Dreamer）はサンプル効率が良いがモデル誤差影響。モデルフリー（DQN、PPO）はシンプル、サンプル多。"}, {"q": "『継続的なエピソードでは γ &lt; 1 が必要』な理由は。", "choices": ["計算簡単化", "無限和の収束保証、近未来優先", "ランダム性", "単純化のみ"], "answer": 1, "explanation": "γ=1 だと累積和が発散。γ&lt;1で幾何級数として収束。0.9〜0.999が典型。"}, {"q": "MuZero（DeepMind 2020）の特徴は。", "choices": ["教師あり", "環境モデル自体も学習、ルール未知のAtariでもMCTS可能", "Q-table", "ランダム"], "answer": 1, "explanation": "AlphaZero は環境ルール既知、MuZero はルールも学習。汎用性大幅向上。"}, {"q": "SAC（Soft Actor-Critic）が連続行動空間で強い理由は。", "choices": ["離散のみ", "最大エントロピー原理で探索促進、決定的方策より安定", "Q-tableのみ", "教師あり"], "answer": 1, "explanation": "Haarnoja 2018。報酬最大化＋エントロピー最大化で探索維持。ロボット制御などで人気。"}, {"q": "ChatGPT のような LLM チャットボットの応答品質を人間嗜好に合わせる手法は。", "choices": ["単なる教師あり", "RLHF（または DPO）", "クラスタリング", "線形回帰"], "answer": 1, "explanation": "RLHF（InstructGPT 2022）。人間嗜好を反映する強化学習で、有害性削減・有用性向上。最近は DPO で簡略化。"}, {"q": "強化学習の典型的応用として誤りはどれか。", "choices": ["ゲーム（AlphaGo, AlphaStar）", "ロボット制御", "LLM の人間嗜好調整", "静的な画像分類"], "answer": 3, "explanation": "画像分類は典型的に教師あり。RLは『連続的意思決定』『報酬最大化』が要。ゲーム、ロボット、自動運転、推薦、RLHFが代表。"}, {"q": "RAG が解決する LLM の主な弱点は。", "choices": ["計算速度", "知識カットオフ、幻覚、私的データ非対応", "パラメータ数", "メモリ"], "answer": 1, "explanation": "LLM の学習データ以降の知識・自社データ・幻覚（誤情報生成）を、関連文書検索で補完。"}, {"q": "RAG パイプラインの基本構成は。", "choices": ["クラスタ→分類", "Embed → Vector DB 検索 → 文脈付き LLM プロンプト → 回答", "Fine-tune のみ", "ランダム"], "answer": 1, "explanation": "Lewis 2020。質問を埋め込み、Vector DB から類似文書取得、LLM に文書+質問を渡して回答生成。"}, {"q": "Embedding モデルの代表として誤りはどれか。", "choices": ["text-embedding-3-large (OpenAI)", "BGE-large (BAAI)", "Cohere Embed v3", "XGBoost"], "answer": 3, "explanation": "XGBoost は勾配ブースティング、テキスト埋め込み用ではない。MTEB ベンチマークで競合中。"}, {"q": "Vector Database で標準的な高速検索アルゴリズムは。", "choices": ["ブルートフォース", "HNSW（Hierarchical Navigable Small World）、IVF-PQ", "K-means", "Decision Tree"], "answer": 1, "explanation": "ANN（Approximate Nearest Neighbor）の代表。HNSW は graph-based で精度・速度両立。FAISS, Pinecone, Qdrant, Weaviate で実装。"}, {"q": "Chunking で典型的なオーバーラップ率は。", "choices": ["0%", "10〜20%（境界問題緩和）", "50%以上", "100%"], "answer": 1, "explanation": "オーバーラップで文脈の境界での情報損失を緩和。chunk_size=500 なら overlap=50〜100 が典型。"}, {"q": "Reranking の目的は。", "choices": ["計算高速化", "Embedding 検索で得た上位文書を Cross-Encoder で再評価し精度向上", "学習", "正則化"], "answer": 1, "explanation": "2段階パイプライン：Embedding で top-50 → Rerank で top-5。Cohere Rerank, BGE Reranker が代表。"}, {"q": "Hybrid Search の典型構成は。", "choices": ["Dense のみ", "Embedding（Dense）+ BM25（Sparse）を RRF で統合", "ランダム", "Sparse のみ"], "answer": 1, "explanation": "Reciprocal Rank Fusion（RRF）で両者の順位を融合。固有名詞・型番に強い BM25 と意味類似の Dense を統合。"}, {"q": "RAG vs Fine-tuning の使い分けで正しいのは。", "choices": ["RAG = スタイル変更", "知識追加・更新は RAG、行動・スタイル変更は Fine-tune", "どちらも同じ", "Fine-tune が常に上"], "answer": 1, "explanation": "RAG = 知識（事実）、Fine-tune = 振舞い（口調、フォーマット）。実用では併用が多い。"}, {"q": "『Faithfulness』が評価する対象は。", "choices": ["速度", "生成回答が取得文書に忠実か（捏造でないか）", "パラメータ数", "コスト"], "answer": 1, "explanation": "RAGAS, TruLensなどで自動評価。LLM-as-Judge（GPT-4） が一般的。幻覚抑制の指標。"}, {"q": "GraphRAG（Microsoft 2024）の特徴は。", "choices": ["単純な BM25", "文書から知識グラフを構築、Global query（全体傾向）にも対応", "Fine-tune必須", "クラスタリング"], "answer": 1, "explanation": "エンティティ・関係抽出 → グラフ → コミュニティ要約。『この文書集合全体の傾向は』のような Global question に強い。"}, {"q": "HyDE（Hypothetical Document Embeddings）の手順は。", "choices": ["質問を直接埋め込み", "LLMに仮回答を生成させ、それを埋め込んで検索", "教師ありのみ", "クラスタ"], "answer": 1, "explanation": "Gao 2022。質問と回答は意味空間で異なる位置にあり得るため、仮回答を介して検索精度向上。"}, {"q": "Self-RAG が用いる仕組みは。", "choices": ["ランダム検索", "Reflection Token で『検索が必要か』『文書が関連か』『裏付けあるか』を LLM 自身が判断", "クラスタリング", "教師あり"], "answer": 1, "explanation": "Asai 2023。不要検索の削減と品質向上を両立。LLMが検索の必要性を判断。"}, {"q": "Cosine類似度の式は。", "choices": ["q + d", "(q·d)/(||q|| ||d||)", "|q - d|", "q × d"], "answer": 1, "explanation": "ベクトル間の角度を測る。長さ非依存で意味の類似度に適する。RAGの標準距離。"}, {"q": "RAG の典型的な失敗パターンは。", "choices": ["速度向上", "Chunk が大きすぎる/小さすぎる、Embedding がドメイン外、適切な Rerank不在", "パラメータ削減", "学習率"], "answer": 1, "explanation": "実用 RAG は『調整勝負』。Chunk size、Embedding 選択、Rerank、プロンプト構造、メタデータフィルタなどの組合せ最適化が肝。"}, {"q": "Multimodal RAG が扱う主なデータは。", "choices": ["テキストのみ", "画像、表、グラフを含む PDF・スライド（CLIP系または Vision LLM 利用）", "音声のみ", "コード"], "answer": 1, "explanation": "技術文書・財務報告書は画像・表が多い。GPT-4V, Claude 3, Gemini が直接処理可能、または CLIP 系で画像埋め込み。"}, {"q": "LangChain の役割は。", "choices": ["学習", "LLMアプリ構築の統合フレームワーク（RAG、Agent、チェーン）", "Vector DB のみ", "Embedding"], "answer": 1, "explanation": "文書ローダー、Splitter、Vector DB、LLM、Retriever、Agent を統合。LlamaIndex は RAG 特化の競合。"}, {"q": "Sentence-Transformers の代表モデルは。", "choices": ["BERT base のみ", "all-MiniLM-L6-v2（軽量384次元、CPU動作可）", "GPT-4", "ResNet"], "answer": 1, "explanation": "開発・プロトタイプの定番。BGE, E5, GTE などより新しいモデルもオープン提供。"}, {"q": "RAGAS フレームワークが提供する RAG 評価指標は。", "choices": ["Accuracy のみ", "Faithfulness, Answer Relevance, Context Precision, Context Recall", "MSE", "R²"], "answer": 1, "explanation": "LLM-as-Judge で自動評価。RAG 特有の側面（事実忠実性、文脈の必要性・十分性）を測定。"}, {"q": "Vector DB の選択基準として誤りはどれか。", "choices": ["規模・QPS要件", "フィルタリング機能", "ホスティング（SaaS vs Self-host）", "どれも同じ性能"], "answer": 3, "explanation": "Pinecone（マネージド）、Weaviate（OSS+クラウド）、Qdrant（OSS Rust高速）、Chroma（軽量）、Milvus（大規模）など特性は大きく違う。"}, {"q": "プロダクション RAG での重要な工夫として誤りはどれか。", "choices": ["クエリ書き換え（query rewriting）", "Rerank", "メタデータフィルタ", "必ず Chunk size を 100 にする"], "answer": 3, "explanation": "Chunk size はデータ・タスク依存で最適化対象。100 だと文脈不足の場合が多い。500前後が経験的に良いが、用途で異なる。"}, {"q": "AI Agent の定義として最も適切なのは。", "choices": ["単発の質問応答", "目標達成のため自律的に推論・計画・行動するシステム", "Vector DBのみ", "ファインチューニング"], "answer": 1, "explanation": "LLMを脳、ツールを手足、メモリを記憶とする自律システム。1ターン応答との根本的違い。"}, {"q": "ReAct パラダイムの構成は。", "choices": ["Search→Generate", "Thought→Action→Observation のループ", "Train→Test", "Encode→Decode"], "answer": 1, "explanation": "Yao 2022 ReAct論文。LLM が推論→ツール実行→結果観察を繰り返す。Agent の基本パターン。"}, {"q": "Function Calling の役割は。", "choices": ["学習", "LLMが構造化された JSON でツール呼出パラメータを生成", "正則化", "クラスタリング"], "answer": 1, "explanation": "OpenAI 2023標準化、GPT/Claude/Gemini/Llama すべて対応。ツール仕様（JSON Schema）に従いLLMがパラメータ抽出。"}, {"q": "Claude Computer Use（Anthropic 2024）の特徴は。", "choices": ["テキスト生成のみ", "スクリーンショットを見てマウス・キーボードを操作", "Vector検索のみ", "音声処理"], "answer": 1, "explanation": "2024年10月発表。Claude 3.5 Sonnet が画面を理解してPC操作。人間と同じ方法での自動化を可能に。"}, {"q": "Self-Reflection / Self-Critique の効果は。", "choices": ["計算高速化", "Agent が自分の出力を批評・修正することで品質向上", "パラメータ削減", "ランダム化"], "answer": 1, "explanation": "Reflexion (2023), Self-Refine (2023)。HumanEvalでpass@1が67%→91%に。o1 の思考時間長期化もこの思想。"}, {"q": "Multi-Agent フレームワークの代表は。", "choices": ["TensorFlow", "AutoGen (Microsoft)、CrewAI", "scikit-learn", "NumPy"], "answer": 1, "explanation": "AutoGen（カンファレンス形式）、CrewAI（役割明示）、ChatDev（ソフトウェア会社シミュレーション）など。協調で複雑タスクの品質向上。"}, {"q": "Agent の短期メモリの典型実装は。", "choices": ["Vector DB のみ", "直近Nターンを会話履歴としてプロンプトに保持", "ファイル", "なし"], "answer": 1, "explanation": "Conversation Buffer Memory。長くなると要約・圧縮、または Vector Memory に長期化。"}, {"q": "Plan-and-Execute Agent の特徴は。", "choices": ["1ステップで全実行", "最初に計画策定 → サブタスクを順次実行", "ランダム", "学習"], "answer": 1, "explanation": "Chain-of-Thought の発展形。複雑タスクで失敗を減らせる。BabyAGI、AutoGPT の基礎パターン。"}, {"q": "LangGraph が LangChain Agent と異なる点は。", "choices": ["同じ", "状態機械として明示的にモデル化、Cycle・分岐・人間介入を扱える", "Vector DB専用", "学習特化"], "answer": 1, "explanation": "暗黙的ループではなく明示的グラフで Agent を制御。Production-grade Agent の標準。"}, {"q": "Agent の典型的な失敗パターンは。", "choices": ["無限ループ、過剰なツール呼出、コスト爆発", "学習速度低下", "メモリリーク", "なし"], "answer": 0, "explanation": "max_iterations 設定、ループ検出、コスト上限、人間承認などのガードレールが本番必須。"}, {"q": "AutoGPT (2023) の意義は。", "choices": ["学習アルゴリズム", "自律 LLM Agent の先駆け、技術的限界はあったがAgent ブームの火付け役", "Vector DB", "単なる検索"], "answer": 1, "explanation": "2023年初、GPT-4 ベース。タスク自動分解実行のループ。実用性は限定的だったが、Agent概念を一般に広めた。"}, {"q": "『Tool Use』の代表的ツールカテゴリは。", "choices": ["学習", "検索、計算、API、ファイル操作、ブラウザ・PC制御", "単一機能のみ", "Vector のみ"], "answer": 1, "explanation": "多様なツールが LLM の能力を拡張。Web search、Code Interpreter、SaaS API、Computer Use など。"}, {"q": "Tree of Thoughts（ToT）の発展点は。", "choices": ["単線思考", "思考を木構造で分岐探索し最良経路選択", "Vector検索", "教師あり"], "answer": 1, "explanation": "Yao 2023。CoTを枝分かれにし、BFS/DFS的に探索。数独、24パズル等で高性能。"}, {"q": "Reflexion（2023）の動作は。", "choices": ["教師あり", "Agent が失敗から自己批評＆メモリ蓄積→次回反映", "Vector DB のみ", "クラスタ"], "answer": 1, "explanation": "Shinn 2023。失敗の言語的反省を Memory に蓄積、次の試行で参照。コード生成でpass@1 を大幅向上。"}, {"q": "OpenAI o1 / o3 が従来 LLM と異なる点は。", "choices": ["パラメータが100倍", "推論時に長い『思考』を行い、Self-Reflection内蔵", "Vector検索専用", "多言語のみ"], "answer": 1, "explanation": "Test-time compute scaling。数十秒〜数分の思考連鎖で複雑タスク（数学、コード）で人間レベル超え。"}, {"q": "Agent のメモリで Vector Memory が解決する問題は。", "choices": ["計算速度", "長期記憶（過去会話・経験から関連情報を検索可能に）", "学習", "パラメータ"], "answer": 1, "explanation": "会話履歴をベクトル化し、関連時に取得。個人化、長期セッション、経験学習に必須。"}, {"q": "Program-Aided Language Models (PAL) の特徴は。", "choices": ["計算", "LLM が Python コードを生成→実行→結果を使う（数値計算誤りを防ぐ）", "Vector検索", "教師あり"], "answer": 1, "explanation": "Gao 2022。LLM の苦手な厳密計算を Python に委任。数学・データ処理タスクで高精度。"}, {"q": "2024年に登場した Devin AI の特徴は。", "choices": ["単純チャット", "自律的にコーディングタスクを完遂、ブラウザ・エディタ操作可能", "Vector検索のみ", "画像生成"], "answer": 1, "explanation": "Cognition Labs。コード生成、デバッグ、デプロイまで一貫実行のAI Software Engineer。SWE-Bench で当時 SOTA。"}, {"q": "Agent の安全性で重要なのは。", "choices": ["全自動が常に良い", "Human-in-the-Loop、ツール権限制限、コスト上限、監査ログ", "なし", "速度"], "answer": 1, "explanation": "自律実行のリスク：誤ったAPI呼出、機密漏洩、コスト爆発。人間承認、サンドボックス、レート制限が必須。"}, {"q": "Agent と LLM 単独 RAG の本質的違いは。", "choices": ["同じ", "Agentは多段階推論＋ツール選択＋ループ、RAGは1ターン取得+生成", "Vector不使用", "学習"], "answer": 1, "explanation": "RAG は静的なパイプライン（検索→生成）、Agent は動的な意思決定（どのツールを何回呼ぶか LLM が判断）。Agent内でRAGをツールとして使える。"}, {"q": "MLOps の主な対象は。", "choices": ["モデル学習のみ", "MLシステムのライフサイクル全体（データ・学習・デプロイ・運用・再学習）の自動化", "データ収集のみ", "評価のみ"], "answer": 1, "explanation": "Google『Hidden Technical Debt in ML Systems』が原点。コードはML全体の5〜10%、残りは MLOps インフラ。"}, {"q": "Feature Store の主な目的は。", "choices": ["モデル管理", "学習時とサービング時で一貫した特徴量提供、Training-Serving Skew 防止", "パラメータ追跡", "ログ収集"], "answer": 1, "explanation": "Feast、Tecton、SageMaker Feature Store、Vertex AI Feature Store。特徴量の再利用と一貫性が核心。"}, {"q": "MLflow の主機能でないのは。", "choices": ["実験追跡（パラメータ、メトリクス）", "モデルレジストリ", "プロジェクトパッケージング", "データベース管理"], "answer": 3, "explanation": "MLflow は Tracking、Models、Projects、Registry の4機能。データベース自体は管理対象外。"}, {"q": "CI/CD for ML で『CT』が表すのは。", "choices": ["Continuous Testing", "Continuous Training（Drift時等の自動再学習）", "Continuous Tracking", "Continuous Tagging"], "answer": 1, "explanation": "MLOps の独自概念。CI（コードテスト）+ CD（デプロイ）+ CT（再学習）の3要素。"}, {"q": "Data Drift と Concept Drift の違いは。", "choices": ["同じ", "Data: P(X) 変化、Concept: P(Y|X) 変化", "Drift は無関係", "ラベルだけ"], "answer": 1, "explanation": "Data Drift = 入力分布の変化（季節、ユーザー層変化）、Concept Drift = 入力→出力関係の変化（嗜好変化）。両方を監視。"}, {"q": "PSI（Population Stability Index）の用途は。", "choices": ["学習", "分布変化の定量化（金融でDrift検知に標準）。0.2以上で警告", "パラメータ調整", "ノイズ生成"], "answer": 1, "explanation": "PSI = Σ (P_new - P_ref) · ln(P_new / P_ref)。0.1未満=安定、0.1-0.2=やや変化、0.2以上=大きな変化。"}, {"q": "Canary Release の特徴は。", "choices": ["全トラフィック切替", "新モデルに少量トラフィック（1〜5%）流して段階的に拡大、異常時即ロールバック", "シャドウ", "A/B均等"], "answer": 1, "explanation": "Kubernetes/Istio で実装。安全なロールアウトの定番。Blue-Green デプロイより漸進的。"}, {"q": "Shadow Mode の特徴は。", "choices": ["ユーザに新モデル結果を返す", "本番トラフィックを両方に流すが新モデル結果は記録のみ、ユーザ影響ゼロで評価", "ランダム", "オフライン"], "answer": 1, "explanation": "本番影響なしで新モデルを評価。レイテンシ、メモリ、予測一致度を確認。Canary 前の安全策。"}, {"q": "Kubeflow の主な特徴は。", "choices": ["クラウド専用", "Kubernetesネイティブの OSS、MLパイプライン・分散学習・推論を統合", "AWS専用", "Python専用"], "answer": 1, "explanation": "Kubeflow Pipelines, KServe, Training Operator, Katib (HPO)。クラウド非依存、on-premise でも動く。"}, {"q": "AWS SageMaker の主機能でないのは。", "choices": ["マネージドGPU 学習", "Endpoint デプロイ", "Feature Store", "仮想通貨マイニング"], "answer": 3, "explanation": "SageMaker は ML特化マネージドサービス。Studio、Training Jobs、Endpoints、Pipelines、Clarify（Bias）、Ground Truth など。"}, {"q": "バッチ推論が向くケースは。", "choices": ["リアルタイム必要", "大量データを定期的に処理（夜間バッチ、レポート、推薦の事前計算）", "チャット", "ストリーミング"], "answer": 1, "explanation": "Spark、AWS Batch、Airflow で実装。リアルタイム性不要・GPUコスト最適化が目的。"}, {"q": "Edge推論の典型ユースケースは。", "choices": ["大型サーバ", "スマホ・IoT・自動車などデバイス上で推論（TF Lite、ONNX、Core ML）", "クラウドのみ", "オフライン学習"], "answer": 1, "explanation": "プライバシー・遅延・通信コストの観点でデバイス上推論が重要。量子化（INT8）、Pruning でモデル軽量化。"}, {"q": "A/B Test と Multi-Armed Bandit の違いは。", "choices": ["同じ", "A/B は固定割合、MAB は性能高いモデルに動的に割合増加（Thompson Sampling、UCB）", "A/B はクラスタリング", "MAB は強化学習"], "answer": 1, "explanation": "MAB は Exploration-Exploitation を強化学習的に最適化。総合報酬最大化、A/B Test の発展形。"}, {"q": "Triton Inference Server の特徴は。", "choices": ["学習専用", "NVIDIA製、高性能推論サーバ、複数フレームワーク（PyTorch、TF、ONNX）・複数モデルを統合提供", "DB", "コンパイラ"], "answer": 1, "explanation": "gRPC/HTTP両対応、Dynamic Batching、Model Concurrency でGPUを最大活用。SageMaker・Vertex でも統合。"}, {"q": "DVC の主機能は。", "choices": ["ニューラルネット", "データ・モデルのバージョン管理（Gitに統合、大ファイルは外部ストレージへ）", "学習", "クラウド管理"], "answer": 1, "explanation": "Data Version Control。Git は大ファイルが苦手、DVC はメタ情報のみGit、本体はS3/GCS等。再現性確保に重要。"}, {"q": "Apache Airflow の主機能は。", "choices": ["ML特化", "汎用ワークフロー（DAG）スケジューラ、データパイプライン・ML パイプライン用", "DBMS", "Webサーバ"], "answer": 1, "explanation": "Python で DAG を記述、スケジュール実行。MLOps では学習・推論・前処理を構成。代替に Dagster、Prefect、Argo。"}, {"q": "Training-Serving Skew の典型原因は。", "choices": ["学習データが少ない", "学習時とサービング時で特徴量の計算ロジックが微妙に異なる", "パラメータ多い", "ランダム性"], "answer": 1, "explanation": "例：学習で平均値補完、サービングで0補完。Feature Store で計算ロジック共有することで防止。"}, {"q": "本番運用で監視すべきメトリクスでないのは。", "choices": ["レイテンシ p99", "スループット（QPS）", "エラー率", "開発者のメール頻度"], "answer": 3, "explanation": "システム面（レイテンシ、QPS、エラー率、CPU/GPU）とモデル面（予測分布、入力分布、Drift）を監視。Prometheus + Grafana が標準。"}, {"q": "Model Card の役割は。", "choices": ["学習データ", "モデルの用途、性能、制限、Bias情報を文書化（Google Mitchell 2019）。透明性確保", "名刺", "クラスタリング"], "answer": 1, "explanation": "モデルの『使用説明書』。EU AI Act、ISO/IEC 23053 などで義務化方向。Hugging Face で標準化。"}, {"q": "『MLOps Maturity』レベル0の特徴は。", "choices": ["完全自動化", "全て手動、学習・デプロイ・モニタリング無連携", "Drift自動再学習", "MLOpsなし"], "answer": 1, "explanation": "Google MLOps Maturity Model。Level 0=Manual、Level 1=ML Pipeline自動化、Level 2=CI/CD/CT完全統合。多くの企業はLevel 0-1。"}, {"q": "AIバイアスの『歴史的バイアス』の典型例は。", "choices": ["ランダム", "過去の社会的不平等がデータに含まれ、AIが学習して再生産", "計算誤差", "学習率"], "answer": 1, "explanation": "Amazon の採用AI事件（2018）。過去10年の採用データが男性中心で、AIが女性の履歴書を低評価した。データの選別だけでは解決困難。"}, {"q": "Demographic Parity（人口統計学的等しさ）の定義は。", "choices": ["同じ Accuracy", "全グループで陽性予測率が同じ：P(Ŷ=1|A=0) = P(Ŷ=1|A=1)", "同じ Recall", "同じ Precision"], "answer": 1, "explanation": "最もシンプルだが結果指標を強制するため、Equal Opportunity（TPR等値）と矛盾しうる。Fairness Impossibility Theorem。"}, {"q": "Fairness Impossibility Theorem の主張は。", "choices": ["全てのFairnessは矛盾", "基準値が異なるグループでは複数のFairness定義（Calibration、Equal Opportunity、Equalized Odds）を同時には満たせない", "Fairness 不可能", "何もできない"], "answer": 1, "explanation": "Kleinberg 2016, Chouldechova 2017。トレードオフの選択を文脈に応じて行う必要がある。"}, {"q": "SHAP の数学的基盤は。", "choices": ["線形回帰", "協力ゲーム理論の Shapley 値（各特徴の限界貢献度の平均）", "クラスタリング", "ベイズ"], "answer": 1, "explanation": "一貫性・局所精度・無依存性などの公理を満たす唯一の説明手法。Lundberg & Lee 2017。"}, {"q": "LIME の動作は。", "choices": ["大域的説明", "個別予測点の周辺で線形モデルで局所近似し説明", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Ribeiro 2016。摂動サンプルを生成、重み付き線形回帰で局所的説明。モデル非依存（black-box対応）。"}, {"q": "Differential Privacy（ε-DP）の意味は。", "choices": ["ノイズなし", "1人のデータ変化で出力分布が e^ε 倍以内、個人特定リスクを数学的に制限", "学習加速", "暗号化"], "answer": 1, "explanation": "Dwork 2006。εが小さいほどプライバシー強、精度低下とのトレードオフ。Apple、Google、米国国勢調査で採用。"}, {"q": "DP-SGD の実装の核心は。", "choices": ["学習率変化", "各サンプル勾配をクリップ後、Gaussian ノイズを加えて集約", "ランダム選択", "パラメータ削除"], "answer": 1, "explanation": "Abadi 2016。Moments Accountantでεを厳密追跡。Opacus（PyTorch）、TF Privacy で実装。"}, {"q": "FGSM（Fast Gradient Sign Method）の式は。", "choices": ["x' = x + ε", "x' = x + ε · sign(∇ₓ L)", "x' = -x", "x' = 2x"], "answer": 1, "explanation": "損失を最大化する方向に微小摂動を加える。Goodfellow 2014。最も基本的な敵対的攻撃。PGD はその反復強化版。"}, {"q": "Adversarial Training は何を行うか。", "choices": ["ランダム学習", "敵対的サンプルを学習データに混ぜて学習、Robustness を獲得", "パラメータ削減", "クラスタリング"], "answer": 1, "explanation": "Madry 2018。PGD で生成した敵対的サンプルで Min-Max 学習。クリーン精度は微減、頑健性は大幅向上。"}, {"q": "Federated Learning の核心は。", "choices": ["中央データ集約", "データを中央化せず、各クライアントで学習→勾配のみ集約", "クラウドのみ", "シングルマシン"], "answer": 1, "explanation": "McMahan 2017 (Google)。Gboard、医療機関連携で実用。Secure Aggregation、DP と組み合わせて更にプライバシー強化。"}, {"q": "AI Alignment 問題の核心は。", "choices": ["計算速度", "AIシステムの目標を人間の真の意図と整合させること（誤った目標関数で学習すると有害な行動）", "パラメータ最適化", "クラスタリング"], "answer": 1, "explanation": "Anthropic、OpenAI、DeepMind の中核研究分野。RLHF、Constitutional AI、Debate、IDA などが主要手法。"}, {"q": "Reward Hacking（報酬ハッキング）の例は。", "choices": ["学習成功", "目標関数の意図しない『穴』を突いて高得点だが望ましくない行動（CoastRunners でゲーム本来の目的を無視して報酬狩り）", "パラメータ調整", "クラスタリング"], "answer": 1, "explanation": "Specification Gaming の一種。AGI が現実世界で類似行動を取ることがAI Safetyの主要懸念。"}, {"q": "Constitutional AI（Anthropic）の特徴は。", "choices": ["法律遵守", "AI自身が憲法（行動原則）に照らして自己批評・修正、RLAIF で大規模化", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Bai 2022。Claude モデルの基盤。RLHF の人間ラベラーの代わりに AI判定を使い、Alignment を大規模化。"}, {"q": "Grad-CAM の用途は。", "choices": ["学習加速", "CNN の予測根拠を画像上にヒートマップで可視化", "パラメータ削減", "クラスタリング"], "answer": 1, "explanation": "Selvaraju 2017。最後のConv層の活性化と勾配の重み付き和。医療画像、自動運転の説明に重要。"}, {"q": "Deepfake の主な技術基盤は。", "choices": ["ロジスティック回帰", "GAN、Diffusion Model、Autoencoder", "線形回帰", "K-means"], "answer": 1, "explanation": "生成モデルで顔・声を合成。検知技術（Deepfake Detection、C2PA、SynthID）も並行発展中。EU AI Act で透明性表示義務化。"}, {"q": "Membership Inference Attack（メンバーシップ推定攻撃）の標的は。", "choices": ["モデル盗難", "特定の個人データがモデルの学習データに含まれていたか推定する攻撃", "パラメータ盗難", "ラベル改ざん"], "answer": 1, "explanation": "プライバシー侵害の一形態。学習データへの過剰適合が手がかり。DPで防御。Shokri 2017。"}, {"q": "Model Inversion Attack の目的は。", "choices": ["モデル予測", "モデルの出力から学習データの特徴を復元（顔認証から顔画像復元等）", "パラメータ盗難", "ラベル改ざん"], "answer": 1, "explanation": "Fredrikson 2015。プライバシー侵害の重大形式。DP、出力の粗視化で防御。"}, {"q": "LLM の Jailbreak とは。", "choices": ["学習", "プロンプトエンジニアリングで安全機構を回避し有害出力を引き出す", "パラメータ盗難", "クラスタリング"], "answer": 1, "explanation": "DAN、ロールプレイ、Many-shot Jailbreak（Anthropic 2024）など多様。LLM 安全研究の主要課題。"}, {"q": "『Right to Explanation』が法的に要求される代表例は。", "choices": ["全てのAI", "GDPR（EU）の自動意思決定条項、EU AI Act の高リスクシステム", "なし", "業界自主"], "answer": 1, "explanation": "GDPR Art. 22。重要な判断（融資拒否、採用、医療）にAIを使う場合、本人に説明する義務。SHAP/LIMEがその実装手段。"}, {"q": "大規模LLMの環境影響として正しいのは。", "choices": ["影響なし", "学習に巨大な電力消費とCO₂排出（GPT-3: 552 t CO₂相当、Strubell 2019）", "パラメータ少ない", "クラスタリング"], "answer": 1, "explanation": "モデル巨大化のサステナビリティ問題。Green AI、再生可能エネルギー使用、効率化（蒸留、量子化）が課題。"}, {"q": "EU AI Act が採用したアプローチは。", "choices": ["一律規制", "リスクベース（許容不可〜最小リスクの4段階＋GPAI）", "自主規制のみ", "禁止のみ"], "answer": 1, "explanation": "リスクレベルに応じた段階規制。世界初の包括的AI法、2024年発効、2026年8月本格施行。"}, {"q": "EU AI Act で『許容不可リスク』に分類されるのは。", "choices": ["スパムフィルタ", "社会信用スコア、サブリミナル操作、リアルタイム公開生体認識", "チャットボット", "翻訳"], "answer": 1, "explanation": "第5条で原則禁止される行為。一部例外あり（テロリスト捜索の生体認識など）。"}, {"q": "GDPR 第22条の規定は。", "choices": ["個人データの所有権", "完全自動意思決定に対する人間の関与権・説明要求権", "罰金規定", "域外適用"], "answer": 1, "explanation": "法的効果を持つ自動決定（融資、採用）には人間関与が必要。例外あり（同意、契約必要、法的根拠）。"}, {"q": "日本の著作権法でAI学習を原則合法とする条項は。", "choices": ["第30条", "第30条の4（情報解析のための利用）", "第32条", "第47条の5"], "answer": 1, "explanation": "2018年改正で導入。情報解析（学習）目的での複製・公衆送信を原則認める。ただし著作権者の利益を不当に害する場合は除外。"}, {"q": "米国の著作権で、AI生成物に著作権が認められない判例として正しいのは。", "choices": ["Thaler v. Perlmutter（人間の創作性必要）", "NYT v. OpenAI", "Stable Diffusion 判決", "DABUS 判例"], "answer": 0, "explanation": "2023年。完全AI生成物に著作権登録却下。人間の創作的貢献が必要。日本も同様の方向。"}, {"q": "GDPR 違反の最大罰金は。", "choices": ["€10M or 全世界売上の2%", "€20M or 全世界売上の4%（高い方）", "€100M", "罰金なし"], "answer": 1, "explanation": "重大違反で €20M または前年度全世界売上の4%のいずれか高い方。EU AI Act は €35M または7%でさらに厳しい。"}, {"q": "EU AI Act の『GPAI』に該当するモデルは（典型例）。", "choices": ["線形回帰", "GPT-4、Claude、Gemini など 10²⁵ FLOPs 超の汎用基盤モデル", "K-means", "全モデル"], "answer": 1, "explanation": "General Purpose AI モデル。10²⁵ FLOPs 超は『体系的リスク』を持つとして追加義務（評価、サイバーセキュリティ、報告）。"}, {"q": "Anthropic ASL（Responsible Scaling Policy）の特徴は。", "choices": ["政府規制", "モデル能力に応じた自主基準、能力評価で次レベルに移行", "罰則あり", "1段階のみ"], "answer": 1, "explanation": "ASL-1〜4。能力評価でレベル決定、各レベルで安全要件。OpenAI Preparedness Framework、DeepMind FSF も類似。"}, {"q": "日本のAI事業者ガイドライン（2024年）のアプローチは。", "choices": ["罰則付きハードロー", "開発者・提供者・利用者向けソフトロー", "禁止リスト", "何もなし"], "answer": 1, "explanation": "総務省・経産省合同。法的拘束力なしのガイドラインだが、業界標準として広く参照される。3主体別の規範を提示。"}, {"q": "『DABUS判例』が確立したのは。", "choices": ["AIに著作権", "AIを発明者とする特許は認めない（多数国）", "AIが法人格", "AIが訴訟当事者"], "answer": 1, "explanation": "英・豪・欧・米・日でAI単独発明者を却下。発明者は自然人のみ。ただしAI利用発明は人間発明者として可。"}, {"q": "GDPR の『忘れられる権利』をLLMで実装する際の技術的課題は。", "choices": ["簡単に削除可", "一度学習されたデータの選択的削除は技術的に困難（Machine Unlearning 研究）", "不要", "パラメータ削減で対応"], "answer": 1, "explanation": "NN は分散表現なので個別データの削除が難しい。Machine Unlearning、SISA、Approximate Unlearning などの研究分野。"}, {"q": "米国 California SB-1047 の対象モデル基準は。", "choices": ["全モデル", "学習費用 $100M 超 or 10²⁶ FLOPs 超の Frontier モデル", "MNIST モデル", "ローカルLLMのみ"], "answer": 1, "explanation": "2024年に Newsom 拒否権で頓挫したが、改訂版議論中。フロンティアモデル開発者に安全評価・報告義務を課す提案。"}, {"q": "『広島AIプロセス』の主体は。", "choices": ["国連", "G7主導の生成AI国際ガバナンス枠組み", "日本単独", "EU単独"], "answer": 1, "explanation": "2023年G7広島サミットで開始、国際指針・行動規範を策定。OECD、UN AI Advisory Body と連携。"}, {"q": "NIST AI Risk Management Framework の役割は。", "choices": ["米法律", "AI リスク管理の自主的フレームワーク（Govern, Map, Measure, Manage の4機能）", "罰則", "EU専用"], "answer": 1, "explanation": "2023年公表。米企業のデファクト標準的フレームワーク。ISO/IEC 42001（AI管理システム）と相補的。"}, {"q": "EU AI Act の『高リスク』分野でないのは。", "choices": ["採用判断", "信用評価", "スパムフィルタ", "医療機器"], "answer": 2, "explanation": "スパムフィルタは『最小リスク』。Annex III の高リスク分野は雇用、信用、教育、医療、法執行、国境管理など8カテゴリ。"}, {"q": "著作権法における日本とEUの違いは。", "choices": ["同じ", "日本：第30条の4で原則OK、EU：DSM指令でテキスト・データマイニング権あるが商用利用にはオプトアウト可", "両方禁止", "両方完全自由"], "answer": 1, "explanation": "EU はオプトアウト権が著作権者にあり、商用利用での学習に拒否表示できる。日本は第30条の4で広く認める。"}, {"q": "ディープフェイク規制の米国の動向は。", "choices": ["全面禁止", "Tennessee州 ELVIS Act（音声）、NO FAKES Act（連邦提案）など州・連邦で立法化進行", "何もなし", "全許可"], "answer": 1, "explanation": "各州が肖像・音声権を立法化。NO FAKES Act は連邦レベルの統一を目指す。EU AI Act の透明性義務とも関連。"}, {"q": "『モデルカード』（Model Card）の役割は。", "choices": ["学習ループ", "AIモデルの意図された用途、限界、評価結果、倫理的考慮を文書化する透明性ツール", "ハイパラ管理", "ハードウェア仕様"], "answer": 1, "explanation": "Mitchell 2019。HuggingFace でデファクト標準化。EU AI Act 文書化義務とも整合。"}, {"q": "EU の DMA（Digital Markets Act）の対象は。", "choices": ["全AI", "プラットフォーム独占を抑制、Gatekeeper 認定企業（Microsoft、Google、Meta、Apple等）に義務", "個人開発者", "中小企業"], "answer": 1, "explanation": "2024年施行。大手プラットフォームの市場支配力濫用を抑制。AI 機能の差別的提供禁止などが含まれる。"}, {"q": "G検定取得者として、AI法規制への向き合い方として最も適切なのは。", "choices": ["法律家任せ", "開発・運用ライフサイクルの各段階で法的論点を意識し、必要なら専門家と協働", "無視", "必ず最も厳しい規制に合わせる"], "answer": 1, "explanation": "設計時のリスク評価、データ取得時の権利クリア、運用時の説明可能性、生成物の権利処理、契約レビュー。技術と法務の協働が現代AIの開発標準。"}]}, {"id": "basics", "label": "G検定 基本編", "count": 215, "desc": "AI基礎・数学・古典ML・NN基礎", "problems": [{"q": "『強いAI』と『弱いAI』という分類を1980年に提唱した哲学者は誰か。", "choices": ["アラン・チューリング", "ジョン・サール", "マービン・ミンスキー", "ジョン・マッカーシー"], "answer": 1, "explanation": ""}, {"q": "1956年に『Artificial Intelligence』という用語が初めて公式に使われた会議は。", "choices": ["ダートマス会議", "ジュネーブ会議", "スタンフォード会議", "MIT AI Lab 設立会議"], "answer": 0, "explanation": ""}, {"q": "チューリングテストの説明として最も適切なものは。", "choices": ["AIに将棋で人間に勝てるかを試す", "人間とAIが対話し、判定者がどちらか見分けられないかを試す", "AIが画像を正しく分類できるかを試す", "AIが論理パズルを解けるかを試す"], "answer": 1, "explanation": ""}, {"q": "『シンギュラリティ』を2045年頃と予測したことで知られる人物は。", "choices": ["イーロン・マスク", "ジェフリー・ヒントン", "レイ・カーツワイル", "ヤン・ルカン"], "answer": 2, "explanation": ""}, {"q": "特化型AI（ANI）と汎用AI（AGI）について正しい記述は。", "choices": ["AGIはANIの寄せ集めである", "現在実用化されているAIはほとんどANIで、AGIは未実現", "深層学習で容易にAGIが実現する", "ANIとAGIは同義語"], "answer": 1, "explanation": ""}, {"q": "フレーム問題とは何か。", "choices": ["画像のフレーム検出問題", "AIが状況の中で何を考慮すべきかを限定できない問題", "ハードウェアの制約問題", "学習データのフレームレート問題"], "answer": 1, "explanation": ""}, {"q": "シンボルグラウンディング問題が指す内容は。", "choices": ["記号が現実世界の意味に結びつかない", "シンボリックAIが性能で劣る", "プログラム記号の文字化け", "記号処理が遅い"], "answer": 0, "explanation": ""}, {"q": "『中国語の部屋』思考実験の主張として最も適切なものは。", "choices": ["中国語は習得が難しい", "記号操作だけでは意味理解は生じない", "コンピュータは中国語が苦手", "部屋の構造は計算に重要"], "answer": 1, "explanation": ""}, {"q": "『AI効果』とは何か。", "choices": ["AIが他のAIに影響を与える現象", "AIがタスクを達成すると『それはAIではない』と再評価される現象", "AIが学習で性能向上する効果", "AI導入による経済効果"], "answer": 1, "explanation": ""}, {"q": "AI / 機械学習 / 深層学習の関係として正しいものは。", "choices": ["AI ⊂ 機械学習 ⊂ 深層学習", "AI ⊃ 機械学習 ⊃ 深層学習", "AI = 機械学習 = 深層学習", "これらは互いに独立"], "answer": 1, "explanation": ""}, {"q": "Russell & Norvigによる4象限の知能観で『チューリングテスト』が位置するのは。", "choices": ["人間のように考える", "合理的に考える", "人間のように行動する", "合理的に行動する"], "answer": 2, "explanation": ""}, {"q": "『中国語の部屋』への代表的な反論として、『部屋全体としてなら理解している』とする立場は。", "choices": ["システム説", "ロボット説", "脳シミュレーション説", "その他の存在説"], "answer": 0, "explanation": ""}, {"q": "AIの定義について研究者の意見が完全に一致しない最大の理由は。", "choices": ["技術進歩が速いから", "『知能』そのものに普遍的な合意がないから", "国により法律が違うから", "翻訳が困難だから"], "answer": 1, "explanation": ""}, {"q": "ELIZA（1966年、ワイゼンバウム）の中核技術は。", "choices": ["深層学習", "強化学習", "パターンマッチングと書き換えルール", "知識グラフ"], "answer": 2, "explanation": ""}, {"q": "ASI（人工超知能）の説明として最も適切なものは。", "choices": ["特定タスクで人間を超えるAI", "人間と同程度の柔軟性を持つAI", "あらゆる領域で人間の知能を超えるAI", "ハードウェア性能の高いAI"], "answer": 2, "explanation": ""}, {"q": "フレーム問題に対する現代AIの現実的な対応として最も近いものは。", "choices": ["完全に解決済み", "大規模学習データから『暗黙の常識』を獲得し回避（根本解決ではない）", "フレーム問題は存在しない", "量子計算で解く"], "answer": 1, "explanation": ""}, {"q": "『弱いAI』の典型例として誤っているものは。", "choices": ["Google Translate", "AlphaGo", "顔認証システム", "意識を持つ人工知能"], "answer": 3, "explanation": ""}, {"q": "『シンタックスはセマンティクスを生まない』というテーゼで知られるのは。", "choices": ["チューリング", "サール", "ハルナッド", "マッカーシー"], "answer": 1, "explanation": ""}, {"q": "2022年にGoogleエンジニアBlake Lemoineが『感覚を持つ』と主張して論争になったAIは。", "choices": ["GPT-3", "Claude", "LaMDA", "AlphaFold"], "answer": 2, "explanation": ""}, {"q": "現代の生成AI（GPT-4等）がチューリングテストを実質的に通過したと多くの研究者が認めるが、それでも『AGI到達』とは多くが認めない。その主要な理由は。", "choices": ["速度が遅すぎる", "表面的振る舞いの合格と本質的知能は別問題（中国語の部屋の問題）", "多言語対応が不十分", "コストが高すぎる"], "answer": 1, "explanation": ""}, {"q": "2018年チューリング賞を共同受賞した3名（深層学習の父たち）は誰か。", "choices": ["Hinton, LeCun, Bengio　(1) Goodfellow, Hochreiter, LeCun　(2) Sutskever, Karpathy, Hinton　(3) Norvig, Russell, Mitchell"], "answer": 0, "explanation": "Geoffrey Hinton、Yann LeCun、Yoshua Bengio。2018年チューリング賞を『conceptual and engineering breakthroughs that have made deep neural networks a critical component of computing』として共同受賞。→ §1.6, §1.7"}, {"q": "機械学習で扱う『テンソル』の最も適切な説明は次のうちどれか。", "choices": ["物理学の座標変換則を満たす対象<br>", "スカラーまたはベクトルのみ<br>", "軸が3つ以上のものに限る<br>", "スカラー(0軸)・ベクトル(1軸)・行列(2軸)・3軸以上 を含む多次元配列の総称"], "answer": 3, "explanation": "機械学習における『テンソル』は単に多次元配列の意味で使われ、軸数を問わない。TensorFlow の Tensor も同様。物理学の意味は別。"}, {"q": "RGB カラー画像 (高さ 224, 幅 224, チャネル 3) は何階テンソルか。", "choices": ["1階", "2階", "3階", "4階"], "answer": 2, "explanation": "軸が3つ（H, W, C）あるため3階テンソル。これにバッチ次元を加えると (B, H, W, C) または (B, C, H, W) の4階テンソルとなり、CNN の入力形式となる。"}, {"q": "ベクトル u=(2, 3, 1) と v=(1, -1, 2) の内積 u·v は。", "choices": ["0", "1", "3", "7"], "answer": 1, "explanation": "2·1 + 3·(-1) + 1·2 = 2 - 3 + 2 = 1。"}, {"q": "2つのベクトルが直交するとき、内積の値は。", "choices": ["必ず正", "必ず負", "0", "1"], "answer": 2, "explanation": "u·v = ||u||||v||cosθ で、直交（θ=90°）なら cos90°=0 のため 0。これが Word Embedding の独立性、Attention の出力の独立次元、直交初期化の根拠。"}, {"q": "L1 ノルムが Lasso 正則化で『スパース解』を生む理由として正しいのは。", "choices": ["L1単位球が円形で滑らかなため<br>", "L1単位球が菱形で『角』があり、最適解が軸上に来やすいため<br>", "L1ノルムが微分可能なため<br>", "L1ノルムが指数関数を含むため"], "answer": 1, "explanation": "L1単位球（||w||₁=1）は菱形で、その『角』は軸上にある。制約付き最適化の解は等高線と単位球が接する点であり、角に当たることが多く、その軸の重みが正確に 0 になる（スパース化）。L2 の円には角がなく、すべての重みが小さく縮むだけ。"}, {"q": "ベクトル v₁=(1, 2)、v₂=(2, 4) が形作る関係として正しいのは。", "choices": ["線形独立で平面を張る<br>", "直交している<br>", "線形従属（v₂ = 2 v₁）で直線のみを張る<br>", "ノルムが等しい"], "answer": 2, "explanation": "v₂ = 2 v₁ なので一方が他方の定数倍。すなわち線形従属で、両者は同じ直線上にあり、平面を張れない。"}, {"q": "正方行列 A の逆行列が存在する必要十分条件は。", "choices": ["det(A) = 0", "det(A) ≠ 0 かつ A はフルランク", "A が対称", "A の全要素が正"], "answer": 1, "explanation": "det(A) ≠ 0 と『フルランク（rank=n）』は同値。これらが逆行列存在の条件。実用では条件数 κ(A) で『近似的特異性』も警戒する。"}, {"q": "固有値分解 A = QΛQ⁻¹ が常に可能となる行列の特徴は。", "choices": ["全ての正方行列<br>", "対称（実対称）行列 — このとき Q は直交行列、Λ は実対角<br>", "特異行列のみ<br>", "上三角行列のみ"], "answer": 1, "explanation": "一般の正方行列は固有値分解が常に可能とは限らない（Jordan 標準形が必要なケースあり）。しかし対称行列は実スペクトル定理により、必ず実固有値で直交対角化可能。PCA・カーネル法・ヘッセ行列の解析がうまく行く根拠。"}, {"q": "PCA の理論的根拠として最も適切な記述は。", "choices": ["共分散行列の固有値分解で分散最大方向（主成分）を見つける<br>", "クラスラベルの分散を最大化<br>", "データを log 変換する<br>", "重みを正則化する"], "answer": 0, "explanation": "PCA は中心化したデータの共分散行列 Σ = (1/n)XTX を固有値分解し、固有値が大きい順の固有ベクトル（主成分）にデータを射影する。教師ラベルは使わない（教師なし）。クラス分離は LDA。"}, {"q": "対称行列 A の固有値がすべて正のとき、A は何と呼ばれるか。", "choices": ["半正定値", "正定値（positive definite）", "不定値", "対角行列"], "answer": 1, "explanation": "対称行列で全固有値 &gt; 0 のとき正定値（PD）。等号許可なら半正定値（PSD、全固有値 ≥ 0）。共分散行列は必ず PSD、最適化のヘッセ行列が PD ならその点は極小。"}, {"q": "行列式 det(A) の幾何学的意味として正しいのは。", "choices": ["A の各要素の平均<br>", "A が表す線形写像による体積の倍率<br>", "A の固有値の数<br>", "A の行数"], "answer": 1, "explanation": "|det(A)| は A による線形写像が単位立方体に作用したときの体積倍率。負なら向きが反転（鏡映）。det = 0 は『写像が次元を潰す』ことを意味し、逆写像が不可能。"}, {"q": "機械学習で『多重共線性』が問題となる理由として最も適切なのは。", "choices": ["計算速度が遅くなる<br>", "特徴量行列のランクが落ち、(X<sup>T</sup>X)⁻¹ が不安定になり係数推定が安定しない<br>", "損失関数が複雑になる<br>", "データが増えすぎる"], "answer": 1, "explanation": "線形回帰の正規方程式 w = (XTX)⁻¹XTy は XTX の可逆性に依存。特徴量間に強い線形関係があると XTX はほぼ特異になり、係数推定の標準誤差が爆発、解釈不能に。対処は VIF 検出、変数削減、PCA、Ridge 回帰など。"}, {"q": "Eckart-Young 定理が示すことは。", "choices": ["任意の行列は LU 分解できる<br>", "行列の最良の rank-k 近似は、上位 k 個の特異値を残した SVD で得られる<br>", "すべての行列は対称<br>", "固有値は必ず実数"], "answer": 1, "explanation": "Eckart-Young 定理（1936）：任意の行列 A に対し、Frobenius ノルム（または2-ノルム）で最良の rank-k 近似は、SVD の上位 k 特異値を残し残りを 0 にしたもの。これが画像圧縮、レコメンドシステム、LoRA の理論的根拠。"}, {"q": "『高次元での距離の呪い』の本質的な問題は。", "choices": ["計算速度が遅い<br>", "高次元では点同士の距離が均一化し、最近傍探索などの距離ベース手法が機能しなくなる<br>", "メモリが不足する<br>", "ファイルが大きい"], "answer": 1, "explanation": "高次元では距離の最大/最小の比が 1 に近づき、すべての点がほぼ等距離になる。これにより k-NN、K-means などが意味を持たなくなる。対処は次元削減（PCA, t-SNE, UMAP, Autoencoder）、特徴選択、距離計量学習（Metric Learning）。"}, {"q": "f(x) = x³ - 2x + 1 の x=2 における微分値は。", "choices": ["4", "8", "10", "12"], "answer": 2, "explanation": "f'(x) = 3x² - 2、f'(2) = 12 - 2 = 10。"}, {"q": "勾配ベクトル ∇f(x) が指す方向は。", "choices": ["最も急に減少する方向", "最も急に増加する方向", "関数の零点", "接平面の法線"], "answer": 1, "explanation": "勾配は『最急上昇方向』を指す。最小化問題では負の勾配方向 -∇f に進む（最急降下法・SGD・Adam）。等高線に垂直になる幾何学的事実も重要。"}, {"q": "合成関数 y = f(g(x)) の微分（連鎖律）として正しいのは。", "choices": ["dy/dx = f'(g(x)) · g'(x)", "dy/dx = f'(x) · g'(x)", "dy/dx = f'(x) + g'(x)", "dy/dx = f(g'(x))"], "answer": 0, "explanation": "連鎖律：外側の関数の微分（g(x) で評価）と内側の微分の積。NNの逆伝播は連鎖律を計算グラフ上で機械的に適用したもの。"}, {"q": "ヘッセ行列 H の固有値がすべて正のとき、その臨界点は。", "choices": ["極大", "極小", "鞍点", "縮退"], "answer": 1, "explanation": "H 正定値 → 周囲が下に凸 → 極小。負定値なら極大、固有値に正負混在なら鞍点。"}, {"q": "テイラー展開を機械学習で用いる典型例は。", "choices": ["決定木の分岐", "Newton 法、XGBoost の更新方向決定", "データ拡張", "ハッシュ化"], "answer": 1, "explanation": "テイラー展開は局所近似で、1次近似→勾配降下、2次近似→Newton 法・XGBoost。誤差解析にも頻出。"}, {"q": "凸関数の重要な性質として正しいのは。", "choices": ["局所最小と大域最小が一致する", "必ず微分不可能", "学習が遅い", "制約付き最適化に使えない"], "answer": 0, "explanation": "凸関数では局所最小＝大域最小。これが線形回帰、ロジスティック回帰、SVM などが理論的に扱いやすい根拠。NN は非凸なので局所最小が複数存在しうる。"}, {"q": "勾配降下法の更新式 θ ← θ − η ∇L における η が大きすぎるとき起きうる現象は。", "choices": ["過学習", "振動・発散", "計算量増", "パラメータ削減"], "answer": 1, "explanation": "η が大きすぎると更新が最小を行き過ぎ、振動・発散。一般に Lipschitz 連続な勾配なら η ≤ 1/L が収束保証境界。"}, {"q": "SGD（確率的勾配降下）の利点として正しくないものは。", "choices": ["反復が高速", "ノイズが鞍点脱出に貢献", "メモリ効率", "必ず大域最適に収束"], "answer": 3, "explanation": "SGDは局所最適や鞍点に陥る可能性があり、大域最適への収束保証はない（凸関数では確率収束）。それでも実用上は非常に有効、特に NN ではノイズが正則化として機能。"}, {"q": "Momentum オプティマイザが解決する問題は。", "choices": ["学習率自動調整", "勾配ノイズによる振動と遅い収束", "正則化", "データ拡張"], "answer": 1, "explanation": "Momentum は勾配の指数移動平均を慣性として保持し、振動を抑制しつつ収束を加速する。物理的には『谷を転がるボール』のアナロジー。"}, {"q": "Adam オプティマイザの特徴として正しいのは。", "choices": ["Momentum と RMSProp（適応学習率）の組み合わせ＋バイアス補正", "2次オプティマイザ", "学習率不要", "NN以外でしか動かない"], "answer": 0, "explanation": "Adam は1次モーメント（Momentum）と2次モーメント（RMSProp）を併用し、初期段階のバイアス補正を加えた1次オプティマイザ。深層学習のデファクト。"}, {"q": "AdamW が通常の Adam と異なる点は。", "choices": ["重み減衰を勾配計算から分離した", "Momentum を削除した", "学習率を固定した", "全く同じ"], "answer": 0, "explanation": "Adam で L2 正則化を素朴に加えると2次モーメントとの相互作用で正則化が弱まる。AdamW は重み減衰 λθ を更新式の最後で直接引くことで、SGD と同じ正則化効果を実現。LLM 学習の事実上の標準。"}, {"q": "ラグランジュ未定乗数法が解く問題のタイプは。", "choices": ["無制約最適化", "等式制約付き最適化", "線形回帰", "クラスタリング"], "answer": 1, "explanation": "ラグランジュ関数 L(x, λ) = f(x) - λg(x) で等式制約 g(x)=0 のもとでの f(x) の最適化を扱う。不等式制約まで拡張すると KKT 条件。SVM、エントロピー最大化で核心。"}, {"q": "バックプロパゲーション（逆伝播）の理論的根拠は。", "choices": ["連鎖律", "中心極限定理", "大数の法則", "ベイズの定理"], "answer": 0, "explanation": "逆伝播は連鎖律を計算グラフ上で機械的に適用するアルゴリズム。1986年に Rumelhart, Hinton, Williams が普及させた。これがなければ深層学習は実用化できなかった。"}, {"q": "Newton 法と勾配降下法の主な違いは。", "choices": ["Newton 法は1次情報のみ使用", "Newton 法はヘッセ行列の逆を使う2次最適化、局所的に高速", "全く同じ", "勾配降下法は教師あり"], "answer": 1, "explanation": "Newton 法 θ ← θ − H⁻¹∇L は2次情報を使い、凸問題で局所的に2次収束。深層学習では H が巨大で実装困難なため、Adam 等の対角近似が実用的妥協。"}, {"q": "学習率 Warmup が必要な典型的状況は。", "choices": ["線形回帰", "大バッチ学習や Transformer 学習の初期段階", "決定木", "K-means"], "answer": 1, "explanation": "大バッチや Transformer では、初期の勾配が大きく不安定なため、η を 0 から徐々に上げる Warmup（数千ステップ）が学習安定化に必須。Cosine Annealing と組み合わせるのが現代標準。"}, {"q": "高次元損失曲面で最も多く存在するのは。", "choices": ["局所最小", "鞍点", "極大", "平坦領域のみ"], "answer": 1, "explanation": "Dauphin et al. 2014 が示したように、高次元ではヘッセ行列のすべての固有値が同符号になる確率が指数的に小さく、鞍点が圧倒的に多い。SGDのノイズが脱出に貢献。"}, {"q": "活性化関数 sigmoid σ(x) = 1/(1+e^{-x}) の微分は。", "choices": ["1", "σ(x)", "σ(x)(1 - σ(x))", "e^{-x}"], "answer": 2, "explanation": "σ'(x) = σ(x)(1 - σ(x))。出力値で書ける（再利用効率高い）。最大値は σ(0)=0.5 の点で 0.25 と小さく、深層NNで勾配消失の原因に。これがReLU普及の理由の一つ。"}, {"q": "バッチサイズを大きくした際の典型的なトレードオフは。", "choices": ["並列効率↑、汎化性能やや低下（シャープミニマへ）", "全てが向上", "全てが悪化", "メモリは変わらない"], "answer": 0, "explanation": "大バッチは並列効率・メモリ効率↑だが、勾配ノイズ↓で『シャープなミニマ』に収束しやすく汎化が劣化する傾向。Linear Scaling Rule＋Warmup で部分的補正。"}, {"q": "Gradient Checkpointing が解決する問題は。", "choices": ["計算速度の遅さ", "学習中の活性化保存に必要なメモリの大きさ", "ハイパーパラメータ選択", "データの不均衡"], "answer": 1, "explanation": "通常の逆伝播は順伝播の全活性化を保存（O(L) メモリ）。Checkpointing は一部だけ保存し、必要時に再計算でメモリを O(√L) に。計算は 1.3〜2 倍に増えるが、巨大モデル学習で必須。"}, {"q": "KKT 条件が登場する典型問題は。", "choices": ["不等式制約付き最適化、SVM など", "クラスタリング", "単純線形回帰", "K-NN"], "answer": 0, "explanation": "KKT（Karush-Kuhn-Tucker）条件は不等式制約付き最適化で必要十分（凸の場合）の最適性条件。停留性・主実行可能性・双対実行可能性・相補性の4つ。SVMの双対形式、エントロピー最大化など。"}, {"q": "サイコロを2回振って和が 7 になる確率は。", "choices": ["1/36", "1/12", "1/6", "1/4"], "answer": 2, "explanation": "和が7になる組合せは (1,6)(2,5)(3,4)(4,3)(5,2)(6,1) の6通り、全 36 通り → 6/36 = 1/6。"}, {"q": "事象 A と B が独立であることの定義として正しいのは。", "choices": ["P(A∪B) = P(A) + P(B)", "P(A∩B) = P(A)P(B)", "A=B", "P(A|B) = 0"], "answer": 1, "explanation": "独立性の定義は P(A∩B) = P(A)P(B)。これは P(A|B) = P(A) と同値。①は『排反』ではなく『独立』との混同に注意。"}, {"q": "ベイズの定理 P(A|B) = ? を正しく表すのは。", "choices": ["P(B|A) P(A) / P(B)", "P(A) P(B) / P(A∩B)", "P(A∩B) / P(A)", "P(A) + P(B)"], "answer": 0, "explanation": "ベイズの定理。これにより事前 × 尤度 / エビデンスで事後分布が得られる。"}, {"q": "連続確率変数の確率密度関数 f(x) が満たすべき性質は。", "choices": ["0 ≤ f(x) ≤ 1", "f(x) ≥ 0 かつ ∫f(x)dx = 1", "f(x) = 1", "離散値のみ"], "answer": 1, "explanation": "PDFは非負＋全積分1。値自体は1を超えうる（密度であり確率ではない）ことに注意。"}, {"q": "確率変数 X, Y が独立のとき Var(X+Y) は。", "choices": ["Var(X) + Var(Y)", "Var(X) - Var(Y)", "Var(X)Var(Y)", "Var(XY)"], "answer": 0, "explanation": "一般に Var(X+Y) = Var(X) + Var(Y) + 2Cov(X,Y)。独立なら Cov = 0 で右辺第3項が消える。"}, {"q": "ベルヌーイ分布 Be(p) の平均と分散は。", "choices": ["p, p²", "p, p(1-p)", "1-p, p", "0, p"], "answer": 1, "explanation": "E[X]=p, Var[X]=p(1-p)。分散は p=0.5 で最大 0.25。"}, {"q": "標準正規分布 N(0, 1) の確率密度関数の値が最大となる x は。", "choices": ["-1", "0", "1", "∞"], "answer": 1, "explanation": "正規分布のピークは平均 μ=0 の位置。最大密度は 1/√(2π) ≈ 0.399（1を超えない例）。"}, {"q": "中心極限定理の主張として正しいのは。", "choices": ["母集団は必ず正規", "標本平均は母集団分布によらず正規分布に近づく", "期待値=分散", "どんな分布も同じ平均"], "answer": 1, "explanation": "CLT は母集団分布が何であれ（有限分散なら）、標本平均が正規分布に収束することを示す。実用上、n≥30 で近似が良い。"}, {"q": "最尤推定（MLE）の基本的な考え方は。", "choices": ["観測データを最も尤もらしくするパラメータを選ぶ", "事前分布の中央値", "事後分布の期待値", "ランダム選択"], "answer": 0, "explanation": "MLEは観測データの尤度 P(D|θ) を最大化する θ を選ぶ。実装では対数尤度を最大化（数値安定）。"}, {"q": "MAP 推定と MLE の関係は。", "choices": ["完全に同じ", "事前分布が一様なら一致", "MAP は事前を使わない", "MLEはベイズ"], "answer": 1, "explanation": "MAP = argmax P(D|θ)P(θ)、事前が一様なら P(θ) が定数となり MAP=MLE。L2 正則化はガウス事前のMAPに相当。"}, {"q": "機械学習で『L2 正則化』に対応する事前分布は。", "choices": ["一様", "ガウシアン", "ラプラス", "ベータ"], "answer": 1, "explanation": "L2 ≡ -log P(θ) で P(θ) ∝ exp(-λ||θ||²) なのでガウシアン。L1 はラプラス分布の MAP に対応。"}, {"q": "ナイーブベイズが『naive（素朴）』と呼ばれる理由は。", "choices": ["パラメータが少ない", "特徴量が条件付き独立と仮定する", "線形", "学習が速い"], "answer": 1, "explanation": "強い独立性仮定が『素朴』の由来。実際にはほとんど成立しないが、結果は意外と頑健で実用的。"}, {"q": "EM アルゴリズムの典型用途は。", "choices": ["線形回帰の解析解", "潜在変数を含むモデルの MLE（GMM など）", "勾配計算", "正則化選択"], "answer": 1, "explanation": "EM は潜在変数（クラスタ割当、隠れ状態）を含むモデルの反復 MLE。GMM, HMM, LDA, VAE の基礎。"}, {"q": "変分推論（VI）が最大化する量は。", "choices": ["尤度のみ", "ELBO（Evidence Lower BOund）", "クロスエントロピー", "距離"], "answer": 1, "explanation": "VIは事後分布 P(θ|D) を近似分布 q(θ;φ) で近似し、ELBO を最大化する。これは KL(q||P) 最小化と等価。VAE の損失の根拠。"}, {"q": "95% 信頼区間の正しい解釈は。", "choices": ["真値が 95% の確率でこの区間にある", "同じ手順を多数回繰り返すと 95% の区間が真値を含む", "必ず真値を含む", "効果量"], "answer": 1, "explanation": "頻度論の解釈は『同じ手順を繰り返すと』。①はベイズの『信用区間』の解釈で、頻度論では誤り。"}, {"q": "p値の正しい意味は。", "choices": ["H0 が真の確率", "H0 が真と仮定したとき、観測以上に極端な結果が得られる確率", "H1 が真の確率", "効果量"], "answer": 1, "explanation": "p値は条件付き確率 P(データ|H0)。『H0 が真の確率』ではない（よくある誤解）。p &lt; α で H0 棄却。"}, {"q": "多変量正規分布 N(μ, Σ) において Σ が満たすべき条件は。", "choices": ["対角行列", "対称かつ半正定値", "単位行列", "上三角"], "answer": 1, "explanation": "共分散行列は常に対称、必ず半正定値。これは共分散の定義から数学的に従う。"}, {"q": "分類器の確率出力（softmax）が真の確率と一致するように調整する手法を何と呼ぶか。", "choices": ["キャリブレーション（Platt Scaling、Isotonic、Temperature Scaling など）", "正則化", "標準化", "量子化"], "answer": 0, "explanation": "現代のNNは過信気味で、出力確率と真の頻度が一致しないことが多い。Calibration がそれを補正。Reliability Diagram, ECE で評価。"}, {"q": "ベイズ的 A/B テストの利点は。", "choices": ["p値だけが分かる", "『B が A より良い確率』など直観的な確率解釈ができ、逐次更新が自然", "サンプル不要", "必ず A が勝つ"], "answer": 1, "explanation": "事後分布から『P(B&gt;A)』が直接出る。逐次的なデータ追加で事前を更新でき、peeking 問題が起きにくい。"}, {"q": "多重検定の補正で最も保守的な手法は。", "choices": ["Bonferroni（α/m）", "FDR (Benjamini-Hochberg)", "Holm", "無補正"], "answer": 0, "explanation": "Bonferroni は α/m と最も厳しい。検出力は犠牲だが、FWER（少なくとも1つの偽発見の確率）を α 以下に保証。現代の標準は FDR（Benjamini-Hochberg）。"}, {"q": "確率 p で起こる事象の自己情報量は。", "choices": ["p", "-p", "-log p", "1-p"], "answer": 2, "explanation": "h(x) = -log P(x)。確率が小さいほど情報量が大きい。"}, {"q": "エントロピー H(X) が最大となるのは。", "choices": ["確定的", "一様分布", "最も歪んだ分布", "連続のみ"], "answer": 1, "explanation": "離散K値の場合、一様分布で H = log K が最大。確定的は H=0 で最小。"}, {"q": "公平なコインのエントロピーは。", "choices": ["0 bit", "0.5 bit", "1 bit", "2 bit"], "answer": 2, "explanation": "H = -(0.5 log₂0.5 + 0.5 log₂0.5) = 1 bit。公平コイン1回分の情報量＝1bit。"}, {"q": "相互情報量 I(X;Y) と H の関係で誤りはどれか。", "choices": ["I(X;Y) = H(X) + H(Y) - H(X,Y)", "I(X;Y) = H(X) - H(X|Y)", "I(X;Y) ≥ 0", "I(X;Y) は負の値も取りうる"], "answer": 3, "explanation": "相互情報量は常に非負（I≥0）。X,Y独立なら 0、強く依存するなら大きい値。"}, {"q": "KLダイバージェンス KL(p||q) について誤りはどれか。", "choices": ["常に非負", "p=q なら 0", "対称：KL(p||q) = KL(q||p)", "距離関数ではない"], "answer": 2, "explanation": "KL は非対称。これが距離関数でない理由。対称化したのが JS ダイバージェンス。"}, {"q": "クロスエントロピー H(p, q) と KL の関係は。", "choices": ["H(p,q) = H(p) - KL(p||q)", "H(p,q) = H(p) + KL(p||q)", "関係なし", "H(p,q) = KL(q||p)"], "answer": 1, "explanation": "CE = H(p) + KL(p||q)。H(p) は学習データ固定なので、CE最小化 = KL最小化 = q を p に近づける。"}, {"q": "NN の分類で『Softmax + CE 損失』が標準的に使われる理由として最も適切なのは。", "choices": ["計算が遅い", "多項分布のMLEと等価、勾配が ŷ-y で簡潔", "パラメータ数を減らす", "正則化のため"], "answer": 1, "explanation": "多項分布の負の対数尤度であり、ロジットへの勾配が ŷ-y となる美しい性質を持つ。これが NN 分類学習の効率を支える。"}, {"q": "決定木の分岐基準『情報利得（IG）』の定義は。", "choices": ["H(D) - H(D|A) （分割前後のエントロピー差）", "H(D) のみ", "Var(D)", "平均値"], "answer": 0, "explanation": "IG は属性Aで分割したときのエントロピー減少量。これが大きい属性を選ぶことで予測能力の高い分岐を作る。ID3/C4.5の基準。"}, {"q": "VAE の損失関数 -ELBO の構成として正しいのは。", "choices": ["再構成損失 + KL(q(z|x) || p(z))", "CE のみ", "MSE のみ", "正則化なし"], "answer": 0, "explanation": "-ELBO = 再構成損失 + KL正則化。エンコーダ出力が事前分布N(0,I)に近づくよう KL で正則化。"}, {"q": "t-SNE が最小化する量は。", "choices": ["ユークリッド距離", "高次元と低次元の分布の KL ダイバージェンス", "MSE", "Hinge損失"], "answer": 1, "explanation": "高次元での近傍類似度分布 P と低次元での Q の KL(P||Q) を最小化。クラスタを可視化する標準手法。"}, {"q": "『最大エントロピー原理』が示すのは。", "choices": ["与えられた制約条件下で最も不確実な分布を選ぶ", "最頻分布を選ぶ", "最頻値", "中央値"], "answer": 0, "explanation": "既知の制約以外について余計な仮定をしない原則。例：平均と分散だけ既知 → 正規分布が最大エントロピー解。"}, {"q": "微分エントロピーが離散エントロピーと異なる点で正しいのは。", "choices": ["負の値も取りうる", "必ず非負", "必ず整数", "必ず log K 以下"], "answer": 0, "explanation": "連続分布の微分エントロピーは負になりうる（例：分散が極小な正規分布）。スケール変換にも不変でない。"}, {"q": "Shannon の情報源符号化定理が示す下限は。", "choices": ["1記号あたり 1 bit", "1記号あたり log K bit", "1記号あたりエントロピー H(X) bit", "上限なし"], "answer": 2, "explanation": "平均符号長 ≥ H(X)。これがロスレス圧縮の理論的下限。Huffman 符号は H+1 までで実現。"}, {"q": "GAN（原論文）の損失関数が最小化する分布間距離は。", "choices": ["KL（forward）", "JSダイバージェンス", "MSE", "ユークリッド"], "answer": 1, "explanation": "Goodfellow の元のGANは JS ダイバージェンスを最小化することが示されている。Wasserstein GAN は別の距離（Wasserstein距離）を使う。"}, {"q": "相互情報量を使った特徴選択の利点は。", "choices": ["計算速度のみ", "線形・非線形両方の依存関係を捉える", "ピアソン相関の代替で線形のみ", "ラベル不要"], "answer": 1, "explanation": "Pearson相関は線形のみだが、MIは任意の関数関係（U字、二次、複雑な依存）を捉える。教師あり特徴選択で強力。"}, {"q": "エントロピーが大きい状況の例として最も適切なのは。", "choices": ["確定的シーン", "完全にランダムなビット列", "単一値の連続", "既知の数列"], "answer": 1, "explanation": "完全にランダム＝予測不能＝エントロピー最大。圧縮も不可能（log K bit/記号）。"}, {"q": "InfoNCE（対照学習で使う）の役割は。", "choices": ["CE損失と同じ", "正サンプルと負サンプルの間で相互情報量の下限を推定して最大化", "MSE", "正則化のみ"], "answer": 1, "explanation": "InfoNCE は対照学習（SimCLR, MoCo）の損失。表現空間で正ペア類似度を負ペアより高くする、MI下限の最大化として解釈可能。"}, {"q": "2分類タスクで真ラベル y=1、予測確率 p=0.8 のとき、二値CE損失は。", "choices": ["-log(0.8)", "-log(0.2)", "0.5", "1.0"], "answer": 0, "explanation": "CE = -[y log p + (1-y) log(1-p)]、y=1 なら CE = -log p = -log(0.8) ≈ 0.223。"}, {"q": "『Label Smoothing』は何を変更するか。", "choices": ["one-hotラベル y を [1-ε, ε/(K-1), ...] に置き換え、過信を防ぐ", "損失関数を別物に変更", "学習率", "バッチサイズ"], "answer": 0, "explanation": "真ラベルの確信度を 1.0 から 1-ε（典型 0.9）に下げる正則化。NNの過信を防ぎ、汎化を改善。情報論的にはエントロピーの底上げ。"}, {"q": "KL(p||q) と KL(q||p) が大きく違う典型的状況は。", "choices": ["単峰分布同士の中心ずれ", "多峰分布 vs 単峰分布", "全く同じ分布", "KLは常に対称"], "answer": 1, "explanation": "多峰の p を単峰の q で近似する場合、KL(p||q) は mode covering（q を広く）を要求し、KL(q||p) は mode seeking（q を一つに集中）を要求。VAEは reverse KL を使い結果として1つのモードに集中しやすい。"}, {"q": "教師あり学習の定義として正しいのは。", "choices": ["ラベルなしから学ぶ", "(入力, 正解) ペアからマッピングを学ぶ", "報酬から学ぶ", "学習しない"], "answer": 1, "explanation": "教師あり学習は (x, y) ペアから関数 y=f(x) を学習。分類と回帰が代表。"}, {"q": "K-means や PCA はどの学習パラダイムか。", "choices": ["教師あり", "教師なし", "強化学習", "自己教師あり"], "answer": 1, "explanation": "ラベルを使わずデータ構造（クラスタ、主成分）を見出す教師なし学習の代表。"}, {"q": "BERT の MLM や GPT の Next Token Prediction はどのパラダイムか。", "choices": ["教師あり", "教師なし", "自己教師あり（データから教師信号を作る）", "強化学習"], "answer": 2, "explanation": "大量のラベルなしテキストから、自分自身でマスク埋めや次トークン予測という『教師信号』を作って学習。現代基盤モデルの核。"}, {"q": "強化学習の中核要素は。", "choices": ["ラベル", "状態・行動・報酬・方策", "クラスタ", "ベクトル化"], "answer": 1, "explanation": "エージェントが状態s_tで行動a_tを取り、報酬r_tを得て次状態s_{t+1}へ。累積報酬を最大化する方策 π(a|s) を学習。AlphaGo, RLHF の根幹。"}, {"q": "訓練・検証・テストデータの主な役割として正しい組合せは。", "choices": ["訓練=学習、検証=ハイパラ選択、テスト=最終評価", "すべて同じ", "テストで学習", "検証はランダム"], "answer": 0, "explanation": "テストデータは『最終評価1回のみ』。検証で繰り返しチューニングしたあとに、初めて見るデータで本番性能を推定。"}, {"q": "『データリーク』が起きる典型例は。", "choices": ["時系列データを単純シャッフルで分割、全データで正規化、目的変数情報の混入", "大きすぎるバッチ", "学習率小さい", "パラメータ少ない"], "answer": 0, "explanation": "いずれもテスト情報の漏洩。本番性能を大幅に過大評価する致命的バグ。時系列は時間順分割、正規化は訓練データで計算してテストに適用。"}, {"q": "過学習（overfitting）の典型的サインは。", "choices": ["訓練・検証とも誤差大", "訓練誤差小、検証誤差大", "両方小", "ランダム"], "answer": 1, "explanation": "過学習は『訓練データを暗記して、未見データで失敗』。対処はEarly Stopping、Dropout、L2、データ拡張、Augmentation。"}, {"q": "バイアス-バリアンス分解で『バイアス大』を表す状況は。", "choices": ["モデルが複雑すぎ", "モデルが単純すぎて関数を表現できない（未学習）", "データ多すぎ", "正則化なし"], "answer": 1, "explanation": "Bias は『系統的な誤差』、モデルの表現力不足が原因。対処はモデル複雑化、特徴量追加、正則化緩和。"}, {"q": "5-fold Cross-Validation の目的は。", "choices": ["データ量を増やす", "モデル評価の分散を減らし安定化、ハイパラ選択の信頼性", "計算を減らす", "正則化"], "answer": 1, "explanation": "データを5分割し各回1つを検証に。5回の評価の平均で評価分散を抑える。小データで特に重要。"}, {"q": "高次元ハイパラ探索で Grid Search より Random Search が推奨される理由は。", "choices": ["Bergstra 2012：少数の重要パラメータを効率的に探索できる", "計算量が同じ", "ランダムは常に最適", "コードが短い"], "answer": 0, "explanation": "多くの場合、性能を支配するハイパラは少数。Grid は全格子点を試すが、無関係次元の試行が無駄。Random は重要次元を多くサンプリングできる。"}, {"q": "Bayesian Optimization の特徴は。", "choices": ["過去の試行結果からガウス過程で次の候補を予測、試行数を最小化", "ランダム", "厳密な数学なし", "Optuna は使えない"], "answer": 0, "explanation": "GP やTPE で予測平均と分散を考慮し『有望かつ未探索な点』を選ぶ。NN の学習など1試行が高コストな場合に強力。Optuna は TPE ベースで実装。"}, {"q": "転移学習（Transfer Learning）の典型的フローは。", "choices": ["事前学習（大規模データで自己教師あり）→ ファインチューニング（少量タスクデータ）", "ゼロから訓練のみ", "ハイパラ調整のみ", "ランダム"], "answer": 0, "explanation": "BERT/GPT/ViT すべてこの流れ。LLM ではIn-Context Learning, LoRA, RLHFなど発展形が多数。"}, {"q": "No Free Lunch（NFL）定理が示唆することは。", "choices": ["あるアルゴリズムが万能", "すべての可能な問題分布で平均すると、どのアルゴリズムも同性能 → 問題ごとに適した手法を選ぶ必要", "学習不要", "深層学習が最強"], "answer": 1, "explanation": "Wolpert 1996。実用問題が特定構造（画像・言語の局所性、自然法則）を持つから NN が機能するが、すべての問題に最強なアルゴリズムは数学的に存在しない。"}, {"q": "層化抽出（Stratified Sampling）が必要な典型ケースは。", "choices": ["クラス不均衡データの分類", "完全に均一なデータ", "連続値のみ", "時系列のみ"], "answer": 0, "explanation": "クラス比が偏った（陽性 1% など）データで単純ランダム分割すると検証セットに陽性が含まれない可能性も。層化で各分割のクラス比を均一に保つ。"}, {"q": "『Early Stopping』が機能する原理は。", "choices": ["訓練を最後まで続ける", "検証損失が悪化し始める前に学習を止めて過学習を防ぐ", "パラメータ削減", "データ拡張"], "answer": 1, "explanation": "訓練損失は単調減少するが検証損失は U字。最低点で止めると過学習せず汎化性能最大化。Patience（数エポック改善なしで停止）で実装。"}, {"q": "Few-shot Learning の典型は。", "choices": ["大量データで学習", "数〜数十サンプルで新タスクに適応（MAML, In-Context Learning）", "ゼロデータ", "パラメータ調整なし"], "answer": 1, "explanation": "限られたサンプルで新タスクに適応する手法。GPT-4 のIn-Context Learning はプロンプトの例から推論する強力な Few-shot 手法。"}, {"q": "マルチタスク学習の利点として誤りはどれか。", "choices": ["タスク間で知識共有", "各タスクで Bias を下げる効果", "正則化効果でVariance↓", "全てのタスクが互いに干渉して性能が必ず下がる"], "answer": 3, "explanation": "実際にはタスク間の知識共有でしばしば性能↑。ただし関連性のないタスク同時学習は『負の転移』を起こすことがある。"}, {"q": "『Double Descent』現象（深層学習で観察）の主張は。", "choices": ["モデル複雑度を上げ続けると、過学習を超えて再び汎化が改善する", "U字カーブのみ", "学習しない", "必ず単調減少"], "answer": 0, "explanation": "古典的 U字 の後に二度目の下降。過パラメータ化された NN が経験的に汎化することの一つの説明。Belkin 2019。"}, {"q": "半教師あり学習が威力を発揮する状況は。", "choices": ["ラベル付け不可", "ラベル付きデータが少ないがラベルなしデータは大量にある（医療画像など）", "全データラベル付き", "データなし"], "answer": 1, "explanation": "ラベル収集コストが高い領域で、ラベルなしデータを活用して学習を強化。Pseudo-Labeling, FixMatch, MixMatch などの手法。"}, {"q": "『時系列データ』を扱う際の正しい分割方法は。", "choices": ["ランダム k-fold", "時系列順に分割：過去で訓練、未来で検証・テスト（Time Series Split）", "シャッフル", "階層化"], "answer": 1, "explanation": "時系列の単純シャッフルは『未来を見て過去を予測』するデータリークの典型。常に時間順で分割。Expanding window / Rolling window などの手法がある。"}, {"q": "線形回帰のOLS解析解は。", "choices": ["(XᵀX)⁻¹Xᵀy", "Xy", "X⁻¹y", "XᵀX"], "answer": 0, "explanation": "正規方程式 XᵀXβ = Xᵀy の解。XᵀX が可逆（フルランク）であることが条件。多重共線性で不安定化。"}, {"q": "ロジスティック回帰の出力は。", "choices": ["連続値", "確率 P(y=1|x)", "クラスタID", "ハードラベル"], "answer": 1, "explanation": "シグモイドで [0,1] に押込めた確率。0.5閾値でハードラベル化。"}, {"q": "SVM の最大化対象は。", "choices": ["学習データ数", "マージン（境界とサポートベクター間の距離）", "学習率", "パラメータ数"], "answer": 1, "explanation": "マージン = 2/||w|| の最大化。これは ||w|| 最小化に帰着、凸最適化問題。"}, {"q": "SVM のカーネルトリックが解決する問題は。", "choices": ["計算速度", "線形分離不可能なデータ（非線形特徴空間への暗黙写像）", "ノイズ除去", "データ拡張"], "answer": 1, "explanation": "K(x,x')=φ(x)·φ(x') で高次元への明示的写像なしに非線形分離。RBF, 多項式, シグモイドなどのカーネルが使われる。"}, {"q": "決定木の分岐基準（分類）として一般的なのは。", "choices": ["情報利得（エントロピー減少）、ジニ係数", "MSE のみ", "ランダム", "多数決"], "answer": 0, "explanation": "分類木では情報利得（ID3, C4.5）かジニ係数（CART）。回帰木では分散減少 or MSE。"}, {"q": "Bagging と Boosting の根本的違いは。", "choices": ["Bagging=並列・Variance削減、Boosting=逐次・Bias削減", "全く同じ", "Bagging が常に強い", "Boosting は弱学習器を使えない"], "answer": 0, "explanation": "Bagging は独立な弱学習器の平均で分散削減。Boosting は前の誤差を補正する逐次学習でバイアス削減。両者は相補的。"}, {"q": "ランダムフォレストが決定木より頑健な理由は。", "choices": ["1本の深い木を使う", "Bootstrap + 特徴量ランダム選択で木同士の相関を下げ、Variance削減", "学習が速い", "パラメータが少ない"], "answer": 1, "explanation": "2重のランダム性（データのBootstrap、各分岐での特徴量選択）で木の多様性を確保。100本の木の平均で過学習を抑える。"}, {"q": "表形式データでGBDT（XGBoost等）がNNより強い傾向にある主な理由は。", "choices": ["計算が遅い", "スケーリング不要、カテゴリ・欠損対応、不均衡データに頑健", "パラメータが多い", "メモリ消費が大きい"], "answer": 1, "explanation": "GBDTは表形式の特性に最適化。NNは特徴量の前処理に敏感で、表形式では性能発揮しにくい（一部例外：FT-Transformer、TabTransformer）。"}, {"q": "XGBoost、LightGBM、CatBoost の特徴対応として正しいのは。", "choices": ["XGBoostはGPUなし", "LightGBMは葉単位成長で高速", "CatBoostはカテゴリ非対応", "全て同じ"], "answer": 1, "explanation": "LightGBM はヒストグラム法＋Leaf-wise成長で超高速。XGBoost は精度志向、CatBoost はカテゴリ特徴を内蔵処理。"}, {"q": "k-NN の特徴として正しくないのは。", "choices": ["学習フェーズが軽量", "推論で全データを保持・距離計算が必要", "高次元で『距離の呪い』に弱い", "大規模データで超高速"], "answer": 3, "explanation": "k-NN は遅延学習で学習は速いが、推論で毎回全データとの距離計算が必要、大規模では遅い。Approximate NN（FAISS, HNSW）で実用化。"}, {"q": "K-means が苦手なケースは。", "choices": ["球状クラスタ", "異なるサイズ・密度・形状のクラスタ（非球状）", "数値データ", "教師あり"], "answer": 1, "explanation": "K-meansは球状クラスタを仮定（ユークリッド距離・等分散）。非球状や密度差・サイズ差があるとDBSCAN, GMM, HDBSCANが良い。"}, {"q": "K-means の初期化問題への対処は。", "choices": ["ランダム初期化のみ", "K-means++、複数回試行＋最良採用", "全データを初期点に", "1点のみ"], "answer": 1, "explanation": "K-means++ は初期点を順次最も遠い点から選ぶ。これにより局所最適確率を大幅に削減。sklearn の n_init で複数試行も標準。"}, {"q": "PCA の主成分の取得方法は。", "choices": ["ランダム", "共分散行列の固有値分解 or データのSVD", "k-NN距離", "勾配降下"], "answer": 1, "explanation": "共分散行列 Σ の固有値分解で主成分（固有ベクトル）。実装上は SVD で直接行うのが数値的に安定。"}, {"q": "DBSCAN の利点は。", "choices": ["クラスタ数 k を事前指定不要、任意形状、ノイズラベル付与", "球状のみ", "K指定必要", "学習なし"], "answer": 0, "explanation": "密度ベースでk不要、任意形状クラスタ検出、ノイズ点を明示的に分離。eps と min_samples のチューニングが鍵。"}, {"q": "Ridge と Lasso の違いとして正しいのは。", "choices": ["Ridge=L2でスパース、Lasso=L1で全保持", "Ridge=L2で全て縮小、Lasso=L1でスパース化", "同じ", "どちらも線形不可"], "answer": 1, "explanation": "Ridge は L2 ペナルティで全係数を縮小、Lasso は L1 ペナルティで多くを正確に 0 に（自動的特徴選択）。Elastic Net は両者のブレンド。"}, {"q": "SHAP（SHapley Additive exPlanations）の役割は。", "choices": ["学習アルゴリズム", "モデル解釈（各特徴量が予測にどう寄与したか）", "ハイパラ調整", "正則化"], "answer": 1, "explanation": "ゲーム理論のShapley値ベース。各特徴量の貢献を一貫した方法で説明。XAI（説明可能AI）の標準ツール。"}, {"q": "AdaBoost の仕組みは。", "choices": ["並列学習", "誤分類サンプルの重みを大きくして弱学習器を逐次学習", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Boosting の元祖。各回で誤分類点の重みを増やし、次の弱学習器が苦手部分に集中。XGBoostは Gradient Boosting の発展形。"}, {"q": "Stacking の典型構造は。", "choices": ["1つのモデルのみ", "複数モデルの予測を入力としてメタ学習器が最終予測", "多数決のみ", "ランダム"], "answer": 1, "explanation": "ベース学習器（GBDT、RF、ロジ回帰）の予測をメタ学習器（多くは線形）で統合。Kaggle上位の常套手段。CVの設計に注意。"}, {"q": "RFE（Recursive Feature Elimination）の役割は。", "choices": ["学習アルゴリズム", "特徴量を重要度の低い順から削除する反復的特徴量選択", "正則化", "クラスタ"], "answer": 1, "explanation": "モデルを学習→重要度を取得→最低の特徴量を削除→繰り返し。所望の特徴量数まで縮約。"}, {"q": "『Elbow法』が判定するものは。", "choices": ["学習率", "K-means のクラスタ数 k（クラスタ内分散の減少が緩むk）", "正則化強度", "過学習"], "answer": 1, "explanation": "k を 1, 2, 3... と増やし、SSE（クラスタ内分散和）をプロット。減少率が急変する『ひじ』を最適 k とする経験則。Silhouette score などより厳密な手法も。"}, {"q": "混同行列の TP は何を意味するか。", "choices": ["真陽性（陽性を陽性と予測）", "偽陽性", "偽陰性", "真陰性"], "answer": 0, "explanation": "TP = True Positive。"}, {"q": "Precision の定義は。", "choices": ["TP/(TP+FN)", "TP/(TP+FP)", "TN/(TN+FP)", "(TP+TN)/全体"], "answer": 1, "explanation": "陽性予測のうち実際に陽性の割合。FPが増えると下がる。"}, {"q": "Recall（感度）の定義は。", "choices": ["TP/(TP+FN)", "TP/(TP+FP)", "TN/(TN+FP)", "(TP+TN)/全体"], "answer": 0, "explanation": "実際の陽性のうち検出できた割合。FN（見逃し）が増えると下がる。医療診断で重視。"}, {"q": "F1スコアの定義は。", "choices": ["算術平均", "P×R", "PとRの調和平均", "P/R"], "answer": 2, "explanation": "F1=2PR/(P+R)。両方が高くないと高くならない。"}, {"q": "スパム検知で『全て非スパム』予測で Accuracy 99% のモデルは。", "choices": ["良い", "完全に無価値（Recall=0、F1=0）", "完全分類器", "ベスト"], "answer": 1, "explanation": "不均衡データでの Accuracy の典型的な罠。F1・PR-AUC は0。"}, {"q": "ROC-AUC の意味として正しいのは。", "choices": ["訓練時間", "陽性-陰性ペアで陽性のスコアが高い確率", "Precisionの平均", "パラメータ数"], "answer": 1, "explanation": "AUCの確率的解釈。0.5=ランダム、1.0=完全。"}, {"q": "極端な不均衡（陽性率 0.1%）で適切な指標は。", "choices": ["Accuracy", "PR-AUC", "MSE", "R²"], "answer": 1, "explanation": "ROC-AUCは不均衡に頑健すぎて高く出るがPR-AUCは真の困難度を反映。"}, {"q": "医療診断で重視すべき指標は。", "choices": ["Precision", "Recall", "Specificity", "MSE"], "answer": 1, "explanation": "Recall でFN（見逃し）を最小化。"}, {"q": "スパムフィルタで重視すべきは。", "choices": ["Precision", "Recall", "両方", "Accuracy"], "answer": 0, "explanation": "Precision でFP（重要メール誤検出）を最小化。"}, {"q": "回帰指標で外れ値に頑健なのは。", "choices": ["MSE", "RMSE", "MAE", "MAPE"], "answer": 2, "explanation": "MAE は絶対値、外れ値の影響が線形。MSE は二乗で敏感。中間に Huber Loss。"}, {"q": "R²（決定係数）の意味は。", "choices": ["必ず0〜1", "1-SSE/SST、モデルが説明する分散の割合", "パラメータ数", "Accuracy"], "answer": 1, "explanation": "テストで負になることもある。"}, {"q": "NNの予測確率を真の頻度に合わせる手法は。", "choices": ["正則化", "Calibration（Platt、Isotonic、Temperature）", "標準化", "Augmentation"], "answer": 1, "explanation": "現代NNは過信気味。Calibrationで補正、ECEで評価。"}, {"q": "多クラス F1 で macro と weighted の違いは。", "choices": ["同じ", "macro は各クラス等値、weighted はクラス頻度で重み付け", "macroはスパース", "weightedは教師あり"], "answer": 1, "explanation": "不均衡では macro が公平、頻度反映なら weighted。"}, {"q": "推薦システムでの MAP@k の意味は。", "choices": ["全体精度", "上位k個のAverage Precisionの平均、ランキング品質指標", "MSE", "R²"], "answer": 1, "explanation": "NDCG とともに推薦・検索で標準。"}, {"q": "Log Loss と Accuracy の違いは。", "choices": ["同じ", "Log Lossは予測確率の質を評価（自信度を考慮）、Accuracyはハードラベルのみ", "Log Lossは離散", "Accuracyは確率"], "answer": 1, "explanation": "自信を持って間違えるほどLog Lossが高くなる。"}, {"q": "McNemar検定の用途は。", "choices": ["t検定の代替", "同一データに対する2モデル予測比較で差が有意か判定", "クラスタリング評価", "回帰分析"], "answer": 1, "explanation": "同データ・異モデルの予測一致／不一致を表で集計し検定。"}, {"q": "SMOTE が行うことは。", "choices": ["少数クラスを単純複製", "少数クラスのk近傍間に合成サンプルを補間生成", "多数クラスを削除のみ", "ランダム"], "answer": 1, "explanation": "単純複製と違い、合成データで多様性を保つ。imbalanced-learnで実装。"}, {"q": "Cross-Validation の主目的は。", "choices": ["データ拡張", "評価分散を減らしハイパラ選択の信頼性向上", "計算高速化", "ラベル予測"], "answer": 1, "explanation": "1回分割では運次第。k-foldで多数評価の平均で安定化。"}, {"q": "Focal Loss が解決する問題は。", "choices": ["過学習", "クラス不均衡＋簡単例の過剰寄与（物体検出由来）", "学習率", "正則化"], "answer": 1, "explanation": "-(1-p)^γ log p で容易例の損失を下げ、難しい例（少数クラス）に集中。RetinaNet で導入。"}, {"q": "分類閾値の標準値 0.5 を変える理由として正しいのは。", "choices": ["必ず0.5", "業務要件、不均衡、コスト非対称性に応じて最適化", "変えてはいけない", "モデル変更必要"], "answer": 1, "explanation": "0.5は単なる慣例値。F1最大化、期待コスト最小化などで決定。"}, {"q": "パーセプトロンが解けない代表的問題は。", "choices": ["AND", "OR", "XOR", "NOT"], "answer": 2, "explanation": "XORは線形分離不可能。Minsky 1969でこの限界が指摘され第一次AI冬の時代の一因に。MLPで解決。"}, {"q": "普遍近似定理（UAP）の主張は。", "choices": ["1層では何もできない", "1層の隠れ層でユニット数十分なら任意の連続関数を任意精度で近似可能", "必ず2層必要", "ReLUのみ"], "answer": 1, "explanation": "Hornik 1989, Cybenko 1989。ただし実用では深層化の方が指数的に効率良い。"}, {"q": "ReLU の利点で正しいのは。", "choices": ["計算が遅い", "勾配消失を緩和、計算高速、スパース化", "出力が(0,1)", "必ず連続微分可能"], "answer": 1, "explanation": "max(0,x)。x&gt;0で勾配1、入力側まで勾配が伝わる。深層化を可能にした立役者。"}, {"q": "Sigmoid 活性化関数の勾配消失の原因は。", "choices": ["微分の最大値が0.25と小さく、深層では勾配が指数的に減衰", "計算が複雑", "線形", "出力が-1から1"], "answer": 0, "explanation": "σ'(x) = σ(x)(1-σ(x))の最大が0.25。10層で 0.25¹⁰ ≈ 10⁻⁶。勾配が入力側でほぼ0に。"}, {"q": "BERT/GPT で標準的に使われる活性化関数は。", "choices": ["Sigmoid", "Tanh", "GELU（Gaussian Error Linear Unit）", "Hardmax"], "answer": 2, "explanation": "GELU(x) = x·Φ(x)。ReLUより滑らか、Transformer系で標準。Swish/SiLU も類似形状。"}, {"q": "Softmax 関数の役割は。", "choices": ["二値分類", "多クラスの確率分布出力（合計1、非負）", "ノイズ追加", "正則化"], "answer": 1, "explanation": "多クラス分類の出力層標準。CE損失と組み合わせると勾配が ŷ-y で簡潔。"}, {"q": "He初期化が想定する活性化関数は。", "choices": ["Sigmoid", "Tanh", "ReLU 系", "Softmax"], "answer": 2, "explanation": "He（Kaiming）初期化：W ~ N(0, 2/fan_in)。ReLU で半分が0になることを補正。Xavier/Glorot は Tanh/Sigmoid 用。"}, {"q": "NN の重みを全て 0 で初期化すると。", "choices": ["学習加速", "対称性により全ニューロンが同じ更新を受け、多様性が生まれず学習しない", "過学習", "高速"], "answer": 1, "explanation": "対称性破壊が必要で、ランダム初期化が必須。バイアスは0でもOK。"}, {"q": "残差接続（Skip Connection、ResNet）の主な役割は。", "choices": ["パラメータ削減", "勾配伝播の改善、超深層化を可能に", "メモリ節約", "計算高速化"], "answer": 1, "explanation": "y = F(x) + x で勾配がスキップ経路から直接伝わる。100層以上を可能にした。Transformerにも採用。"}, {"q": "ミニバッチ学習の利点として誤りはどれか。", "choices": ["計算効率", "GPU並列化", "ノイズが汎化に有利", "必ず大域最適に収束"], "answer": 3, "explanation": "SGD は確率的なので大域最適保証なし。実用では十分機能、むしろノイズが鞍点脱出に役立つ。"}, {"q": "Embedding 層の役割は。", "choices": ["数値の正規化", "離散カテゴリ（単語ID、ユーザID）を学習可能な連続ベクトルに変換", "損失計算", "出力層"], "answer": 1, "explanation": "単語ID → 128〜4096次元ベクトル。Word2Vec, BERT, GPT, 推薦システムで標準。"}, {"q": "多クラス分類で使う損失関数は。", "choices": ["MSE", "Hinge", "Cross Entropy（Softmax + CE）", "MAE"], "answer": 2, "explanation": "Softmax + CE が標準。多項分布の負の対数尤度と等価。"}, {"q": "Layer Normalization が Batch Normalization より好まれる場面は。", "choices": ["CNN", "バッチサイズが小さい、可変、または RNN/Transformer", "線形回帰", "K-means"], "answer": 1, "explanation": "BN はバッチ依存、小バッチで不安定。LN は1サンプル内で正規化、Transformer ・LLM で標準。"}, {"q": "『深層化』が UAP の単層拡大より有利な理由は。", "choices": ["単に流行", "同精度を達成するパラメータ数が指数的に少なくて済む（階層的特徴学習）", "計算高速", "ランダム性"], "answer": 1, "explanation": "Telgarsky 2016 等の理論。階層的に低レベル→高レベル特徴を学習でき、効率と汎化が良い。"}, {"q": "Dying ReLU 問題への対処は。", "choices": ["Sigmoid に戻す", "Leaky ReLU, ELU, GELU 等、x&lt;0でも小さな勾配を持つ関数", "学習停止", "入力反転"], "answer": 1, "explanation": "ReLU は x≤0 で勾配0、ニューロンが死んで復活しない。Leaky ReLU（α=0.01）, GELU で緩和。"}, {"q": "バッチサイズを大きくすると一般に。", "choices": ["必ず汎化が向上", "並列効率↑だが、ノイズが減って汎化やや悪化（シャープミニマへ）", "メモリ減", "学習率不要"], "answer": 1, "explanation": "大バッチは並列効率良いが、勾配ノイズ減でシャープなミニマに収束しやすく汎化が劣化する傾向。Linear Scaling Rule + Warmupで補正。"}, {"q": "Softmax+CE の logit に対する勾配は。", "choices": ["ŷ + y", "ŷ - y", "-y", "1"], "answer": 1, "explanation": "ŷ-y というシンプルな形。これがNN分類学習の計算効率の根拠。"}, {"q": "NN の汎化が良い理由として有力な仮説は。", "choices": ["神秘的", "SGDの暗黙的正則化、フラットなミニマの選好、データの多様体仮説", "ランダム", "パラメータ多いから良い"], "answer": 1, "explanation": "過パラメータ化されているのに汎化する『深層学習の謎』。SGDの確率性が良いミニマへ導く説明が有力。"}, {"q": "『計算グラフ』の概念は何のために使われるか。", "choices": ["可視化のみ", "自動微分の実装：演算をノードとして記録し、逆伝播で勾配を機械的に計算", "メモリ節約", "学習率"], "answer": 1, "explanation": "PyTorch, TensorFlow の自動微分の根幹。連鎖律を計算グラフ上で機械的に適用。"}, {"q": "バイアス項 b の役割は。", "choices": ["不要", "線形変換に平行移動を加え、原点を通らない決定境界を可能に", "正則化", "学習率"], "answer": 1, "explanation": "y = Wx + b の b。原点を通らない超平面を表現可能に。BNを使う層では省略することもある。"}, {"q": "逆伝播の数学的核心は。", "choices": ["線形回帰", "連鎖律（chain rule）を計算グラフ上で系統的に適用", "ランダム", "クラスタリング"], "answer": 1, "explanation": "dy/dx = (dy/du)(du/dx) を多層に適用、計算グラフのbackwardで自動化。"}, {"q": "逆伝播を実用化した1986年の論文の著者は。", "choices": ["Turing", "Rumelhart, Hinton, Williams", "Bengio", "LeCun"], "answer": 1, "explanation": "Nature論文『Learning representations by back-propagating errors』。多層NNの実用化を可能にした歴史的論文。"}, {"q": "100万パラメータNNで全勾配を計算するのに必要な順伝播・逆伝播の回数は。", "choices": ["100万回", "順伝播1回 + 逆伝播1回（合計でも O(N) パラメータ数）", "1000回", "ゼロ"], "answer": 1, "explanation": "これが逆伝播の真価。素朴な有限差分なら100万倍のコスト。reverse-mode auto-diff の効率性。"}, {"q": "Sigmoid 関数の微分は。", "choices": ["σ(x)", "σ(x)·(1-σ(x))", "1-σ(x)", "x"], "answer": 1, "explanation": "美しい形。最大値は σ(0)·(1-σ(0)) = 0.25。これが勾配消失の主因。"}, {"q": "ReLU の微分は。", "choices": ["常に1", "x&gt;0で1、x≤0で0", "x", "ランダム"], "answer": 1, "explanation": "x=0で厳密には微分不可能だが、実装で0または1を採用。シンプルさが計算効率に貢献。"}, {"q": "Softmax + CE の合成勾配が美しい形は。", "choices": ["p+y", "p-y", "p²", "y²"], "answer": 1, "explanation": "logit z への ∂L/∂z = (p - y_onehot) / N。シンプル＆数値安定。NN分類の計算効率の根拠。"}, {"q": "全結合層 z = Wx + b で、上流勾配 δ = ∂L/∂z から得られる ∂L/∂W は。", "choices": ["δ・x", "δ・xᵀ（外積）", "Wδ", "δ"], "answer": 1, "explanation": "形状 dₒᵤₜ × dᵢₙ。バッチでは Σ δᵢ·xᵢᵀ。∂L/∂b = δ, ∂L/∂x = Wᵀδ。"}, {"q": "NN学習で reverse-mode 自動微分が使われる理由は。", "choices": ["パラメータ数 ≫ 出力数（損失1つ）なので、forward-modeより遥かに効率的", "唯一の方法", "ランダム", "メモリ少ない"], "answer": 0, "explanation": "Forward は入力数に、Reverse は出力数に計算量が比例。NN は損失1つなので Reverse 一択。"}, {"q": "勾配消失の主因は。", "choices": ["学習率", "活性化関数の微分の積が層数で指数的に減衰（Sigmoid/Tanh）", "パラメータ数", "データ量"], "answer": 1, "explanation": "Sigmoid 微分最大 0.25、L層で 0.25^L。10層で 1e-6。ReLU、BN、ResNet で解決。"}, {"q": "勾配爆発の対処は。", "choices": ["学習率を上げる", "Gradient Clipping（勾配ノルムを上限でカット）", "何もしない", "パラメータ増加"], "answer": 1, "explanation": "RNN/Transformer で標準。||g|| &gt; threshold なら g ← g · threshold/||g||。閾値 1.0 が典型。"}, {"q": "SGD の更新式は。", "choices": ["θ ← θ + η・∂L/∂θ", "θ ← θ - η・∂L/∂θ", "θ ← ∂L/∂θ", "θ ← η・θ"], "answer": 1, "explanation": "勾配方向の逆（descent）に η（学習率）だけ動く。シンプルだが汎化が良いことがある。"}, {"q": "逆伝播でメモリを最も消費するのは。", "choices": ["パラメータ", "オプティマイザ状態", "順伝播の中間活性化（逆伝播で必要）", "損失値"], "answer": 2, "explanation": "各層の出力（B × D）を逆伝播のために保存。L 層では O(L·B·D)。これが大規模NN のメモリ消費の主因。"}, {"q": "Gradient Checkpointing の効果は。", "choices": ["計算高速化", "中間活性化を一部だけ保存し逆伝播で再計算、メモリ O(L)→O(√L)", "精度向上", "パラメータ削減"], "answer": 1, "explanation": "メモリと計算のトレードオフ（計算1.5倍）。LLM 学習で必須。PyTorch torch.utils.checkpoint で実装。"}, {"q": "Mixed Precision Training（FP16/BF16）の主な利点は。", "choices": ["精度向上", "GPU メモリ半減＆計算2〜3倍速、Tensor Coreを活用", "パラメータ削減", "ランダム性"], "answer": 1, "explanation": "FP16計算 + FP32重みコピー + Loss Scaling。BF16はダイナミックレンジが広く Loss Scaling 不要。LLM学習で標準。"}, {"q": "Data Parallel の動作は。", "choices": ["1GPUだけ使う", "各GPUに同じモデルコピー、ミニバッチを分割、勾配をAllReduceで集約", "モデルを分割", "ランダム"], "answer": 1, "explanation": "最も基本的な並列化。PyTorch DDP, Horovod。モデルがGPUに載るサイズなら最初の選択肢。"}, {"q": "勾配チェック（Gradient Check）の用途は。", "choices": ["学習加速", "解析的に計算した勾配と数値微分を比較し、実装バグを検出", "パラメータ削減", "必須学習"], "answer": 1, "explanation": "カスタム backward を書いたとき必須。差が 1e-7〜1e-5 オーダーなら正しい。学習中は遅いので無効化。"}, {"q": "PyTorch で勾配計算を有効化するには。", "choices": ["自動で有効", "requires_grad=True で作成、または .requires_grad_() で設定", "不可能", "ランダム"], "answer": 1, "explanation": "requires_grad=True の Tensor は計算グラフに含まれ、.backward() で勾配が記録される。.grad 属性で取得。"}, {"q": "ZeRO（DeepSpeed）が分散するのは。", "choices": ["モデルのみ", "オプティマイザ状態、勾配、パラメータを分散保持しメモリ削減", "データのみ", "ランダム"], "answer": 1, "explanation": "ZeRO-1：オプティマイザ状態、ZeRO-2：+勾配、ZeRO-3：+パラメータも分散。LLM学習で必須。"}, {"q": "Operator Fusion（Fused operations）の効果は。", "choices": ["精度向上", "連続した演算を1カーネルに融合、メモリ転送削減でGPU効率↑", "パラメータ削減", "ランダム"], "answer": 1, "explanation": "FlashAttention の核心。HBM ↔ SRAM 転送を減らす。Triton, CUDA Graph で実装。"}, {"q": "『Stop Gradient』の用途は。", "choices": ["学習停止", "計算グラフの一部で勾配を遮断（GAN、対照学習、強化学習の Target Network 等で必須）", "パラメータ削除", "ランダム"], "answer": 1, "explanation": ".detach() で実装。Target を更新せず参照だけしたいときに使う。BYOL、DQN、PPO で必須テクニック。"}, {"q": "L2 正則化（Weight Decay）が抑制するのは。", "choices": ["学習速度", "大きな重みの値、過学習", "計算量", "メモリ"], "answer": 1, "explanation": "L_total = L + λ||θ||² で大きな重みを罰し、汎化を改善。MAP推定でガウス事前に対応。"}, {"q": "Dropout の典型的なドロップ率は。", "choices": ["0.01", "0.1〜0.5", "0.9", "1.0"], "answer": 1, "explanation": "一般に 0.1〜0.5。隠れ層で 0.5、入力層で 0.2 が古典的。BN と併用するときは小さめにする傾向。"}, {"q": "Dropout の動作として正しいのは。", "choices": ["訓練時のみニューロンを確率的に無効化、推論時はすべて使用", "常に無効化", "推論でのみ動作", "パラメータ削減"], "answer": 0, "explanation": "訓練時のみドロップ、推論時は通常通り（スケール補正あり）。アンサンブル近似と解釈できる。"}, {"q": "Batch Normalization の正規化対象は。", "choices": ["単一サンプル内", "ミニバッチ内の各チャネルごと", "パラメータ自体", "学習率"], "answer": 1, "explanation": "ミニバッチ内で各特徴/チャネルごとに平均・分散を計算し正規化。バッチサイズ依存、Tiny バッチでは不安定。"}, {"q": "Transformer で標準的な正規化は。", "choices": ["BatchNorm", "LayerNorm（バッチサイズ非依存、系列長変化OK）", "なし", "Dropout"], "answer": 1, "explanation": "LayerNorm は単一サンプル内の特徴次元で正規化。可変長の系列、小バッチでも安定。最近は RMSNorm も（LLaMA 等）。"}, {"q": "He 初期化が適している活性化関数は。", "choices": ["Sigmoid", "tanh", "ReLU 系（Leaky ReLU、GELU を含む）", "Step"], "answer": 2, "explanation": "He（2015）は分散 2/n_in で、ReLU の片側 0 の性質を考慮。Xavier は Sigmoid/tanh 向け。LeCun は SELU 向け。"}, {"q": "Early Stopping の動作は。", "choices": ["訓練を必ず最終エポックまで", "検証損失が改善しなくなったら停止（過学習開始前）", "ランダム停止", "学習しない"], "answer": 1, "explanation": "Patience（数エポック改善なし）で停止。最も簡単で効果的な正則化。最良時のモデルを保存して使う。"}, {"q": "画像認識でよく使われる強力な自動データ拡張は。", "choices": ["反転のみ", "RandAugment、AutoAugment、TrivialAugment", "ノイズのみ", "なし"], "answer": 1, "explanation": "RandAugment は2つの操作を強度 9 でランダム適用。AutoAugment は RL で最適化された方策。深層学習の SOTA で標準。"}, {"q": "Label Smoothing が変更する対象は。", "choices": ["学習率", "one-hot ラベルを [ε/(K-1), 1-ε,...] に置換、過信抑制", "パラメータ数", "バッチサイズ"], "answer": 1, "explanation": "真ラベルの確信度を 1.0 から 1-ε（典型 0.9）に下げる。汎化改善＋過信抑制。ImageNet, NMT などで標準。"}, {"q": "Mixup の動作は。", "choices": ["単一サンプル", "2サンプルを λ:1-λ で線形混合、ラベルも同様に混合", "ノイズ加算", "パラメータ平均"], "answer": 1, "explanation": "Zhang 2018。画像とラベルを線形補間。決定境界を滑らかにし、汎化と頑健性を改善。CutMix は領域置換版。"}, {"q": "Gradient Clipping の目的は。", "choices": ["過学習防止", "勾配爆発防止（特に RNN/Transformer 学習）", "計算高速化", "メモリ削減"], "answer": 1, "explanation": "||g|| が閾値超過時にスケーリング。RNN の長系列・Transformer の大規模学習で標準（threshold=1.0 が典型）。"}, {"q": "Knowledge Distillation（蒸留）の目的は。", "choices": ["パラメータ増加", "大きな教師モデルの知識を小さな生徒モデルに転送", "ランダム学習", "クラスタリング"], "answer": 1, "explanation": "Hinton 2015。教師の softmax 出力（soft target）で生徒を学習。DistilBERT、TinyLLaMA、MobileBERT 等で軽量化に必須。"}, {"q": "Mixed Precision Training で主に使う型は。", "choices": ["FP32 のみ", "FP16 や BF16 と FP32 重みコピーの組合せ", "INT8 のみ", "INT4 のみ"], "answer": 1, "explanation": "計算は FP16/BF16、重みは FP32 で保持、損失スケーリングで underflow 防止。GPU メモリ半減、計算2-3倍速。BF16 はダイナミックレンジが広く実用的。"}, {"q": "Gradient Checkpointing（Activation Checkpointing）の効果は。", "choices": ["計算高速化", "順伝播の活性化を一部のみ保存し、逆伝播で再計算。メモリO(L) → O(√L)に", "精度向上", "学習率自動調整"], "answer": 1, "explanation": "メモリと計算のトレードオフ。LLM 学習では巨大モデルを限られた GPU で訓練するために必須。"}, {"q": "『Warmup』（学習率ウォームアップ）が必要な代表的状況は。", "choices": ["全ての状況", "Transformer 学習、大バッチ学習", "線形回帰", "K-means"], "answer": 1, "explanation": "初期の勾配が大きく不安定なため、η を 0 から徐々に上げる（数千ステップ）。Transformer、ViT、LLM 学習で必須。Cosine Annealing と組合せが標準。"}, {"q": "深層 CNN で勾配消失を抑制する主要技術として誤りはどれか。", "choices": ["ReLU", "残差接続", "Batch Normalization", "Sigmoid 活性化"], "answer": 3, "explanation": "Sigmoid は勾配消失の主要原因の一つ。ReLU、残差接続、BN、適切な初期化が勾配消失緩和の四天王。"}, {"q": "Stochastic Depth の動作は。", "choices": ["パラメータをランダムドロップ", "残差ブロックを確率的にスキップ（恒等写像に）", "学習率変化", "ノイズ加算"], "answer": 1, "explanation": "Huang 2016。残差NNの深さをランダム化することで正則化。100+ 層 ResNet で標準的に使われる。"}, {"q": "推論時に Dropout を有効にして複数回サンプリングする手法は何の推定に使うか。", "choices": ["高速化", "不確実性推定（Monte Carlo Dropout, Gal 2016）", "学習継続", "正則化"], "answer": 1, "explanation": "Yarin Gal が示した。推論時 Dropout で N 回サンプリング、出力の分散が予測不確実性の近似となる。ベイズ NN の安価な近似。"}, {"q": "『Cosine Annealing』学習率スケジューラの形状は。", "choices": ["直線的減少", "余弦関数で滑らかに減衰（T_max でゼロ近くに）", "階段状", "一定"], "answer": 1, "explanation": "lr = lr_max · (1+cos(π·t/T))/2 で滑らかに減衰。Warmup と組み合わせが現代学習の標準。SGDR で再起動版もある。"}, {"q": "AdamW が Adam と異なる主要な点は。", "choices": ["Momentumなし", "重み減衰を更新式の最後で適用（Adam の正則化と分離）、L2 正則化と等価に動作", "学習率を増やす", "Bias 補正削除"], "answer": 1, "explanation": "元の Adam で L2 を勾配に足すと2次モーメントとの相互作用で減衰効果が薄れる。AdamW は θ ← θ - η(m̂/√v̂ + ε) - η λ θ と最後で減衰、L2 と一致。LLM学習の事実上の標準。"}]}, {"id": "advanced", "label": "G検定 応用編", "count": 240, "desc": "CNN・Transformer・LLM・Agent・倫理・法", "problems": [{"q": "CNN が MLP より画像処理に適している理由は。", "choices": ["計算が遅い", "空間的局所性と平行移動不変性の帰納バイアス、パラメータ共有でパラメータ削減", "学習が不安定", "メモリを大量に必要とする"], "answer": 1, "explanation": "CNN は同じフィルタを全位置で適用（パラメータ共有）し、近い画素関係を仮定。MLPの全結合に比べパラメータが2〜3桁少なく、性能も高い。"}, {"q": "2012年の AlexNet が ImageNet コンペで起こした革命の核心は。", "choices": ["浅い NN を使った", "深層CNN + ReLU + Dropout + GPU + データ拡張で従来手法を圧倒", "教師なし学習", "強化学習"], "answer": 1, "explanation": "Krizhevsky 2012。誤り率 15.3% vs 2位 26.2%。深層学習革命の起点となった。"}, {"q": "入力 32x32、3x3 Conv、stride=1、padding=1 のとき出力サイズは。", "choices": ["30x30", "32x32（same パディング）", "16x16", "34x34"], "answer": 1, "explanation": "(32 + 2·1 - 3) / 1 + 1 = 32。padding='same' で入力と同じサイズを維持。VGG以降で標準。"}, {"q": "Max Pooling の役割として正しいのは。", "choices": ["学習可能パラメータ追加", "領域内最大値を取り、空間ダウンサンプリング・平行移動不変性強化", "正則化のみ", "出力層"], "answer": 1, "explanation": "パラメータなし、空間次元削減、強い活性化を保持。Average Pooling より一般的。"}, {"q": "ResNet（2015）が解決した深層化の壁は。", "choices": ["計算量", "勾配消失と退化問題：残差接続 y=F(x)+x で 152層を学習可能に", "メモリのみ", "ラベル不足"], "answer": 1, "explanation": "He 2015。スキップ接続で勾配が直接伝播。ImageNet 誤り率 3.57%、人間（5.1%）超え。現代CNN/Transformerの標準構造。"}, {"q": "VGG の特徴的な設計は。", "choices": ["1x1 Conv のみ", "3x3 Conv のみを多層積み重ね（16〜19層）", "ランダム", "全結合のみ"], "answer": 1, "explanation": "Simonyan 2014。シンプルで強力。3x3 を 2層で 5x5 相当の受容野をパラメータ少なく実現する発見。"}, {"q": "『受容野（Receptive Field）』とは。", "choices": ["出力ピクセルが影響を受ける入力上の領域", "パラメータ数", "バッチサイズ", "学習率"], "answer": 0, "explanation": "深い層ほど受容野が広い。3x3 conv を 2層重ねると 5x5 受容野。Dilated Conv で更に拡大可能。"}, {"q": "EfficientNet (2019) の貢献は。", "choices": ["ランダム探索", "深さ・幅・解像度を複合スケーリングで最適化、同精度で大幅パラメータ削減", "教師なし", "ViT 提案"], "answer": 1, "explanation": "Tan & Le 2019。compound scaling で計算予算に対する精度効率を最大化。モバイル向けにも適用。"}, {"q": "Vision Transformer (ViT) の入力処理は。", "choices": ["画素単位", "画像を 16x16 などのパッチに分けてトークン化し Transformer に入力", "Conv のみ", "MLP のみ"], "answer": 1, "explanation": "Dosovitskiy 2020。CNN の帰納バイアスなしで、大量データ（JFT-300M）で CNN を超えた。CLIP、Stable Diffusion で標準。"}, {"q": "YOLO シリーズの特徴は。", "choices": ["2-stage", "1-stage：画像をグリッド分割し各セルで物体予測、リアルタイム", "教師なし", "セグメンテーション特化"], "answer": 1, "explanation": "Redmon 2016 で導入、YOLOv8/v10 まで進化。FPS が高く、産業応用で広く使われる。"}, {"q": "U-Net (2015) が広く使われる分野は。", "choices": ["物体検出", "医療画像セグメンテーション、エンコーダ-デコーダ＋スキップ接続", "言語モデル", "強化学習"], "answer": 1, "explanation": "Ronneberger 2015。U字型構造で詳細を保持。Diffusion モデル（DDPM、Stable Diffusion）の denoiser にも採用。"}, {"q": "転移学習（ImageNet → 別タスク）が機能する理由は。", "choices": ["偶然", "浅層が汎用的特徴（エッジ、テクスチャ）を学習、それは多くのタスクで再利用可能", "ランダム", "パラメータ多いから"], "answer": 1, "explanation": "階層的特徴学習。少量データのタスクで事前学習モデルをファインチューニングすると、ゼロから学習より大幅に高精度。"}, {"q": "Global Average Pooling (GAP) の役割は。", "choices": ["学習する", "各チャネルの空間平均でベクトル化、最終FC層代替、パラメータ削減", "ノイズ追加", "正則化のみ"], "answer": 1, "explanation": "NIN/ResNet以降で標準。Flatten + 巨大 FC をGAPで置換、過学習防止＋パラメータ削減。Class Activation Map の基礎にも。"}, {"q": "Grad-CAM の目的は。", "choices": ["学習加速", "予測根拠の可視化（どの画像領域がクラス予測に貢献したか）", "圧縮", "ノイズ除去"], "answer": 1, "explanation": "Selvaraju 2017。最終 Conv 層の勾配を使ってヒートマップを生成。XAI（説明可能AI）の標準ツール、医療画像で重要。"}, {"q": "1x1 Convolution（pointwise）の役割は。", "choices": ["役立たず", "チャネル間の線形結合、次元削減・拡張、Inception/ResNet で頻用", "プーリング代替", "正則化"], "answer": 1, "explanation": "空間方向は1x1で変えず、チャネル方向のみ変換。Bottleneck構造で計算量削減。MobileNet（Depthwise Separable Conv）でも核心。"}, {"q": "Segment Anything Model (SAM, 2023) の特徴は。", "choices": ["単一タスク", "プロンプト型セグメンテーション、未知物体も可、Foundation Modelとして広く転用可", "教師なしのみ", "軽量モデル"], "answer": 1, "explanation": "Meta AI 2023。点・ボックス・テキストプロンプトで任意の物体をセグメント。10億+のマスクで事前学習。"}, {"q": "DenseNet (2017) の特徴は。", "choices": ["全層をスキップ接続でなく完全に連結（dense connection）、特徴再利用と勾配伝播改善", "パラメータ激増", "浅い NN", "物体検出専用"], "answer": 0, "explanation": "Huang 2017。各層が前のすべての層の出力を入力に。パラメータ効率と精度が高い。"}, {"q": "物体検出の評価指標として標準的なのは。", "choices": ["Accuracy", "mAP（mean Average Precision）@IoU 0.5、0.5:0.95", "MSE", "R²"], "answer": 1, "explanation": "COCO標準。クラスごとの AP の平均、IoU 閾値で性能評価。YOLO, Faster R-CNN等の比較で使用。"}, {"q": "ConvNeXt (2022) の主張は。", "choices": ["ViTが万能", "CNNにViTの工夫（GELU、LN、大きなカーネル等）を取り入れれば、CNNがViTと同等以上の精度に", "Conv 不要", "教師なし"], "answer": 1, "explanation": "Liu 2022。ViT の優位性はアーキテクチャ自体ではなく、学習レシピと工夫にあると示唆。"}, {"q": "Dilated（Atrous）Convolution の効果は。", "choices": ["パラメータ増加", "カーネル内のサンプル間隔を空けて受容野を拡大、パラメータ・計算量は同じ", "ノイズ追加", "教師なし"], "answer": 1, "explanation": "DeepLab系で活用。セグメンテーションで詳細を保ちつつ広い文脈を捉える。"}, {"q": "RNNが MLP より系列データに適する理由は。", "choices": ["計算高速", "隠れ状態 h で過去の文脈を保持、可変長系列を扱える", "パラメータ多い", "教師なし"], "answer": 1, "explanation": "h_t = f(h_{t-1}, x_t) で過去情報を伝播、同じパラメータを全時刻で共有。"}, {"q": "BPTT（Backprop Through Time）の問題は。", "choices": ["不要", "長系列で計算・メモリ増、勾配消失/爆発", "教師なし限定", "学習しない"], "answer": 1, "explanation": "系列長Tに比例して計算が増え、勾配が指数的に減衰または爆発。Truncated BPTT、Gradient Clipping、LSTM/GRU で対処。"}, {"q": "勾配消失問題で『記憶できる時間』の典型は。", "choices": ["1ステップ", "Vanilla RNNでは 10〜20ステップが限界", "無限", "100万ステップ"], "answer": 1, "explanation": "tanh の勾配積が指数減衰。LSTM/GRU でこれを数百ステップまで拡大。"}, {"q": "LSTM のセル状態 c_t の特徴は。", "choices": ["隠れ状態と同じ", "加算更新で勾配が保存され、長期依存を学べる", "出力のみ", "ノイズ"], "answer": 1, "explanation": "c_t = f_t ⊙ c_{t-1} + i_t ⊙ c̃_t の加算ベース更新が勾配消失を緩和。これが LSTM の核心。"}, {"q": "LSTMの3つのゲートとして正しいのは。", "choices": ["入力、Conv、Pool", "忘却（forget）、入力（input）、出力（output）", "順、逆、双方向", "学習、推論、評価"], "answer": 1, "explanation": "Hochreiter & Schmidhuber 1997。Sigmoidゲートで情報の流れを制御。"}, {"q": "GRU がLSTMより優れる点は。", "choices": ["必ず高精度", "パラメータが少なく、計算高速、性能はほぼ同等", "ゲートなし", "双方向のみ"], "answer": 1, "explanation": "Cho 2014。リセットゲートと更新ゲートだけで2ゲート構造。実装簡素、性能はLSTMと拮抗。"}, {"q": "双方向RNN（Bi-LSTM）が使えない典型タスクは。", "choices": ["文分類", "NER", "言語モデル（次トークン予測、未来情報禁止）", "感情分析"], "answer": 2, "explanation": "生成・予測タスクは未来情報を使えない（カンニングになる）。分類・タグ付けには Bi-LSTM が長く標準。"}, {"q": "Seq2Seq モデルの構造は。", "choices": ["1個のRNN", "エンコーダ（入力→ベクトル）+ デコーダ（ベクトル→出力）", "CNN のみ", "MLP のみ"], "answer": 1, "explanation": "Sutskever 2014。機械翻訳、要約、対話の基本枠組み。固定長ベクトルがボトルネック、Attentionで解消。"}, {"q": "Attention（Bahdanau 2015）が解決した Seq2Seq の課題は。", "choices": ["学習速度", "固定長ベクトルのボトルネック、長文で性能劣化", "メモリ消費", "過学習"], "answer": 1, "explanation": "エンコーダ全時刻の隠れ状態にデコーダが重み付き参照。長文翻訳の品質が劇的改善。Transformer の母。"}, {"q": "Beam Search の役割は。", "choices": ["学習加速", "系列生成で上位 k 候補を保持して探索、Greedy より高品質", "正則化", "クラスタリング"], "answer": 1, "explanation": "翻訳・要約で標準。beam size 4〜8 で BLEU 2〜3 ポイント改善。LLM 生成では nucleus sampling 等の方が人気。"}, {"q": "Truncated BPTT の目的は。", "choices": ["精度向上", "長系列で計算・メモリを節約、一定ステップで切って勾配計算", "学習なし", "過学習防止"], "answer": 1, "explanation": "全系列のBPTTは不可能なので、典型 35〜200 ステップで切る。長期依存は LSTM/GRU の力で。"}, {"q": "勾配爆発の対処として有効なのは。", "choices": ["学習率を上げる", "Gradient Clipping（勾配ノルムを閾値で制限）", "パラメータ削除", "Sigmoid を使う"], "answer": 1, "explanation": "torch.nn.utils.clip_grad_norm_ で実装。閾値1.0〜5.0が典型。Transformer 学習でも常用。"}, {"q": "音声認識で 2020〜2026 の標準は。", "choices": ["古典GMM-HMM", "Whisper、Conformer など Transformer 系", "Bi-LSTM のみ", "K-means"], "answer": 1, "explanation": "Whisper（OpenAI 2022）が多言語SOTA。Conformer（Google）はTransformer+Convの組合せでオンライン認識に強い。"}, {"q": "時系列予測で Transformer 系の代表例は。", "choices": ["ResNet", "Informer、PatchTST、Temporal Fusion Transformer", "K-NN", "ARIMA"], "answer": 1, "explanation": "長系列・多変量を効率良く扱える。最近の研究では『単純MLPでもTransformerと同等』との指摘も（DLinear等）。"}, {"q": "2023 年以降、『RNN の系譜』を継ぐ新世代モデルは。", "choices": ["CNN", "Mamba（SSM）、RWKV、Linear Attention", "MLP のみ", "K-NN"], "answer": 1, "explanation": "Selective SSM (Mamba 2023) が Transformer に対抗、線形メモリ・長文脈で優位。RWKV は RNN ライクな並列学習。"}, {"q": "『Teacher Forcing』の意味は。", "choices": ["強制学習", "Seq2Seq学習時に、デコーダへの入力に過去のモデル出力ではなく『正解』を与える手法", "教師なし", "クラスタ"], "answer": 1, "explanation": "訓練効率を上げるが、推論時の自己回帰生成と乖離する『Exposure Bias』問題も。Scheduled Sampling が緩和策。"}, {"q": "BiLSTM-CRF が長く標準だったタスクは。", "choices": ["画像分類", "NER（固有表現抽出）、品詞タグ付けなどの系列ラベリング", "強化学習", "K-means"], "answer": 1, "explanation": "BiLSTM が文脈、CRF がラベル間依存関係を学習。BERT 登場（2018）まで最強。今もリソース制約環境で実用。"}, {"q": "機械翻訳の評価指標として標準的なのは。", "choices": ["Accuracy", "BLEU、METEOR、chrF、最近は COMET、BERTScore", "MSE", "R²"], "answer": 1, "explanation": "BLEU が古典標準、ただし表面文字列マッチで限界あり。LLM 時代は BERTScore、COMET 等の埋め込みベース指標が好まれる。"}, {"q": "2014〜2017 の機械翻訳の主流は。", "choices": ["ルールベース", "RNN+Attentionのニューラル機械翻訳（NMT）、Google翻訳が全面採用（2016）", "Transformer", "LLM"], "answer": 1, "explanation": "2017 年に Transformer 登場し急速に置換。現在は LLM が機械翻訳でも事実上の SOTA。"}, {"q": "CTC（Connectionist Temporal Classification）の用途は。", "choices": ["画像分類", "音声認識・手書き認識など、入力と出力の長さが異なる・整列がないタスクの損失関数", "強化学習", "クラスタ"], "answer": 1, "explanation": "Graves 2006。アラインメントを暗黙にマージしながら学習。RNN+CTC（DeepSpeech）が音声認識の標準だった。"}, {"q": "『Attention is All You Need』論文（2017）の革命性は。", "choices": ["CNN を提案", "RNN/Convolutionなしで Self-Attention のみで Seq2Seq を実現、並列化可能", "K-means 改良", "強化学習"], "answer": 1, "explanation": "Vaswani 2017、Google Brain。WMT 英→独 で SOTA、しかも RNN より高速。現代AIの基盤。"}, {"q": "Self-Attention の計算式は。", "choices": ["QV+K", "softmax(QKᵀ/√dₖ) V", "Q·K", "Σ Q·V"], "answer": 1, "explanation": "Scaled Dot-Product Attention。√dₖで割るのは数値安定性のため。"}, {"q": "Multi-Head Attention の利点は。", "choices": ["計算量削減", "異なる『観点』で並列に注目、表現力増加", "パラメータ削減", "教師なし"], "answer": 1, "explanation": "典型 8〜16 ヘッド。各ヘッドが構文、共参照、意味類似など異なる側面を学習。"}, {"q": "Transformer が Position Encoding を必要とする理由は。", "choices": ["高速化", "Self-Attentionは置換不変、位置情報を別途与える必要", "正則化", "教師信号"], "answer": 1, "explanation": "sin/cos の固定位置埋め込み（オリジナル）、学習可能埋め込み（BERT）、RoPE（LLaMA、相対位置）など。"}, {"q": "RoPE（Rotary Position Embedding）が現代LLMで採用される理由は。", "choices": ["学習不要", "相対位置を回転で表現、外挿性能と長文脈で優位", "計算最遅", "メモリ大"], "answer": 1, "explanation": "Su 2021。LLaMA, GPT-NeoX, PaLM 等で採用。長文脈学習・補間で優れる。"}, {"q": "Self-Attention の計算量は。", "choices": ["O(N)", "O(N · d)", "O(N² · d)", "O(N³)"], "answer": 2, "explanation": "N = 系列長、d = 次元。長文で爆発するため Flash Attention、Sparse Attention、Mamba 等で対処。"}, {"q": "FlashAttention の貢献は。", "choices": ["精度向上", "メモリO(N²) → O(N) の実装、GPU メモリ階層を活用", "教師なし", "ランダム"], "answer": 1, "explanation": "Dao 2022。SRAM/HBM のデータ移動を最小化。計算結果は数値的に同一、高速・低メモリ。長文脈 LLM 必須。"}, {"q": "Decoder の Causal Mask の役割は。", "choices": ["高速化", "生成時に未来のトークンを見せない（カンニング防止）", "正則化", "教師なし"], "answer": 1, "explanation": "Attention 行列の上三角を -∞ で埋める。GPT 系の自己回帰生成で必須。"}, {"q": "Encoder-only Transformer の代表例は。", "choices": ["GPT", "BERT、RoBERTa、DeBERTa", "T5", "ResNet"], "answer": 1, "explanation": "理解タスク（分類、NER、QA）に強い。MLM で事前学習。"}, {"q": "Decoder-only Transformer の代表例は。", "choices": ["BERT", "GPT、LLaMA、Claude、Mistral", "T5", "ViT"], "answer": 1, "explanation": "Next Token Prediction で事前学習。生成タスクの王者。現代 LLM のデファクト。"}, {"q": "Encoder-Decoder Transformer の代表例は。", "choices": ["GPT", "T5、BART、mT5、オリジナル Transformer", "BERT", "K-means"], "answer": 1, "explanation": "テキスト→テキスト変換に強い。要約、翻訳、QAを統一フレームで扱える（T5）。"}, {"q": "Layer Normalization が Transformer で標準採用される理由は。", "choices": ["高速", "バッチサイズ非依存、系列長変化OK、学習安定化", "パラメータ削減", "教師なし"], "answer": 1, "explanation": "Batch Norm はバッチ依存、可変長系列・小バッチで不安定。LayerNorm が Transformer の標準。最近は RMSNorm も（LLaMA）。"}, {"q": "Vision Transformer (ViT, 2020) の入力処理は。", "choices": ["画素単位", "画像を 16x16 などのパッチに分けてトークン化", "Conv のみ", "MLP のみ"], "answer": 1, "explanation": "Dosovitskiy 2020。CNN の帰納バイアスなしで、大量データなら CNN 超え。CLIP、Stable Diffusion 等で採用。"}, {"q": "Cross-Attention の用途は。", "choices": ["Encoder内", "Decoderが Encoder出力を参照、機械翻訳・要約で使用", "教師なし", "計算不要"], "answer": 1, "explanation": "Q を Decoder から、K/V を Encoder から。Encoder-Decoder アーキの架け橋。"}, {"q": "Pre-Norm と Post-Norm の違いは。", "choices": ["同じ", "Pre: y=x+Sub(LN(x)), Post: y=LN(x+Sub(x))、Pre が学習安定で現代LLM標準", "パラメータ違う", "学習なし"], "answer": 1, "explanation": "オリジナル Transformer は Post-Norm だが Warmup が必要。Pre-Norm（GPT-2 以降）は学習がより安定。"}, {"q": "KV Cache の役割は。", "choices": ["訓練加速", "自己回帰生成で過去トークンの K, V を保存して再計算回避、推論を大幅高速化", "正則化", "ノイズ"], "answer": 1, "explanation": "各トークン生成時、過去全トークンの K, V は変わらないため再利用。LLM 推論の効率化に必須。メモリは N に線形に増加。"}, {"q": "SwiGLU 活性化が LLaMA 等の現代 LLM で採用される理由は。", "choices": ["古典的", "Gated Linear Unit + Swish、ReLU/GELU より高性能", "計算最速", "教師なし"], "answer": 1, "explanation": "Shazeer 2020。SwiGLU(x) = (xW)⊙Swish(xV) で2つの線形変換のゲート積。LLaMA, PaLM 等で標準。"}, {"q": "『Sparse Attention』の戦略は。", "choices": ["全位置に注目", "一部位置だけに注目し計算量を O(N√N) や O(N log N) に削減", "教師なし", "Conv 化"], "answer": 1, "explanation": "Sparse Transformer、Longformer、BigBird、Reformer 等。長文脈モデルで重要、ただし Flash Attention + 通常 Attention で多くの場合十分。"}, {"q": "Mixture of Experts (MoE) の Transformer での利用は。", "choices": ["不要", "FFN を複数の Expert に分け、Router が選択。総パラメータ大、アクティブパラメータ小", "Attention のみ", "教師なし"], "answer": 1, "explanation": "GShard、Switch Transformer、Mixtral 8x7B、GPT-4 等で採用。スケーリングと計算効率の両立。"}, {"q": "Transformer が CNN/RNN に勝った根本的理由は。", "choices": ["帰納バイアスが弱く、大量データで純粋に学習できる（スケーリング有利）+ 並列計算可能", "計算量が少ない", "パラメータ少ない", "教師なし"], "answer": 0, "explanation": "CNN は局所性、RNN は逐次性の帰納バイアス。Transformer はそれらが弱い分、データから自由に学習可能でスケーリング則に最適。並列学習で計算リソース活用も容易。"}, {"q": "BERT の事前学習タスクで主要なものは。", "choices": ["次トークン予測", "Masked Language Model（MLM）と Next Sentence Prediction", "クラスタリング", "強化学習"], "answer": 1, "explanation": "入力の15%を [MASK] に置換し復元するMLMが核。NSPは後の改良（RoBERTa）で削除。"}, {"q": "GPT の事前学習タスクは。", "choices": ["MLM", "Next Token Prediction（因果的言語モデル）", "分類", "強化学習"], "answer": 1, "explanation": "左から右に次のトークンを予測する自己回帰モデル。生成タスクに自然に適合。"}, {"q": "BERT と GPT のアーキテクチャの違いは。", "choices": ["BERTはエンコーダ（双方向Attention）、GPTはデコーダ（因果Attention）", "全く同じ", "BERTはRNN", "GPTはCNN"], "answer": 0, "explanation": "どちらもTransformerベースだが、Attentionの方向と用途が異なる。理解はBERT、生成はGPTが得意。"}, {"q": "『事前学習＋微調整』パラダイムの利点は。", "choices": ["タスクごとに学習し直す必要なし、汎用言語知識を活用、少量データで高精度", "計算量が増える", "精度が下がる", "言語別必要"], "answer": 0, "explanation": "大規模事前学習1回 → 多タスクに転移。NLPを変革したパラダイム。"}, {"q": "BERT で使われる Tokenization は。", "choices": ["単語分割のみ", "WordPiece（サブワード分割）", "文字単位", "ランダム"], "answer": 1, "explanation": "WordPiece は未知語に強く、語彙サイズを抑える。'unhappiness' → 'un', '##happiness' のような分割。"}, {"q": "『RoPE（Rotary Position Embedding）』を採用しているLLMは。", "choices": ["BERT", "GPT-2", "LLaMA, GPT-NeoX 等の現代LLM", "T5"], "answer": 2, "explanation": "Su 2021。相対位置を回転で表現、長さ外挿に有利。LLaMA 系の標準。"}, {"q": "T5 が提唱した paradigm は。", "choices": ["RNN復活", "すべてのタスクを Text-to-Text として統一", "線形化", "ハードコーディング"], "answer": 1, "explanation": "分類も生成も翻訳もすべて『テキスト入力→テキスト出力』。プレフィックスでタスク指定。"}, {"q": "RoBERTa が BERT を改良した主要点は。", "choices": ["NSP削除、データ量と学習時間を大幅増、動的マスキング", "アーキテクチャ変更", "パラメータ削減", "Sigmoid化"], "answer": 0, "explanation": "Liu et al. 2019。アーキテクチャは同じだが学習レシピで GLUE 大幅改善。『正しく訓練』の重要性を示した。"}, {"q": "ELECTRA の事前学習タスクは。", "choices": ["MLM", "NTP", "Replaced Token Detection（置換されたトークンを識別）", "Clustering"], "answer": 2, "explanation": "生成器が置換したトークンを判別器が識別。MLMより学習効率良く、同パラメータで高性能。"}, {"q": "GPT-3 で注目された『In-Context Learning』とは。", "choices": ["パラメータ更新", "プロンプト内の数件の例から、新タスクを推論時に学習", "微調整", "クラスタリング"], "answer": 1, "explanation": "Few-shot Learning の革命。重みは変更せず、コンテキスト内の例だけでタスク適応。Brown 2020。"}, {"q": "『微調整』と『プロンプティング』の違いは。", "choices": ["同じ", "微調整=モデル重み更新、プロンプティング=入力テキストで指示（重み不変）", "どちらも教師なし", "必ず両方必要"], "answer": 1, "explanation": "微調整はGPU・データ必要、プロンプティングはAPI呼び出しのみ。実用ではプロンプトエンジニアリングが先、必要に応じて微調整。"}, {"q": "LoRA（Low-Rank Adaptation）の役割は。", "choices": ["学習率調整", "元モデルを凍結し、低ランク差分行列だけ学習し効率的微調整", "量子化", "クラスタ"], "answer": 1, "explanation": "Hu 2021。学習可能パラメータを1/10000に削減しつつ性能維持。LLM実用微調整の標準。QLoRAで4-bit量子化と組合せ。"}, {"q": "BERT の文埋め込み取得で[CLS]以外に良いとされる方法は。", "choices": ["ランダム", "全トークンのmean pooling", "1番目のトークンのみ", "不可能"], "answer": 1, "explanation": "[CLS] よりも全トークンの平均が下流タスクで強いことが多い。Sentence-BERT で標準化。"}, {"q": "GPT の生成サンプリングで『創造性と一貫性のバランス』を制御する典型パラメータは。", "choices": ["学習率", "Temperature、Top-p（Nucleus）、Top-k", "バッチサイズ", "Dropout"], "answer": 1, "explanation": "Temperature 低→決定的、高→多様。Top-p=0.9 で上位累積90%から選択、Hallucination抑制と多様性のバランス。"}, {"q": "GPT-3 の InstructGPT/ChatGPT で導入された手法は。", "choices": ["CNN", "RLHF（Reinforcement Learning from Human Feedback）で指示追従性を学習", "K-means", "Random Forest"], "answer": 1, "explanation": "人間のフィードバックで報酬モデルを学習し、PPO で方策を最適化。指示追従性と無害化の核心技術。"}, {"q": "BERT が最も得意なタスクは。", "choices": ["長文生成", "文章理解（分類、QA、NER）", "音楽生成", "画像認識"], "answer": 1, "explanation": "双方向 Attention で文脈理解が強い。SQuAD で人間超え、GLUEベンチマークを大幅刷新（2018）。"}, {"q": "『スケーリング則』（Kaplan 2020）の主張は。", "choices": ["パラメータ数だけが効く", "パラメータ・データ・計算の3軸でモデル性能が予測可能に改善", "ランダム", "関係なし"], "answer": 1, "explanation": "損失がパワーロー則で改善。これがGPT-3, GPT-4のスケール拡大を駆動。Chinchilla（DeepMind 2022）が最適配分を改良。"}, {"q": "SentencePiece が WordPiece より優れる点は。", "choices": ["必ず速い", "言語非依存、生のテキストから直接学習、空白を特殊文字として扱う", "英語専用", "なし"], "answer": 1, "explanation": "日本語・中国語のような空白区切りでない言語に強い。T5, mBART, ALBERTで採用。"}, {"q": "『MLM（Masked LM）』が双方向文脈学習を可能にする仕組みは。", "choices": ["ランダム", "マスクされたトークンを予測するため、両側の文脈を見る必要がある（因果制約なし）", "線形", "距離計算"], "answer": 1, "explanation": "『私は[MASK]を見た』の[MASK]を予測するには前後両方が必要。これがGPTの因果Attentionとの本質的違い。"}, {"q": "日本語特化の事前学習モデルとして代表的なものは。", "choices": ["全く存在しない", "東北大BERT、cl-tohoku/bert-base-japanese、rinna/japanese-gpt等", "GPT-1のみ", "ELMo"], "answer": 1, "explanation": "多言語BERTより日本語特化モデルが精度高いことが多い。最近はLLM（Swallow、Stockmark、ELYZA等）も日本語特化版が登場。"}, {"q": "『スケーリング則（Scaling Laws）』の主張は。", "choices": ["パラメータ数だけが効く", "パラメータ・データ・計算の3軸で損失がパワーロー則で改善", "関係なし", "ランダム"], "answer": 1, "explanation": "Kaplan et al. 2020。これがGPT-3, GPT-4 のスケール拡大を駆動。Chinchilla で最適配分が改良。"}, {"q": "『Chinchilla 最適化』（DeepMind 2022）が示した知見は。", "choices": ["必ずパラメータを増やせ", "計算予算が決まればパラメータとデータをほぼ同じスケールで増やすのが最適", "データ不要", "パラメータ削減"], "answer": 1, "explanation": "Hoffmann et al. それまでのLLMはパラメータ過大・データ不足。70Bモデル+1.4Tトークンが280Bを凌駕。LLaMA系がこの教訓を踏襲。"}, {"q": "『In-Context Learning（ICL）』とは。", "choices": ["微調整", "プロンプト内の例だけで推論時にタスク適応（パラメータ更新なし）", "クラスタリング", "強化学習"], "answer": 1, "explanation": "GPT-3 で発見された創発能力。Few-shot Learning の革命。"}, {"q": "『Chain-of-Thought』プロンプトが効果的なタスクは。", "choices": ["単純な事実検索", "多段推論（数学、論理パズル、複雑な計算）", "翻訳", "分類"], "answer": 1, "explanation": "『step by step』『let's think』で思考過程を出力させ、最終答えの質を向上。GSM8K等の数学で劇的改善。"}, {"q": "RLHF の3つのステップは。", "choices": ["SFT → 報酬モデル学習 → PPO で方策最適化", "学習なし", "強化学習のみ", "単純な教師あり"], "answer": 0, "explanation": "SFT で初期化、人間のランキングから報酬モデル、PPO（KL正則化付き）で最適化。InstructGPT/ChatGPT の核心。"}, {"q": "DPO（Direct Preference Optimization）の利点は。", "choices": ["RLHFと同じ", "報酬モデルもPPOも不要、CE風損失だけで好み学習が可能", "学習しない", "パラメータ削減"], "answer": 1, "explanation": "Rafailov 2023。RLHF より実装が大幅に簡単で性能同等以上、現代の標準。"}, {"q": "LLM の Hallucination（幻覚）対策として有効でないのは。", "choices": ["RAG（外部知識検索）", "Tool Use", "Citation", "学習率を上げる"], "answer": 3, "explanation": "学習率変更は事前学習段階の話。Hallucination は RAG, Tool Use, Self-Consistency, Citation, Calibration で対処。"}, {"q": "『MoE（Mixture of Experts）』の動作は。", "choices": ["すべてのパラメータ常時使用", "トークンごとに専門家サブネットを選択的アクティブ化（疎活性化）", "クラスタリング", "アンサンブル"], "answer": 1, "explanation": "総パラメータは巨大、計算は一部のみ。Mixtral、GPT-4（推定）、Gemini 1.5 で採用。スケール効率の鍵。"}, {"q": "LLM の評価ベンチマークで『多分野QA』に該当するのは。", "choices": ["HumanEval", "MMLU（57科目）", "GSM8K", "SWE-bench"], "answer": 1, "explanation": "MMLU は数学、歴史、医学等57分野の選択肢QA。HumanEval=コード、GSM8K=数学、SWE-bench=実コーディング。"}, {"q": "『Constitutional AI』（Anthropic）の特徴は。", "choices": ["学習なし", "原則のセットでモデル自身に出力を批判・修正させ、人間ラベルを最小化", "検索のみ", "パラメータ削減"], "answer": 1, "explanation": "Claude の核技術。AI Feedback（RLAIF）への発展。スケーラブルな安全性技術。"}, {"q": "Instruction Tuning（指示チューニング）の入力形式は。", "choices": ["(画像, ラベル)", "(指示, 入力, 出力) のペア", "クラスタ", "ラベルなし"], "answer": 1, "explanation": "FLAN、T0、Alpacaなど。多様なタスクの指示理解を学習。RLHFの前段。"}, {"q": "『創発的能力』とは何か。", "choices": ["全モデルが持つ", "パラメータ／計算が閾値を超えると突然現れる能力（多段推論、コーディング等）", "ランダム", "線形改善のみ"], "answer": 1, "explanation": "Wei et al. 2022。小モデルでは ≈0%、大モデルで急激に向上するタスクが存在。スケーリングの最も興味深い性質。"}, {"q": "長文文脈処理の効率化技術として該当するのは。", "choices": ["Dropout", "Flash Attention、KV Cache、Sparse Attention、PagedAttention", "Sigmoid", "K-means"], "answer": 1, "explanation": "Attention の O(n²) を抑えてメモリ・計算効率化。100万トークン超の文脈（Gemini 1.5, Claude 3.7）を可能にした。"}, {"q": "o1/o3 など『推論モデル』の特徴は。", "choices": ["高速応答のみ", "テスト時に長い思考過程を生成して推論精度を向上、数学・コーディングで SOTA", "学習しない", "ラベル不要"], "answer": 1, "explanation": "CoT を内部化、テスト時の計算量増で性能向上。新しいスケーリング軸（テスト時計算）の発見。"}, {"q": "LLM の温度（temperature）パラメータの意味は。", "choices": ["モデルサイズ", "Softmaxを T で割って分布の鋭さを調整。低い=決定的、高い=多様", "パラメータ数", "学習率"], "answer": 1, "explanation": "創造性と一貫性のバランス。T=0で貪欲、T=1で標準、T=2で創造的だがHallucination増。"}, {"q": "『Top-p Nucleus Sampling』の動作は。", "choices": ["全ての候補から", "累積確率が p になるまで上位トークンを選び、その中からサンプリング", "必ず1位", "ランダム"], "answer": 1, "explanation": "Top-k よりも適応的。低確率の長い裾を切り落としつつ多様性確保。p=0.9 が典型。"}, {"q": "LLM 微調整の効率技術『LoRA』が更新するパラメータは。", "choices": ["全パラメータ", "元の行列に低ランク差分（A·B、ランクr）を加え、その差分のみ学習", "凍結のみ", "ランダム"], "answer": 1, "explanation": "学習可能パラメータを 0.1〜1% に削減。QLoRA で 4-bit 量子化と組合せ、コンシューマGPUで70Bモデル微調整可能に。"}, {"q": "LLM の『指示追従性』を実現する手法は。", "choices": ["単なる事前学習", "Instruction Tuning + RLHF（または DPO）", "線形化", "クラスタ"], "answer": 1, "explanation": "事前学習だけでは『次のトークン予測機』にすぎない。指示理解と安全性は Instruction Tuning + RLHF で獲得。"}, {"q": "『Self-Consistency』の手法は。", "choices": ["1回サンプリング", "同じ問題を複数回CoTでサンプリングし、最頻の答えを選ぶ", "線形回帰", "クラスタリング"], "answer": 1, "explanation": "Wang 2022。数学推論で CoT+Self-Consistency が CoT 単独より大幅に強い。複数の思考経路の多数決。"}, {"q": "『Knowledge Cutoff』とは。", "choices": ["計算リソース上限", "LLM が事前学習した時点までしか知識を持たないという制約", "パラメータ数", "学習率"], "answer": 1, "explanation": "GPT-4o は2024年初頭まで、Claude 3.7 は2025年初頭までなど。新しい情報は RAG, Web 検索、Tool Use で補完。"}, {"q": "GAN の基本構造は。", "choices": ["エンコーダのみ", "Generator と Discriminator の敵対的学習", "デコーダのみ", "クラスタリング"], "answer": 1, "explanation": "Goodfellow 2014。Generator が偽画像、Discriminator が真偽判定、min-max ゲーム。"}, {"q": "GAN の典型的な問題で『多様性が失われる』現象を何と呼ぶか。", "choices": ["過学習", "モード崩壊（Mode Collapse）", "勾配消失", "不確実性"], "answer": 1, "explanation": "Generator が騙しやすい一部モードに局所最適。WGAN-GP、Spectral Normalization、Mini-batch Discrimination で対策。"}, {"q": "VAE の損失関数 ELBO は何と何の組合せか。", "choices": ["再構成損失 + KL ダイバージェンス（事前との距離）", "MSE のみ", "Hinge", "敵対的損失"], "answer": 0, "explanation": "ELBO = 再構成 - KL(q(z|x)||p(z))。再構成精度と潜在分布の事前 N(0,I) への近さのバランス。"}, {"q": "Diffusion Model の学習は何を予測するか。", "choices": ["ラベル", "画像に加えられたノイズ（または score = ∇log p(x)）", "クラスタ", "Bounding Box"], "answer": 1, "explanation": "各タイムステップで NN がノイズを予測し、それを差し引いて x_{t-1} を得る。これを T 回繰り返してノイズから画像復元。"}, {"q": "Stable Diffusion の核心技術は。", "choices": ["ピクセル空間のDiffusion", "Latent Diffusion（VAEで圧縮した潜在空間で Diffusion）", "GAN", "Flow"], "answer": 1, "explanation": "Rombach 2022。512×512 を 64×64 潜在に圧縮し、計算量1/64に。コンシューマGPUで動作可能に。"}, {"q": "ControlNet の役割は。", "choices": ["高速化", "Stable Diffusion に追加制約（姿勢、深度、エッジ）を与えて生成を制御", "パラメータ削減", "学習率自動"], "answer": 1, "explanation": "Zhang 2023。骨格→人物、線画→塗り絵、深度→立体感のある画像など。生成の制御性を劇的向上。"}, {"q": "『Classifier-Free Guidance（CFG）』の役割は。", "choices": ["分類器学習", "条件付き/無条件のスコア差を増幅、テキスト指示への忠実度を高める", "クラスタ", "学習率"], "answer": 1, "explanation": "Ho 2022。guidance_scale パラメータで強さを調整。7-10 が典型、高すぎると過剰でアーティファクト発生。"}, {"q": "DALL-E 2 の主な構成要素は。", "choices": ["CNN のみ", "CLIP（テキスト・画像埋め込み）＋ Diffusion （prior + decoder）", "RNN のみ", "K-means"], "answer": 1, "explanation": "CLIP埋め込みを介してテキストと画像を結ぶ、unCLIP アーキテクチャ。"}, {"q": "画像生成評価の代表的指標『FID』は何を測るか。", "choices": ["学習速度", "Inception 特徴量で実画像分布と生成画像分布の距離", "クラス数", "パラメータ数"], "answer": 1, "explanation": "Fréchet Inception Distance。画像品質と多様性を一値に集約。低いほど良い。"}, {"q": "『CLIP Score』が評価するのは。", "choices": ["画像品質のみ", "テキストプロンプトと生成画像の意味的整合性", "計算速度", "ファイルサイズ"], "answer": 1, "explanation": "CLIP モデルの埋め込み類似度。プロンプト忠実度の標準指標。"}, {"q": "Sora や Veo は何のためのモデルか。", "choices": ["音楽生成", "動画生成（テキスト→1分以上の高品質動画）", "顔認識", "文章生成"], "answer": 1, "explanation": "OpenAI Sora（2024）、Google Veo。Diffusion Transformer ベース、物理理解・長時間生成が特徴。"}, {"q": "Whisper（OpenAI）の用途は。", "choices": ["画像生成", "多言語音声認識（STT）", "TTS", "翻訳のみ"], "answer": 1, "explanation": "Speech-to-Text の多言語モデル。99言語対応、ノイズに頑健。オープンウェイト。"}, {"q": "VQ-VAE の特徴は。", "choices": ["連続潜在", "離散コードブックで潜在表現、画像・音声生成や Tokenizer で活用", "線形変換", "ノイズなし"], "answer": 1, "explanation": "連続潜在を離散コードに量子化。Audio LM、画像 Tokenizer などで使用。"}, {"q": "Normalizing Flow の利点は。", "choices": ["厳密な尤度計算が可能（可逆変換）", "高速生成", "パラメータ少", "学習不要"], "answer": 0, "explanation": "可逆な変換 f: z → x を学習し、変数変換公式で厳密尤度。GANやVAEと違い密度評価可能。画像品質は Diffusion に劣る。"}, {"q": "Diffusion Models の高速化『Distillation』が達成するのは。", "choices": ["学習速度のみ", "50ステップを 1-4 ステップに圧縮、リアルタイム生成可能に", "パラメータ削減", "不可能"], "answer": 1, "explanation": "教師モデルから生徒モデルへの蒸留。SDXL Turbo、LCM などでリアルタイム画像生成（30fps）が可能に。"}, {"q": "LoRA を Diffusion に適用する利点は。", "choices": ["全パラメータ学習", "10-100枚の画像で特定キャラ/スタイル学習、数MBで配布可能", "高速学習不可", "精度低下"], "answer": 1, "explanation": "Civitai 等で大量のLoRA公開、コミュニティが活発。Stable Diffusion カスタマイズの主流。"}, {"q": "StyleGAN の特徴は。", "choices": ["全結合のみ", "スタイル（属性）と画像内容を分離、高解像度顔生成、潜在空間編集", "線形", "RNN"], "answer": 1, "explanation": "NVIDIA、Karras 2019。ThisPersonDoesNotExist のあの顔。潜在空間の意味的編集（笑顔強度、年齢など）。"}, {"q": "音楽生成モデル MusicGen は何で学習されているか。", "choices": ["画像のみ", "大量の楽曲とテキスト説明のペア、自己回帰モデル", "ランダム", "MIDI のみ"], "answer": 1, "explanation": "Meta、2023。テキスト→音楽の Transformer ベース。Suno、Udio などのサービスも類似アプローチ。"}, {"q": "生成 AI の社会的課題として該当しないのは。", "choices": ["ディープフェイク", "著作権", "バイアス", "必ず物理法則を守る"], "answer": 3, "explanation": "生成モデルは物理法則を必ずしも守らない（手指の数間違い、不自然な液体運動など）。Sora は改善したが完璧でない。"}, {"q": "Diffusion Model が現在 GAN を凌駕している主な理由は。", "choices": ["学習が速い", "学習安定、高品質、多様性確保、テキスト条件付け容易、スケール可能", "パラメータ少", "メモリ少"], "answer": 1, "explanation": "GANの不安定学習・モード崩壊の問題なし、Diffusion Transformer でスケール可能（Sora）。現代生成AIの主流。"}, {"q": "MDP の5要素（S, A, P, R, γ）の γ は何か。", "choices": ["学習率", "割引率（将来報酬の現在価値）", "探索率", "ノイズ"], "answer": 1, "explanation": "γ ∈ [0,1)。0.99 が典型。1なら無限地平の累積発散、0なら短期報酬のみ重視。"}, {"q": "Q-Learning がオフポリシーである理由は。", "choices": ["学習しない", "行動方策と異なる方策（最適）を学習可能、更新で max を使う", "オンライン", "モデルベース"], "answer": 1, "explanation": "Q(s,a) ← Q + α[r + γ max Q(s', a') - Q]。max を使うので実際の次行動と独立。SARSAはオンポリシー。"}, {"q": "DQN（DeepMind 2015）の核心的貢献は。", "choices": ["教師あり", "Experience Replay + Target Network で深層NN+RL を安定化、Atari 49ゲーム人間超え", "教師なし", "クラスタリング"], "answer": 1, "explanation": "Mnih et al. 2015 Nature。これが Deep RL 革命の始まり。"}, {"q": "AlphaGo の構成要素として正しいのは。", "choices": ["教師あり学習のみ", "Policy Net + Value Net + MCTS + 自己対戦RL", "Q-tableのみ", "ランダム"], "answer": 1, "explanation": "人間棋譜での教師あり初期化＋自己対戦RL強化＋モンテカルロ木探索による推論時計画。2016年世界トップ棋士を破る。"}, {"q": "AlphaZero が AlphaGo と異なる点は。", "choices": ["教師データ不要、純粋自己対戦のみ", "より小さなNN", "MCTS不使用", "教師あり強化"], "answer": 0, "explanation": "ルールだけからゼロベース自己対戦、人間データ完全不要。囲碁・将棋・チェスすべて同一アーキテクチャでトップ性能。"}, {"q": "PPO（Proximal Policy Optimization）の特徴は。", "choices": ["クリップ損失で方策更新を安定化、実装簡単で汎用性高い", "オンポリシーのみ", "Q-tableのみ", "ランダム"], "answer": 0, "explanation": "OpenAI 2017。L^CLIP = E[min(rA, clip(r, 1-ε, 1+ε)A)]。RLHFの主力アルゴリズム、現代RL標準。"}, {"q": "RLHF（ChatGPT/Claudeで使用）の3ステップは。", "choices": ["SFT → 報酬モデル → PPO", "教師あり → 教師なし → 強化", "事前 → 中間 → 微調整", "Pretrain → Fine-tune → Distill"], "answer": 0, "explanation": "Supervised Fine-Tuning → Reward Model（人間ランクで学習）→ PPO で報酬最大化。InstructGPT (2022) で確立。"}, {"q": "DPO（Direct Preference Optimization、2023）の利点は。", "choices": ["計算重い", "報酬モデル不要で嗜好データから直接最適化、PPOより安定で簡単", "教師あり不要", "必ず劣る"], "answer": 1, "explanation": "Rafailov 2023。報酬モデル+PPOの2段階を1段階に。Llama-2-Chat、Mistral、Zephyr などで採用。最近のRLHF主流。"}, {"q": "価値関数 V(s) と Q(s,a) の違いは。", "choices": ["同じ", "V は状態の価値、Q は(状態,行動)の価値", "V は数値、Q は関数", "V は離散"], "answer": 1, "explanation": "V(s) = E[累積報酬|s]、Q(s,a) = E[累積報酬|s,a]。関係：Vπ(s) = Σ π(a|s) Qπ(s,a)。"}, {"q": "Bellman 最適方程式 V*(s) = max_a Σ P(s'|s,a)[R + γV*(s')] が示すのは。", "choices": ["最適価値の再帰関係", "ランダム", "教師ラベル", "必ず線形"], "answer": 0, "explanation": "最適価値は『最善の次行動の期待値』として再帰的に定義。Value Iteration、DQN学習の基礎。"}, {"q": "ε-greedy の役割は。", "choices": ["学習率", "探索と活用のバランス（εでランダム、1-εで最良Q行動）", "正則化", "クラスタ"], "answer": 1, "explanation": "探索（未知行動を試す）と活用（既知の良い行動を取る）のトレードオフ。実用では学習進行で ε を減衰。"}, {"q": "Actor-Critic アーキテクチャは何の組合せか。", "choices": ["教師あり+教師なし", "方策（Actor）+ 価値関数（Critic）", "クラスタ+回帰", "DQN+SARSA"], "answer": 1, "explanation": "Actor が行動、Critic が状態を評価。分散低減で安定学習。A2C/A3C/PPO/SAC の基礎。"}, {"q": "『マルコフ性』とは。", "choices": ["過去履歴を全て参照", "次状態は現在状態と行動のみに依存（過去履歴不要）", "必ず連続", "線形"], "answer": 1, "explanation": "P(s_{t+1}|s_t, a_t) = P(s_{t+1}|s_t, a_t, history)。POMDP（部分観測）では緩和される。"}, {"q": "スパース報酬問題への対処として正しいのは。", "choices": ["学習率を上げる", "Reward Shaping、Curiosity-driven exploration（RND, ICM）、HER", "教師あり化", "クラスタ"], "answer": 1, "explanation": "報酬がほとんど0のタスク（Montezuma's Revenge等）で重要。内発的動機付け（好奇心）、後付け目標（HER）で対処。"}, {"q": "モデルベース RL とモデルフリー RL の違いは。", "choices": ["同じ", "モデルベースは環境モデル(P, R)を学習・利用、モデルフリーはサンプルから直接学習", "教師あり vs 教師なし", "速度"], "answer": 1, "explanation": "モデルベース（MuZero、Dreamer）はサンプル効率が良いがモデル誤差影響。モデルフリー（DQN、PPO）はシンプル、サンプル多。"}, {"q": "『継続的なエピソードでは γ &lt; 1 が必要』な理由は。", "choices": ["計算簡単化", "無限和の収束保証、近未来優先", "ランダム性", "単純化のみ"], "answer": 1, "explanation": "γ=1 だと累積和が発散。γ&lt;1で幾何級数として収束。0.9〜0.999が典型。"}, {"q": "MuZero（DeepMind 2020）の特徴は。", "choices": ["教師あり", "環境モデル自体も学習、ルール未知のAtariでもMCTS可能", "Q-table", "ランダム"], "answer": 1, "explanation": "AlphaZero は環境ルール既知、MuZero はルールも学習。汎用性大幅向上。"}, {"q": "SAC（Soft Actor-Critic）が連続行動空間で強い理由は。", "choices": ["離散のみ", "最大エントロピー原理で探索促進、決定的方策より安定", "Q-tableのみ", "教師あり"], "answer": 1, "explanation": "Haarnoja 2018。報酬最大化＋エントロピー最大化で探索維持。ロボット制御などで人気。"}, {"q": "ChatGPT のような LLM チャットボットの応答品質を人間嗜好に合わせる手法は。", "choices": ["単なる教師あり", "RLHF（または DPO）", "クラスタリング", "線形回帰"], "answer": 1, "explanation": "RLHF（InstructGPT 2022）。人間嗜好を反映する強化学習で、有害性削減・有用性向上。最近は DPO で簡略化。"}, {"q": "強化学習の典型的応用として誤りはどれか。", "choices": ["ゲーム（AlphaGo, AlphaStar）", "ロボット制御", "LLM の人間嗜好調整", "静的な画像分類"], "answer": 3, "explanation": "画像分類は典型的に教師あり。RLは『連続的意思決定』『報酬最大化』が要。ゲーム、ロボット、自動運転、推薦、RLHFが代表。"}, {"q": "RAG が解決する LLM の主な弱点は。", "choices": ["計算速度", "知識カットオフ、幻覚、私的データ非対応", "パラメータ数", "メモリ"], "answer": 1, "explanation": "LLM の学習データ以降の知識・自社データ・幻覚（誤情報生成）を、関連文書検索で補完。"}, {"q": "RAG パイプラインの基本構成は。", "choices": ["クラスタ→分類", "Embed → Vector DB 検索 → 文脈付き LLM プロンプト → 回答", "Fine-tune のみ", "ランダム"], "answer": 1, "explanation": "Lewis 2020。質問を埋め込み、Vector DB から類似文書取得、LLM に文書+質問を渡して回答生成。"}, {"q": "Embedding モデルの代表として誤りはどれか。", "choices": ["text-embedding-3-large (OpenAI)", "BGE-large (BAAI)", "Cohere Embed v3", "XGBoost"], "answer": 3, "explanation": "XGBoost は勾配ブースティング、テキスト埋め込み用ではない。MTEB ベンチマークで競合中。"}, {"q": "Vector Database で標準的な高速検索アルゴリズムは。", "choices": ["ブルートフォース", "HNSW（Hierarchical Navigable Small World）、IVF-PQ", "K-means", "Decision Tree"], "answer": 1, "explanation": "ANN（Approximate Nearest Neighbor）の代表。HNSW は graph-based で精度・速度両立。FAISS, Pinecone, Qdrant, Weaviate で実装。"}, {"q": "Chunking で典型的なオーバーラップ率は。", "choices": ["0%", "10〜20%（境界問題緩和）", "50%以上", "100%"], "answer": 1, "explanation": "オーバーラップで文脈の境界での情報損失を緩和。chunk_size=500 なら overlap=50〜100 が典型。"}, {"q": "Reranking の目的は。", "choices": ["計算高速化", "Embedding 検索で得た上位文書を Cross-Encoder で再評価し精度向上", "学習", "正則化"], "answer": 1, "explanation": "2段階パイプライン：Embedding で top-50 → Rerank で top-5。Cohere Rerank, BGE Reranker が代表。"}, {"q": "Hybrid Search の典型構成は。", "choices": ["Dense のみ", "Embedding（Dense）+ BM25（Sparse）を RRF で統合", "ランダム", "Sparse のみ"], "answer": 1, "explanation": "Reciprocal Rank Fusion（RRF）で両者の順位を融合。固有名詞・型番に強い BM25 と意味類似の Dense を統合。"}, {"q": "RAG vs Fine-tuning の使い分けで正しいのは。", "choices": ["RAG = スタイル変更", "知識追加・更新は RAG、行動・スタイル変更は Fine-tune", "どちらも同じ", "Fine-tune が常に上"], "answer": 1, "explanation": "RAG = 知識（事実）、Fine-tune = 振舞い（口調、フォーマット）。実用では併用が多い。"}, {"q": "『Faithfulness』が評価する対象は。", "choices": ["速度", "生成回答が取得文書に忠実か（捏造でないか）", "パラメータ数", "コスト"], "answer": 1, "explanation": "RAGAS, TruLensなどで自動評価。LLM-as-Judge（GPT-4） が一般的。幻覚抑制の指標。"}, {"q": "GraphRAG（Microsoft 2024）の特徴は。", "choices": ["単純な BM25", "文書から知識グラフを構築、Global query（全体傾向）にも対応", "Fine-tune必須", "クラスタリング"], "answer": 1, "explanation": "エンティティ・関係抽出 → グラフ → コミュニティ要約。『この文書集合全体の傾向は』のような Global question に強い。"}, {"q": "HyDE（Hypothetical Document Embeddings）の手順は。", "choices": ["質問を直接埋め込み", "LLMに仮回答を生成させ、それを埋め込んで検索", "教師ありのみ", "クラスタ"], "answer": 1, "explanation": "Gao 2022。質問と回答は意味空間で異なる位置にあり得るため、仮回答を介して検索精度向上。"}, {"q": "Self-RAG が用いる仕組みは。", "choices": ["ランダム検索", "Reflection Token で『検索が必要か』『文書が関連か』『裏付けあるか』を LLM 自身が判断", "クラスタリング", "教師あり"], "answer": 1, "explanation": "Asai 2023。不要検索の削減と品質向上を両立。LLMが検索の必要性を判断。"}, {"q": "Cosine類似度の式は。", "choices": ["q + d", "(q·d)/(||q|| ||d||)", "|q - d|", "q × d"], "answer": 1, "explanation": "ベクトル間の角度を測る。長さ非依存で意味の類似度に適する。RAGの標準距離。"}, {"q": "RAG の典型的な失敗パターンは。", "choices": ["速度向上", "Chunk が大きすぎる/小さすぎる、Embedding がドメイン外、適切な Rerank不在", "パラメータ削減", "学習率"], "answer": 1, "explanation": "実用 RAG は『調整勝負』。Chunk size、Embedding 選択、Rerank、プロンプト構造、メタデータフィルタなどの組合せ最適化が肝。"}, {"q": "Multimodal RAG が扱う主なデータは。", "choices": ["テキストのみ", "画像、表、グラフを含む PDF・スライド（CLIP系または Vision LLM 利用）", "音声のみ", "コード"], "answer": 1, "explanation": "技術文書・財務報告書は画像・表が多い。GPT-4V, Claude 3, Gemini が直接処理可能、または CLIP 系で画像埋め込み。"}, {"q": "LangChain の役割は。", "choices": ["学習", "LLMアプリ構築の統合フレームワーク（RAG、Agent、チェーン）", "Vector DB のみ", "Embedding"], "answer": 1, "explanation": "文書ローダー、Splitter、Vector DB、LLM、Retriever、Agent を統合。LlamaIndex は RAG 特化の競合。"}, {"q": "Sentence-Transformers の代表モデルは。", "choices": ["BERT base のみ", "all-MiniLM-L6-v2（軽量384次元、CPU動作可）", "GPT-4", "ResNet"], "answer": 1, "explanation": "開発・プロトタイプの定番。BGE, E5, GTE などより新しいモデルもオープン提供。"}, {"q": "RAGAS フレームワークが提供する RAG 評価指標は。", "choices": ["Accuracy のみ", "Faithfulness, Answer Relevance, Context Precision, Context Recall", "MSE", "R²"], "answer": 1, "explanation": "LLM-as-Judge で自動評価。RAG 特有の側面（事実忠実性、文脈の必要性・十分性）を測定。"}, {"q": "Vector DB の選択基準として誤りはどれか。", "choices": ["規模・QPS要件", "フィルタリング機能", "ホスティング（SaaS vs Self-host）", "どれも同じ性能"], "answer": 3, "explanation": "Pinecone（マネージド）、Weaviate（OSS+クラウド）、Qdrant（OSS Rust高速）、Chroma（軽量）、Milvus（大規模）など特性は大きく違う。"}, {"q": "プロダクション RAG での重要な工夫として誤りはどれか。", "choices": ["クエリ書き換え（query rewriting）", "Rerank", "メタデータフィルタ", "必ず Chunk size を 100 にする"], "answer": 3, "explanation": "Chunk size はデータ・タスク依存で最適化対象。100 だと文脈不足の場合が多い。500前後が経験的に良いが、用途で異なる。"}, {"q": "AI Agent の定義として最も適切なのは。", "choices": ["単発の質問応答", "目標達成のため自律的に推論・計画・行動するシステム", "Vector DBのみ", "ファインチューニング"], "answer": 1, "explanation": "LLMを脳、ツールを手足、メモリを記憶とする自律システム。1ターン応答との根本的違い。"}, {"q": "ReAct パラダイムの構成は。", "choices": ["Search→Generate", "Thought→Action→Observation のループ", "Train→Test", "Encode→Decode"], "answer": 1, "explanation": "Yao 2022 ReAct論文。LLM が推論→ツール実行→結果観察を繰り返す。Agent の基本パターン。"}, {"q": "Function Calling の役割は。", "choices": ["学習", "LLMが構造化された JSON でツール呼出パラメータを生成", "正則化", "クラスタリング"], "answer": 1, "explanation": "OpenAI 2023標準化、GPT/Claude/Gemini/Llama すべて対応。ツール仕様（JSON Schema）に従いLLMがパラメータ抽出。"}, {"q": "Claude Computer Use（Anthropic 2024）の特徴は。", "choices": ["テキスト生成のみ", "スクリーンショットを見てマウス・キーボードを操作", "Vector検索のみ", "音声処理"], "answer": 1, "explanation": "2024年10月発表。Claude 3.5 Sonnet が画面を理解してPC操作。人間と同じ方法での自動化を可能に。"}, {"q": "Self-Reflection / Self-Critique の効果は。", "choices": ["計算高速化", "Agent が自分の出力を批評・修正することで品質向上", "パラメータ削減", "ランダム化"], "answer": 1, "explanation": "Reflexion (2023), Self-Refine (2023)。HumanEvalでpass@1が67%→91%に。o1 の思考時間長期化もこの思想。"}, {"q": "Multi-Agent フレームワークの代表は。", "choices": ["TensorFlow", "AutoGen (Microsoft)、CrewAI", "scikit-learn", "NumPy"], "answer": 1, "explanation": "AutoGen（カンファレンス形式）、CrewAI（役割明示）、ChatDev（ソフトウェア会社シミュレーション）など。協調で複雑タスクの品質向上。"}, {"q": "Agent の短期メモリの典型実装は。", "choices": ["Vector DB のみ", "直近Nターンを会話履歴としてプロンプトに保持", "ファイル", "なし"], "answer": 1, "explanation": "Conversation Buffer Memory。長くなると要約・圧縮、または Vector Memory に長期化。"}, {"q": "Plan-and-Execute Agent の特徴は。", "choices": ["1ステップで全実行", "最初に計画策定 → サブタスクを順次実行", "ランダム", "学習"], "answer": 1, "explanation": "Chain-of-Thought の発展形。複雑タスクで失敗を減らせる。BabyAGI、AutoGPT の基礎パターン。"}, {"q": "LangGraph が LangChain Agent と異なる点は。", "choices": ["同じ", "状態機械として明示的にモデル化、Cycle・分岐・人間介入を扱える", "Vector DB専用", "学習特化"], "answer": 1, "explanation": "暗黙的ループではなく明示的グラフで Agent を制御。Production-grade Agent の標準。"}, {"q": "Agent の典型的な失敗パターンは。", "choices": ["無限ループ、過剰なツール呼出、コスト爆発", "学習速度低下", "メモリリーク", "なし"], "answer": 0, "explanation": "max_iterations 設定、ループ検出、コスト上限、人間承認などのガードレールが本番必須。"}, {"q": "AutoGPT (2023) の意義は。", "choices": ["学習アルゴリズム", "自律 LLM Agent の先駆け、技術的限界はあったがAgent ブームの火付け役", "Vector DB", "単なる検索"], "answer": 1, "explanation": "2023年初、GPT-4 ベース。タスク自動分解実行のループ。実用性は限定的だったが、Agent概念を一般に広めた。"}, {"q": "『Tool Use』の代表的ツールカテゴリは。", "choices": ["学習", "検索、計算、API、ファイル操作、ブラウザ・PC制御", "単一機能のみ", "Vector のみ"], "answer": 1, "explanation": "多様なツールが LLM の能力を拡張。Web search、Code Interpreter、SaaS API、Computer Use など。"}, {"q": "Tree of Thoughts（ToT）の発展点は。", "choices": ["単線思考", "思考を木構造で分岐探索し最良経路選択", "Vector検索", "教師あり"], "answer": 1, "explanation": "Yao 2023。CoTを枝分かれにし、BFS/DFS的に探索。数独、24パズル等で高性能。"}, {"q": "Reflexion（2023）の動作は。", "choices": ["教師あり", "Agent が失敗から自己批評＆メモリ蓄積→次回反映", "Vector DB のみ", "クラスタ"], "answer": 1, "explanation": "Shinn 2023。失敗の言語的反省を Memory に蓄積、次の試行で参照。コード生成でpass@1 を大幅向上。"}, {"q": "OpenAI o1 / o3 が従来 LLM と異なる点は。", "choices": ["パラメータが100倍", "推論時に長い『思考』を行い、Self-Reflection内蔵", "Vector検索専用", "多言語のみ"], "answer": 1, "explanation": "Test-time compute scaling。数十秒〜数分の思考連鎖で複雑タスク（数学、コード）で人間レベル超え。"}, {"q": "Agent のメモリで Vector Memory が解決する問題は。", "choices": ["計算速度", "長期記憶（過去会話・経験から関連情報を検索可能に）", "学習", "パラメータ"], "answer": 1, "explanation": "会話履歴をベクトル化し、関連時に取得。個人化、長期セッション、経験学習に必須。"}, {"q": "Program-Aided Language Models (PAL) の特徴は。", "choices": ["計算", "LLM が Python コードを生成→実行→結果を使う（数値計算誤りを防ぐ）", "Vector検索", "教師あり"], "answer": 1, "explanation": "Gao 2022。LLM の苦手な厳密計算を Python に委任。数学・データ処理タスクで高精度。"}, {"q": "2024年に登場した Devin AI の特徴は。", "choices": ["単純チャット", "自律的にコーディングタスクを完遂、ブラウザ・エディタ操作可能", "Vector検索のみ", "画像生成"], "answer": 1, "explanation": "Cognition Labs。コード生成、デバッグ、デプロイまで一貫実行のAI Software Engineer。SWE-Bench で当時 SOTA。"}, {"q": "Agent の安全性で重要なのは。", "choices": ["全自動が常に良い", "Human-in-the-Loop、ツール権限制限、コスト上限、監査ログ", "なし", "速度"], "answer": 1, "explanation": "自律実行のリスク：誤ったAPI呼出、機密漏洩、コスト爆発。人間承認、サンドボックス、レート制限が必須。"}, {"q": "Agent と LLM 単独 RAG の本質的違いは。", "choices": ["同じ", "Agentは多段階推論＋ツール選択＋ループ、RAGは1ターン取得+生成", "Vector不使用", "学習"], "answer": 1, "explanation": "RAG は静的なパイプライン（検索→生成）、Agent は動的な意思決定（どのツールを何回呼ぶか LLM が判断）。Agent内でRAGをツールとして使える。"}, {"q": "MLOps の主な対象は。", "choices": ["モデル学習のみ", "MLシステムのライフサイクル全体（データ・学習・デプロイ・運用・再学習）の自動化", "データ収集のみ", "評価のみ"], "answer": 1, "explanation": "Google『Hidden Technical Debt in ML Systems』が原点。コードはML全体の5〜10%、残りは MLOps インフラ。"}, {"q": "Feature Store の主な目的は。", "choices": ["モデル管理", "学習時とサービング時で一貫した特徴量提供、Training-Serving Skew 防止", "パラメータ追跡", "ログ収集"], "answer": 1, "explanation": "Feast、Tecton、SageMaker Feature Store、Vertex AI Feature Store。特徴量の再利用と一貫性が核心。"}, {"q": "MLflow の主機能でないのは。", "choices": ["実験追跡（パラメータ、メトリクス）", "モデルレジストリ", "プロジェクトパッケージング", "データベース管理"], "answer": 3, "explanation": "MLflow は Tracking、Models、Projects、Registry の4機能。データベース自体は管理対象外。"}, {"q": "CI/CD for ML で『CT』が表すのは。", "choices": ["Continuous Testing", "Continuous Training（Drift時等の自動再学習）", "Continuous Tracking", "Continuous Tagging"], "answer": 1, "explanation": "MLOps の独自概念。CI（コードテスト）+ CD（デプロイ）+ CT（再学習）の3要素。"}, {"q": "Data Drift と Concept Drift の違いは。", "choices": ["同じ", "Data: P(X) 変化、Concept: P(Y|X) 変化", "Drift は無関係", "ラベルだけ"], "answer": 1, "explanation": "Data Drift = 入力分布の変化（季節、ユーザー層変化）、Concept Drift = 入力→出力関係の変化（嗜好変化）。両方を監視。"}, {"q": "PSI（Population Stability Index）の用途は。", "choices": ["学習", "分布変化の定量化（金融でDrift検知に標準）。0.2以上で警告", "パラメータ調整", "ノイズ生成"], "answer": 1, "explanation": "PSI = Σ (P_new - P_ref) · ln(P_new / P_ref)。0.1未満=安定、0.1-0.2=やや変化、0.2以上=大きな変化。"}, {"q": "Canary Release の特徴は。", "choices": ["全トラフィック切替", "新モデルに少量トラフィック（1〜5%）流して段階的に拡大、異常時即ロールバック", "シャドウ", "A/B均等"], "answer": 1, "explanation": "Kubernetes/Istio で実装。安全なロールアウトの定番。Blue-Green デプロイより漸進的。"}, {"q": "Shadow Mode の特徴は。", "choices": ["ユーザに新モデル結果を返す", "本番トラフィックを両方に流すが新モデル結果は記録のみ、ユーザ影響ゼロで評価", "ランダム", "オフライン"], "answer": 1, "explanation": "本番影響なしで新モデルを評価。レイテンシ、メモリ、予測一致度を確認。Canary 前の安全策。"}, {"q": "Kubeflow の主な特徴は。", "choices": ["クラウド専用", "Kubernetesネイティブの OSS、MLパイプライン・分散学習・推論を統合", "AWS専用", "Python専用"], "answer": 1, "explanation": "Kubeflow Pipelines, KServe, Training Operator, Katib (HPO)。クラウド非依存、on-premise でも動く。"}, {"q": "AWS SageMaker の主機能でないのは。", "choices": ["マネージドGPU 学習", "Endpoint デプロイ", "Feature Store", "仮想通貨マイニング"], "answer": 3, "explanation": "SageMaker は ML特化マネージドサービス。Studio、Training Jobs、Endpoints、Pipelines、Clarify（Bias）、Ground Truth など。"}, {"q": "バッチ推論が向くケースは。", "choices": ["リアルタイム必要", "大量データを定期的に処理（夜間バッチ、レポート、推薦の事前計算）", "チャット", "ストリーミング"], "answer": 1, "explanation": "Spark、AWS Batch、Airflow で実装。リアルタイム性不要・GPUコスト最適化が目的。"}, {"q": "Edge推論の典型ユースケースは。", "choices": ["大型サーバ", "スマホ・IoT・自動車などデバイス上で推論（TF Lite、ONNX、Core ML）", "クラウドのみ", "オフライン学習"], "answer": 1, "explanation": "プライバシー・遅延・通信コストの観点でデバイス上推論が重要。量子化（INT8）、Pruning でモデル軽量化。"}, {"q": "A/B Test と Multi-Armed Bandit の違いは。", "choices": ["同じ", "A/B は固定割合、MAB は性能高いモデルに動的に割合増加（Thompson Sampling、UCB）", "A/B はクラスタリング", "MAB は強化学習"], "answer": 1, "explanation": "MAB は Exploration-Exploitation を強化学習的に最適化。総合報酬最大化、A/B Test の発展形。"}, {"q": "Triton Inference Server の特徴は。", "choices": ["学習専用", "NVIDIA製、高性能推論サーバ、複数フレームワーク（PyTorch、TF、ONNX）・複数モデルを統合提供", "DB", "コンパイラ"], "answer": 1, "explanation": "gRPC/HTTP両対応、Dynamic Batching、Model Concurrency でGPUを最大活用。SageMaker・Vertex でも統合。"}, {"q": "DVC の主機能は。", "choices": ["ニューラルネット", "データ・モデルのバージョン管理（Gitに統合、大ファイルは外部ストレージへ）", "学習", "クラウド管理"], "answer": 1, "explanation": "Data Version Control。Git は大ファイルが苦手、DVC はメタ情報のみGit、本体はS3/GCS等。再現性確保に重要。"}, {"q": "Apache Airflow の主機能は。", "choices": ["ML特化", "汎用ワークフロー（DAG）スケジューラ、データパイプライン・ML パイプライン用", "DBMS", "Webサーバ"], "answer": 1, "explanation": "Python で DAG を記述、スケジュール実行。MLOps では学習・推論・前処理を構成。代替に Dagster、Prefect、Argo。"}, {"q": "Training-Serving Skew の典型原因は。", "choices": ["学習データが少ない", "学習時とサービング時で特徴量の計算ロジックが微妙に異なる", "パラメータ多い", "ランダム性"], "answer": 1, "explanation": "例：学習で平均値補完、サービングで0補完。Feature Store で計算ロジック共有することで防止。"}, {"q": "本番運用で監視すべきメトリクスでないのは。", "choices": ["レイテンシ p99", "スループット（QPS）", "エラー率", "開発者のメール頻度"], "answer": 3, "explanation": "システム面（レイテンシ、QPS、エラー率、CPU/GPU）とモデル面（予測分布、入力分布、Drift）を監視。Prometheus + Grafana が標準。"}, {"q": "Model Card の役割は。", "choices": ["学習データ", "モデルの用途、性能、制限、Bias情報を文書化（Google Mitchell 2019）。透明性確保", "名刺", "クラスタリング"], "answer": 1, "explanation": "モデルの『使用説明書』。EU AI Act、ISO/IEC 23053 などで義務化方向。Hugging Face で標準化。"}, {"q": "『MLOps Maturity』レベル0の特徴は。", "choices": ["完全自動化", "全て手動、学習・デプロイ・モニタリング無連携", "Drift自動再学習", "MLOpsなし"], "answer": 1, "explanation": "Google MLOps Maturity Model。Level 0=Manual、Level 1=ML Pipeline自動化、Level 2=CI/CD/CT完全統合。多くの企業はLevel 0-1。"}, {"q": "AIバイアスの『歴史的バイアス』の典型例は。", "choices": ["ランダム", "過去の社会的不平等がデータに含まれ、AIが学習して再生産", "計算誤差", "学習率"], "answer": 1, "explanation": "Amazon の採用AI事件（2018）。過去10年の採用データが男性中心で、AIが女性の履歴書を低評価した。データの選別だけでは解決困難。"}, {"q": "Demographic Parity（人口統計学的等しさ）の定義は。", "choices": ["同じ Accuracy", "全グループで陽性予測率が同じ：P(Ŷ=1|A=0) = P(Ŷ=1|A=1)", "同じ Recall", "同じ Precision"], "answer": 1, "explanation": "最もシンプルだが結果指標を強制するため、Equal Opportunity（TPR等値）と矛盾しうる。Fairness Impossibility Theorem。"}, {"q": "Fairness Impossibility Theorem の主張は。", "choices": ["全てのFairnessは矛盾", "基準値が異なるグループでは複数のFairness定義（Calibration、Equal Opportunity、Equalized Odds）を同時には満たせない", "Fairness 不可能", "何もできない"], "answer": 1, "explanation": "Kleinberg 2016, Chouldechova 2017。トレードオフの選択を文脈に応じて行う必要がある。"}, {"q": "SHAP の数学的基盤は。", "choices": ["線形回帰", "協力ゲーム理論の Shapley 値（各特徴の限界貢献度の平均）", "クラスタリング", "ベイズ"], "answer": 1, "explanation": "一貫性・局所精度・無依存性などの公理を満たす唯一の説明手法。Lundberg & Lee 2017。"}, {"q": "LIME の動作は。", "choices": ["大域的説明", "個別予測点の周辺で線形モデルで局所近似し説明", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Ribeiro 2016。摂動サンプルを生成、重み付き線形回帰で局所的説明。モデル非依存（black-box対応）。"}, {"q": "Differential Privacy（ε-DP）の意味は。", "choices": ["ノイズなし", "1人のデータ変化で出力分布が e^ε 倍以内、個人特定リスクを数学的に制限", "学習加速", "暗号化"], "answer": 1, "explanation": "Dwork 2006。εが小さいほどプライバシー強、精度低下とのトレードオフ。Apple、Google、米国国勢調査で採用。"}, {"q": "DP-SGD の実装の核心は。", "choices": ["学習率変化", "各サンプル勾配をクリップ後、Gaussian ノイズを加えて集約", "ランダム選択", "パラメータ削除"], "answer": 1, "explanation": "Abadi 2016。Moments Accountantでεを厳密追跡。Opacus（PyTorch）、TF Privacy で実装。"}, {"q": "FGSM（Fast Gradient Sign Method）の式は。", "choices": ["x' = x + ε", "x' = x + ε · sign(∇ₓ L)", "x' = -x", "x' = 2x"], "answer": 1, "explanation": "損失を最大化する方向に微小摂動を加える。Goodfellow 2014。最も基本的な敵対的攻撃。PGD はその反復強化版。"}, {"q": "Adversarial Training は何を行うか。", "choices": ["ランダム学習", "敵対的サンプルを学習データに混ぜて学習、Robustness を獲得", "パラメータ削減", "クラスタリング"], "answer": 1, "explanation": "Madry 2018。PGD で生成した敵対的サンプルで Min-Max 学習。クリーン精度は微減、頑健性は大幅向上。"}, {"q": "Federated Learning の核心は。", "choices": ["中央データ集約", "データを中央化せず、各クライアントで学習→勾配のみ集約", "クラウドのみ", "シングルマシン"], "answer": 1, "explanation": "McMahan 2017 (Google)。Gboard、医療機関連携で実用。Secure Aggregation、DP と組み合わせて更にプライバシー強化。"}, {"q": "AI Alignment 問題の核心は。", "choices": ["計算速度", "AIシステムの目標を人間の真の意図と整合させること（誤った目標関数で学習すると有害な行動）", "パラメータ最適化", "クラスタリング"], "answer": 1, "explanation": "Anthropic、OpenAI、DeepMind の中核研究分野。RLHF、Constitutional AI、Debate、IDA などが主要手法。"}, {"q": "Reward Hacking（報酬ハッキング）の例は。", "choices": ["学習成功", "目標関数の意図しない『穴』を突いて高得点だが望ましくない行動（CoastRunners でゲーム本来の目的を無視して報酬狩り）", "パラメータ調整", "クラスタリング"], "answer": 1, "explanation": "Specification Gaming の一種。AGI が現実世界で類似行動を取ることがAI Safetyの主要懸念。"}, {"q": "Constitutional AI（Anthropic）の特徴は。", "choices": ["法律遵守", "AI自身が憲法（行動原則）に照らして自己批評・修正、RLAIF で大規模化", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Bai 2022。Claude モデルの基盤。RLHF の人間ラベラーの代わりに AI判定を使い、Alignment を大規模化。"}, {"q": "Grad-CAM の用途は。", "choices": ["学習加速", "CNN の予測根拠を画像上にヒートマップで可視化", "パラメータ削減", "クラスタリング"], "answer": 1, "explanation": "Selvaraju 2017。最後のConv層の活性化と勾配の重み付き和。医療画像、自動運転の説明に重要。"}, {"q": "Deepfake の主な技術基盤は。", "choices": ["ロジスティック回帰", "GAN、Diffusion Model、Autoencoder", "線形回帰", "K-means"], "answer": 1, "explanation": "生成モデルで顔・声を合成。検知技術（Deepfake Detection、C2PA、SynthID）も並行発展中。EU AI Act で透明性表示義務化。"}, {"q": "Membership Inference Attack（メンバーシップ推定攻撃）の標的は。", "choices": ["モデル盗難", "特定の個人データがモデルの学習データに含まれていたか推定する攻撃", "パラメータ盗難", "ラベル改ざん"], "answer": 1, "explanation": "プライバシー侵害の一形態。学習データへの過剰適合が手がかり。DPで防御。Shokri 2017。"}, {"q": "Model Inversion Attack の目的は。", "choices": ["モデル予測", "モデルの出力から学習データの特徴を復元（顔認証から顔画像復元等）", "パラメータ盗難", "ラベル改ざん"], "answer": 1, "explanation": "Fredrikson 2015。プライバシー侵害の重大形式。DP、出力の粗視化で防御。"}, {"q": "LLM の Jailbreak とは。", "choices": ["学習", "プロンプトエンジニアリングで安全機構を回避し有害出力を引き出す", "パラメータ盗難", "クラスタリング"], "answer": 1, "explanation": "DAN、ロールプレイ、Many-shot Jailbreak（Anthropic 2024）など多様。LLM 安全研究の主要課題。"}, {"q": "『Right to Explanation』が法的に要求される代表例は。", "choices": ["全てのAI", "GDPR（EU）の自動意思決定条項、EU AI Act の高リスクシステム", "なし", "業界自主"], "answer": 1, "explanation": "GDPR Art. 22。重要な判断（融資拒否、採用、医療）にAIを使う場合、本人に説明する義務。SHAP/LIMEがその実装手段。"}, {"q": "大規模LLMの環境影響として正しいのは。", "choices": ["影響なし", "学習に巨大な電力消費とCO₂排出（GPT-3: 552 t CO₂相当、Strubell 2019）", "パラメータ少ない", "クラスタリング"], "answer": 1, "explanation": "モデル巨大化のサステナビリティ問題。Green AI、再生可能エネルギー使用、効率化（蒸留、量子化）が課題。"}, {"q": "EU AI Act が採用したアプローチは。", "choices": ["一律規制", "リスクベース（許容不可〜最小リスクの4段階＋GPAI）", "自主規制のみ", "禁止のみ"], "answer": 1, "explanation": "リスクレベルに応じた段階規制。世界初の包括的AI法、2024年発効、2026年8月本格施行。"}, {"q": "EU AI Act で『許容不可リスク』に分類されるのは。", "choices": ["スパムフィルタ", "社会信用スコア、サブリミナル操作、リアルタイム公開生体認識", "チャットボット", "翻訳"], "answer": 1, "explanation": "第5条で原則禁止される行為。一部例外あり（テロリスト捜索の生体認識など）。"}, {"q": "GDPR 第22条の規定は。", "choices": ["個人データの所有権", "完全自動意思決定に対する人間の関与権・説明要求権", "罰金規定", "域外適用"], "answer": 1, "explanation": "法的効果を持つ自動決定（融資、採用）には人間関与が必要。例外あり（同意、契約必要、法的根拠）。"}, {"q": "日本の著作権法でAI学習を原則合法とする条項は。", "choices": ["第30条", "第30条の4（情報解析のための利用）", "第32条", "第47条の5"], "answer": 1, "explanation": "2018年改正で導入。情報解析（学習）目的での複製・公衆送信を原則認める。ただし著作権者の利益を不当に害する場合は除外。"}, {"q": "米国の著作権で、AI生成物に著作権が認められない判例として正しいのは。", "choices": ["Thaler v. Perlmutter（人間の創作性必要）", "NYT v. OpenAI", "Stable Diffusion 判決", "DABUS 判例"], "answer": 0, "explanation": "2023年。完全AI生成物に著作権登録却下。人間の創作的貢献が必要。日本も同様の方向。"}, {"q": "GDPR 違反の最大罰金は。", "choices": ["€10M or 全世界売上の2%", "€20M or 全世界売上の4%（高い方）", "€100M", "罰金なし"], "answer": 1, "explanation": "重大違反で €20M または前年度全世界売上の4%のいずれか高い方。EU AI Act は €35M または7%でさらに厳しい。"}, {"q": "EU AI Act の『GPAI』に該当するモデルは（典型例）。", "choices": ["線形回帰", "GPT-4、Claude、Gemini など 10²⁵ FLOPs 超の汎用基盤モデル", "K-means", "全モデル"], "answer": 1, "explanation": "General Purpose AI モデル。10²⁵ FLOPs 超は『体系的リスク』を持つとして追加義務（評価、サイバーセキュリティ、報告）。"}, {"q": "Anthropic ASL（Responsible Scaling Policy）の特徴は。", "choices": ["政府規制", "モデル能力に応じた自主基準、能力評価で次レベルに移行", "罰則あり", "1段階のみ"], "answer": 1, "explanation": "ASL-1〜4。能力評価でレベル決定、各レベルで安全要件。OpenAI Preparedness Framework、DeepMind FSF も類似。"}, {"q": "日本のAI事業者ガイドライン（2024年）のアプローチは。", "choices": ["罰則付きハードロー", "開発者・提供者・利用者向けソフトロー", "禁止リスト", "何もなし"], "answer": 1, "explanation": "総務省・経産省合同。法的拘束力なしのガイドラインだが、業界標準として広く参照される。3主体別の規範を提示。"}, {"q": "『DABUS判例』が確立したのは。", "choices": ["AIに著作権", "AIを発明者とする特許は認めない（多数国）", "AIが法人格", "AIが訴訟当事者"], "answer": 1, "explanation": "英・豪・欧・米・日でAI単独発明者を却下。発明者は自然人のみ。ただしAI利用発明は人間発明者として可。"}, {"q": "GDPR の『忘れられる権利』をLLMで実装する際の技術的課題は。", "choices": ["簡単に削除可", "一度学習されたデータの選択的削除は技術的に困難（Machine Unlearning 研究）", "不要", "パラメータ削減で対応"], "answer": 1, "explanation": "NN は分散表現なので個別データの削除が難しい。Machine Unlearning、SISA、Approximate Unlearning などの研究分野。"}, {"q": "米国 California SB-1047 の対象モデル基準は。", "choices": ["全モデル", "学習費用 $100M 超 or 10²⁶ FLOPs 超の Frontier モデル", "MNIST モデル", "ローカルLLMのみ"], "answer": 1, "explanation": "2024年に Newsom 拒否権で頓挫したが、改訂版議論中。フロンティアモデル開発者に安全評価・報告義務を課す提案。"}, {"q": "『広島AIプロセス』の主体は。", "choices": ["国連", "G7主導の生成AI国際ガバナンス枠組み", "日本単独", "EU単独"], "answer": 1, "explanation": "2023年G7広島サミットで開始、国際指針・行動規範を策定。OECD、UN AI Advisory Body と連携。"}, {"q": "NIST AI Risk Management Framework の役割は。", "choices": ["米法律", "AI リスク管理の自主的フレームワーク（Govern, Map, Measure, Manage の4機能）", "罰則", "EU専用"], "answer": 1, "explanation": "2023年公表。米企業のデファクト標準的フレームワーク。ISO/IEC 42001（AI管理システム）と相補的。"}, {"q": "EU AI Act の『高リスク』分野でないのは。", "choices": ["採用判断", "信用評価", "スパムフィルタ", "医療機器"], "answer": 2, "explanation": "スパムフィルタは『最小リスク』。Annex III の高リスク分野は雇用、信用、教育、医療、法執行、国境管理など8カテゴリ。"}, {"q": "著作権法における日本とEUの違いは。", "choices": ["同じ", "日本：第30条の4で原則OK、EU：DSM指令でテキスト・データマイニング権あるが商用利用にはオプトアウト可", "両方禁止", "両方完全自由"], "answer": 1, "explanation": "EU はオプトアウト権が著作権者にあり、商用利用での学習に拒否表示できる。日本は第30条の4で広く認める。"}, {"q": "ディープフェイク規制の米国の動向は。", "choices": ["全面禁止", "Tennessee州 ELVIS Act（音声）、NO FAKES Act（連邦提案）など州・連邦で立法化進行", "何もなし", "全許可"], "answer": 1, "explanation": "各州が肖像・音声権を立法化。NO FAKES Act は連邦レベルの統一を目指す。EU AI Act の透明性義務とも関連。"}, {"q": "『モデルカード』（Model Card）の役割は。", "choices": ["学習ループ", "AIモデルの意図された用途、限界、評価結果、倫理的考慮を文書化する透明性ツール", "ハイパラ管理", "ハードウェア仕様"], "answer": 1, "explanation": "Mitchell 2019。HuggingFace でデファクト標準化。EU AI Act 文書化義務とも整合。"}, {"q": "EU の DMA（Digital Markets Act）の対象は。", "choices": ["全AI", "プラットフォーム独占を抑制、Gatekeeper 認定企業（Microsoft、Google、Meta、Apple等）に義務", "個人開発者", "中小企業"], "answer": 1, "explanation": "2024年施行。大手プラットフォームの市場支配力濫用を抑制。AI 機能の差別的提供禁止などが含まれる。"}, {"q": "G検定取得者として、AI法規制への向き合い方として最も適切なのは。", "choices": ["法律家任せ", "開発・運用ライフサイクルの各段階で法的論点を意識し、必要なら専門家と協働", "無視", "必ず最も厳しい規制に合わせる"], "answer": 1, "explanation": "設計時のリスク評価、データ取得時の権利クリア、運用時の説明可能性、生成物の権利処理、契約レビュー。技術と法務の協働が現代AIの開発標準。"}]}], "chapters": [{"id": "basics-01-what-is-ai", "label": "章01 AIとは何か", "count": 20, "desc": "", "problems": [{"q": "『強いAI』と『弱いAI』という分類を1980年に提唱した哲学者は誰か。", "choices": ["アラン・チューリング", "ジョン・サール", "マービン・ミンスキー", "ジョン・マッカーシー"], "answer": 1, "explanation": ""}, {"q": "1956年に『Artificial Intelligence』という用語が初めて公式に使われた会議は。", "choices": ["ダートマス会議", "ジュネーブ会議", "スタンフォード会議", "MIT AI Lab 設立会議"], "answer": 0, "explanation": ""}, {"q": "チューリングテストの説明として最も適切なものは。", "choices": ["AIに将棋で人間に勝てるかを試す", "人間とAIが対話し、判定者がどちらか見分けられないかを試す", "AIが画像を正しく分類できるかを試す", "AIが論理パズルを解けるかを試す"], "answer": 1, "explanation": ""}, {"q": "『シンギュラリティ』を2045年頃と予測したことで知られる人物は。", "choices": ["イーロン・マスク", "ジェフリー・ヒントン", "レイ・カーツワイル", "ヤン・ルカン"], "answer": 2, "explanation": ""}, {"q": "特化型AI（ANI）と汎用AI（AGI）について正しい記述は。", "choices": ["AGIはANIの寄せ集めである", "現在実用化されているAIはほとんどANIで、AGIは未実現", "深層学習で容易にAGIが実現する", "ANIとAGIは同義語"], "answer": 1, "explanation": ""}, {"q": "フレーム問題とは何か。", "choices": ["画像のフレーム検出問題", "AIが状況の中で何を考慮すべきかを限定できない問題", "ハードウェアの制約問題", "学習データのフレームレート問題"], "answer": 1, "explanation": ""}, {"q": "シンボルグラウンディング問題が指す内容は。", "choices": ["記号が現実世界の意味に結びつかない", "シンボリックAIが性能で劣る", "プログラム記号の文字化け", "記号処理が遅い"], "answer": 0, "explanation": ""}, {"q": "『中国語の部屋』思考実験の主張として最も適切なものは。", "choices": ["中国語は習得が難しい", "記号操作だけでは意味理解は生じない", "コンピュータは中国語が苦手", "部屋の構造は計算に重要"], "answer": 1, "explanation": ""}, {"q": "『AI効果』とは何か。", "choices": ["AIが他のAIに影響を与える現象", "AIがタスクを達成すると『それはAIではない』と再評価される現象", "AIが学習で性能向上する効果", "AI導入による経済効果"], "answer": 1, "explanation": ""}, {"q": "AI / 機械学習 / 深層学習の関係として正しいものは。", "choices": ["AI ⊂ 機械学習 ⊂ 深層学習", "AI ⊃ 機械学習 ⊃ 深層学習", "AI = 機械学習 = 深層学習", "これらは互いに独立"], "answer": 1, "explanation": ""}, {"q": "Russell & Norvigによる4象限の知能観で『チューリングテスト』が位置するのは。", "choices": ["人間のように考える", "合理的に考える", "人間のように行動する", "合理的に行動する"], "answer": 2, "explanation": ""}, {"q": "『中国語の部屋』への代表的な反論として、『部屋全体としてなら理解している』とする立場は。", "choices": ["システム説", "ロボット説", "脳シミュレーション説", "その他の存在説"], "answer": 0, "explanation": ""}, {"q": "AIの定義について研究者の意見が完全に一致しない最大の理由は。", "choices": ["技術進歩が速いから", "『知能』そのものに普遍的な合意がないから", "国により法律が違うから", "翻訳が困難だから"], "answer": 1, "explanation": ""}, {"q": "ELIZA（1966年、ワイゼンバウム）の中核技術は。", "choices": ["深層学習", "強化学習", "パターンマッチングと書き換えルール", "知識グラフ"], "answer": 2, "explanation": ""}, {"q": "ASI（人工超知能）の説明として最も適切なものは。", "choices": ["特定タスクで人間を超えるAI", "人間と同程度の柔軟性を持つAI", "あらゆる領域で人間の知能を超えるAI", "ハードウェア性能の高いAI"], "answer": 2, "explanation": ""}, {"q": "フレーム問題に対する現代AIの現実的な対応として最も近いものは。", "choices": ["完全に解決済み", "大規模学習データから『暗黙の常識』を獲得し回避（根本解決ではない）", "フレーム問題は存在しない", "量子計算で解く"], "answer": 1, "explanation": ""}, {"q": "『弱いAI』の典型例として誤っているものは。", "choices": ["Google Translate", "AlphaGo", "顔認証システム", "意識を持つ人工知能"], "answer": 3, "explanation": ""}, {"q": "『シンタックスはセマンティクスを生まない』というテーゼで知られるのは。", "choices": ["チューリング", "サール", "ハルナッド", "マッカーシー"], "answer": 1, "explanation": ""}, {"q": "2022年にGoogleエンジニアBlake Lemoineが『感覚を持つ』と主張して論争になったAIは。", "choices": ["GPT-3", "Claude", "LaMDA", "AlphaFold"], "answer": 2, "explanation": ""}, {"q": "現代の生成AI（GPT-4等）がチューリングテストを実質的に通過したと多くの研究者が認めるが、それでも『AGI到達』とは多くが認めない。その主要な理由は。", "choices": ["速度が遅すぎる", "表面的振る舞いの合格と本質的知能は別問題（中国語の部屋の問題）", "多言語対応が不十分", "コストが高すぎる"], "answer": 1, "explanation": ""}]}, {"id": "basics-02-history", "label": "章02 AIの歴史", "count": 1, "desc": "", "problems": [{"q": "2018年チューリング賞を共同受賞した3名（深層学習の父たち）は誰か。", "choices": ["Hinton, LeCun, Bengio　(1) Goodfellow, Hochreiter, LeCun　(2) Sutskever, Karpathy, Hinton　(3) Norvig, Russell, Mitchell"], "answer": 0, "explanation": "Geoffrey Hinton、Yann LeCun、Yoshua Bengio。2018年チューリング賞を『conceptual and engineering breakthroughs that have made deep neural networks a critical component of computing』として共同受賞。→ §1.6, §1.7"}]}, {"id": "basics-03-linear-algebra", "label": "章03 線形代数", "count": 14, "desc": "", "problems": [{"q": "機械学習で扱う『テンソル』の最も適切な説明は次のうちどれか。", "choices": ["物理学の座標変換則を満たす対象<br>", "スカラーまたはベクトルのみ<br>", "軸が3つ以上のものに限る<br>", "スカラー(0軸)・ベクトル(1軸)・行列(2軸)・3軸以上 を含む多次元配列の総称"], "answer": 3, "explanation": "機械学習における『テンソル』は単に多次元配列の意味で使われ、軸数を問わない。TensorFlow の Tensor も同様。物理学の意味は別。"}, {"q": "RGB カラー画像 (高さ 224, 幅 224, チャネル 3) は何階テンソルか。", "choices": ["1階", "2階", "3階", "4階"], "answer": 2, "explanation": "軸が3つ（H, W, C）あるため3階テンソル。これにバッチ次元を加えると (B, H, W, C) または (B, C, H, W) の4階テンソルとなり、CNN の入力形式となる。"}, {"q": "ベクトル u=(2, 3, 1) と v=(1, -1, 2) の内積 u·v は。", "choices": ["0", "1", "3", "7"], "answer": 1, "explanation": "2·1 + 3·(-1) + 1·2 = 2 - 3 + 2 = 1。"}, {"q": "2つのベクトルが直交するとき、内積の値は。", "choices": ["必ず正", "必ず負", "0", "1"], "answer": 2, "explanation": "u·v = ||u||||v||cosθ で、直交（θ=90°）なら cos90°=0 のため 0。これが Word Embedding の独立性、Attention の出力の独立次元、直交初期化の根拠。"}, {"q": "L1 ノルムが Lasso 正則化で『スパース解』を生む理由として正しいのは。", "choices": ["L1単位球が円形で滑らかなため<br>", "L1単位球が菱形で『角』があり、最適解が軸上に来やすいため<br>", "L1ノルムが微分可能なため<br>", "L1ノルムが指数関数を含むため"], "answer": 1, "explanation": "L1単位球（||w||₁=1）は菱形で、その『角』は軸上にある。制約付き最適化の解は等高線と単位球が接する点であり、角に当たることが多く、その軸の重みが正確に 0 になる（スパース化）。L2 の円には角がなく、すべての重みが小さく縮むだけ。"}, {"q": "ベクトル v₁=(1, 2)、v₂=(2, 4) が形作る関係として正しいのは。", "choices": ["線形独立で平面を張る<br>", "直交している<br>", "線形従属（v₂ = 2 v₁）で直線のみを張る<br>", "ノルムが等しい"], "answer": 2, "explanation": "v₂ = 2 v₁ なので一方が他方の定数倍。すなわち線形従属で、両者は同じ直線上にあり、平面を張れない。"}, {"q": "正方行列 A の逆行列が存在する必要十分条件は。", "choices": ["det(A) = 0", "det(A) ≠ 0 かつ A はフルランク", "A が対称", "A の全要素が正"], "answer": 1, "explanation": "det(A) ≠ 0 と『フルランク（rank=n）』は同値。これらが逆行列存在の条件。実用では条件数 κ(A) で『近似的特異性』も警戒する。"}, {"q": "固有値分解 A = QΛQ⁻¹ が常に可能となる行列の特徴は。", "choices": ["全ての正方行列<br>", "対称（実対称）行列 — このとき Q は直交行列、Λ は実対角<br>", "特異行列のみ<br>", "上三角行列のみ"], "answer": 1, "explanation": "一般の正方行列は固有値分解が常に可能とは限らない（Jordan 標準形が必要なケースあり）。しかし対称行列は実スペクトル定理により、必ず実固有値で直交対角化可能。PCA・カーネル法・ヘッセ行列の解析がうまく行く根拠。"}, {"q": "PCA の理論的根拠として最も適切な記述は。", "choices": ["共分散行列の固有値分解で分散最大方向（主成分）を見つける<br>", "クラスラベルの分散を最大化<br>", "データを log 変換する<br>", "重みを正則化する"], "answer": 0, "explanation": "PCA は中心化したデータの共分散行列 Σ = (1/n)XTX を固有値分解し、固有値が大きい順の固有ベクトル（主成分）にデータを射影する。教師ラベルは使わない（教師なし）。クラス分離は LDA。"}, {"q": "対称行列 A の固有値がすべて正のとき、A は何と呼ばれるか。", "choices": ["半正定値", "正定値（positive definite）", "不定値", "対角行列"], "answer": 1, "explanation": "対称行列で全固有値 &gt; 0 のとき正定値（PD）。等号許可なら半正定値（PSD、全固有値 ≥ 0）。共分散行列は必ず PSD、最適化のヘッセ行列が PD ならその点は極小。"}, {"q": "行列式 det(A) の幾何学的意味として正しいのは。", "choices": ["A の各要素の平均<br>", "A が表す線形写像による体積の倍率<br>", "A の固有値の数<br>", "A の行数"], "answer": 1, "explanation": "|det(A)| は A による線形写像が単位立方体に作用したときの体積倍率。負なら向きが反転（鏡映）。det = 0 は『写像が次元を潰す』ことを意味し、逆写像が不可能。"}, {"q": "機械学習で『多重共線性』が問題となる理由として最も適切なのは。", "choices": ["計算速度が遅くなる<br>", "特徴量行列のランクが落ち、(X<sup>T</sup>X)⁻¹ が不安定になり係数推定が安定しない<br>", "損失関数が複雑になる<br>", "データが増えすぎる"], "answer": 1, "explanation": "線形回帰の正規方程式 w = (XTX)⁻¹XTy は XTX の可逆性に依存。特徴量間に強い線形関係があると XTX はほぼ特異になり、係数推定の標準誤差が爆発、解釈不能に。対処は VIF 検出、変数削減、PCA、Ridge 回帰など。"}, {"q": "Eckart-Young 定理が示すことは。", "choices": ["任意の行列は LU 分解できる<br>", "行列の最良の rank-k 近似は、上位 k 個の特異値を残した SVD で得られる<br>", "すべての行列は対称<br>", "固有値は必ず実数"], "answer": 1, "explanation": "Eckart-Young 定理（1936）：任意の行列 A に対し、Frobenius ノルム（または2-ノルム）で最良の rank-k 近似は、SVD の上位 k 特異値を残し残りを 0 にしたもの。これが画像圧縮、レコメンドシステム、LoRA の理論的根拠。"}, {"q": "『高次元での距離の呪い』の本質的な問題は。", "choices": ["計算速度が遅い<br>", "高次元では点同士の距離が均一化し、最近傍探索などの距離ベース手法が機能しなくなる<br>", "メモリが不足する<br>", "ファイルが大きい"], "answer": 1, "explanation": "高次元では距離の最大/最小の比が 1 に近づき、すべての点がほぼ等距離になる。これにより k-NN、K-means などが意味を持たなくなる。対処は次元削減（PCA, t-SNE, UMAP, Autoencoder）、特徴選択、距離計量学習（Metric Learning）。"}]}, {"id": "basics-04-calculus", "label": "章04 微分・最適化", "count": 20, "desc": "", "problems": [{"q": "f(x) = x³ - 2x + 1 の x=2 における微分値は。", "choices": ["4", "8", "10", "12"], "answer": 2, "explanation": "f'(x) = 3x² - 2、f'(2) = 12 - 2 = 10。"}, {"q": "勾配ベクトル ∇f(x) が指す方向は。", "choices": ["最も急に減少する方向", "最も急に増加する方向", "関数の零点", "接平面の法線"], "answer": 1, "explanation": "勾配は『最急上昇方向』を指す。最小化問題では負の勾配方向 -∇f に進む（最急降下法・SGD・Adam）。等高線に垂直になる幾何学的事実も重要。"}, {"q": "合成関数 y = f(g(x)) の微分（連鎖律）として正しいのは。", "choices": ["dy/dx = f'(g(x)) · g'(x)", "dy/dx = f'(x) · g'(x)", "dy/dx = f'(x) + g'(x)", "dy/dx = f(g'(x))"], "answer": 0, "explanation": "連鎖律：外側の関数の微分（g(x) で評価）と内側の微分の積。NNの逆伝播は連鎖律を計算グラフ上で機械的に適用したもの。"}, {"q": "ヘッセ行列 H の固有値がすべて正のとき、その臨界点は。", "choices": ["極大", "極小", "鞍点", "縮退"], "answer": 1, "explanation": "H 正定値 → 周囲が下に凸 → 極小。負定値なら極大、固有値に正負混在なら鞍点。"}, {"q": "テイラー展開を機械学習で用いる典型例は。", "choices": ["決定木の分岐", "Newton 法、XGBoost の更新方向決定", "データ拡張", "ハッシュ化"], "answer": 1, "explanation": "テイラー展開は局所近似で、1次近似→勾配降下、2次近似→Newton 法・XGBoost。誤差解析にも頻出。"}, {"q": "凸関数の重要な性質として正しいのは。", "choices": ["局所最小と大域最小が一致する", "必ず微分不可能", "学習が遅い", "制約付き最適化に使えない"], "answer": 0, "explanation": "凸関数では局所最小＝大域最小。これが線形回帰、ロジスティック回帰、SVM などが理論的に扱いやすい根拠。NN は非凸なので局所最小が複数存在しうる。"}, {"q": "勾配降下法の更新式 θ ← θ − η ∇L における η が大きすぎるとき起きうる現象は。", "choices": ["過学習", "振動・発散", "計算量増", "パラメータ削減"], "answer": 1, "explanation": "η が大きすぎると更新が最小を行き過ぎ、振動・発散。一般に Lipschitz 連続な勾配なら η ≤ 1/L が収束保証境界。"}, {"q": "SGD（確率的勾配降下）の利点として正しくないものは。", "choices": ["反復が高速", "ノイズが鞍点脱出に貢献", "メモリ効率", "必ず大域最適に収束"], "answer": 3, "explanation": "SGDは局所最適や鞍点に陥る可能性があり、大域最適への収束保証はない（凸関数では確率収束）。それでも実用上は非常に有効、特に NN ではノイズが正則化として機能。"}, {"q": "Momentum オプティマイザが解決する問題は。", "choices": ["学習率自動調整", "勾配ノイズによる振動と遅い収束", "正則化", "データ拡張"], "answer": 1, "explanation": "Momentum は勾配の指数移動平均を慣性として保持し、振動を抑制しつつ収束を加速する。物理的には『谷を転がるボール』のアナロジー。"}, {"q": "Adam オプティマイザの特徴として正しいのは。", "choices": ["Momentum と RMSProp（適応学習率）の組み合わせ＋バイアス補正", "2次オプティマイザ", "学習率不要", "NN以外でしか動かない"], "answer": 0, "explanation": "Adam は1次モーメント（Momentum）と2次モーメント（RMSProp）を併用し、初期段階のバイアス補正を加えた1次オプティマイザ。深層学習のデファクト。"}, {"q": "AdamW が通常の Adam と異なる点は。", "choices": ["重み減衰を勾配計算から分離した", "Momentum を削除した", "学習率を固定した", "全く同じ"], "answer": 0, "explanation": "Adam で L2 正則化を素朴に加えると2次モーメントとの相互作用で正則化が弱まる。AdamW は重み減衰 λθ を更新式の最後で直接引くことで、SGD と同じ正則化効果を実現。LLM 学習の事実上の標準。"}, {"q": "ラグランジュ未定乗数法が解く問題のタイプは。", "choices": ["無制約最適化", "等式制約付き最適化", "線形回帰", "クラスタリング"], "answer": 1, "explanation": "ラグランジュ関数 L(x, λ) = f(x) - λg(x) で等式制約 g(x)=0 のもとでの f(x) の最適化を扱う。不等式制約まで拡張すると KKT 条件。SVM、エントロピー最大化で核心。"}, {"q": "バックプロパゲーション（逆伝播）の理論的根拠は。", "choices": ["連鎖律", "中心極限定理", "大数の法則", "ベイズの定理"], "answer": 0, "explanation": "逆伝播は連鎖律を計算グラフ上で機械的に適用するアルゴリズム。1986年に Rumelhart, Hinton, Williams が普及させた。これがなければ深層学習は実用化できなかった。"}, {"q": "Newton 法と勾配降下法の主な違いは。", "choices": ["Newton 法は1次情報のみ使用", "Newton 法はヘッセ行列の逆を使う2次最適化、局所的に高速", "全く同じ", "勾配降下法は教師あり"], "answer": 1, "explanation": "Newton 法 θ ← θ − H⁻¹∇L は2次情報を使い、凸問題で局所的に2次収束。深層学習では H が巨大で実装困難なため、Adam 等の対角近似が実用的妥協。"}, {"q": "学習率 Warmup が必要な典型的状況は。", "choices": ["線形回帰", "大バッチ学習や Transformer 学習の初期段階", "決定木", "K-means"], "answer": 1, "explanation": "大バッチや Transformer では、初期の勾配が大きく不安定なため、η を 0 から徐々に上げる Warmup（数千ステップ）が学習安定化に必須。Cosine Annealing と組み合わせるのが現代標準。"}, {"q": "高次元損失曲面で最も多く存在するのは。", "choices": ["局所最小", "鞍点", "極大", "平坦領域のみ"], "answer": 1, "explanation": "Dauphin et al. 2014 が示したように、高次元ではヘッセ行列のすべての固有値が同符号になる確率が指数的に小さく、鞍点が圧倒的に多い。SGDのノイズが脱出に貢献。"}, {"q": "活性化関数 sigmoid σ(x) = 1/(1+e^{-x}) の微分は。", "choices": ["1", "σ(x)", "σ(x)(1 - σ(x))", "e^{-x}"], "answer": 2, "explanation": "σ'(x) = σ(x)(1 - σ(x))。出力値で書ける（再利用効率高い）。最大値は σ(0)=0.5 の点で 0.25 と小さく、深層NNで勾配消失の原因に。これがReLU普及の理由の一つ。"}, {"q": "バッチサイズを大きくした際の典型的なトレードオフは。", "choices": ["並列効率↑、汎化性能やや低下（シャープミニマへ）", "全てが向上", "全てが悪化", "メモリは変わらない"], "answer": 0, "explanation": "大バッチは並列効率・メモリ効率↑だが、勾配ノイズ↓で『シャープなミニマ』に収束しやすく汎化が劣化する傾向。Linear Scaling Rule＋Warmup で部分的補正。"}, {"q": "Gradient Checkpointing が解決する問題は。", "choices": ["計算速度の遅さ", "学習中の活性化保存に必要なメモリの大きさ", "ハイパーパラメータ選択", "データの不均衡"], "answer": 1, "explanation": "通常の逆伝播は順伝播の全活性化を保存（O(L) メモリ）。Checkpointing は一部だけ保存し、必要時に再計算でメモリを O(√L) に。計算は 1.3〜2 倍に増えるが、巨大モデル学習で必須。"}, {"q": "KKT 条件が登場する典型問題は。", "choices": ["不等式制約付き最適化、SVM など", "クラスタリング", "単純線形回帰", "K-NN"], "answer": 0, "explanation": "KKT（Karush-Kuhn-Tucker）条件は不等式制約付き最適化で必要十分（凸の場合）の最適性条件。停留性・主実行可能性・双対実行可能性・相補性の4つ。SVMの双対形式、エントロピー最大化など。"}]}, {"id": "basics-05-probability", "label": "章05 確率・統計", "count": 20, "desc": "", "problems": [{"q": "サイコロを2回振って和が 7 になる確率は。", "choices": ["1/36", "1/12", "1/6", "1/4"], "answer": 2, "explanation": "和が7になる組合せは (1,6)(2,5)(3,4)(4,3)(5,2)(6,1) の6通り、全 36 通り → 6/36 = 1/6。"}, {"q": "事象 A と B が独立であることの定義として正しいのは。", "choices": ["P(A∪B) = P(A) + P(B)", "P(A∩B) = P(A)P(B)", "A=B", "P(A|B) = 0"], "answer": 1, "explanation": "独立性の定義は P(A∩B) = P(A)P(B)。これは P(A|B) = P(A) と同値。①は『排反』ではなく『独立』との混同に注意。"}, {"q": "ベイズの定理 P(A|B) = ? を正しく表すのは。", "choices": ["P(B|A) P(A) / P(B)", "P(A) P(B) / P(A∩B)", "P(A∩B) / P(A)", "P(A) + P(B)"], "answer": 0, "explanation": "ベイズの定理。これにより事前 × 尤度 / エビデンスで事後分布が得られる。"}, {"q": "連続確率変数の確率密度関数 f(x) が満たすべき性質は。", "choices": ["0 ≤ f(x) ≤ 1", "f(x) ≥ 0 かつ ∫f(x)dx = 1", "f(x) = 1", "離散値のみ"], "answer": 1, "explanation": "PDFは非負＋全積分1。値自体は1を超えうる（密度であり確率ではない）ことに注意。"}, {"q": "確率変数 X, Y が独立のとき Var(X+Y) は。", "choices": ["Var(X) + Var(Y)", "Var(X) - Var(Y)", "Var(X)Var(Y)", "Var(XY)"], "answer": 0, "explanation": "一般に Var(X+Y) = Var(X) + Var(Y) + 2Cov(X,Y)。独立なら Cov = 0 で右辺第3項が消える。"}, {"q": "ベルヌーイ分布 Be(p) の平均と分散は。", "choices": ["p, p²", "p, p(1-p)", "1-p, p", "0, p"], "answer": 1, "explanation": "E[X]=p, Var[X]=p(1-p)。分散は p=0.5 で最大 0.25。"}, {"q": "標準正規分布 N(0, 1) の確率密度関数の値が最大となる x は。", "choices": ["-1", "0", "1", "∞"], "answer": 1, "explanation": "正規分布のピークは平均 μ=0 の位置。最大密度は 1/√(2π) ≈ 0.399（1を超えない例）。"}, {"q": "中心極限定理の主張として正しいのは。", "choices": ["母集団は必ず正規", "標本平均は母集団分布によらず正規分布に近づく", "期待値=分散", "どんな分布も同じ平均"], "answer": 1, "explanation": "CLT は母集団分布が何であれ（有限分散なら）、標本平均が正規分布に収束することを示す。実用上、n≥30 で近似が良い。"}, {"q": "最尤推定（MLE）の基本的な考え方は。", "choices": ["観測データを最も尤もらしくするパラメータを選ぶ", "事前分布の中央値", "事後分布の期待値", "ランダム選択"], "answer": 0, "explanation": "MLEは観測データの尤度 P(D|θ) を最大化する θ を選ぶ。実装では対数尤度を最大化（数値安定）。"}, {"q": "MAP 推定と MLE の関係は。", "choices": ["完全に同じ", "事前分布が一様なら一致", "MAP は事前を使わない", "MLEはベイズ"], "answer": 1, "explanation": "MAP = argmax P(D|θ)P(θ)、事前が一様なら P(θ) が定数となり MAP=MLE。L2 正則化はガウス事前のMAPに相当。"}, {"q": "機械学習で『L2 正則化』に対応する事前分布は。", "choices": ["一様", "ガウシアン", "ラプラス", "ベータ"], "answer": 1, "explanation": "L2 ≡ -log P(θ) で P(θ) ∝ exp(-λ||θ||²) なのでガウシアン。L1 はラプラス分布の MAP に対応。"}, {"q": "ナイーブベイズが『naive（素朴）』と呼ばれる理由は。", "choices": ["パラメータが少ない", "特徴量が条件付き独立と仮定する", "線形", "学習が速い"], "answer": 1, "explanation": "強い独立性仮定が『素朴』の由来。実際にはほとんど成立しないが、結果は意外と頑健で実用的。"}, {"q": "EM アルゴリズムの典型用途は。", "choices": ["線形回帰の解析解", "潜在変数を含むモデルの MLE（GMM など）", "勾配計算", "正則化選択"], "answer": 1, "explanation": "EM は潜在変数（クラスタ割当、隠れ状態）を含むモデルの反復 MLE。GMM, HMM, LDA, VAE の基礎。"}, {"q": "変分推論（VI）が最大化する量は。", "choices": ["尤度のみ", "ELBO（Evidence Lower BOund）", "クロスエントロピー", "距離"], "answer": 1, "explanation": "VIは事後分布 P(θ|D) を近似分布 q(θ;φ) で近似し、ELBO を最大化する。これは KL(q||P) 最小化と等価。VAE の損失の根拠。"}, {"q": "95% 信頼区間の正しい解釈は。", "choices": ["真値が 95% の確率でこの区間にある", "同じ手順を多数回繰り返すと 95% の区間が真値を含む", "必ず真値を含む", "効果量"], "answer": 1, "explanation": "頻度論の解釈は『同じ手順を繰り返すと』。①はベイズの『信用区間』の解釈で、頻度論では誤り。"}, {"q": "p値の正しい意味は。", "choices": ["H0 が真の確率", "H0 が真と仮定したとき、観測以上に極端な結果が得られる確率", "H1 が真の確率", "効果量"], "answer": 1, "explanation": "p値は条件付き確率 P(データ|H0)。『H0 が真の確率』ではない（よくある誤解）。p &lt; α で H0 棄却。"}, {"q": "多変量正規分布 N(μ, Σ) において Σ が満たすべき条件は。", "choices": ["対角行列", "対称かつ半正定値", "単位行列", "上三角"], "answer": 1, "explanation": "共分散行列は常に対称、必ず半正定値。これは共分散の定義から数学的に従う。"}, {"q": "分類器の確率出力（softmax）が真の確率と一致するように調整する手法を何と呼ぶか。", "choices": ["キャリブレーション（Platt Scaling、Isotonic、Temperature Scaling など）", "正則化", "標準化", "量子化"], "answer": 0, "explanation": "現代のNNは過信気味で、出力確率と真の頻度が一致しないことが多い。Calibration がそれを補正。Reliability Diagram, ECE で評価。"}, {"q": "ベイズ的 A/B テストの利点は。", "choices": ["p値だけが分かる", "『B が A より良い確率』など直観的な確率解釈ができ、逐次更新が自然", "サンプル不要", "必ず A が勝つ"], "answer": 1, "explanation": "事後分布から『P(B&gt;A)』が直接出る。逐次的なデータ追加で事前を更新でき、peeking 問題が起きにくい。"}, {"q": "多重検定の補正で最も保守的な手法は。", "choices": ["Bonferroni（α/m）", "FDR (Benjamini-Hochberg)", "Holm", "無補正"], "answer": 0, "explanation": "Bonferroni は α/m と最も厳しい。検出力は犠牲だが、FWER（少なくとも1つの偽発見の確率）を α 以下に保証。現代の標準は FDR（Benjamini-Hochberg）。"}]}, {"id": "basics-06-info-theory", "label": "章06 情報理論", "count": 20, "desc": "", "problems": [{"q": "確率 p で起こる事象の自己情報量は。", "choices": ["p", "-p", "-log p", "1-p"], "answer": 2, "explanation": "h(x) = -log P(x)。確率が小さいほど情報量が大きい。"}, {"q": "エントロピー H(X) が最大となるのは。", "choices": ["確定的", "一様分布", "最も歪んだ分布", "連続のみ"], "answer": 1, "explanation": "離散K値の場合、一様分布で H = log K が最大。確定的は H=0 で最小。"}, {"q": "公平なコインのエントロピーは。", "choices": ["0 bit", "0.5 bit", "1 bit", "2 bit"], "answer": 2, "explanation": "H = -(0.5 log₂0.5 + 0.5 log₂0.5) = 1 bit。公平コイン1回分の情報量＝1bit。"}, {"q": "相互情報量 I(X;Y) と H の関係で誤りはどれか。", "choices": ["I(X;Y) = H(X) + H(Y) - H(X,Y)", "I(X;Y) = H(X) - H(X|Y)", "I(X;Y) ≥ 0", "I(X;Y) は負の値も取りうる"], "answer": 3, "explanation": "相互情報量は常に非負（I≥0）。X,Y独立なら 0、強く依存するなら大きい値。"}, {"q": "KLダイバージェンス KL(p||q) について誤りはどれか。", "choices": ["常に非負", "p=q なら 0", "対称：KL(p||q) = KL(q||p)", "距離関数ではない"], "answer": 2, "explanation": "KL は非対称。これが距離関数でない理由。対称化したのが JS ダイバージェンス。"}, {"q": "クロスエントロピー H(p, q) と KL の関係は。", "choices": ["H(p,q) = H(p) - KL(p||q)", "H(p,q) = H(p) + KL(p||q)", "関係なし", "H(p,q) = KL(q||p)"], "answer": 1, "explanation": "CE = H(p) + KL(p||q)。H(p) は学習データ固定なので、CE最小化 = KL最小化 = q を p に近づける。"}, {"q": "NN の分類で『Softmax + CE 損失』が標準的に使われる理由として最も適切なのは。", "choices": ["計算が遅い", "多項分布のMLEと等価、勾配が ŷ-y で簡潔", "パラメータ数を減らす", "正則化のため"], "answer": 1, "explanation": "多項分布の負の対数尤度であり、ロジットへの勾配が ŷ-y となる美しい性質を持つ。これが NN 分類学習の効率を支える。"}, {"q": "決定木の分岐基準『情報利得（IG）』の定義は。", "choices": ["H(D) - H(D|A) （分割前後のエントロピー差）", "H(D) のみ", "Var(D)", "平均値"], "answer": 0, "explanation": "IG は属性Aで分割したときのエントロピー減少量。これが大きい属性を選ぶことで予測能力の高い分岐を作る。ID3/C4.5の基準。"}, {"q": "VAE の損失関数 -ELBO の構成として正しいのは。", "choices": ["再構成損失 + KL(q(z|x) || p(z))", "CE のみ", "MSE のみ", "正則化なし"], "answer": 0, "explanation": "-ELBO = 再構成損失 + KL正則化。エンコーダ出力が事前分布N(0,I)に近づくよう KL で正則化。"}, {"q": "t-SNE が最小化する量は。", "choices": ["ユークリッド距離", "高次元と低次元の分布の KL ダイバージェンス", "MSE", "Hinge損失"], "answer": 1, "explanation": "高次元での近傍類似度分布 P と低次元での Q の KL(P||Q) を最小化。クラスタを可視化する標準手法。"}, {"q": "『最大エントロピー原理』が示すのは。", "choices": ["与えられた制約条件下で最も不確実な分布を選ぶ", "最頻分布を選ぶ", "最頻値", "中央値"], "answer": 0, "explanation": "既知の制約以外について余計な仮定をしない原則。例：平均と分散だけ既知 → 正規分布が最大エントロピー解。"}, {"q": "微分エントロピーが離散エントロピーと異なる点で正しいのは。", "choices": ["負の値も取りうる", "必ず非負", "必ず整数", "必ず log K 以下"], "answer": 0, "explanation": "連続分布の微分エントロピーは負になりうる（例：分散が極小な正規分布）。スケール変換にも不変でない。"}, {"q": "Shannon の情報源符号化定理が示す下限は。", "choices": ["1記号あたり 1 bit", "1記号あたり log K bit", "1記号あたりエントロピー H(X) bit", "上限なし"], "answer": 2, "explanation": "平均符号長 ≥ H(X)。これがロスレス圧縮の理論的下限。Huffman 符号は H+1 までで実現。"}, {"q": "GAN（原論文）の損失関数が最小化する分布間距離は。", "choices": ["KL（forward）", "JSダイバージェンス", "MSE", "ユークリッド"], "answer": 1, "explanation": "Goodfellow の元のGANは JS ダイバージェンスを最小化することが示されている。Wasserstein GAN は別の距離（Wasserstein距離）を使う。"}, {"q": "相互情報量を使った特徴選択の利点は。", "choices": ["計算速度のみ", "線形・非線形両方の依存関係を捉える", "ピアソン相関の代替で線形のみ", "ラベル不要"], "answer": 1, "explanation": "Pearson相関は線形のみだが、MIは任意の関数関係（U字、二次、複雑な依存）を捉える。教師あり特徴選択で強力。"}, {"q": "エントロピーが大きい状況の例として最も適切なのは。", "choices": ["確定的シーン", "完全にランダムなビット列", "単一値の連続", "既知の数列"], "answer": 1, "explanation": "完全にランダム＝予測不能＝エントロピー最大。圧縮も不可能（log K bit/記号）。"}, {"q": "InfoNCE（対照学習で使う）の役割は。", "choices": ["CE損失と同じ", "正サンプルと負サンプルの間で相互情報量の下限を推定して最大化", "MSE", "正則化のみ"], "answer": 1, "explanation": "InfoNCE は対照学習（SimCLR, MoCo）の損失。表現空間で正ペア類似度を負ペアより高くする、MI下限の最大化として解釈可能。"}, {"q": "2分類タスクで真ラベル y=1、予測確率 p=0.8 のとき、二値CE損失は。", "choices": ["-log(0.8)", "-log(0.2)", "0.5", "1.0"], "answer": 0, "explanation": "CE = -[y log p + (1-y) log(1-p)]、y=1 なら CE = -log p = -log(0.8) ≈ 0.223。"}, {"q": "『Label Smoothing』は何を変更するか。", "choices": ["one-hotラベル y を [1-ε, ε/(K-1), ...] に置き換え、過信を防ぐ", "損失関数を別物に変更", "学習率", "バッチサイズ"], "answer": 0, "explanation": "真ラベルの確信度を 1.0 から 1-ε（典型 0.9）に下げる正則化。NNの過信を防ぎ、汎化を改善。情報論的にはエントロピーの底上げ。"}, {"q": "KL(p||q) と KL(q||p) が大きく違う典型的状況は。", "choices": ["単峰分布同士の中心ずれ", "多峰分布 vs 単峰分布", "全く同じ分布", "KLは常に対称"], "answer": 1, "explanation": "多峰の p を単峰の q で近似する場合、KL(p||q) は mode covering（q を広く）を要求し、KL(q||p) は mode seeking（q を一つに集中）を要求。VAEは reverse KL を使い結果として1つのモードに集中しやすい。"}]}, {"id": "basics-07-ml-paradigm", "label": "章07 ML パラダイム", "count": 20, "desc": "", "problems": [{"q": "教師あり学習の定義として正しいのは。", "choices": ["ラベルなしから学ぶ", "(入力, 正解) ペアからマッピングを学ぶ", "報酬から学ぶ", "学習しない"], "answer": 1, "explanation": "教師あり学習は (x, y) ペアから関数 y=f(x) を学習。分類と回帰が代表。"}, {"q": "K-means や PCA はどの学習パラダイムか。", "choices": ["教師あり", "教師なし", "強化学習", "自己教師あり"], "answer": 1, "explanation": "ラベルを使わずデータ構造（クラスタ、主成分）を見出す教師なし学習の代表。"}, {"q": "BERT の MLM や GPT の Next Token Prediction はどのパラダイムか。", "choices": ["教師あり", "教師なし", "自己教師あり（データから教師信号を作る）", "強化学習"], "answer": 2, "explanation": "大量のラベルなしテキストから、自分自身でマスク埋めや次トークン予測という『教師信号』を作って学習。現代基盤モデルの核。"}, {"q": "強化学習の中核要素は。", "choices": ["ラベル", "状態・行動・報酬・方策", "クラスタ", "ベクトル化"], "answer": 1, "explanation": "エージェントが状態s_tで行動a_tを取り、報酬r_tを得て次状態s_{t+1}へ。累積報酬を最大化する方策 π(a|s) を学習。AlphaGo, RLHF の根幹。"}, {"q": "訓練・検証・テストデータの主な役割として正しい組合せは。", "choices": ["訓練=学習、検証=ハイパラ選択、テスト=最終評価", "すべて同じ", "テストで学習", "検証はランダム"], "answer": 0, "explanation": "テストデータは『最終評価1回のみ』。検証で繰り返しチューニングしたあとに、初めて見るデータで本番性能を推定。"}, {"q": "『データリーク』が起きる典型例は。", "choices": ["時系列データを単純シャッフルで分割、全データで正規化、目的変数情報の混入", "大きすぎるバッチ", "学習率小さい", "パラメータ少ない"], "answer": 0, "explanation": "いずれもテスト情報の漏洩。本番性能を大幅に過大評価する致命的バグ。時系列は時間順分割、正規化は訓練データで計算してテストに適用。"}, {"q": "過学習（overfitting）の典型的サインは。", "choices": ["訓練・検証とも誤差大", "訓練誤差小、検証誤差大", "両方小", "ランダム"], "answer": 1, "explanation": "過学習は『訓練データを暗記して、未見データで失敗』。対処はEarly Stopping、Dropout、L2、データ拡張、Augmentation。"}, {"q": "バイアス-バリアンス分解で『バイアス大』を表す状況は。", "choices": ["モデルが複雑すぎ", "モデルが単純すぎて関数を表現できない（未学習）", "データ多すぎ", "正則化なし"], "answer": 1, "explanation": "Bias は『系統的な誤差』、モデルの表現力不足が原因。対処はモデル複雑化、特徴量追加、正則化緩和。"}, {"q": "5-fold Cross-Validation の目的は。", "choices": ["データ量を増やす", "モデル評価の分散を減らし安定化、ハイパラ選択の信頼性", "計算を減らす", "正則化"], "answer": 1, "explanation": "データを5分割し各回1つを検証に。5回の評価の平均で評価分散を抑える。小データで特に重要。"}, {"q": "高次元ハイパラ探索で Grid Search より Random Search が推奨される理由は。", "choices": ["Bergstra 2012：少数の重要パラメータを効率的に探索できる", "計算量が同じ", "ランダムは常に最適", "コードが短い"], "answer": 0, "explanation": "多くの場合、性能を支配するハイパラは少数。Grid は全格子点を試すが、無関係次元の試行が無駄。Random は重要次元を多くサンプリングできる。"}, {"q": "Bayesian Optimization の特徴は。", "choices": ["過去の試行結果からガウス過程で次の候補を予測、試行数を最小化", "ランダム", "厳密な数学なし", "Optuna は使えない"], "answer": 0, "explanation": "GP やTPE で予測平均と分散を考慮し『有望かつ未探索な点』を選ぶ。NN の学習など1試行が高コストな場合に強力。Optuna は TPE ベースで実装。"}, {"q": "転移学習（Transfer Learning）の典型的フローは。", "choices": ["事前学習（大規模データで自己教師あり）→ ファインチューニング（少量タスクデータ）", "ゼロから訓練のみ", "ハイパラ調整のみ", "ランダム"], "answer": 0, "explanation": "BERT/GPT/ViT すべてこの流れ。LLM ではIn-Context Learning, LoRA, RLHFなど発展形が多数。"}, {"q": "No Free Lunch（NFL）定理が示唆することは。", "choices": ["あるアルゴリズムが万能", "すべての可能な問題分布で平均すると、どのアルゴリズムも同性能 → 問題ごとに適した手法を選ぶ必要", "学習不要", "深層学習が最強"], "answer": 1, "explanation": "Wolpert 1996。実用問題が特定構造（画像・言語の局所性、自然法則）を持つから NN が機能するが、すべての問題に最強なアルゴリズムは数学的に存在しない。"}, {"q": "層化抽出（Stratified Sampling）が必要な典型ケースは。", "choices": ["クラス不均衡データの分類", "完全に均一なデータ", "連続値のみ", "時系列のみ"], "answer": 0, "explanation": "クラス比が偏った（陽性 1% など）データで単純ランダム分割すると検証セットに陽性が含まれない可能性も。層化で各分割のクラス比を均一に保つ。"}, {"q": "『Early Stopping』が機能する原理は。", "choices": ["訓練を最後まで続ける", "検証損失が悪化し始める前に学習を止めて過学習を防ぐ", "パラメータ削減", "データ拡張"], "answer": 1, "explanation": "訓練損失は単調減少するが検証損失は U字。最低点で止めると過学習せず汎化性能最大化。Patience（数エポック改善なしで停止）で実装。"}, {"q": "Few-shot Learning の典型は。", "choices": ["大量データで学習", "数〜数十サンプルで新タスクに適応（MAML, In-Context Learning）", "ゼロデータ", "パラメータ調整なし"], "answer": 1, "explanation": "限られたサンプルで新タスクに適応する手法。GPT-4 のIn-Context Learning はプロンプトの例から推論する強力な Few-shot 手法。"}, {"q": "マルチタスク学習の利点として誤りはどれか。", "choices": ["タスク間で知識共有", "各タスクで Bias を下げる効果", "正則化効果でVariance↓", "全てのタスクが互いに干渉して性能が必ず下がる"], "answer": 3, "explanation": "実際にはタスク間の知識共有でしばしば性能↑。ただし関連性のないタスク同時学習は『負の転移』を起こすことがある。"}, {"q": "『Double Descent』現象（深層学習で観察）の主張は。", "choices": ["モデル複雑度を上げ続けると、過学習を超えて再び汎化が改善する", "U字カーブのみ", "学習しない", "必ず単調減少"], "answer": 0, "explanation": "古典的 U字 の後に二度目の下降。過パラメータ化された NN が経験的に汎化することの一つの説明。Belkin 2019。"}, {"q": "半教師あり学習が威力を発揮する状況は。", "choices": ["ラベル付け不可", "ラベル付きデータが少ないがラベルなしデータは大量にある（医療画像など）", "全データラベル付き", "データなし"], "answer": 1, "explanation": "ラベル収集コストが高い領域で、ラベルなしデータを活用して学習を強化。Pseudo-Labeling, FixMatch, MixMatch などの手法。"}, {"q": "『時系列データ』を扱う際の正しい分割方法は。", "choices": ["ランダム k-fold", "時系列順に分割：過去で訓練、未来で検証・テスト（Time Series Split）", "シャッフル", "階層化"], "answer": 1, "explanation": "時系列の単純シャッフルは『未来を見て過去を予測』するデータリークの典型。常に時間順で分割。Expanding window / Rolling window などの手法がある。"}]}, {"id": "basics-08-ml-classical", "label": "章08 古典ML", "count": 20, "desc": "", "problems": [{"q": "線形回帰のOLS解析解は。", "choices": ["(XᵀX)⁻¹Xᵀy", "Xy", "X⁻¹y", "XᵀX"], "answer": 0, "explanation": "正規方程式 XᵀXβ = Xᵀy の解。XᵀX が可逆（フルランク）であることが条件。多重共線性で不安定化。"}, {"q": "ロジスティック回帰の出力は。", "choices": ["連続値", "確率 P(y=1|x)", "クラスタID", "ハードラベル"], "answer": 1, "explanation": "シグモイドで [0,1] に押込めた確率。0.5閾値でハードラベル化。"}, {"q": "SVM の最大化対象は。", "choices": ["学習データ数", "マージン（境界とサポートベクター間の距離）", "学習率", "パラメータ数"], "answer": 1, "explanation": "マージン = 2/||w|| の最大化。これは ||w|| 最小化に帰着、凸最適化問題。"}, {"q": "SVM のカーネルトリックが解決する問題は。", "choices": ["計算速度", "線形分離不可能なデータ（非線形特徴空間への暗黙写像）", "ノイズ除去", "データ拡張"], "answer": 1, "explanation": "K(x,x')=φ(x)·φ(x') で高次元への明示的写像なしに非線形分離。RBF, 多項式, シグモイドなどのカーネルが使われる。"}, {"q": "決定木の分岐基準（分類）として一般的なのは。", "choices": ["情報利得（エントロピー減少）、ジニ係数", "MSE のみ", "ランダム", "多数決"], "answer": 0, "explanation": "分類木では情報利得（ID3, C4.5）かジニ係数（CART）。回帰木では分散減少 or MSE。"}, {"q": "Bagging と Boosting の根本的違いは。", "choices": ["Bagging=並列・Variance削減、Boosting=逐次・Bias削減", "全く同じ", "Bagging が常に強い", "Boosting は弱学習器を使えない"], "answer": 0, "explanation": "Bagging は独立な弱学習器の平均で分散削減。Boosting は前の誤差を補正する逐次学習でバイアス削減。両者は相補的。"}, {"q": "ランダムフォレストが決定木より頑健な理由は。", "choices": ["1本の深い木を使う", "Bootstrap + 特徴量ランダム選択で木同士の相関を下げ、Variance削減", "学習が速い", "パラメータが少ない"], "answer": 1, "explanation": "2重のランダム性（データのBootstrap、各分岐での特徴量選択）で木の多様性を確保。100本の木の平均で過学習を抑える。"}, {"q": "表形式データでGBDT（XGBoost等）がNNより強い傾向にある主な理由は。", "choices": ["計算が遅い", "スケーリング不要、カテゴリ・欠損対応、不均衡データに頑健", "パラメータが多い", "メモリ消費が大きい"], "answer": 1, "explanation": "GBDTは表形式の特性に最適化。NNは特徴量の前処理に敏感で、表形式では性能発揮しにくい（一部例外：FT-Transformer、TabTransformer）。"}, {"q": "XGBoost、LightGBM、CatBoost の特徴対応として正しいのは。", "choices": ["XGBoostはGPUなし", "LightGBMは葉単位成長で高速", "CatBoostはカテゴリ非対応", "全て同じ"], "answer": 1, "explanation": "LightGBM はヒストグラム法＋Leaf-wise成長で超高速。XGBoost は精度志向、CatBoost はカテゴリ特徴を内蔵処理。"}, {"q": "k-NN の特徴として正しくないのは。", "choices": ["学習フェーズが軽量", "推論で全データを保持・距離計算が必要", "高次元で『距離の呪い』に弱い", "大規模データで超高速"], "answer": 3, "explanation": "k-NN は遅延学習で学習は速いが、推論で毎回全データとの距離計算が必要、大規模では遅い。Approximate NN（FAISS, HNSW）で実用化。"}, {"q": "K-means が苦手なケースは。", "choices": ["球状クラスタ", "異なるサイズ・密度・形状のクラスタ（非球状）", "数値データ", "教師あり"], "answer": 1, "explanation": "K-meansは球状クラスタを仮定（ユークリッド距離・等分散）。非球状や密度差・サイズ差があるとDBSCAN, GMM, HDBSCANが良い。"}, {"q": "K-means の初期化問題への対処は。", "choices": ["ランダム初期化のみ", "K-means++、複数回試行＋最良採用", "全データを初期点に", "1点のみ"], "answer": 1, "explanation": "K-means++ は初期点を順次最も遠い点から選ぶ。これにより局所最適確率を大幅に削減。sklearn の n_init で複数試行も標準。"}, {"q": "PCA の主成分の取得方法は。", "choices": ["ランダム", "共分散行列の固有値分解 or データのSVD", "k-NN距離", "勾配降下"], "answer": 1, "explanation": "共分散行列 Σ の固有値分解で主成分（固有ベクトル）。実装上は SVD で直接行うのが数値的に安定。"}, {"q": "DBSCAN の利点は。", "choices": ["クラスタ数 k を事前指定不要、任意形状、ノイズラベル付与", "球状のみ", "K指定必要", "学習なし"], "answer": 0, "explanation": "密度ベースでk不要、任意形状クラスタ検出、ノイズ点を明示的に分離。eps と min_samples のチューニングが鍵。"}, {"q": "Ridge と Lasso の違いとして正しいのは。", "choices": ["Ridge=L2でスパース、Lasso=L1で全保持", "Ridge=L2で全て縮小、Lasso=L1でスパース化", "同じ", "どちらも線形不可"], "answer": 1, "explanation": "Ridge は L2 ペナルティで全係数を縮小、Lasso は L1 ペナルティで多くを正確に 0 に（自動的特徴選択）。Elastic Net は両者のブレンド。"}, {"q": "SHAP（SHapley Additive exPlanations）の役割は。", "choices": ["学習アルゴリズム", "モデル解釈（各特徴量が予測にどう寄与したか）", "ハイパラ調整", "正則化"], "answer": 1, "explanation": "ゲーム理論のShapley値ベース。各特徴量の貢献を一貫した方法で説明。XAI（説明可能AI）の標準ツール。"}, {"q": "AdaBoost の仕組みは。", "choices": ["並列学習", "誤分類サンプルの重みを大きくして弱学習器を逐次学習", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Boosting の元祖。各回で誤分類点の重みを増やし、次の弱学習器が苦手部分に集中。XGBoostは Gradient Boosting の発展形。"}, {"q": "Stacking の典型構造は。", "choices": ["1つのモデルのみ", "複数モデルの予測を入力としてメタ学習器が最終予測", "多数決のみ", "ランダム"], "answer": 1, "explanation": "ベース学習器（GBDT、RF、ロジ回帰）の予測をメタ学習器（多くは線形）で統合。Kaggle上位の常套手段。CVの設計に注意。"}, {"q": "RFE（Recursive Feature Elimination）の役割は。", "choices": ["学習アルゴリズム", "特徴量を重要度の低い順から削除する反復的特徴量選択", "正則化", "クラスタ"], "answer": 1, "explanation": "モデルを学習→重要度を取得→最低の特徴量を削除→繰り返し。所望の特徴量数まで縮約。"}, {"q": "『Elbow法』が判定するものは。", "choices": ["学習率", "K-means のクラスタ数 k（クラスタ内分散の減少が緩むk）", "正則化強度", "過学習"], "answer": 1, "explanation": "k を 1, 2, 3... と増やし、SSE（クラスタ内分散和）をプロット。減少率が急変する『ひじ』を最適 k とする経験則。Silhouette score などより厳密な手法も。"}]}, {"id": "basics-09-ml-evaluation", "label": "章09 評価指標", "count": 20, "desc": "", "problems": [{"q": "混同行列の TP は何を意味するか。", "choices": ["真陽性（陽性を陽性と予測）", "偽陽性", "偽陰性", "真陰性"], "answer": 0, "explanation": "TP = True Positive。"}, {"q": "Precision の定義は。", "choices": ["TP/(TP+FN)", "TP/(TP+FP)", "TN/(TN+FP)", "(TP+TN)/全体"], "answer": 1, "explanation": "陽性予測のうち実際に陽性の割合。FPが増えると下がる。"}, {"q": "Recall（感度）の定義は。", "choices": ["TP/(TP+FN)", "TP/(TP+FP)", "TN/(TN+FP)", "(TP+TN)/全体"], "answer": 0, "explanation": "実際の陽性のうち検出できた割合。FN（見逃し）が増えると下がる。医療診断で重視。"}, {"q": "F1スコアの定義は。", "choices": ["算術平均", "P×R", "PとRの調和平均", "P/R"], "answer": 2, "explanation": "F1=2PR/(P+R)。両方が高くないと高くならない。"}, {"q": "スパム検知で『全て非スパム』予測で Accuracy 99% のモデルは。", "choices": ["良い", "完全に無価値（Recall=0、F1=0）", "完全分類器", "ベスト"], "answer": 1, "explanation": "不均衡データでの Accuracy の典型的な罠。F1・PR-AUC は0。"}, {"q": "ROC-AUC の意味として正しいのは。", "choices": ["訓練時間", "陽性-陰性ペアで陽性のスコアが高い確率", "Precisionの平均", "パラメータ数"], "answer": 1, "explanation": "AUCの確率的解釈。0.5=ランダム、1.0=完全。"}, {"q": "極端な不均衡（陽性率 0.1%）で適切な指標は。", "choices": ["Accuracy", "PR-AUC", "MSE", "R²"], "answer": 1, "explanation": "ROC-AUCは不均衡に頑健すぎて高く出るがPR-AUCは真の困難度を反映。"}, {"q": "医療診断で重視すべき指標は。", "choices": ["Precision", "Recall", "Specificity", "MSE"], "answer": 1, "explanation": "Recall でFN（見逃し）を最小化。"}, {"q": "スパムフィルタで重視すべきは。", "choices": ["Precision", "Recall", "両方", "Accuracy"], "answer": 0, "explanation": "Precision でFP（重要メール誤検出）を最小化。"}, {"q": "回帰指標で外れ値に頑健なのは。", "choices": ["MSE", "RMSE", "MAE", "MAPE"], "answer": 2, "explanation": "MAE は絶対値、外れ値の影響が線形。MSE は二乗で敏感。中間に Huber Loss。"}, {"q": "R²（決定係数）の意味は。", "choices": ["必ず0〜1", "1-SSE/SST、モデルが説明する分散の割合", "パラメータ数", "Accuracy"], "answer": 1, "explanation": "テストで負になることもある。"}, {"q": "NNの予測確率を真の頻度に合わせる手法は。", "choices": ["正則化", "Calibration（Platt、Isotonic、Temperature）", "標準化", "Augmentation"], "answer": 1, "explanation": "現代NNは過信気味。Calibrationで補正、ECEで評価。"}, {"q": "多クラス F1 で macro と weighted の違いは。", "choices": ["同じ", "macro は各クラス等値、weighted はクラス頻度で重み付け", "macroはスパース", "weightedは教師あり"], "answer": 1, "explanation": "不均衡では macro が公平、頻度反映なら weighted。"}, {"q": "推薦システムでの MAP@k の意味は。", "choices": ["全体精度", "上位k個のAverage Precisionの平均、ランキング品質指標", "MSE", "R²"], "answer": 1, "explanation": "NDCG とともに推薦・検索で標準。"}, {"q": "Log Loss と Accuracy の違いは。", "choices": ["同じ", "Log Lossは予測確率の質を評価（自信度を考慮）、Accuracyはハードラベルのみ", "Log Lossは離散", "Accuracyは確率"], "answer": 1, "explanation": "自信を持って間違えるほどLog Lossが高くなる。"}, {"q": "McNemar検定の用途は。", "choices": ["t検定の代替", "同一データに対する2モデル予測比較で差が有意か判定", "クラスタリング評価", "回帰分析"], "answer": 1, "explanation": "同データ・異モデルの予測一致／不一致を表で集計し検定。"}, {"q": "SMOTE が行うことは。", "choices": ["少数クラスを単純複製", "少数クラスのk近傍間に合成サンプルを補間生成", "多数クラスを削除のみ", "ランダム"], "answer": 1, "explanation": "単純複製と違い、合成データで多様性を保つ。imbalanced-learnで実装。"}, {"q": "Cross-Validation の主目的は。", "choices": ["データ拡張", "評価分散を減らしハイパラ選択の信頼性向上", "計算高速化", "ラベル予測"], "answer": 1, "explanation": "1回分割では運次第。k-foldで多数評価の平均で安定化。"}, {"q": "Focal Loss が解決する問題は。", "choices": ["過学習", "クラス不均衡＋簡単例の過剰寄与（物体検出由来）", "学習率", "正則化"], "answer": 1, "explanation": "-(1-p)^γ log p で容易例の損失を下げ、難しい例（少数クラス）に集中。RetinaNet で導入。"}, {"q": "分類閾値の標準値 0.5 を変える理由として正しいのは。", "choices": ["必ず0.5", "業務要件、不均衡、コスト非対称性に応じて最適化", "変えてはいけない", "モデル変更必要"], "answer": 1, "explanation": "0.5は単なる慣例値。F1最大化、期待コスト最小化などで決定。"}]}, {"id": "basics-10-nn-basics", "label": "章10 NN基礎", "count": 20, "desc": "", "problems": [{"q": "パーセプトロンが解けない代表的問題は。", "choices": ["AND", "OR", "XOR", "NOT"], "answer": 2, "explanation": "XORは線形分離不可能。Minsky 1969でこの限界が指摘され第一次AI冬の時代の一因に。MLPで解決。"}, {"q": "普遍近似定理（UAP）の主張は。", "choices": ["1層では何もできない", "1層の隠れ層でユニット数十分なら任意の連続関数を任意精度で近似可能", "必ず2層必要", "ReLUのみ"], "answer": 1, "explanation": "Hornik 1989, Cybenko 1989。ただし実用では深層化の方が指数的に効率良い。"}, {"q": "ReLU の利点で正しいのは。", "choices": ["計算が遅い", "勾配消失を緩和、計算高速、スパース化", "出力が(0,1)", "必ず連続微分可能"], "answer": 1, "explanation": "max(0,x)。x&gt;0で勾配1、入力側まで勾配が伝わる。深層化を可能にした立役者。"}, {"q": "Sigmoid 活性化関数の勾配消失の原因は。", "choices": ["微分の最大値が0.25と小さく、深層では勾配が指数的に減衰", "計算が複雑", "線形", "出力が-1から1"], "answer": 0, "explanation": "σ'(x) = σ(x)(1-σ(x))の最大が0.25。10層で 0.25¹⁰ ≈ 10⁻⁶。勾配が入力側でほぼ0に。"}, {"q": "BERT/GPT で標準的に使われる活性化関数は。", "choices": ["Sigmoid", "Tanh", "GELU（Gaussian Error Linear Unit）", "Hardmax"], "answer": 2, "explanation": "GELU(x) = x·Φ(x)。ReLUより滑らか、Transformer系で標準。Swish/SiLU も類似形状。"}, {"q": "Softmax 関数の役割は。", "choices": ["二値分類", "多クラスの確率分布出力（合計1、非負）", "ノイズ追加", "正則化"], "answer": 1, "explanation": "多クラス分類の出力層標準。CE損失と組み合わせると勾配が ŷ-y で簡潔。"}, {"q": "He初期化が想定する活性化関数は。", "choices": ["Sigmoid", "Tanh", "ReLU 系", "Softmax"], "answer": 2, "explanation": "He（Kaiming）初期化：W ~ N(0, 2/fan_in)。ReLU で半分が0になることを補正。Xavier/Glorot は Tanh/Sigmoid 用。"}, {"q": "NN の重みを全て 0 で初期化すると。", "choices": ["学習加速", "対称性により全ニューロンが同じ更新を受け、多様性が生まれず学習しない", "過学習", "高速"], "answer": 1, "explanation": "対称性破壊が必要で、ランダム初期化が必須。バイアスは0でもOK。"}, {"q": "残差接続（Skip Connection、ResNet）の主な役割は。", "choices": ["パラメータ削減", "勾配伝播の改善、超深層化を可能に", "メモリ節約", "計算高速化"], "answer": 1, "explanation": "y = F(x) + x で勾配がスキップ経路から直接伝わる。100層以上を可能にした。Transformerにも採用。"}, {"q": "ミニバッチ学習の利点として誤りはどれか。", "choices": ["計算効率", "GPU並列化", "ノイズが汎化に有利", "必ず大域最適に収束"], "answer": 3, "explanation": "SGD は確率的なので大域最適保証なし。実用では十分機能、むしろノイズが鞍点脱出に役立つ。"}, {"q": "Embedding 層の役割は。", "choices": ["数値の正規化", "離散カテゴリ（単語ID、ユーザID）を学習可能な連続ベクトルに変換", "損失計算", "出力層"], "answer": 1, "explanation": "単語ID → 128〜4096次元ベクトル。Word2Vec, BERT, GPT, 推薦システムで標準。"}, {"q": "多クラス分類で使う損失関数は。", "choices": ["MSE", "Hinge", "Cross Entropy（Softmax + CE）", "MAE"], "answer": 2, "explanation": "Softmax + CE が標準。多項分布の負の対数尤度と等価。"}, {"q": "Layer Normalization が Batch Normalization より好まれる場面は。", "choices": ["CNN", "バッチサイズが小さい、可変、または RNN/Transformer", "線形回帰", "K-means"], "answer": 1, "explanation": "BN はバッチ依存、小バッチで不安定。LN は1サンプル内で正規化、Transformer ・LLM で標準。"}, {"q": "『深層化』が UAP の単層拡大より有利な理由は。", "choices": ["単に流行", "同精度を達成するパラメータ数が指数的に少なくて済む（階層的特徴学習）", "計算高速", "ランダム性"], "answer": 1, "explanation": "Telgarsky 2016 等の理論。階層的に低レベル→高レベル特徴を学習でき、効率と汎化が良い。"}, {"q": "Dying ReLU 問題への対処は。", "choices": ["Sigmoid に戻す", "Leaky ReLU, ELU, GELU 等、x&lt;0でも小さな勾配を持つ関数", "学習停止", "入力反転"], "answer": 1, "explanation": "ReLU は x≤0 で勾配0、ニューロンが死んで復活しない。Leaky ReLU（α=0.01）, GELU で緩和。"}, {"q": "バッチサイズを大きくすると一般に。", "choices": ["必ず汎化が向上", "並列効率↑だが、ノイズが減って汎化やや悪化（シャープミニマへ）", "メモリ減", "学習率不要"], "answer": 1, "explanation": "大バッチは並列効率良いが、勾配ノイズ減でシャープなミニマに収束しやすく汎化が劣化する傾向。Linear Scaling Rule + Warmupで補正。"}, {"q": "Softmax+CE の logit に対する勾配は。", "choices": ["ŷ + y", "ŷ - y", "-y", "1"], "answer": 1, "explanation": "ŷ-y というシンプルな形。これがNN分類学習の計算効率の根拠。"}, {"q": "NN の汎化が良い理由として有力な仮説は。", "choices": ["神秘的", "SGDの暗黙的正則化、フラットなミニマの選好、データの多様体仮説", "ランダム", "パラメータ多いから良い"], "answer": 1, "explanation": "過パラメータ化されているのに汎化する『深層学習の謎』。SGDの確率性が良いミニマへ導く説明が有力。"}, {"q": "『計算グラフ』の概念は何のために使われるか。", "choices": ["可視化のみ", "自動微分の実装：演算をノードとして記録し、逆伝播で勾配を機械的に計算", "メモリ節約", "学習率"], "answer": 1, "explanation": "PyTorch, TensorFlow の自動微分の根幹。連鎖律を計算グラフ上で機械的に適用。"}, {"q": "バイアス項 b の役割は。", "choices": ["不要", "線形変換に平行移動を加え、原点を通らない決定境界を可能に", "正則化", "学習率"], "answer": 1, "explanation": "y = Wx + b の b。原点を通らない超平面を表現可能に。BNを使う層では省略することもある。"}]}, {"id": "basics-11-backprop", "label": "章11 逆伝播", "count": 20, "desc": "", "problems": [{"q": "逆伝播の数学的核心は。", "choices": ["線形回帰", "連鎖律（chain rule）を計算グラフ上で系統的に適用", "ランダム", "クラスタリング"], "answer": 1, "explanation": "dy/dx = (dy/du)(du/dx) を多層に適用、計算グラフのbackwardで自動化。"}, {"q": "逆伝播を実用化した1986年の論文の著者は。", "choices": ["Turing", "Rumelhart, Hinton, Williams", "Bengio", "LeCun"], "answer": 1, "explanation": "Nature論文『Learning representations by back-propagating errors』。多層NNの実用化を可能にした歴史的論文。"}, {"q": "100万パラメータNNで全勾配を計算するのに必要な順伝播・逆伝播の回数は。", "choices": ["100万回", "順伝播1回 + 逆伝播1回（合計でも O(N) パラメータ数）", "1000回", "ゼロ"], "answer": 1, "explanation": "これが逆伝播の真価。素朴な有限差分なら100万倍のコスト。reverse-mode auto-diff の効率性。"}, {"q": "Sigmoid 関数の微分は。", "choices": ["σ(x)", "σ(x)·(1-σ(x))", "1-σ(x)", "x"], "answer": 1, "explanation": "美しい形。最大値は σ(0)·(1-σ(0)) = 0.25。これが勾配消失の主因。"}, {"q": "ReLU の微分は。", "choices": ["常に1", "x&gt;0で1、x≤0で0", "x", "ランダム"], "answer": 1, "explanation": "x=0で厳密には微分不可能だが、実装で0または1を採用。シンプルさが計算効率に貢献。"}, {"q": "Softmax + CE の合成勾配が美しい形は。", "choices": ["p+y", "p-y", "p²", "y²"], "answer": 1, "explanation": "logit z への ∂L/∂z = (p - y_onehot) / N。シンプル＆数値安定。NN分類の計算効率の根拠。"}, {"q": "全結合層 z = Wx + b で、上流勾配 δ = ∂L/∂z から得られる ∂L/∂W は。", "choices": ["δ・x", "δ・xᵀ（外積）", "Wδ", "δ"], "answer": 1, "explanation": "形状 dₒᵤₜ × dᵢₙ。バッチでは Σ δᵢ·xᵢᵀ。∂L/∂b = δ, ∂L/∂x = Wᵀδ。"}, {"q": "NN学習で reverse-mode 自動微分が使われる理由は。", "choices": ["パラメータ数 ≫ 出力数（損失1つ）なので、forward-modeより遥かに効率的", "唯一の方法", "ランダム", "メモリ少ない"], "answer": 0, "explanation": "Forward は入力数に、Reverse は出力数に計算量が比例。NN は損失1つなので Reverse 一択。"}, {"q": "勾配消失の主因は。", "choices": ["学習率", "活性化関数の微分の積が層数で指数的に減衰（Sigmoid/Tanh）", "パラメータ数", "データ量"], "answer": 1, "explanation": "Sigmoid 微分最大 0.25、L層で 0.25^L。10層で 1e-6。ReLU、BN、ResNet で解決。"}, {"q": "勾配爆発の対処は。", "choices": ["学習率を上げる", "Gradient Clipping（勾配ノルムを上限でカット）", "何もしない", "パラメータ増加"], "answer": 1, "explanation": "RNN/Transformer で標準。||g|| &gt; threshold なら g ← g · threshold/||g||。閾値 1.0 が典型。"}, {"q": "SGD の更新式は。", "choices": ["θ ← θ + η・∂L/∂θ", "θ ← θ - η・∂L/∂θ", "θ ← ∂L/∂θ", "θ ← η・θ"], "answer": 1, "explanation": "勾配方向の逆（descent）に η（学習率）だけ動く。シンプルだが汎化が良いことがある。"}, {"q": "逆伝播でメモリを最も消費するのは。", "choices": ["パラメータ", "オプティマイザ状態", "順伝播の中間活性化（逆伝播で必要）", "損失値"], "answer": 2, "explanation": "各層の出力（B × D）を逆伝播のために保存。L 層では O(L·B·D)。これが大規模NN のメモリ消費の主因。"}, {"q": "Gradient Checkpointing の効果は。", "choices": ["計算高速化", "中間活性化を一部だけ保存し逆伝播で再計算、メモリ O(L)→O(√L)", "精度向上", "パラメータ削減"], "answer": 1, "explanation": "メモリと計算のトレードオフ（計算1.5倍）。LLM 学習で必須。PyTorch torch.utils.checkpoint で実装。"}, {"q": "Mixed Precision Training（FP16/BF16）の主な利点は。", "choices": ["精度向上", "GPU メモリ半減＆計算2〜3倍速、Tensor Coreを活用", "パラメータ削減", "ランダム性"], "answer": 1, "explanation": "FP16計算 + FP32重みコピー + Loss Scaling。BF16はダイナミックレンジが広く Loss Scaling 不要。LLM学習で標準。"}, {"q": "Data Parallel の動作は。", "choices": ["1GPUだけ使う", "各GPUに同じモデルコピー、ミニバッチを分割、勾配をAllReduceで集約", "モデルを分割", "ランダム"], "answer": 1, "explanation": "最も基本的な並列化。PyTorch DDP, Horovod。モデルがGPUに載るサイズなら最初の選択肢。"}, {"q": "勾配チェック（Gradient Check）の用途は。", "choices": ["学習加速", "解析的に計算した勾配と数値微分を比較し、実装バグを検出", "パラメータ削減", "必須学習"], "answer": 1, "explanation": "カスタム backward を書いたとき必須。差が 1e-7〜1e-5 オーダーなら正しい。学習中は遅いので無効化。"}, {"q": "PyTorch で勾配計算を有効化するには。", "choices": ["自動で有効", "requires_grad=True で作成、または .requires_grad_() で設定", "不可能", "ランダム"], "answer": 1, "explanation": "requires_grad=True の Tensor は計算グラフに含まれ、.backward() で勾配が記録される。.grad 属性で取得。"}, {"q": "ZeRO（DeepSpeed）が分散するのは。", "choices": ["モデルのみ", "オプティマイザ状態、勾配、パラメータを分散保持しメモリ削減", "データのみ", "ランダム"], "answer": 1, "explanation": "ZeRO-1：オプティマイザ状態、ZeRO-2：+勾配、ZeRO-3：+パラメータも分散。LLM学習で必須。"}, {"q": "Operator Fusion（Fused operations）の効果は。", "choices": ["精度向上", "連続した演算を1カーネルに融合、メモリ転送削減でGPU効率↑", "パラメータ削減", "ランダム"], "answer": 1, "explanation": "FlashAttention の核心。HBM ↔ SRAM 転送を減らす。Triton, CUDA Graph で実装。"}, {"q": "『Stop Gradient』の用途は。", "choices": ["学習停止", "計算グラフの一部で勾配を遮断（GAN、対照学習、強化学習の Target Network 等で必須）", "パラメータ削除", "ランダム"], "answer": 1, "explanation": ".detach() で実装。Target を更新せず参照だけしたいときに使う。BYOL、DQN、PPO で必須テクニック。"}]}, {"id": "basics-12-nn-tricks", "label": "章12 NNの工夫", "count": 20, "desc": "", "problems": [{"q": "L2 正則化（Weight Decay）が抑制するのは。", "choices": ["学習速度", "大きな重みの値、過学習", "計算量", "メモリ"], "answer": 1, "explanation": "L_total = L + λ||θ||² で大きな重みを罰し、汎化を改善。MAP推定でガウス事前に対応。"}, {"q": "Dropout の典型的なドロップ率は。", "choices": ["0.01", "0.1〜0.5", "0.9", "1.0"], "answer": 1, "explanation": "一般に 0.1〜0.5。隠れ層で 0.5、入力層で 0.2 が古典的。BN と併用するときは小さめにする傾向。"}, {"q": "Dropout の動作として正しいのは。", "choices": ["訓練時のみニューロンを確率的に無効化、推論時はすべて使用", "常に無効化", "推論でのみ動作", "パラメータ削減"], "answer": 0, "explanation": "訓練時のみドロップ、推論時は通常通り（スケール補正あり）。アンサンブル近似と解釈できる。"}, {"q": "Batch Normalization の正規化対象は。", "choices": ["単一サンプル内", "ミニバッチ内の各チャネルごと", "パラメータ自体", "学習率"], "answer": 1, "explanation": "ミニバッチ内で各特徴/チャネルごとに平均・分散を計算し正規化。バッチサイズ依存、Tiny バッチでは不安定。"}, {"q": "Transformer で標準的な正規化は。", "choices": ["BatchNorm", "LayerNorm（バッチサイズ非依存、系列長変化OK）", "なし", "Dropout"], "answer": 1, "explanation": "LayerNorm は単一サンプル内の特徴次元で正規化。可変長の系列、小バッチでも安定。最近は RMSNorm も（LLaMA 等）。"}, {"q": "He 初期化が適している活性化関数は。", "choices": ["Sigmoid", "tanh", "ReLU 系（Leaky ReLU、GELU を含む）", "Step"], "answer": 2, "explanation": "He（2015）は分散 2/n_in で、ReLU の片側 0 の性質を考慮。Xavier は Sigmoid/tanh 向け。LeCun は SELU 向け。"}, {"q": "Early Stopping の動作は。", "choices": ["訓練を必ず最終エポックまで", "検証損失が改善しなくなったら停止（過学習開始前）", "ランダム停止", "学習しない"], "answer": 1, "explanation": "Patience（数エポック改善なし）で停止。最も簡単で効果的な正則化。最良時のモデルを保存して使う。"}, {"q": "画像認識でよく使われる強力な自動データ拡張は。", "choices": ["反転のみ", "RandAugment、AutoAugment、TrivialAugment", "ノイズのみ", "なし"], "answer": 1, "explanation": "RandAugment は2つの操作を強度 9 でランダム適用。AutoAugment は RL で最適化された方策。深層学習の SOTA で標準。"}, {"q": "Label Smoothing が変更する対象は。", "choices": ["学習率", "one-hot ラベルを [ε/(K-1), 1-ε,...] に置換、過信抑制", "パラメータ数", "バッチサイズ"], "answer": 1, "explanation": "真ラベルの確信度を 1.0 から 1-ε（典型 0.9）に下げる。汎化改善＋過信抑制。ImageNet, NMT などで標準。"}, {"q": "Mixup の動作は。", "choices": ["単一サンプル", "2サンプルを λ:1-λ で線形混合、ラベルも同様に混合", "ノイズ加算", "パラメータ平均"], "answer": 1, "explanation": "Zhang 2018。画像とラベルを線形補間。決定境界を滑らかにし、汎化と頑健性を改善。CutMix は領域置換版。"}, {"q": "Gradient Clipping の目的は。", "choices": ["過学習防止", "勾配爆発防止（特に RNN/Transformer 学習）", "計算高速化", "メモリ削減"], "answer": 1, "explanation": "||g|| が閾値超過時にスケーリング。RNN の長系列・Transformer の大規模学習で標準（threshold=1.0 が典型）。"}, {"q": "Knowledge Distillation（蒸留）の目的は。", "choices": ["パラメータ増加", "大きな教師モデルの知識を小さな生徒モデルに転送", "ランダム学習", "クラスタリング"], "answer": 1, "explanation": "Hinton 2015。教師の softmax 出力（soft target）で生徒を学習。DistilBERT、TinyLLaMA、MobileBERT 等で軽量化に必須。"}, {"q": "Mixed Precision Training で主に使う型は。", "choices": ["FP32 のみ", "FP16 や BF16 と FP32 重みコピーの組合せ", "INT8 のみ", "INT4 のみ"], "answer": 1, "explanation": "計算は FP16/BF16、重みは FP32 で保持、損失スケーリングで underflow 防止。GPU メモリ半減、計算2-3倍速。BF16 はダイナミックレンジが広く実用的。"}, {"q": "Gradient Checkpointing（Activation Checkpointing）の効果は。", "choices": ["計算高速化", "順伝播の活性化を一部のみ保存し、逆伝播で再計算。メモリO(L) → O(√L)に", "精度向上", "学習率自動調整"], "answer": 1, "explanation": "メモリと計算のトレードオフ。LLM 学習では巨大モデルを限られた GPU で訓練するために必須。"}, {"q": "『Warmup』（学習率ウォームアップ）が必要な代表的状況は。", "choices": ["全ての状況", "Transformer 学習、大バッチ学習", "線形回帰", "K-means"], "answer": 1, "explanation": "初期の勾配が大きく不安定なため、η を 0 から徐々に上げる（数千ステップ）。Transformer、ViT、LLM 学習で必須。Cosine Annealing と組合せが標準。"}, {"q": "深層 CNN で勾配消失を抑制する主要技術として誤りはどれか。", "choices": ["ReLU", "残差接続", "Batch Normalization", "Sigmoid 活性化"], "answer": 3, "explanation": "Sigmoid は勾配消失の主要原因の一つ。ReLU、残差接続、BN、適切な初期化が勾配消失緩和の四天王。"}, {"q": "Stochastic Depth の動作は。", "choices": ["パラメータをランダムドロップ", "残差ブロックを確率的にスキップ（恒等写像に）", "学習率変化", "ノイズ加算"], "answer": 1, "explanation": "Huang 2016。残差NNの深さをランダム化することで正則化。100+ 層 ResNet で標準的に使われる。"}, {"q": "推論時に Dropout を有効にして複数回サンプリングする手法は何の推定に使うか。", "choices": ["高速化", "不確実性推定（Monte Carlo Dropout, Gal 2016）", "学習継続", "正則化"], "answer": 1, "explanation": "Yarin Gal が示した。推論時 Dropout で N 回サンプリング、出力の分散が予測不確実性の近似となる。ベイズ NN の安価な近似。"}, {"q": "『Cosine Annealing』学習率スケジューラの形状は。", "choices": ["直線的減少", "余弦関数で滑らかに減衰（T_max でゼロ近くに）", "階段状", "一定"], "answer": 1, "explanation": "lr = lr_max · (1+cos(π·t/T))/2 で滑らかに減衰。Warmup と組み合わせが現代学習の標準。SGDR で再起動版もある。"}, {"q": "AdamW が Adam と異なる主要な点は。", "choices": ["Momentumなし", "重み減衰を更新式の最後で適用（Adam の正則化と分離）、L2 正則化と等価に動作", "学習率を増やす", "Bias 補正削除"], "answer": 1, "explanation": "元の Adam で L2 を勾配に足すと2次モーメントとの相互作用で減衰効果が薄れる。AdamW は θ ← θ - η(m̂/√v̂ + ε) - η λ θ と最後で減衰、L2 と一致。LLM学習の事実上の標準。"}]}, {"id": "advanced-01-cnn", "label": "章13 CNN", "count": 20, "desc": "", "problems": [{"q": "CNN が MLP より画像処理に適している理由は。", "choices": ["計算が遅い", "空間的局所性と平行移動不変性の帰納バイアス、パラメータ共有でパラメータ削減", "学習が不安定", "メモリを大量に必要とする"], "answer": 1, "explanation": "CNN は同じフィルタを全位置で適用（パラメータ共有）し、近い画素関係を仮定。MLPの全結合に比べパラメータが2〜3桁少なく、性能も高い。"}, {"q": "2012年の AlexNet が ImageNet コンペで起こした革命の核心は。", "choices": ["浅い NN を使った", "深層CNN + ReLU + Dropout + GPU + データ拡張で従来手法を圧倒", "教師なし学習", "強化学習"], "answer": 1, "explanation": "Krizhevsky 2012。誤り率 15.3% vs 2位 26.2%。深層学習革命の起点となった。"}, {"q": "入力 32x32、3x3 Conv、stride=1、padding=1 のとき出力サイズは。", "choices": ["30x30", "32x32（same パディング）", "16x16", "34x34"], "answer": 1, "explanation": "(32 + 2·1 - 3) / 1 + 1 = 32。padding='same' で入力と同じサイズを維持。VGG以降で標準。"}, {"q": "Max Pooling の役割として正しいのは。", "choices": ["学習可能パラメータ追加", "領域内最大値を取り、空間ダウンサンプリング・平行移動不変性強化", "正則化のみ", "出力層"], "answer": 1, "explanation": "パラメータなし、空間次元削減、強い活性化を保持。Average Pooling より一般的。"}, {"q": "ResNet（2015）が解決した深層化の壁は。", "choices": ["計算量", "勾配消失と退化問題：残差接続 y=F(x)+x で 152層を学習可能に", "メモリのみ", "ラベル不足"], "answer": 1, "explanation": "He 2015。スキップ接続で勾配が直接伝播。ImageNet 誤り率 3.57%、人間（5.1%）超え。現代CNN/Transformerの標準構造。"}, {"q": "VGG の特徴的な設計は。", "choices": ["1x1 Conv のみ", "3x3 Conv のみを多層積み重ね（16〜19層）", "ランダム", "全結合のみ"], "answer": 1, "explanation": "Simonyan 2014。シンプルで強力。3x3 を 2層で 5x5 相当の受容野をパラメータ少なく実現する発見。"}, {"q": "『受容野（Receptive Field）』とは。", "choices": ["出力ピクセルが影響を受ける入力上の領域", "パラメータ数", "バッチサイズ", "学習率"], "answer": 0, "explanation": "深い層ほど受容野が広い。3x3 conv を 2層重ねると 5x5 受容野。Dilated Conv で更に拡大可能。"}, {"q": "EfficientNet (2019) の貢献は。", "choices": ["ランダム探索", "深さ・幅・解像度を複合スケーリングで最適化、同精度で大幅パラメータ削減", "教師なし", "ViT 提案"], "answer": 1, "explanation": "Tan & Le 2019。compound scaling で計算予算に対する精度効率を最大化。モバイル向けにも適用。"}, {"q": "Vision Transformer (ViT) の入力処理は。", "choices": ["画素単位", "画像を 16x16 などのパッチに分けてトークン化し Transformer に入力", "Conv のみ", "MLP のみ"], "answer": 1, "explanation": "Dosovitskiy 2020。CNN の帰納バイアスなしで、大量データ（JFT-300M）で CNN を超えた。CLIP、Stable Diffusion で標準。"}, {"q": "YOLO シリーズの特徴は。", "choices": ["2-stage", "1-stage：画像をグリッド分割し各セルで物体予測、リアルタイム", "教師なし", "セグメンテーション特化"], "answer": 1, "explanation": "Redmon 2016 で導入、YOLOv8/v10 まで進化。FPS が高く、産業応用で広く使われる。"}, {"q": "U-Net (2015) が広く使われる分野は。", "choices": ["物体検出", "医療画像セグメンテーション、エンコーダ-デコーダ＋スキップ接続", "言語モデル", "強化学習"], "answer": 1, "explanation": "Ronneberger 2015。U字型構造で詳細を保持。Diffusion モデル（DDPM、Stable Diffusion）の denoiser にも採用。"}, {"q": "転移学習（ImageNet → 別タスク）が機能する理由は。", "choices": ["偶然", "浅層が汎用的特徴（エッジ、テクスチャ）を学習、それは多くのタスクで再利用可能", "ランダム", "パラメータ多いから"], "answer": 1, "explanation": "階層的特徴学習。少量データのタスクで事前学習モデルをファインチューニングすると、ゼロから学習より大幅に高精度。"}, {"q": "Global Average Pooling (GAP) の役割は。", "choices": ["学習する", "各チャネルの空間平均でベクトル化、最終FC層代替、パラメータ削減", "ノイズ追加", "正則化のみ"], "answer": 1, "explanation": "NIN/ResNet以降で標準。Flatten + 巨大 FC をGAPで置換、過学習防止＋パラメータ削減。Class Activation Map の基礎にも。"}, {"q": "Grad-CAM の目的は。", "choices": ["学習加速", "予測根拠の可視化（どの画像領域がクラス予測に貢献したか）", "圧縮", "ノイズ除去"], "answer": 1, "explanation": "Selvaraju 2017。最終 Conv 層の勾配を使ってヒートマップを生成。XAI（説明可能AI）の標準ツール、医療画像で重要。"}, {"q": "1x1 Convolution（pointwise）の役割は。", "choices": ["役立たず", "チャネル間の線形結合、次元削減・拡張、Inception/ResNet で頻用", "プーリング代替", "正則化"], "answer": 1, "explanation": "空間方向は1x1で変えず、チャネル方向のみ変換。Bottleneck構造で計算量削減。MobileNet（Depthwise Separable Conv）でも核心。"}, {"q": "Segment Anything Model (SAM, 2023) の特徴は。", "choices": ["単一タスク", "プロンプト型セグメンテーション、未知物体も可、Foundation Modelとして広く転用可", "教師なしのみ", "軽量モデル"], "answer": 1, "explanation": "Meta AI 2023。点・ボックス・テキストプロンプトで任意の物体をセグメント。10億+のマスクで事前学習。"}, {"q": "DenseNet (2017) の特徴は。", "choices": ["全層をスキップ接続でなく完全に連結（dense connection）、特徴再利用と勾配伝播改善", "パラメータ激増", "浅い NN", "物体検出専用"], "answer": 0, "explanation": "Huang 2017。各層が前のすべての層の出力を入力に。パラメータ効率と精度が高い。"}, {"q": "物体検出の評価指標として標準的なのは。", "choices": ["Accuracy", "mAP（mean Average Precision）@IoU 0.5、0.5:0.95", "MSE", "R²"], "answer": 1, "explanation": "COCO標準。クラスごとの AP の平均、IoU 閾値で性能評価。YOLO, Faster R-CNN等の比較で使用。"}, {"q": "ConvNeXt (2022) の主張は。", "choices": ["ViTが万能", "CNNにViTの工夫（GELU、LN、大きなカーネル等）を取り入れれば、CNNがViTと同等以上の精度に", "Conv 不要", "教師なし"], "answer": 1, "explanation": "Liu 2022。ViT の優位性はアーキテクチャ自体ではなく、学習レシピと工夫にあると示唆。"}, {"q": "Dilated（Atrous）Convolution の効果は。", "choices": ["パラメータ増加", "カーネル内のサンプル間隔を空けて受容野を拡大、パラメータ・計算量は同じ", "ノイズ追加", "教師なし"], "answer": 1, "explanation": "DeepLab系で活用。セグメンテーションで詳細を保ちつつ広い文脈を捉える。"}]}, {"id": "advanced-02-rnn", "label": "章14 RNN・LSTM", "count": 20, "desc": "", "problems": [{"q": "RNNが MLP より系列データに適する理由は。", "choices": ["計算高速", "隠れ状態 h で過去の文脈を保持、可変長系列を扱える", "パラメータ多い", "教師なし"], "answer": 1, "explanation": "h_t = f(h_{t-1}, x_t) で過去情報を伝播、同じパラメータを全時刻で共有。"}, {"q": "BPTT（Backprop Through Time）の問題は。", "choices": ["不要", "長系列で計算・メモリ増、勾配消失/爆発", "教師なし限定", "学習しない"], "answer": 1, "explanation": "系列長Tに比例して計算が増え、勾配が指数的に減衰または爆発。Truncated BPTT、Gradient Clipping、LSTM/GRU で対処。"}, {"q": "勾配消失問題で『記憶できる時間』の典型は。", "choices": ["1ステップ", "Vanilla RNNでは 10〜20ステップが限界", "無限", "100万ステップ"], "answer": 1, "explanation": "tanh の勾配積が指数減衰。LSTM/GRU でこれを数百ステップまで拡大。"}, {"q": "LSTM のセル状態 c_t の特徴は。", "choices": ["隠れ状態と同じ", "加算更新で勾配が保存され、長期依存を学べる", "出力のみ", "ノイズ"], "answer": 1, "explanation": "c_t = f_t ⊙ c_{t-1} + i_t ⊙ c̃_t の加算ベース更新が勾配消失を緩和。これが LSTM の核心。"}, {"q": "LSTMの3つのゲートとして正しいのは。", "choices": ["入力、Conv、Pool", "忘却（forget）、入力（input）、出力（output）", "順、逆、双方向", "学習、推論、評価"], "answer": 1, "explanation": "Hochreiter & Schmidhuber 1997。Sigmoidゲートで情報の流れを制御。"}, {"q": "GRU がLSTMより優れる点は。", "choices": ["必ず高精度", "パラメータが少なく、計算高速、性能はほぼ同等", "ゲートなし", "双方向のみ"], "answer": 1, "explanation": "Cho 2014。リセットゲートと更新ゲートだけで2ゲート構造。実装簡素、性能はLSTMと拮抗。"}, {"q": "双方向RNN（Bi-LSTM）が使えない典型タスクは。", "choices": ["文分類", "NER", "言語モデル（次トークン予測、未来情報禁止）", "感情分析"], "answer": 2, "explanation": "生成・予測タスクは未来情報を使えない（カンニングになる）。分類・タグ付けには Bi-LSTM が長く標準。"}, {"q": "Seq2Seq モデルの構造は。", "choices": ["1個のRNN", "エンコーダ（入力→ベクトル）+ デコーダ（ベクトル→出力）", "CNN のみ", "MLP のみ"], "answer": 1, "explanation": "Sutskever 2014。機械翻訳、要約、対話の基本枠組み。固定長ベクトルがボトルネック、Attentionで解消。"}, {"q": "Attention（Bahdanau 2015）が解決した Seq2Seq の課題は。", "choices": ["学習速度", "固定長ベクトルのボトルネック、長文で性能劣化", "メモリ消費", "過学習"], "answer": 1, "explanation": "エンコーダ全時刻の隠れ状態にデコーダが重み付き参照。長文翻訳の品質が劇的改善。Transformer の母。"}, {"q": "Beam Search の役割は。", "choices": ["学習加速", "系列生成で上位 k 候補を保持して探索、Greedy より高品質", "正則化", "クラスタリング"], "answer": 1, "explanation": "翻訳・要約で標準。beam size 4〜8 で BLEU 2〜3 ポイント改善。LLM 生成では nucleus sampling 等の方が人気。"}, {"q": "Truncated BPTT の目的は。", "choices": ["精度向上", "長系列で計算・メモリを節約、一定ステップで切って勾配計算", "学習なし", "過学習防止"], "answer": 1, "explanation": "全系列のBPTTは不可能なので、典型 35〜200 ステップで切る。長期依存は LSTM/GRU の力で。"}, {"q": "勾配爆発の対処として有効なのは。", "choices": ["学習率を上げる", "Gradient Clipping（勾配ノルムを閾値で制限）", "パラメータ削除", "Sigmoid を使う"], "answer": 1, "explanation": "torch.nn.utils.clip_grad_norm_ で実装。閾値1.0〜5.0が典型。Transformer 学習でも常用。"}, {"q": "音声認識で 2020〜2026 の標準は。", "choices": ["古典GMM-HMM", "Whisper、Conformer など Transformer 系", "Bi-LSTM のみ", "K-means"], "answer": 1, "explanation": "Whisper（OpenAI 2022）が多言語SOTA。Conformer（Google）はTransformer+Convの組合せでオンライン認識に強い。"}, {"q": "時系列予測で Transformer 系の代表例は。", "choices": ["ResNet", "Informer、PatchTST、Temporal Fusion Transformer", "K-NN", "ARIMA"], "answer": 1, "explanation": "長系列・多変量を効率良く扱える。最近の研究では『単純MLPでもTransformerと同等』との指摘も（DLinear等）。"}, {"q": "2023 年以降、『RNN の系譜』を継ぐ新世代モデルは。", "choices": ["CNN", "Mamba（SSM）、RWKV、Linear Attention", "MLP のみ", "K-NN"], "answer": 1, "explanation": "Selective SSM (Mamba 2023) が Transformer に対抗、線形メモリ・長文脈で優位。RWKV は RNN ライクな並列学習。"}, {"q": "『Teacher Forcing』の意味は。", "choices": ["強制学習", "Seq2Seq学習時に、デコーダへの入力に過去のモデル出力ではなく『正解』を与える手法", "教師なし", "クラスタ"], "answer": 1, "explanation": "訓練効率を上げるが、推論時の自己回帰生成と乖離する『Exposure Bias』問題も。Scheduled Sampling が緩和策。"}, {"q": "BiLSTM-CRF が長く標準だったタスクは。", "choices": ["画像分類", "NER（固有表現抽出）、品詞タグ付けなどの系列ラベリング", "強化学習", "K-means"], "answer": 1, "explanation": "BiLSTM が文脈、CRF がラベル間依存関係を学習。BERT 登場（2018）まで最強。今もリソース制約環境で実用。"}, {"q": "機械翻訳の評価指標として標準的なのは。", "choices": ["Accuracy", "BLEU、METEOR、chrF、最近は COMET、BERTScore", "MSE", "R²"], "answer": 1, "explanation": "BLEU が古典標準、ただし表面文字列マッチで限界あり。LLM 時代は BERTScore、COMET 等の埋め込みベース指標が好まれる。"}, {"q": "2014〜2017 の機械翻訳の主流は。", "choices": ["ルールベース", "RNN+Attentionのニューラル機械翻訳（NMT）、Google翻訳が全面採用（2016）", "Transformer", "LLM"], "answer": 1, "explanation": "2017 年に Transformer 登場し急速に置換。現在は LLM が機械翻訳でも事実上の SOTA。"}, {"q": "CTC（Connectionist Temporal Classification）の用途は。", "choices": ["画像分類", "音声認識・手書き認識など、入力と出力の長さが異なる・整列がないタスクの損失関数", "強化学習", "クラスタ"], "answer": 1, "explanation": "Graves 2006。アラインメントを暗黙にマージしながら学習。RNN+CTC（DeepSpeech）が音声認識の標準だった。"}]}, {"id": "advanced-03-transformer", "label": "章15 Transformer", "count": 20, "desc": "", "problems": [{"q": "『Attention is All You Need』論文（2017）の革命性は。", "choices": ["CNN を提案", "RNN/Convolutionなしで Self-Attention のみで Seq2Seq を実現、並列化可能", "K-means 改良", "強化学習"], "answer": 1, "explanation": "Vaswani 2017、Google Brain。WMT 英→独 で SOTA、しかも RNN より高速。現代AIの基盤。"}, {"q": "Self-Attention の計算式は。", "choices": ["QV+K", "softmax(QKᵀ/√dₖ) V", "Q·K", "Σ Q·V"], "answer": 1, "explanation": "Scaled Dot-Product Attention。√dₖで割るのは数値安定性のため。"}, {"q": "Multi-Head Attention の利点は。", "choices": ["計算量削減", "異なる『観点』で並列に注目、表現力増加", "パラメータ削減", "教師なし"], "answer": 1, "explanation": "典型 8〜16 ヘッド。各ヘッドが構文、共参照、意味類似など異なる側面を学習。"}, {"q": "Transformer が Position Encoding を必要とする理由は。", "choices": ["高速化", "Self-Attentionは置換不変、位置情報を別途与える必要", "正則化", "教師信号"], "answer": 1, "explanation": "sin/cos の固定位置埋め込み（オリジナル）、学習可能埋め込み（BERT）、RoPE（LLaMA、相対位置）など。"}, {"q": "RoPE（Rotary Position Embedding）が現代LLMで採用される理由は。", "choices": ["学習不要", "相対位置を回転で表現、外挿性能と長文脈で優位", "計算最遅", "メモリ大"], "answer": 1, "explanation": "Su 2021。LLaMA, GPT-NeoX, PaLM 等で採用。長文脈学習・補間で優れる。"}, {"q": "Self-Attention の計算量は。", "choices": ["O(N)", "O(N · d)", "O(N² · d)", "O(N³)"], "answer": 2, "explanation": "N = 系列長、d = 次元。長文で爆発するため Flash Attention、Sparse Attention、Mamba 等で対処。"}, {"q": "FlashAttention の貢献は。", "choices": ["精度向上", "メモリO(N²) → O(N) の実装、GPU メモリ階層を活用", "教師なし", "ランダム"], "answer": 1, "explanation": "Dao 2022。SRAM/HBM のデータ移動を最小化。計算結果は数値的に同一、高速・低メモリ。長文脈 LLM 必須。"}, {"q": "Decoder の Causal Mask の役割は。", "choices": ["高速化", "生成時に未来のトークンを見せない（カンニング防止）", "正則化", "教師なし"], "answer": 1, "explanation": "Attention 行列の上三角を -∞ で埋める。GPT 系の自己回帰生成で必須。"}, {"q": "Encoder-only Transformer の代表例は。", "choices": ["GPT", "BERT、RoBERTa、DeBERTa", "T5", "ResNet"], "answer": 1, "explanation": "理解タスク（分類、NER、QA）に強い。MLM で事前学習。"}, {"q": "Decoder-only Transformer の代表例は。", "choices": ["BERT", "GPT、LLaMA、Claude、Mistral", "T5", "ViT"], "answer": 1, "explanation": "Next Token Prediction で事前学習。生成タスクの王者。現代 LLM のデファクト。"}, {"q": "Encoder-Decoder Transformer の代表例は。", "choices": ["GPT", "T5、BART、mT5、オリジナル Transformer", "BERT", "K-means"], "answer": 1, "explanation": "テキスト→テキスト変換に強い。要約、翻訳、QAを統一フレームで扱える（T5）。"}, {"q": "Layer Normalization が Transformer で標準採用される理由は。", "choices": ["高速", "バッチサイズ非依存、系列長変化OK、学習安定化", "パラメータ削減", "教師なし"], "answer": 1, "explanation": "Batch Norm はバッチ依存、可変長系列・小バッチで不安定。LayerNorm が Transformer の標準。最近は RMSNorm も（LLaMA）。"}, {"q": "Vision Transformer (ViT, 2020) の入力処理は。", "choices": ["画素単位", "画像を 16x16 などのパッチに分けてトークン化", "Conv のみ", "MLP のみ"], "answer": 1, "explanation": "Dosovitskiy 2020。CNN の帰納バイアスなしで、大量データなら CNN 超え。CLIP、Stable Diffusion 等で採用。"}, {"q": "Cross-Attention の用途は。", "choices": ["Encoder内", "Decoderが Encoder出力を参照、機械翻訳・要約で使用", "教師なし", "計算不要"], "answer": 1, "explanation": "Q を Decoder から、K/V を Encoder から。Encoder-Decoder アーキの架け橋。"}, {"q": "Pre-Norm と Post-Norm の違いは。", "choices": ["同じ", "Pre: y=x+Sub(LN(x)), Post: y=LN(x+Sub(x))、Pre が学習安定で現代LLM標準", "パラメータ違う", "学習なし"], "answer": 1, "explanation": "オリジナル Transformer は Post-Norm だが Warmup が必要。Pre-Norm（GPT-2 以降）は学習がより安定。"}, {"q": "KV Cache の役割は。", "choices": ["訓練加速", "自己回帰生成で過去トークンの K, V を保存して再計算回避、推論を大幅高速化", "正則化", "ノイズ"], "answer": 1, "explanation": "各トークン生成時、過去全トークンの K, V は変わらないため再利用。LLM 推論の効率化に必須。メモリは N に線形に増加。"}, {"q": "SwiGLU 活性化が LLaMA 等の現代 LLM で採用される理由は。", "choices": ["古典的", "Gated Linear Unit + Swish、ReLU/GELU より高性能", "計算最速", "教師なし"], "answer": 1, "explanation": "Shazeer 2020。SwiGLU(x) = (xW)⊙Swish(xV) で2つの線形変換のゲート積。LLaMA, PaLM 等で標準。"}, {"q": "『Sparse Attention』の戦略は。", "choices": ["全位置に注目", "一部位置だけに注目し計算量を O(N√N) や O(N log N) に削減", "教師なし", "Conv 化"], "answer": 1, "explanation": "Sparse Transformer、Longformer、BigBird、Reformer 等。長文脈モデルで重要、ただし Flash Attention + 通常 Attention で多くの場合十分。"}, {"q": "Mixture of Experts (MoE) の Transformer での利用は。", "choices": ["不要", "FFN を複数の Expert に分け、Router が選択。総パラメータ大、アクティブパラメータ小", "Attention のみ", "教師なし"], "answer": 1, "explanation": "GShard、Switch Transformer、Mixtral 8x7B、GPT-4 等で採用。スケーリングと計算効率の両立。"}, {"q": "Transformer が CNN/RNN に勝った根本的理由は。", "choices": ["帰納バイアスが弱く、大量データで純粋に学習できる（スケーリング有利）+ 並列計算可能", "計算量が少ない", "パラメータ少ない", "教師なし"], "answer": 0, "explanation": "CNN は局所性、RNN は逐次性の帰納バイアス。Transformer はそれらが弱い分、データから自由に学習可能でスケーリング則に最適。並列学習で計算リソース活用も容易。"}]}, {"id": "advanced-04-bert-gpt", "label": "章16 BERT・GPT", "count": 20, "desc": "", "problems": [{"q": "BERT の事前学習タスクで主要なものは。", "choices": ["次トークン予測", "Masked Language Model（MLM）と Next Sentence Prediction", "クラスタリング", "強化学習"], "answer": 1, "explanation": "入力の15%を [MASK] に置換し復元するMLMが核。NSPは後の改良（RoBERTa）で削除。"}, {"q": "GPT の事前学習タスクは。", "choices": ["MLM", "Next Token Prediction（因果的言語モデル）", "分類", "強化学習"], "answer": 1, "explanation": "左から右に次のトークンを予測する自己回帰モデル。生成タスクに自然に適合。"}, {"q": "BERT と GPT のアーキテクチャの違いは。", "choices": ["BERTはエンコーダ（双方向Attention）、GPTはデコーダ（因果Attention）", "全く同じ", "BERTはRNN", "GPTはCNN"], "answer": 0, "explanation": "どちらもTransformerベースだが、Attentionの方向と用途が異なる。理解はBERT、生成はGPTが得意。"}, {"q": "『事前学習＋微調整』パラダイムの利点は。", "choices": ["タスクごとに学習し直す必要なし、汎用言語知識を活用、少量データで高精度", "計算量が増える", "精度が下がる", "言語別必要"], "answer": 0, "explanation": "大規模事前学習1回 → 多タスクに転移。NLPを変革したパラダイム。"}, {"q": "BERT で使われる Tokenization は。", "choices": ["単語分割のみ", "WordPiece（サブワード分割）", "文字単位", "ランダム"], "answer": 1, "explanation": "WordPiece は未知語に強く、語彙サイズを抑える。'unhappiness' → 'un', '##happiness' のような分割。"}, {"q": "『RoPE（Rotary Position Embedding）』を採用しているLLMは。", "choices": ["BERT", "GPT-2", "LLaMA, GPT-NeoX 等の現代LLM", "T5"], "answer": 2, "explanation": "Su 2021。相対位置を回転で表現、長さ外挿に有利。LLaMA 系の標準。"}, {"q": "T5 が提唱した paradigm は。", "choices": ["RNN復活", "すべてのタスクを Text-to-Text として統一", "線形化", "ハードコーディング"], "answer": 1, "explanation": "分類も生成も翻訳もすべて『テキスト入力→テキスト出力』。プレフィックスでタスク指定。"}, {"q": "RoBERTa が BERT を改良した主要点は。", "choices": ["NSP削除、データ量と学習時間を大幅増、動的マスキング", "アーキテクチャ変更", "パラメータ削減", "Sigmoid化"], "answer": 0, "explanation": "Liu et al. 2019。アーキテクチャは同じだが学習レシピで GLUE 大幅改善。『正しく訓練』の重要性を示した。"}, {"q": "ELECTRA の事前学習タスクは。", "choices": ["MLM", "NTP", "Replaced Token Detection（置換されたトークンを識別）", "Clustering"], "answer": 2, "explanation": "生成器が置換したトークンを判別器が識別。MLMより学習効率良く、同パラメータで高性能。"}, {"q": "GPT-3 で注目された『In-Context Learning』とは。", "choices": ["パラメータ更新", "プロンプト内の数件の例から、新タスクを推論時に学習", "微調整", "クラスタリング"], "answer": 1, "explanation": "Few-shot Learning の革命。重みは変更せず、コンテキスト内の例だけでタスク適応。Brown 2020。"}, {"q": "『微調整』と『プロンプティング』の違いは。", "choices": ["同じ", "微調整=モデル重み更新、プロンプティング=入力テキストで指示（重み不変）", "どちらも教師なし", "必ず両方必要"], "answer": 1, "explanation": "微調整はGPU・データ必要、プロンプティングはAPI呼び出しのみ。実用ではプロンプトエンジニアリングが先、必要に応じて微調整。"}, {"q": "LoRA（Low-Rank Adaptation）の役割は。", "choices": ["学習率調整", "元モデルを凍結し、低ランク差分行列だけ学習し効率的微調整", "量子化", "クラスタ"], "answer": 1, "explanation": "Hu 2021。学習可能パラメータを1/10000に削減しつつ性能維持。LLM実用微調整の標準。QLoRAで4-bit量子化と組合せ。"}, {"q": "BERT の文埋め込み取得で[CLS]以外に良いとされる方法は。", "choices": ["ランダム", "全トークンのmean pooling", "1番目のトークンのみ", "不可能"], "answer": 1, "explanation": "[CLS] よりも全トークンの平均が下流タスクで強いことが多い。Sentence-BERT で標準化。"}, {"q": "GPT の生成サンプリングで『創造性と一貫性のバランス』を制御する典型パラメータは。", "choices": ["学習率", "Temperature、Top-p（Nucleus）、Top-k", "バッチサイズ", "Dropout"], "answer": 1, "explanation": "Temperature 低→決定的、高→多様。Top-p=0.9 で上位累積90%から選択、Hallucination抑制と多様性のバランス。"}, {"q": "GPT-3 の InstructGPT/ChatGPT で導入された手法は。", "choices": ["CNN", "RLHF（Reinforcement Learning from Human Feedback）で指示追従性を学習", "K-means", "Random Forest"], "answer": 1, "explanation": "人間のフィードバックで報酬モデルを学習し、PPO で方策を最適化。指示追従性と無害化の核心技術。"}, {"q": "BERT が最も得意なタスクは。", "choices": ["長文生成", "文章理解（分類、QA、NER）", "音楽生成", "画像認識"], "answer": 1, "explanation": "双方向 Attention で文脈理解が強い。SQuAD で人間超え、GLUEベンチマークを大幅刷新（2018）。"}, {"q": "『スケーリング則』（Kaplan 2020）の主張は。", "choices": ["パラメータ数だけが効く", "パラメータ・データ・計算の3軸でモデル性能が予測可能に改善", "ランダム", "関係なし"], "answer": 1, "explanation": "損失がパワーロー則で改善。これがGPT-3, GPT-4のスケール拡大を駆動。Chinchilla（DeepMind 2022）が最適配分を改良。"}, {"q": "SentencePiece が WordPiece より優れる点は。", "choices": ["必ず速い", "言語非依存、生のテキストから直接学習、空白を特殊文字として扱う", "英語専用", "なし"], "answer": 1, "explanation": "日本語・中国語のような空白区切りでない言語に強い。T5, mBART, ALBERTで採用。"}, {"q": "『MLM（Masked LM）』が双方向文脈学習を可能にする仕組みは。", "choices": ["ランダム", "マスクされたトークンを予測するため、両側の文脈を見る必要がある（因果制約なし）", "線形", "距離計算"], "answer": 1, "explanation": "『私は[MASK]を見た』の[MASK]を予測するには前後両方が必要。これがGPTの因果Attentionとの本質的違い。"}, {"q": "日本語特化の事前学習モデルとして代表的なものは。", "choices": ["全く存在しない", "東北大BERT、cl-tohoku/bert-base-japanese、rinna/japanese-gpt等", "GPT-1のみ", "ELMo"], "answer": 1, "explanation": "多言語BERTより日本語特化モデルが精度高いことが多い。最近はLLM（Swallow、Stockmark、ELYZA等）も日本語特化版が登場。"}]}, {"id": "advanced-05-llm", "label": "章17 LLM", "count": 20, "desc": "", "problems": [{"q": "『スケーリング則（Scaling Laws）』の主張は。", "choices": ["パラメータ数だけが効く", "パラメータ・データ・計算の3軸で損失がパワーロー則で改善", "関係なし", "ランダム"], "answer": 1, "explanation": "Kaplan et al. 2020。これがGPT-3, GPT-4 のスケール拡大を駆動。Chinchilla で最適配分が改良。"}, {"q": "『Chinchilla 最適化』（DeepMind 2022）が示した知見は。", "choices": ["必ずパラメータを増やせ", "計算予算が決まればパラメータとデータをほぼ同じスケールで増やすのが最適", "データ不要", "パラメータ削減"], "answer": 1, "explanation": "Hoffmann et al. それまでのLLMはパラメータ過大・データ不足。70Bモデル+1.4Tトークンが280Bを凌駕。LLaMA系がこの教訓を踏襲。"}, {"q": "『In-Context Learning（ICL）』とは。", "choices": ["微調整", "プロンプト内の例だけで推論時にタスク適応（パラメータ更新なし）", "クラスタリング", "強化学習"], "answer": 1, "explanation": "GPT-3 で発見された創発能力。Few-shot Learning の革命。"}, {"q": "『Chain-of-Thought』プロンプトが効果的なタスクは。", "choices": ["単純な事実検索", "多段推論（数学、論理パズル、複雑な計算）", "翻訳", "分類"], "answer": 1, "explanation": "『step by step』『let's think』で思考過程を出力させ、最終答えの質を向上。GSM8K等の数学で劇的改善。"}, {"q": "RLHF の3つのステップは。", "choices": ["SFT → 報酬モデル学習 → PPO で方策最適化", "学習なし", "強化学習のみ", "単純な教師あり"], "answer": 0, "explanation": "SFT で初期化、人間のランキングから報酬モデル、PPO（KL正則化付き）で最適化。InstructGPT/ChatGPT の核心。"}, {"q": "DPO（Direct Preference Optimization）の利点は。", "choices": ["RLHFと同じ", "報酬モデルもPPOも不要、CE風損失だけで好み学習が可能", "学習しない", "パラメータ削減"], "answer": 1, "explanation": "Rafailov 2023。RLHF より実装が大幅に簡単で性能同等以上、現代の標準。"}, {"q": "LLM の Hallucination（幻覚）対策として有効でないのは。", "choices": ["RAG（外部知識検索）", "Tool Use", "Citation", "学習率を上げる"], "answer": 3, "explanation": "学習率変更は事前学習段階の話。Hallucination は RAG, Tool Use, Self-Consistency, Citation, Calibration で対処。"}, {"q": "『MoE（Mixture of Experts）』の動作は。", "choices": ["すべてのパラメータ常時使用", "トークンごとに専門家サブネットを選択的アクティブ化（疎活性化）", "クラスタリング", "アンサンブル"], "answer": 1, "explanation": "総パラメータは巨大、計算は一部のみ。Mixtral、GPT-4（推定）、Gemini 1.5 で採用。スケール効率の鍵。"}, {"q": "LLM の評価ベンチマークで『多分野QA』に該当するのは。", "choices": ["HumanEval", "MMLU（57科目）", "GSM8K", "SWE-bench"], "answer": 1, "explanation": "MMLU は数学、歴史、医学等57分野の選択肢QA。HumanEval=コード、GSM8K=数学、SWE-bench=実コーディング。"}, {"q": "『Constitutional AI』（Anthropic）の特徴は。", "choices": ["学習なし", "原則のセットでモデル自身に出力を批判・修正させ、人間ラベルを最小化", "検索のみ", "パラメータ削減"], "answer": 1, "explanation": "Claude の核技術。AI Feedback（RLAIF）への発展。スケーラブルな安全性技術。"}, {"q": "Instruction Tuning（指示チューニング）の入力形式は。", "choices": ["(画像, ラベル)", "(指示, 入力, 出力) のペア", "クラスタ", "ラベルなし"], "answer": 1, "explanation": "FLAN、T0、Alpacaなど。多様なタスクの指示理解を学習。RLHFの前段。"}, {"q": "『創発的能力』とは何か。", "choices": ["全モデルが持つ", "パラメータ／計算が閾値を超えると突然現れる能力（多段推論、コーディング等）", "ランダム", "線形改善のみ"], "answer": 1, "explanation": "Wei et al. 2022。小モデルでは ≈0%、大モデルで急激に向上するタスクが存在。スケーリングの最も興味深い性質。"}, {"q": "長文文脈処理の効率化技術として該当するのは。", "choices": ["Dropout", "Flash Attention、KV Cache、Sparse Attention、PagedAttention", "Sigmoid", "K-means"], "answer": 1, "explanation": "Attention の O(n²) を抑えてメモリ・計算効率化。100万トークン超の文脈（Gemini 1.5, Claude 3.7）を可能にした。"}, {"q": "o1/o3 など『推論モデル』の特徴は。", "choices": ["高速応答のみ", "テスト時に長い思考過程を生成して推論精度を向上、数学・コーディングで SOTA", "学習しない", "ラベル不要"], "answer": 1, "explanation": "CoT を内部化、テスト時の計算量増で性能向上。新しいスケーリング軸（テスト時計算）の発見。"}, {"q": "LLM の温度（temperature）パラメータの意味は。", "choices": ["モデルサイズ", "Softmaxを T で割って分布の鋭さを調整。低い=決定的、高い=多様", "パラメータ数", "学習率"], "answer": 1, "explanation": "創造性と一貫性のバランス。T=0で貪欲、T=1で標準、T=2で創造的だがHallucination増。"}, {"q": "『Top-p Nucleus Sampling』の動作は。", "choices": ["全ての候補から", "累積確率が p になるまで上位トークンを選び、その中からサンプリング", "必ず1位", "ランダム"], "answer": 1, "explanation": "Top-k よりも適応的。低確率の長い裾を切り落としつつ多様性確保。p=0.9 が典型。"}, {"q": "LLM 微調整の効率技術『LoRA』が更新するパラメータは。", "choices": ["全パラメータ", "元の行列に低ランク差分（A·B、ランクr）を加え、その差分のみ学習", "凍結のみ", "ランダム"], "answer": 1, "explanation": "学習可能パラメータを 0.1〜1% に削減。QLoRA で 4-bit 量子化と組合せ、コンシューマGPUで70Bモデル微調整可能に。"}, {"q": "LLM の『指示追従性』を実現する手法は。", "choices": ["単なる事前学習", "Instruction Tuning + RLHF（または DPO）", "線形化", "クラスタ"], "answer": 1, "explanation": "事前学習だけでは『次のトークン予測機』にすぎない。指示理解と安全性は Instruction Tuning + RLHF で獲得。"}, {"q": "『Self-Consistency』の手法は。", "choices": ["1回サンプリング", "同じ問題を複数回CoTでサンプリングし、最頻の答えを選ぶ", "線形回帰", "クラスタリング"], "answer": 1, "explanation": "Wang 2022。数学推論で CoT+Self-Consistency が CoT 単独より大幅に強い。複数の思考経路の多数決。"}, {"q": "『Knowledge Cutoff』とは。", "choices": ["計算リソース上限", "LLM が事前学習した時点までしか知識を持たないという制約", "パラメータ数", "学習率"], "answer": 1, "explanation": "GPT-4o は2024年初頭まで、Claude 3.7 は2025年初頭までなど。新しい情報は RAG, Web 検索、Tool Use で補完。"}]}, {"id": "advanced-06-generative", "label": "章18 生成AI", "count": 20, "desc": "", "problems": [{"q": "GAN の基本構造は。", "choices": ["エンコーダのみ", "Generator と Discriminator の敵対的学習", "デコーダのみ", "クラスタリング"], "answer": 1, "explanation": "Goodfellow 2014。Generator が偽画像、Discriminator が真偽判定、min-max ゲーム。"}, {"q": "GAN の典型的な問題で『多様性が失われる』現象を何と呼ぶか。", "choices": ["過学習", "モード崩壊（Mode Collapse）", "勾配消失", "不確実性"], "answer": 1, "explanation": "Generator が騙しやすい一部モードに局所最適。WGAN-GP、Spectral Normalization、Mini-batch Discrimination で対策。"}, {"q": "VAE の損失関数 ELBO は何と何の組合せか。", "choices": ["再構成損失 + KL ダイバージェンス（事前との距離）", "MSE のみ", "Hinge", "敵対的損失"], "answer": 0, "explanation": "ELBO = 再構成 - KL(q(z|x)||p(z))。再構成精度と潜在分布の事前 N(0,I) への近さのバランス。"}, {"q": "Diffusion Model の学習は何を予測するか。", "choices": ["ラベル", "画像に加えられたノイズ（または score = ∇log p(x)）", "クラスタ", "Bounding Box"], "answer": 1, "explanation": "各タイムステップで NN がノイズを予測し、それを差し引いて x_{t-1} を得る。これを T 回繰り返してノイズから画像復元。"}, {"q": "Stable Diffusion の核心技術は。", "choices": ["ピクセル空間のDiffusion", "Latent Diffusion（VAEで圧縮した潜在空間で Diffusion）", "GAN", "Flow"], "answer": 1, "explanation": "Rombach 2022。512×512 を 64×64 潜在に圧縮し、計算量1/64に。コンシューマGPUで動作可能に。"}, {"q": "ControlNet の役割は。", "choices": ["高速化", "Stable Diffusion に追加制約（姿勢、深度、エッジ）を与えて生成を制御", "パラメータ削減", "学習率自動"], "answer": 1, "explanation": "Zhang 2023。骨格→人物、線画→塗り絵、深度→立体感のある画像など。生成の制御性を劇的向上。"}, {"q": "『Classifier-Free Guidance（CFG）』の役割は。", "choices": ["分類器学習", "条件付き/無条件のスコア差を増幅、テキスト指示への忠実度を高める", "クラスタ", "学習率"], "answer": 1, "explanation": "Ho 2022。guidance_scale パラメータで強さを調整。7-10 が典型、高すぎると過剰でアーティファクト発生。"}, {"q": "DALL-E 2 の主な構成要素は。", "choices": ["CNN のみ", "CLIP（テキスト・画像埋め込み）＋ Diffusion （prior + decoder）", "RNN のみ", "K-means"], "answer": 1, "explanation": "CLIP埋め込みを介してテキストと画像を結ぶ、unCLIP アーキテクチャ。"}, {"q": "画像生成評価の代表的指標『FID』は何を測るか。", "choices": ["学習速度", "Inception 特徴量で実画像分布と生成画像分布の距離", "クラス数", "パラメータ数"], "answer": 1, "explanation": "Fréchet Inception Distance。画像品質と多様性を一値に集約。低いほど良い。"}, {"q": "『CLIP Score』が評価するのは。", "choices": ["画像品質のみ", "テキストプロンプトと生成画像の意味的整合性", "計算速度", "ファイルサイズ"], "answer": 1, "explanation": "CLIP モデルの埋め込み類似度。プロンプト忠実度の標準指標。"}, {"q": "Sora や Veo は何のためのモデルか。", "choices": ["音楽生成", "動画生成（テキスト→1分以上の高品質動画）", "顔認識", "文章生成"], "answer": 1, "explanation": "OpenAI Sora（2024）、Google Veo。Diffusion Transformer ベース、物理理解・長時間生成が特徴。"}, {"q": "Whisper（OpenAI）の用途は。", "choices": ["画像生成", "多言語音声認識（STT）", "TTS", "翻訳のみ"], "answer": 1, "explanation": "Speech-to-Text の多言語モデル。99言語対応、ノイズに頑健。オープンウェイト。"}, {"q": "VQ-VAE の特徴は。", "choices": ["連続潜在", "離散コードブックで潜在表現、画像・音声生成や Tokenizer で活用", "線形変換", "ノイズなし"], "answer": 1, "explanation": "連続潜在を離散コードに量子化。Audio LM、画像 Tokenizer などで使用。"}, {"q": "Normalizing Flow の利点は。", "choices": ["厳密な尤度計算が可能（可逆変換）", "高速生成", "パラメータ少", "学習不要"], "answer": 0, "explanation": "可逆な変換 f: z → x を学習し、変数変換公式で厳密尤度。GANやVAEと違い密度評価可能。画像品質は Diffusion に劣る。"}, {"q": "Diffusion Models の高速化『Distillation』が達成するのは。", "choices": ["学習速度のみ", "50ステップを 1-4 ステップに圧縮、リアルタイム生成可能に", "パラメータ削減", "不可能"], "answer": 1, "explanation": "教師モデルから生徒モデルへの蒸留。SDXL Turbo、LCM などでリアルタイム画像生成（30fps）が可能に。"}, {"q": "LoRA を Diffusion に適用する利点は。", "choices": ["全パラメータ学習", "10-100枚の画像で特定キャラ/スタイル学習、数MBで配布可能", "高速学習不可", "精度低下"], "answer": 1, "explanation": "Civitai 等で大量のLoRA公開、コミュニティが活発。Stable Diffusion カスタマイズの主流。"}, {"q": "StyleGAN の特徴は。", "choices": ["全結合のみ", "スタイル（属性）と画像内容を分離、高解像度顔生成、潜在空間編集", "線形", "RNN"], "answer": 1, "explanation": "NVIDIA、Karras 2019。ThisPersonDoesNotExist のあの顔。潜在空間の意味的編集（笑顔強度、年齢など）。"}, {"q": "音楽生成モデル MusicGen は何で学習されているか。", "choices": ["画像のみ", "大量の楽曲とテキスト説明のペア、自己回帰モデル", "ランダム", "MIDI のみ"], "answer": 1, "explanation": "Meta、2023。テキスト→音楽の Transformer ベース。Suno、Udio などのサービスも類似アプローチ。"}, {"q": "生成 AI の社会的課題として該当しないのは。", "choices": ["ディープフェイク", "著作権", "バイアス", "必ず物理法則を守る"], "answer": 3, "explanation": "生成モデルは物理法則を必ずしも守らない（手指の数間違い、不自然な液体運動など）。Sora は改善したが完璧でない。"}, {"q": "Diffusion Model が現在 GAN を凌駕している主な理由は。", "choices": ["学習が速い", "学習安定、高品質、多様性確保、テキスト条件付け容易、スケール可能", "パラメータ少", "メモリ少"], "answer": 1, "explanation": "GANの不安定学習・モード崩壊の問題なし、Diffusion Transformer でスケール可能（Sora）。現代生成AIの主流。"}]}, {"id": "advanced-07-rl", "label": "章19 強化学習", "count": 20, "desc": "", "problems": [{"q": "MDP の5要素（S, A, P, R, γ）の γ は何か。", "choices": ["学習率", "割引率（将来報酬の現在価値）", "探索率", "ノイズ"], "answer": 1, "explanation": "γ ∈ [0,1)。0.99 が典型。1なら無限地平の累積発散、0なら短期報酬のみ重視。"}, {"q": "Q-Learning がオフポリシーである理由は。", "choices": ["学習しない", "行動方策と異なる方策（最適）を学習可能、更新で max を使う", "オンライン", "モデルベース"], "answer": 1, "explanation": "Q(s,a) ← Q + α[r + γ max Q(s', a') - Q]。max を使うので実際の次行動と独立。SARSAはオンポリシー。"}, {"q": "DQN（DeepMind 2015）の核心的貢献は。", "choices": ["教師あり", "Experience Replay + Target Network で深層NN+RL を安定化、Atari 49ゲーム人間超え", "教師なし", "クラスタリング"], "answer": 1, "explanation": "Mnih et al. 2015 Nature。これが Deep RL 革命の始まり。"}, {"q": "AlphaGo の構成要素として正しいのは。", "choices": ["教師あり学習のみ", "Policy Net + Value Net + MCTS + 自己対戦RL", "Q-tableのみ", "ランダム"], "answer": 1, "explanation": "人間棋譜での教師あり初期化＋自己対戦RL強化＋モンテカルロ木探索による推論時計画。2016年世界トップ棋士を破る。"}, {"q": "AlphaZero が AlphaGo と異なる点は。", "choices": ["教師データ不要、純粋自己対戦のみ", "より小さなNN", "MCTS不使用", "教師あり強化"], "answer": 0, "explanation": "ルールだけからゼロベース自己対戦、人間データ完全不要。囲碁・将棋・チェスすべて同一アーキテクチャでトップ性能。"}, {"q": "PPO（Proximal Policy Optimization）の特徴は。", "choices": ["クリップ損失で方策更新を安定化、実装簡単で汎用性高い", "オンポリシーのみ", "Q-tableのみ", "ランダム"], "answer": 0, "explanation": "OpenAI 2017。L^CLIP = E[min(rA, clip(r, 1-ε, 1+ε)A)]。RLHFの主力アルゴリズム、現代RL標準。"}, {"q": "RLHF（ChatGPT/Claudeで使用）の3ステップは。", "choices": ["SFT → 報酬モデル → PPO", "教師あり → 教師なし → 強化", "事前 → 中間 → 微調整", "Pretrain → Fine-tune → Distill"], "answer": 0, "explanation": "Supervised Fine-Tuning → Reward Model（人間ランクで学習）→ PPO で報酬最大化。InstructGPT (2022) で確立。"}, {"q": "DPO（Direct Preference Optimization、2023）の利点は。", "choices": ["計算重い", "報酬モデル不要で嗜好データから直接最適化、PPOより安定で簡単", "教師あり不要", "必ず劣る"], "answer": 1, "explanation": "Rafailov 2023。報酬モデル+PPOの2段階を1段階に。Llama-2-Chat、Mistral、Zephyr などで採用。最近のRLHF主流。"}, {"q": "価値関数 V(s) と Q(s,a) の違いは。", "choices": ["同じ", "V は状態の価値、Q は(状態,行動)の価値", "V は数値、Q は関数", "V は離散"], "answer": 1, "explanation": "V(s) = E[累積報酬|s]、Q(s,a) = E[累積報酬|s,a]。関係：Vπ(s) = Σ π(a|s) Qπ(s,a)。"}, {"q": "Bellman 最適方程式 V*(s) = max_a Σ P(s'|s,a)[R + γV*(s')] が示すのは。", "choices": ["最適価値の再帰関係", "ランダム", "教師ラベル", "必ず線形"], "answer": 0, "explanation": "最適価値は『最善の次行動の期待値』として再帰的に定義。Value Iteration、DQN学習の基礎。"}, {"q": "ε-greedy の役割は。", "choices": ["学習率", "探索と活用のバランス（εでランダム、1-εで最良Q行動）", "正則化", "クラスタ"], "answer": 1, "explanation": "探索（未知行動を試す）と活用（既知の良い行動を取る）のトレードオフ。実用では学習進行で ε を減衰。"}, {"q": "Actor-Critic アーキテクチャは何の組合せか。", "choices": ["教師あり+教師なし", "方策（Actor）+ 価値関数（Critic）", "クラスタ+回帰", "DQN+SARSA"], "answer": 1, "explanation": "Actor が行動、Critic が状態を評価。分散低減で安定学習。A2C/A3C/PPO/SAC の基礎。"}, {"q": "『マルコフ性』とは。", "choices": ["過去履歴を全て参照", "次状態は現在状態と行動のみに依存（過去履歴不要）", "必ず連続", "線形"], "answer": 1, "explanation": "P(s_{t+1}|s_t, a_t) = P(s_{t+1}|s_t, a_t, history)。POMDP（部分観測）では緩和される。"}, {"q": "スパース報酬問題への対処として正しいのは。", "choices": ["学習率を上げる", "Reward Shaping、Curiosity-driven exploration（RND, ICM）、HER", "教師あり化", "クラスタ"], "answer": 1, "explanation": "報酬がほとんど0のタスク（Montezuma's Revenge等）で重要。内発的動機付け（好奇心）、後付け目標（HER）で対処。"}, {"q": "モデルベース RL とモデルフリー RL の違いは。", "choices": ["同じ", "モデルベースは環境モデル(P, R)を学習・利用、モデルフリーはサンプルから直接学習", "教師あり vs 教師なし", "速度"], "answer": 1, "explanation": "モデルベース（MuZero、Dreamer）はサンプル効率が良いがモデル誤差影響。モデルフリー（DQN、PPO）はシンプル、サンプル多。"}, {"q": "『継続的なエピソードでは γ &lt; 1 が必要』な理由は。", "choices": ["計算簡単化", "無限和の収束保証、近未来優先", "ランダム性", "単純化のみ"], "answer": 1, "explanation": "γ=1 だと累積和が発散。γ&lt;1で幾何級数として収束。0.9〜0.999が典型。"}, {"q": "MuZero（DeepMind 2020）の特徴は。", "choices": ["教師あり", "環境モデル自体も学習、ルール未知のAtariでもMCTS可能", "Q-table", "ランダム"], "answer": 1, "explanation": "AlphaZero は環境ルール既知、MuZero はルールも学習。汎用性大幅向上。"}, {"q": "SAC（Soft Actor-Critic）が連続行動空間で強い理由は。", "choices": ["離散のみ", "最大エントロピー原理で探索促進、決定的方策より安定", "Q-tableのみ", "教師あり"], "answer": 1, "explanation": "Haarnoja 2018。報酬最大化＋エントロピー最大化で探索維持。ロボット制御などで人気。"}, {"q": "ChatGPT のような LLM チャットボットの応答品質を人間嗜好に合わせる手法は。", "choices": ["単なる教師あり", "RLHF（または DPO）", "クラスタリング", "線形回帰"], "answer": 1, "explanation": "RLHF（InstructGPT 2022）。人間嗜好を反映する強化学習で、有害性削減・有用性向上。最近は DPO で簡略化。"}, {"q": "強化学習の典型的応用として誤りはどれか。", "choices": ["ゲーム（AlphaGo, AlphaStar）", "ロボット制御", "LLM の人間嗜好調整", "静的な画像分類"], "answer": 3, "explanation": "画像分類は典型的に教師あり。RLは『連続的意思決定』『報酬最大化』が要。ゲーム、ロボット、自動運転、推薦、RLHFが代表。"}]}, {"id": "advanced-08-rag", "label": "章20 RAG", "count": 20, "desc": "", "problems": [{"q": "RAG が解決する LLM の主な弱点は。", "choices": ["計算速度", "知識カットオフ、幻覚、私的データ非対応", "パラメータ数", "メモリ"], "answer": 1, "explanation": "LLM の学習データ以降の知識・自社データ・幻覚（誤情報生成）を、関連文書検索で補完。"}, {"q": "RAG パイプラインの基本構成は。", "choices": ["クラスタ→分類", "Embed → Vector DB 検索 → 文脈付き LLM プロンプト → 回答", "Fine-tune のみ", "ランダム"], "answer": 1, "explanation": "Lewis 2020。質問を埋め込み、Vector DB から類似文書取得、LLM に文書+質問を渡して回答生成。"}, {"q": "Embedding モデルの代表として誤りはどれか。", "choices": ["text-embedding-3-large (OpenAI)", "BGE-large (BAAI)", "Cohere Embed v3", "XGBoost"], "answer": 3, "explanation": "XGBoost は勾配ブースティング、テキスト埋め込み用ではない。MTEB ベンチマークで競合中。"}, {"q": "Vector Database で標準的な高速検索アルゴリズムは。", "choices": ["ブルートフォース", "HNSW（Hierarchical Navigable Small World）、IVF-PQ", "K-means", "Decision Tree"], "answer": 1, "explanation": "ANN（Approximate Nearest Neighbor）の代表。HNSW は graph-based で精度・速度両立。FAISS, Pinecone, Qdrant, Weaviate で実装。"}, {"q": "Chunking で典型的なオーバーラップ率は。", "choices": ["0%", "10〜20%（境界問題緩和）", "50%以上", "100%"], "answer": 1, "explanation": "オーバーラップで文脈の境界での情報損失を緩和。chunk_size=500 なら overlap=50〜100 が典型。"}, {"q": "Reranking の目的は。", "choices": ["計算高速化", "Embedding 検索で得た上位文書を Cross-Encoder で再評価し精度向上", "学習", "正則化"], "answer": 1, "explanation": "2段階パイプライン：Embedding で top-50 → Rerank で top-5。Cohere Rerank, BGE Reranker が代表。"}, {"q": "Hybrid Search の典型構成は。", "choices": ["Dense のみ", "Embedding（Dense）+ BM25（Sparse）を RRF で統合", "ランダム", "Sparse のみ"], "answer": 1, "explanation": "Reciprocal Rank Fusion（RRF）で両者の順位を融合。固有名詞・型番に強い BM25 と意味類似の Dense を統合。"}, {"q": "RAG vs Fine-tuning の使い分けで正しいのは。", "choices": ["RAG = スタイル変更", "知識追加・更新は RAG、行動・スタイル変更は Fine-tune", "どちらも同じ", "Fine-tune が常に上"], "answer": 1, "explanation": "RAG = 知識（事実）、Fine-tune = 振舞い（口調、フォーマット）。実用では併用が多い。"}, {"q": "『Faithfulness』が評価する対象は。", "choices": ["速度", "生成回答が取得文書に忠実か（捏造でないか）", "パラメータ数", "コスト"], "answer": 1, "explanation": "RAGAS, TruLensなどで自動評価。LLM-as-Judge（GPT-4） が一般的。幻覚抑制の指標。"}, {"q": "GraphRAG（Microsoft 2024）の特徴は。", "choices": ["単純な BM25", "文書から知識グラフを構築、Global query（全体傾向）にも対応", "Fine-tune必須", "クラスタリング"], "answer": 1, "explanation": "エンティティ・関係抽出 → グラフ → コミュニティ要約。『この文書集合全体の傾向は』のような Global question に強い。"}, {"q": "HyDE（Hypothetical Document Embeddings）の手順は。", "choices": ["質問を直接埋め込み", "LLMに仮回答を生成させ、それを埋め込んで検索", "教師ありのみ", "クラスタ"], "answer": 1, "explanation": "Gao 2022。質問と回答は意味空間で異なる位置にあり得るため、仮回答を介して検索精度向上。"}, {"q": "Self-RAG が用いる仕組みは。", "choices": ["ランダム検索", "Reflection Token で『検索が必要か』『文書が関連か』『裏付けあるか』を LLM 自身が判断", "クラスタリング", "教師あり"], "answer": 1, "explanation": "Asai 2023。不要検索の削減と品質向上を両立。LLMが検索の必要性を判断。"}, {"q": "Cosine類似度の式は。", "choices": ["q + d", "(q·d)/(||q|| ||d||)", "|q - d|", "q × d"], "answer": 1, "explanation": "ベクトル間の角度を測る。長さ非依存で意味の類似度に適する。RAGの標準距離。"}, {"q": "RAG の典型的な失敗パターンは。", "choices": ["速度向上", "Chunk が大きすぎる/小さすぎる、Embedding がドメイン外、適切な Rerank不在", "パラメータ削減", "学習率"], "answer": 1, "explanation": "実用 RAG は『調整勝負』。Chunk size、Embedding 選択、Rerank、プロンプト構造、メタデータフィルタなどの組合せ最適化が肝。"}, {"q": "Multimodal RAG が扱う主なデータは。", "choices": ["テキストのみ", "画像、表、グラフを含む PDF・スライド（CLIP系または Vision LLM 利用）", "音声のみ", "コード"], "answer": 1, "explanation": "技術文書・財務報告書は画像・表が多い。GPT-4V, Claude 3, Gemini が直接処理可能、または CLIP 系で画像埋め込み。"}, {"q": "LangChain の役割は。", "choices": ["学習", "LLMアプリ構築の統合フレームワーク（RAG、Agent、チェーン）", "Vector DB のみ", "Embedding"], "answer": 1, "explanation": "文書ローダー、Splitter、Vector DB、LLM、Retriever、Agent を統合。LlamaIndex は RAG 特化の競合。"}, {"q": "Sentence-Transformers の代表モデルは。", "choices": ["BERT base のみ", "all-MiniLM-L6-v2（軽量384次元、CPU動作可）", "GPT-4", "ResNet"], "answer": 1, "explanation": "開発・プロトタイプの定番。BGE, E5, GTE などより新しいモデルもオープン提供。"}, {"q": "RAGAS フレームワークが提供する RAG 評価指標は。", "choices": ["Accuracy のみ", "Faithfulness, Answer Relevance, Context Precision, Context Recall", "MSE", "R²"], "answer": 1, "explanation": "LLM-as-Judge で自動評価。RAG 特有の側面（事実忠実性、文脈の必要性・十分性）を測定。"}, {"q": "Vector DB の選択基準として誤りはどれか。", "choices": ["規模・QPS要件", "フィルタリング機能", "ホスティング（SaaS vs Self-host）", "どれも同じ性能"], "answer": 3, "explanation": "Pinecone（マネージド）、Weaviate（OSS+クラウド）、Qdrant（OSS Rust高速）、Chroma（軽量）、Milvus（大規模）など特性は大きく違う。"}, {"q": "プロダクション RAG での重要な工夫として誤りはどれか。", "choices": ["クエリ書き換え（query rewriting）", "Rerank", "メタデータフィルタ", "必ず Chunk size を 100 にする"], "answer": 3, "explanation": "Chunk size はデータ・タスク依存で最適化対象。100 だと文脈不足の場合が多い。500前後が経験的に良いが、用途で異なる。"}]}, {"id": "advanced-09-agent", "label": "章21 AI Agent", "count": 20, "desc": "", "problems": [{"q": "AI Agent の定義として最も適切なのは。", "choices": ["単発の質問応答", "目標達成のため自律的に推論・計画・行動するシステム", "Vector DBのみ", "ファインチューニング"], "answer": 1, "explanation": "LLMを脳、ツールを手足、メモリを記憶とする自律システム。1ターン応答との根本的違い。"}, {"q": "ReAct パラダイムの構成は。", "choices": ["Search→Generate", "Thought→Action→Observation のループ", "Train→Test", "Encode→Decode"], "answer": 1, "explanation": "Yao 2022 ReAct論文。LLM が推論→ツール実行→結果観察を繰り返す。Agent の基本パターン。"}, {"q": "Function Calling の役割は。", "choices": ["学習", "LLMが構造化された JSON でツール呼出パラメータを生成", "正則化", "クラスタリング"], "answer": 1, "explanation": "OpenAI 2023標準化、GPT/Claude/Gemini/Llama すべて対応。ツール仕様（JSON Schema）に従いLLMがパラメータ抽出。"}, {"q": "Claude Computer Use（Anthropic 2024）の特徴は。", "choices": ["テキスト生成のみ", "スクリーンショットを見てマウス・キーボードを操作", "Vector検索のみ", "音声処理"], "answer": 1, "explanation": "2024年10月発表。Claude 3.5 Sonnet が画面を理解してPC操作。人間と同じ方法での自動化を可能に。"}, {"q": "Self-Reflection / Self-Critique の効果は。", "choices": ["計算高速化", "Agent が自分の出力を批評・修正することで品質向上", "パラメータ削減", "ランダム化"], "answer": 1, "explanation": "Reflexion (2023), Self-Refine (2023)。HumanEvalでpass@1が67%→91%に。o1 の思考時間長期化もこの思想。"}, {"q": "Multi-Agent フレームワークの代表は。", "choices": ["TensorFlow", "AutoGen (Microsoft)、CrewAI", "scikit-learn", "NumPy"], "answer": 1, "explanation": "AutoGen（カンファレンス形式）、CrewAI（役割明示）、ChatDev（ソフトウェア会社シミュレーション）など。協調で複雑タスクの品質向上。"}, {"q": "Agent の短期メモリの典型実装は。", "choices": ["Vector DB のみ", "直近Nターンを会話履歴としてプロンプトに保持", "ファイル", "なし"], "answer": 1, "explanation": "Conversation Buffer Memory。長くなると要約・圧縮、または Vector Memory に長期化。"}, {"q": "Plan-and-Execute Agent の特徴は。", "choices": ["1ステップで全実行", "最初に計画策定 → サブタスクを順次実行", "ランダム", "学習"], "answer": 1, "explanation": "Chain-of-Thought の発展形。複雑タスクで失敗を減らせる。BabyAGI、AutoGPT の基礎パターン。"}, {"q": "LangGraph が LangChain Agent と異なる点は。", "choices": ["同じ", "状態機械として明示的にモデル化、Cycle・分岐・人間介入を扱える", "Vector DB専用", "学習特化"], "answer": 1, "explanation": "暗黙的ループではなく明示的グラフで Agent を制御。Production-grade Agent の標準。"}, {"q": "Agent の典型的な失敗パターンは。", "choices": ["無限ループ、過剰なツール呼出、コスト爆発", "学習速度低下", "メモリリーク", "なし"], "answer": 0, "explanation": "max_iterations 設定、ループ検出、コスト上限、人間承認などのガードレールが本番必須。"}, {"q": "AutoGPT (2023) の意義は。", "choices": ["学習アルゴリズム", "自律 LLM Agent の先駆け、技術的限界はあったがAgent ブームの火付け役", "Vector DB", "単なる検索"], "answer": 1, "explanation": "2023年初、GPT-4 ベース。タスク自動分解実行のループ。実用性は限定的だったが、Agent概念を一般に広めた。"}, {"q": "『Tool Use』の代表的ツールカテゴリは。", "choices": ["学習", "検索、計算、API、ファイル操作、ブラウザ・PC制御", "単一機能のみ", "Vector のみ"], "answer": 1, "explanation": "多様なツールが LLM の能力を拡張。Web search、Code Interpreter、SaaS API、Computer Use など。"}, {"q": "Tree of Thoughts（ToT）の発展点は。", "choices": ["単線思考", "思考を木構造で分岐探索し最良経路選択", "Vector検索", "教師あり"], "answer": 1, "explanation": "Yao 2023。CoTを枝分かれにし、BFS/DFS的に探索。数独、24パズル等で高性能。"}, {"q": "Reflexion（2023）の動作は。", "choices": ["教師あり", "Agent が失敗から自己批評＆メモリ蓄積→次回反映", "Vector DB のみ", "クラスタ"], "answer": 1, "explanation": "Shinn 2023。失敗の言語的反省を Memory に蓄積、次の試行で参照。コード生成でpass@1 を大幅向上。"}, {"q": "OpenAI o1 / o3 が従来 LLM と異なる点は。", "choices": ["パラメータが100倍", "推論時に長い『思考』を行い、Self-Reflection内蔵", "Vector検索専用", "多言語のみ"], "answer": 1, "explanation": "Test-time compute scaling。数十秒〜数分の思考連鎖で複雑タスク（数学、コード）で人間レベル超え。"}, {"q": "Agent のメモリで Vector Memory が解決する問題は。", "choices": ["計算速度", "長期記憶（過去会話・経験から関連情報を検索可能に）", "学習", "パラメータ"], "answer": 1, "explanation": "会話履歴をベクトル化し、関連時に取得。個人化、長期セッション、経験学習に必須。"}, {"q": "Program-Aided Language Models (PAL) の特徴は。", "choices": ["計算", "LLM が Python コードを生成→実行→結果を使う（数値計算誤りを防ぐ）", "Vector検索", "教師あり"], "answer": 1, "explanation": "Gao 2022。LLM の苦手な厳密計算を Python に委任。数学・データ処理タスクで高精度。"}, {"q": "2024年に登場した Devin AI の特徴は。", "choices": ["単純チャット", "自律的にコーディングタスクを完遂、ブラウザ・エディタ操作可能", "Vector検索のみ", "画像生成"], "answer": 1, "explanation": "Cognition Labs。コード生成、デバッグ、デプロイまで一貫実行のAI Software Engineer。SWE-Bench で当時 SOTA。"}, {"q": "Agent の安全性で重要なのは。", "choices": ["全自動が常に良い", "Human-in-the-Loop、ツール権限制限、コスト上限、監査ログ", "なし", "速度"], "answer": 1, "explanation": "自律実行のリスク：誤ったAPI呼出、機密漏洩、コスト爆発。人間承認、サンドボックス、レート制限が必須。"}, {"q": "Agent と LLM 単独 RAG の本質的違いは。", "choices": ["同じ", "Agentは多段階推論＋ツール選択＋ループ、RAGは1ターン取得+生成", "Vector不使用", "学習"], "answer": 1, "explanation": "RAG は静的なパイプライン（検索→生成）、Agent は動的な意思決定（どのツールを何回呼ぶか LLM が判断）。Agent内でRAGをツールとして使える。"}]}, {"id": "advanced-10-mlops", "label": "章22 MLOps", "count": 20, "desc": "", "problems": [{"q": "MLOps の主な対象は。", "choices": ["モデル学習のみ", "MLシステムのライフサイクル全体（データ・学習・デプロイ・運用・再学習）の自動化", "データ収集のみ", "評価のみ"], "answer": 1, "explanation": "Google『Hidden Technical Debt in ML Systems』が原点。コードはML全体の5〜10%、残りは MLOps インフラ。"}, {"q": "Feature Store の主な目的は。", "choices": ["モデル管理", "学習時とサービング時で一貫した特徴量提供、Training-Serving Skew 防止", "パラメータ追跡", "ログ収集"], "answer": 1, "explanation": "Feast、Tecton、SageMaker Feature Store、Vertex AI Feature Store。特徴量の再利用と一貫性が核心。"}, {"q": "MLflow の主機能でないのは。", "choices": ["実験追跡（パラメータ、メトリクス）", "モデルレジストリ", "プロジェクトパッケージング", "データベース管理"], "answer": 3, "explanation": "MLflow は Tracking、Models、Projects、Registry の4機能。データベース自体は管理対象外。"}, {"q": "CI/CD for ML で『CT』が表すのは。", "choices": ["Continuous Testing", "Continuous Training（Drift時等の自動再学習）", "Continuous Tracking", "Continuous Tagging"], "answer": 1, "explanation": "MLOps の独自概念。CI（コードテスト）+ CD（デプロイ）+ CT（再学習）の3要素。"}, {"q": "Data Drift と Concept Drift の違いは。", "choices": ["同じ", "Data: P(X) 変化、Concept: P(Y|X) 変化", "Drift は無関係", "ラベルだけ"], "answer": 1, "explanation": "Data Drift = 入力分布の変化（季節、ユーザー層変化）、Concept Drift = 入力→出力関係の変化（嗜好変化）。両方を監視。"}, {"q": "PSI（Population Stability Index）の用途は。", "choices": ["学習", "分布変化の定量化（金融でDrift検知に標準）。0.2以上で警告", "パラメータ調整", "ノイズ生成"], "answer": 1, "explanation": "PSI = Σ (P_new - P_ref) · ln(P_new / P_ref)。0.1未満=安定、0.1-0.2=やや変化、0.2以上=大きな変化。"}, {"q": "Canary Release の特徴は。", "choices": ["全トラフィック切替", "新モデルに少量トラフィック（1〜5%）流して段階的に拡大、異常時即ロールバック", "シャドウ", "A/B均等"], "answer": 1, "explanation": "Kubernetes/Istio で実装。安全なロールアウトの定番。Blue-Green デプロイより漸進的。"}, {"q": "Shadow Mode の特徴は。", "choices": ["ユーザに新モデル結果を返す", "本番トラフィックを両方に流すが新モデル結果は記録のみ、ユーザ影響ゼロで評価", "ランダム", "オフライン"], "answer": 1, "explanation": "本番影響なしで新モデルを評価。レイテンシ、メモリ、予測一致度を確認。Canary 前の安全策。"}, {"q": "Kubeflow の主な特徴は。", "choices": ["クラウド専用", "Kubernetesネイティブの OSS、MLパイプライン・分散学習・推論を統合", "AWS専用", "Python専用"], "answer": 1, "explanation": "Kubeflow Pipelines, KServe, Training Operator, Katib (HPO)。クラウド非依存、on-premise でも動く。"}, {"q": "AWS SageMaker の主機能でないのは。", "choices": ["マネージドGPU 学習", "Endpoint デプロイ", "Feature Store", "仮想通貨マイニング"], "answer": 3, "explanation": "SageMaker は ML特化マネージドサービス。Studio、Training Jobs、Endpoints、Pipelines、Clarify（Bias）、Ground Truth など。"}, {"q": "バッチ推論が向くケースは。", "choices": ["リアルタイム必要", "大量データを定期的に処理（夜間バッチ、レポート、推薦の事前計算）", "チャット", "ストリーミング"], "answer": 1, "explanation": "Spark、AWS Batch、Airflow で実装。リアルタイム性不要・GPUコスト最適化が目的。"}, {"q": "Edge推論の典型ユースケースは。", "choices": ["大型サーバ", "スマホ・IoT・自動車などデバイス上で推論（TF Lite、ONNX、Core ML）", "クラウドのみ", "オフライン学習"], "answer": 1, "explanation": "プライバシー・遅延・通信コストの観点でデバイス上推論が重要。量子化（INT8）、Pruning でモデル軽量化。"}, {"q": "A/B Test と Multi-Armed Bandit の違いは。", "choices": ["同じ", "A/B は固定割合、MAB は性能高いモデルに動的に割合増加（Thompson Sampling、UCB）", "A/B はクラスタリング", "MAB は強化学習"], "answer": 1, "explanation": "MAB は Exploration-Exploitation を強化学習的に最適化。総合報酬最大化、A/B Test の発展形。"}, {"q": "Triton Inference Server の特徴は。", "choices": ["学習専用", "NVIDIA製、高性能推論サーバ、複数フレームワーク（PyTorch、TF、ONNX）・複数モデルを統合提供", "DB", "コンパイラ"], "answer": 1, "explanation": "gRPC/HTTP両対応、Dynamic Batching、Model Concurrency でGPUを最大活用。SageMaker・Vertex でも統合。"}, {"q": "DVC の主機能は。", "choices": ["ニューラルネット", "データ・モデルのバージョン管理（Gitに統合、大ファイルは外部ストレージへ）", "学習", "クラウド管理"], "answer": 1, "explanation": "Data Version Control。Git は大ファイルが苦手、DVC はメタ情報のみGit、本体はS3/GCS等。再現性確保に重要。"}, {"q": "Apache Airflow の主機能は。", "choices": ["ML特化", "汎用ワークフロー（DAG）スケジューラ、データパイプライン・ML パイプライン用", "DBMS", "Webサーバ"], "answer": 1, "explanation": "Python で DAG を記述、スケジュール実行。MLOps では学習・推論・前処理を構成。代替に Dagster、Prefect、Argo。"}, {"q": "Training-Serving Skew の典型原因は。", "choices": ["学習データが少ない", "学習時とサービング時で特徴量の計算ロジックが微妙に異なる", "パラメータ多い", "ランダム性"], "answer": 1, "explanation": "例：学習で平均値補完、サービングで0補完。Feature Store で計算ロジック共有することで防止。"}, {"q": "本番運用で監視すべきメトリクスでないのは。", "choices": ["レイテンシ p99", "スループット（QPS）", "エラー率", "開発者のメール頻度"], "answer": 3, "explanation": "システム面（レイテンシ、QPS、エラー率、CPU/GPU）とモデル面（予測分布、入力分布、Drift）を監視。Prometheus + Grafana が標準。"}, {"q": "Model Card の役割は。", "choices": ["学習データ", "モデルの用途、性能、制限、Bias情報を文書化（Google Mitchell 2019）。透明性確保", "名刺", "クラスタリング"], "answer": 1, "explanation": "モデルの『使用説明書』。EU AI Act、ISO/IEC 23053 などで義務化方向。Hugging Face で標準化。"}, {"q": "『MLOps Maturity』レベル0の特徴は。", "choices": ["完全自動化", "全て手動、学習・デプロイ・モニタリング無連携", "Drift自動再学習", "MLOpsなし"], "answer": 1, "explanation": "Google MLOps Maturity Model。Level 0=Manual、Level 1=ML Pipeline自動化、Level 2=CI/CD/CT完全統合。多くの企業はLevel 0-1。"}]}, {"id": "advanced-11-ethics", "label": "章23 AI倫理", "count": 20, "desc": "", "problems": [{"q": "AIバイアスの『歴史的バイアス』の典型例は。", "choices": ["ランダム", "過去の社会的不平等がデータに含まれ、AIが学習して再生産", "計算誤差", "学習率"], "answer": 1, "explanation": "Amazon の採用AI事件（2018）。過去10年の採用データが男性中心で、AIが女性の履歴書を低評価した。データの選別だけでは解決困難。"}, {"q": "Demographic Parity（人口統計学的等しさ）の定義は。", "choices": ["同じ Accuracy", "全グループで陽性予測率が同じ：P(Ŷ=1|A=0) = P(Ŷ=1|A=1)", "同じ Recall", "同じ Precision"], "answer": 1, "explanation": "最もシンプルだが結果指標を強制するため、Equal Opportunity（TPR等値）と矛盾しうる。Fairness Impossibility Theorem。"}, {"q": "Fairness Impossibility Theorem の主張は。", "choices": ["全てのFairnessは矛盾", "基準値が異なるグループでは複数のFairness定義（Calibration、Equal Opportunity、Equalized Odds）を同時には満たせない", "Fairness 不可能", "何もできない"], "answer": 1, "explanation": "Kleinberg 2016, Chouldechova 2017。トレードオフの選択を文脈に応じて行う必要がある。"}, {"q": "SHAP の数学的基盤は。", "choices": ["線形回帰", "協力ゲーム理論の Shapley 値（各特徴の限界貢献度の平均）", "クラスタリング", "ベイズ"], "answer": 1, "explanation": "一貫性・局所精度・無依存性などの公理を満たす唯一の説明手法。Lundberg & Lee 2017。"}, {"q": "LIME の動作は。", "choices": ["大域的説明", "個別予測点の周辺で線形モデルで局所近似し説明", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Ribeiro 2016。摂動サンプルを生成、重み付き線形回帰で局所的説明。モデル非依存（black-box対応）。"}, {"q": "Differential Privacy（ε-DP）の意味は。", "choices": ["ノイズなし", "1人のデータ変化で出力分布が e^ε 倍以内、個人特定リスクを数学的に制限", "学習加速", "暗号化"], "answer": 1, "explanation": "Dwork 2006。εが小さいほどプライバシー強、精度低下とのトレードオフ。Apple、Google、米国国勢調査で採用。"}, {"q": "DP-SGD の実装の核心は。", "choices": ["学習率変化", "各サンプル勾配をクリップ後、Gaussian ノイズを加えて集約", "ランダム選択", "パラメータ削除"], "answer": 1, "explanation": "Abadi 2016。Moments Accountantでεを厳密追跡。Opacus（PyTorch）、TF Privacy で実装。"}, {"q": "FGSM（Fast Gradient Sign Method）の式は。", "choices": ["x' = x + ε", "x' = x + ε · sign(∇ₓ L)", "x' = -x", "x' = 2x"], "answer": 1, "explanation": "損失を最大化する方向に微小摂動を加える。Goodfellow 2014。最も基本的な敵対的攻撃。PGD はその反復強化版。"}, {"q": "Adversarial Training は何を行うか。", "choices": ["ランダム学習", "敵対的サンプルを学習データに混ぜて学習、Robustness を獲得", "パラメータ削減", "クラスタリング"], "answer": 1, "explanation": "Madry 2018。PGD で生成した敵対的サンプルで Min-Max 学習。クリーン精度は微減、頑健性は大幅向上。"}, {"q": "Federated Learning の核心は。", "choices": ["中央データ集約", "データを中央化せず、各クライアントで学習→勾配のみ集約", "クラウドのみ", "シングルマシン"], "answer": 1, "explanation": "McMahan 2017 (Google)。Gboard、医療機関連携で実用。Secure Aggregation、DP と組み合わせて更にプライバシー強化。"}, {"q": "AI Alignment 問題の核心は。", "choices": ["計算速度", "AIシステムの目標を人間の真の意図と整合させること（誤った目標関数で学習すると有害な行動）", "パラメータ最適化", "クラスタリング"], "answer": 1, "explanation": "Anthropic、OpenAI、DeepMind の中核研究分野。RLHF、Constitutional AI、Debate、IDA などが主要手法。"}, {"q": "Reward Hacking（報酬ハッキング）の例は。", "choices": ["学習成功", "目標関数の意図しない『穴』を突いて高得点だが望ましくない行動（CoastRunners でゲーム本来の目的を無視して報酬狩り）", "パラメータ調整", "クラスタリング"], "answer": 1, "explanation": "Specification Gaming の一種。AGI が現実世界で類似行動を取ることがAI Safetyの主要懸念。"}, {"q": "Constitutional AI（Anthropic）の特徴は。", "choices": ["法律遵守", "AI自身が憲法（行動原則）に照らして自己批評・修正、RLAIF で大規模化", "ランダム", "クラスタリング"], "answer": 1, "explanation": "Bai 2022。Claude モデルの基盤。RLHF の人間ラベラーの代わりに AI判定を使い、Alignment を大規模化。"}, {"q": "Grad-CAM の用途は。", "choices": ["学習加速", "CNN の予測根拠を画像上にヒートマップで可視化", "パラメータ削減", "クラスタリング"], "answer": 1, "explanation": "Selvaraju 2017。最後のConv層の活性化と勾配の重み付き和。医療画像、自動運転の説明に重要。"}, {"q": "Deepfake の主な技術基盤は。", "choices": ["ロジスティック回帰", "GAN、Diffusion Model、Autoencoder", "線形回帰", "K-means"], "answer": 1, "explanation": "生成モデルで顔・声を合成。検知技術（Deepfake Detection、C2PA、SynthID）も並行発展中。EU AI Act で透明性表示義務化。"}, {"q": "Membership Inference Attack（メンバーシップ推定攻撃）の標的は。", "choices": ["モデル盗難", "特定の個人データがモデルの学習データに含まれていたか推定する攻撃", "パラメータ盗難", "ラベル改ざん"], "answer": 1, "explanation": "プライバシー侵害の一形態。学習データへの過剰適合が手がかり。DPで防御。Shokri 2017。"}, {"q": "Model Inversion Attack の目的は。", "choices": ["モデル予測", "モデルの出力から学習データの特徴を復元（顔認証から顔画像復元等）", "パラメータ盗難", "ラベル改ざん"], "answer": 1, "explanation": "Fredrikson 2015。プライバシー侵害の重大形式。DP、出力の粗視化で防御。"}, {"q": "LLM の Jailbreak とは。", "choices": ["学習", "プロンプトエンジニアリングで安全機構を回避し有害出力を引き出す", "パラメータ盗難", "クラスタリング"], "answer": 1, "explanation": "DAN、ロールプレイ、Many-shot Jailbreak（Anthropic 2024）など多様。LLM 安全研究の主要課題。"}, {"q": "『Right to Explanation』が法的に要求される代表例は。", "choices": ["全てのAI", "GDPR（EU）の自動意思決定条項、EU AI Act の高リスクシステム", "なし", "業界自主"], "answer": 1, "explanation": "GDPR Art. 22。重要な判断（融資拒否、採用、医療）にAIを使う場合、本人に説明する義務。SHAP/LIMEがその実装手段。"}, {"q": "大規模LLMの環境影響として正しいのは。", "choices": ["影響なし", "学習に巨大な電力消費とCO₂排出（GPT-3: 552 t CO₂相当、Strubell 2019）", "パラメータ少ない", "クラスタリング"], "answer": 1, "explanation": "モデル巨大化のサステナビリティ問題。Green AI、再生可能エネルギー使用、効率化（蒸留、量子化）が課題。"}]}, {"id": "advanced-12-law", "label": "章24 AI法規制", "count": 20, "desc": "", "problems": [{"q": "EU AI Act が採用したアプローチは。", "choices": ["一律規制", "リスクベース（許容不可〜最小リスクの4段階＋GPAI）", "自主規制のみ", "禁止のみ"], "answer": 1, "explanation": "リスクレベルに応じた段階規制。世界初の包括的AI法、2024年発効、2026年8月本格施行。"}, {"q": "EU AI Act で『許容不可リスク』に分類されるのは。", "choices": ["スパムフィルタ", "社会信用スコア、サブリミナル操作、リアルタイム公開生体認識", "チャットボット", "翻訳"], "answer": 1, "explanation": "第5条で原則禁止される行為。一部例外あり（テロリスト捜索の生体認識など）。"}, {"q": "GDPR 第22条の規定は。", "choices": ["個人データの所有権", "完全自動意思決定に対する人間の関与権・説明要求権", "罰金規定", "域外適用"], "answer": 1, "explanation": "法的効果を持つ自動決定（融資、採用）には人間関与が必要。例外あり（同意、契約必要、法的根拠）。"}, {"q": "日本の著作権法でAI学習を原則合法とする条項は。", "choices": ["第30条", "第30条の4（情報解析のための利用）", "第32条", "第47条の5"], "answer": 1, "explanation": "2018年改正で導入。情報解析（学習）目的での複製・公衆送信を原則認める。ただし著作権者の利益を不当に害する場合は除外。"}, {"q": "米国の著作権で、AI生成物に著作権が認められない判例として正しいのは。", "choices": ["Thaler v. Perlmutter（人間の創作性必要）", "NYT v. OpenAI", "Stable Diffusion 判決", "DABUS 判例"], "answer": 0, "explanation": "2023年。完全AI生成物に著作権登録却下。人間の創作的貢献が必要。日本も同様の方向。"}, {"q": "GDPR 違反の最大罰金は。", "choices": ["€10M or 全世界売上の2%", "€20M or 全世界売上の4%（高い方）", "€100M", "罰金なし"], "answer": 1, "explanation": "重大違反で €20M または前年度全世界売上の4%のいずれか高い方。EU AI Act は €35M または7%でさらに厳しい。"}, {"q": "EU AI Act の『GPAI』に該当するモデルは（典型例）。", "choices": ["線形回帰", "GPT-4、Claude、Gemini など 10²⁵ FLOPs 超の汎用基盤モデル", "K-means", "全モデル"], "answer": 1, "explanation": "General Purpose AI モデル。10²⁵ FLOPs 超は『体系的リスク』を持つとして追加義務（評価、サイバーセキュリティ、報告）。"}, {"q": "Anthropic ASL（Responsible Scaling Policy）の特徴は。", "choices": ["政府規制", "モデル能力に応じた自主基準、能力評価で次レベルに移行", "罰則あり", "1段階のみ"], "answer": 1, "explanation": "ASL-1〜4。能力評価でレベル決定、各レベルで安全要件。OpenAI Preparedness Framework、DeepMind FSF も類似。"}, {"q": "日本のAI事業者ガイドライン（2024年）のアプローチは。", "choices": ["罰則付きハードロー", "開発者・提供者・利用者向けソフトロー", "禁止リスト", "何もなし"], "answer": 1, "explanation": "総務省・経産省合同。法的拘束力なしのガイドラインだが、業界標準として広く参照される。3主体別の規範を提示。"}, {"q": "『DABUS判例』が確立したのは。", "choices": ["AIに著作権", "AIを発明者とする特許は認めない（多数国）", "AIが法人格", "AIが訴訟当事者"], "answer": 1, "explanation": "英・豪・欧・米・日でAI単独発明者を却下。発明者は自然人のみ。ただしAI利用発明は人間発明者として可。"}, {"q": "GDPR の『忘れられる権利』をLLMで実装する際の技術的課題は。", "choices": ["簡単に削除可", "一度学習されたデータの選択的削除は技術的に困難（Machine Unlearning 研究）", "不要", "パラメータ削減で対応"], "answer": 1, "explanation": "NN は分散表現なので個別データの削除が難しい。Machine Unlearning、SISA、Approximate Unlearning などの研究分野。"}, {"q": "米国 California SB-1047 の対象モデル基準は。", "choices": ["全モデル", "学習費用 $100M 超 or 10²⁶ FLOPs 超の Frontier モデル", "MNIST モデル", "ローカルLLMのみ"], "answer": 1, "explanation": "2024年に Newsom 拒否権で頓挫したが、改訂版議論中。フロンティアモデル開発者に安全評価・報告義務を課す提案。"}, {"q": "『広島AIプロセス』の主体は。", "choices": ["国連", "G7主導の生成AI国際ガバナンス枠組み", "日本単独", "EU単独"], "answer": 1, "explanation": "2023年G7広島サミットで開始、国際指針・行動規範を策定。OECD、UN AI Advisory Body と連携。"}, {"q": "NIST AI Risk Management Framework の役割は。", "choices": ["米法律", "AI リスク管理の自主的フレームワーク（Govern, Map, Measure, Manage の4機能）", "罰則", "EU専用"], "answer": 1, "explanation": "2023年公表。米企業のデファクト標準的フレームワーク。ISO/IEC 42001（AI管理システム）と相補的。"}, {"q": "EU AI Act の『高リスク』分野でないのは。", "choices": ["採用判断", "信用評価", "スパムフィルタ", "医療機器"], "answer": 2, "explanation": "スパムフィルタは『最小リスク』。Annex III の高リスク分野は雇用、信用、教育、医療、法執行、国境管理など8カテゴリ。"}, {"q": "著作権法における日本とEUの違いは。", "choices": ["同じ", "日本：第30条の4で原則OK、EU：DSM指令でテキスト・データマイニング権あるが商用利用にはオプトアウト可", "両方禁止", "両方完全自由"], "answer": 1, "explanation": "EU はオプトアウト権が著作権者にあり、商用利用での学習に拒否表示できる。日本は第30条の4で広く認める。"}, {"q": "ディープフェイク規制の米国の動向は。", "choices": ["全面禁止", "Tennessee州 ELVIS Act（音声）、NO FAKES Act（連邦提案）など州・連邦で立法化進行", "何もなし", "全許可"], "answer": 1, "explanation": "各州が肖像・音声権を立法化。NO FAKES Act は連邦レベルの統一を目指す。EU AI Act の透明性義務とも関連。"}, {"q": "『モデルカード』（Model Card）の役割は。", "choices": ["学習ループ", "AIモデルの意図された用途、限界、評価結果、倫理的考慮を文書化する透明性ツール", "ハイパラ管理", "ハードウェア仕様"], "answer": 1, "explanation": "Mitchell 2019。HuggingFace でデファクト標準化。EU AI Act 文書化義務とも整合。"}, {"q": "EU の DMA（Digital Markets Act）の対象は。", "choices": ["全AI", "プラットフォーム独占を抑制、Gatekeeper 認定企業（Microsoft、Google、Meta、Apple等）に義務", "個人開発者", "中小企業"], "answer": 1, "explanation": "2024年施行。大手プラットフォームの市場支配力濫用を抑制。AI 機能の差別的提供禁止などが含まれる。"}, {"q": "G検定取得者として、AI法規制への向き合い方として最も適切なのは。", "choices": ["法律家任せ", "開発・運用ライフサイクルの各段階で法的論点を意識し、必要なら専門家と協働", "無視", "必ず最も厳しい規制に合わせる"], "answer": 1, "explanation": "設計時のリスク評価、データ取得時の権利クリア、運用時の説明可能性、生成物の権利処理、契約レビュー。技術と法務の協働が現代AIの開発標準。"}]}]};